    ClearExtractCache: vi.fn(),
    GetThumbnailBatch: vi.fn(),
    GetModelMetaBatch: vi.fn(),
    GetRecentModels: vi.fn(),
    AddRecentModel: vi.fn(),
    GetAllTags: vi.fn(),
    GetModelsByTag: vi.fn(),
    SelectAudioFile: vi.fn(),
