vi.mock('./model-detail', () => ({ buildModelLevel: vi.fn() }));
vi.mock('../menus/scene-menu', () => ({ buildStageTransformLevel: vi.fn() }));
vi.mock('./menu', () => ({ SlideMenu: vi.fn() }));
vi.mock('../core/icons', () => ({ createIconifyIcon: vi.fn(() => null) }));
vi.mock('../core/ui-helpers', () => ({
