vi.mock('../core/config', () => ({
    get allModels() { return mockState.allModels; },
    get libraryRoot() { return mockState.libraryRoot; },
    get displayNamePriority() { return mockState.displayNamePriority; },
    get librarySortMode() { return mockState.librarySortMode; },
