    '左ひじ', '右ひじ', '左手首', '右手首',
    '左足', '右足', '左ひざ', '右ひざ',
    '左足首', '右足首', '左つま先', '右つま先',
    '左足ＩＫ', '右足ＩＫ', '左つま先ＩＫ', '右つま先ＩＫ',
    '左目', '右目', '両目',
    '左胸', '右胸',
];

