            ({ left: 0, width: 200, top: 0, height: 20, right: 200, bottom: 20, x: 0, y: 0, toJSON: () => ({}) }) as DOMRect;

        bar.dispatchEvent(new MouseEvent('click', { clientX: 50 }));
