// xpbd-cloth — 布料拓扑与真实函数
// ====================================================================

interface ClothTopoTest {
    solver: XpbdSolver;
    particleGrid: number[];
    anchorIndices: number[];
    ringSize: number;
    ringCount: number;
}

function makeClothTopo(segmentsH: number, segmentsV: number, innerRadius: number, length: number, slopeDeg: number, compliance: number, bendCompliance: number): ClothTopoTest {
    const solver = new XpbdSolver({ substeps: 4, damping: 0.96 });
    const ringSize = segmentsH, ringCount = segmentsV, totalMass = 0.5;
    const nonAnchorMass = totalMass / (ringSize * (ringCount - 1));
    const particleGrid: number[] = [], anchorIndices: number[] = [];
    for (let row = 0; row < ringCount; row++) {
        const t = row / (ringCount - 1), y = -t * length;
        const slopeRad = (slopeDeg * Math.PI) / 180, r = innerRadius + t * length * Math.tan(slopeRad);
        for (let col = 0; col < ringSize; col++) {
            const angle = (col / ringSize) * Math.PI * 2;
            const idx = solver.addParticle([Math.cos(angle)*r, y, Math.sin(angle)*r], row===0 ? Infinity : nonAnchorMass, 0.03);
            particleGrid.push(idx);
            if (row === 0) anchorIndices.push(idx);
        }
    }
    for (let row = 0; row < ringCount; row++)
        for (let col = 0; col < ringSize; col++) {
            const i = particleGrid[row*ringSize+col];
            solver.addDistanceConstraint(i, particleGrid[row*ringSize+((col+1)%ringSize)], compliance);
            if (row+1 < ringCount) solver.addDistanceConstraint(i, particleGrid[(row+1)*ringSize+col], compliance);
        }
    for (let row = 0; row < ringCount; row++)
        for (let col = 0; col < ringSize; col++) {
            const i = particleGrid[row*ringSize+col];
            solver.addBendConstraint(i, particleGrid[row*ringSize+((col+1)%ringSize)], particleGrid[row*ringSize+((col+2)%ringSize)], bendCompliance);
            if (row+2 < ringCount) solver.addBendConstraint(i, particleGrid[(row+1)*ringSize+col], particleGrid[(row+2)*ringSize+col], bendCompliance);
        }
    return { solver, particleGrid, anchorIndices, ringSize, ringCount };
}

describe('M4: Cloth Topology (xpbd-cloth)', () => {
    const DH = 24, DV = 12;
    const baseOpts = { h: DH, v: DV, inner: 0.15, len: 0.6, slope: 15, comp: 0.001, bend: 0.005 };

    it('total particles = segmentsH * segmentsV', () => {
        const { solver, ringSize, ringCount } = makeClothTopo(baseOpts.h, baseOpts.v, baseOpts.inner, baseOpts.len, baseOpts.slope, baseOpts.comp, baseOpts.bend);
        expect(solver.particles.length).toBe(ringSize * ringCount);
        expect(solver.particles.length).toBe(288);
    });

    it('all top-ring particles are fixed', () => {
        const { anchorIndices, ringSize } = makeClothTopo(baseOpts.h, baseOpts.v, baseOpts.inner, baseOpts.len, baseOpts.slope, baseOpts.comp, baseOpts.bend);
        expect(anchorIndices.length).toBe(ringSize);
    });

    it('distance constraints count = V*H + (V-1)*H', () => {
        const { solver, ringSize, ringCount } = makeClothTopo(baseOpts.h, baseOpts.v, baseOpts.inner, baseOpts.len, baseOpts.slope, baseOpts.comp, baseOpts.bend);
        expect(solver.constraints.filter(c => c.type==='distance').length).toBe(ringCount*ringSize + (ringCount-1)*ringSize);
    });

    it('bend constraints count = V*H + (V-2)*H', () => {
        const { solver, ringSize, ringCount } = makeClothTopo(baseOpts.h, baseOpts.v, baseOpts.inner, baseOpts.len, baseOpts.slope, baseOpts.comp, baseOpts.bend);
        expect(solver.constraints.filter(c => c.type==='bend').length).toBe(ringCount*ringSize + (ringCount-2)*ringSize);
    });

    it('cloth hangs vertically when top ring is fixed', () => {
        const { solver, anchorIndices, ringSize, ringCount } = makeClothTopo(baseOpts.h, baseOpts.v, baseOpts.inner, baseOpts.len, 0, baseOpts.comp, baseOpts.bend);
        for (const idx of anchorIndices) solver.particles[idx].invMass = 0;
        for (let f = 0; f < 300; f++) solver.step(1/60);
        const lastRowStart = (ringCount-1)*ringSize;
        for (let col = 0; col < ringSize; col++)
            expect(solver.particles[lastRowStart+col].p[1]).toBeLessThan(-0.8);
    });

    it('skirt topology: bottom radius > innerRadius when slope > 0', () => {
        const { solver, ringSize, ringCount } = makeClothTopo(baseOpts.h, baseOpts.v, 0.15, 0.6, 45, baseOpts.comp, baseOpts.bend);
        let botDistSum = 0;
        const lastRowStart = (ringCount-1)*ringSize;
        for (let col = 0; col < ringSize; col++) botDistSum += Math.sqrt(solver.particles[lastRowStart+col].p[0]**2 + solver.particles[lastRowStart+col].p[2]**2);
        expect(botDistSum / ringSize).toBeCloseTo(0.75, 1);
    });

    it('low-res (12,6) end-to-end stability', () => {
        const { solver, anchorIndices } = makeClothTopo(12, 6, 0.15, 0.6, 15, 0.001, 0.005);
        for (const idx of anchorIndices) solver.particles[idx].invMass = 0;
        solver.addGroundCollision(-1.5);
        for (let f = 0; f < 200; f++) solver.step(1/60);
        for (const p of solver.particles) expect(isFinite(p.p[0])).toBe(true);
    });

