// ======== Android storage permission (MANAGE_EXTERNAL_STORAGE) ========
// On Android 11+, reading /sdcard/MMD requires "All files access" permission.
// The native side fires a "storage:permissionGranted" event when the user
// grants it in Settings. We listen for that and rescan the model library.
//
// The native bridge also exposes window.wails.hasStoragePermission() and
// window.wails.requestStoragePermission() for the JS side to query/prompt.

declare global {
    interface Window {
        wails?: {
            platform?: () => string;
            hasStoragePermission?: () => boolean;
            requestStoragePermission?: () => void;
        };
    }
}

function isAndroidPlatform(): boolean {
    return typeof window !== 'undefined'
        && typeof window.wails?.platform === 'function'
        && window.wails.platform() === 'android';
}

// On first launch on Android, if permission isn't granted, prompt the user.
// We delay this so the scene/UI is ready before the dialog appears.
let androidStoragePromptShown = false;
function checkAndroidStoragePermission(): void {
    if (!isAndroidPlatform()) return;
    if (androidStoragePromptShown) return;

    const w = window.wails!;
    if (typeof w.hasStoragePermission === 'function' && !w.hasStoragePermission()) {
        androidStoragePromptShown = true;
        if (typeof w.requestStoragePermission === 'function') {
            setStatus('⚠️ 需要文件访问权限才能读取 /sdcard/MMD，请在弹窗中授权', true);
            w.requestStoragePermission();
        }
    }
}

// When the native side reports a fresh grant, rescan the library.
Events.On('storage:permissionGranted', async () => {
    setStatus('✅ 文件权限已授予，正在重新扫描模型库...', false);
    try {
        await refreshLibrary();
        setStatus('✅ 模型库已刷新', false);
    } catch (err) {
        console.error('refreshLibrary after permission grant:', err);
        setStatus('⚠️ 模型库刷新失败：' + formatError(err), true);
    }
});

// Boot the app, then on Android prompt for storage permission if needed.
init().then(() => {
    // Small delay so the main UI is ready before the permission dialog.
    setTimeout(checkAndroidStoragePermission, 1500);
}).catch(console.error);

// [doc:adr-049] 球面坐标轨道控制 — 笛卡尔 ↔ 球面坐标统一转换工具
// 与灯光系统 `lighting.ts` 的 orbit 公式保持完全一致（atan2(x, z) / asin(y/len)）。
// 模型与道具共用此模块，避免各子系统重复实现导致漂移。

export interface OrbitCoords {
    /** 水平方位角，度，绕 Y 轴，范围 -180~180 */
    azimuth: number;
    /** 垂直仰角，度，范围 -90~90 */
    elevation: number;
    /** 距原点距离，> 0 */
    distance: number;
}

/** 轨道距离下限：distance<=0 或非有限时钳制到此值，避免塌缩到原点或 NaN。 */
export const MIN_ORBIT_DISTANCE = 0.001;

/**
 * 钳制一组原始轨道参数为合法值域。
 * - distance 必须 > 0 且有限，否则取 MIN_ORBIT_DISTANCE
 * - elevation 收敛到 [-90, 90]
 * - azimuth 必须有限，否则取 0
 * 合法输入原样返回，因此对正常工作流零影响。供 model-manager / props 的 setter 复用，
 * 确保持久化的 orbit 字段始终合法（损坏场景文件反序列化也不会写入退化值）。
 */
export function normalizeOrbit(
    azimuth: number,
    elevation: number,
    distance: number,
): OrbitCoords {
    const safeDistance = Number.isFinite(distance) && distance > 0 ? distance : MIN_ORBIT_DISTANCE;
    const safeElevation = Number.isFinite(elevation) ? Math.max(-90, Math.min(90, elevation)) : 0;
    const safeAzimuth = Number.isFinite(azimuth) ? azimuth : 0;
    return { azimuth: safeAzimuth, elevation: safeElevation, distance: safeDistance };
}

/**
 * 球面坐标 → 笛卡尔坐标。
 * 以原点为中心：azimuth 决定水平朝向，elevation 决定高低，distance 决定半径。
 * 自带边界保护：elevation 收敛到 [-90,90]，distance 非有限或 <=0 时钳制到最小值，
 * 任何输入均返回有限坐标，绝不产生 NaN。
 */
export function orbitToCartesian(
    azimuthDeg: number,
    elevationDeg: number,
    distance: number,
): [number, number, number] {
    const safeElevation = Number.isFinite(elevationDeg) ? Math.max(-90, Math.min(90, elevationDeg)) : 0;
    const safeDistance = Number.isFinite(distance) && distance > 0 ? distance : MIN_ORBIT_DISTANCE;
    const safeAzimuth = Number.isFinite(azimuthDeg) ? azimuthDeg : 0;
    const az = (safeAzimuth * Math.PI) / 180;
    const el = (safeElevation * Math.PI) / 180;
    const x = safeDistance * Math.cos(el) * Math.sin(az);
    const y = safeDistance * Math.sin(el);
    const z = safeDistance * Math.cos(el) * Math.cos(az);
    return [x, y, z];
}

/**
 * 笛卡尔坐标 → 球面坐标。
 * 公式与 `lighting.ts` 对齐：azimuth = atan2(x, z)，elevation = asin(y / len)。
 * 距离下限取 0.1，避免原点处 asin 除零；len 非有限时返回原点轨道坐标（有限值）。
 */
export function cartesianToOrbit(x: number, y: number, z: number): OrbitCoords {
    const len = Math.sqrt(x * x + y * y + z * z);
    if (!Number.isFinite(len)) {
        return { azimuth: 0, elevation: 0, distance: 0 };
    }
    const azimuth = (Math.atan2(x, z) * 180) / Math.PI;
    const elevation = (Math.asin(y / Math.max(0.1, len)) * 180) / Math.PI;
    return { azimuth, elevation, distance: len };
}

/**
 * wind-utils.ts — 统一风场辅助函数
 *
 * 各子系统（粒子/水面/布料/云）通过此模块获取统一的风矢量，
 * 避免各自重复实现 windDirection × windSpeed 的读取逻辑。
 *
 * 使用方式：
 *   import { getWindVector } from '../core/physics/wind-utils';
 *   const wind = getWindVector(); // Vector3
 */

import { Vector3 } from '@babylonjs/core/Maths/math.vector';
import { envState } from '../config';

/** 风场强度倍率（各系统可在此统一调节灵敏度） */
const WIND_STRENGTH_SCALE = 1.0;

/**
 * 返回当前风矢量（方向 × 速度），windEnabled=false 时返回零向量。
 */
export function getWindVector(): Vector3 {
    if (!envState.windEnabled) {
        return Vector3.Zero();
    }
    const { windDirection, windSpeed } = envState;
    return new Vector3(
        windDirection[0] * windSpeed * WIND_STRENGTH_SCALE,
        windDirection[1] * windSpeed * WIND_STRENGTH_SCALE,
        windDirection[2] * windSpeed * WIND_STRENGTH_SCALE,
    );
}

/**
 * 返回当前风速标量（windEnabled=false 返回 0）。
 */
export function getWindStrength(): number {
    return envState.windEnabled ? envState.windSpeed : 0;
}

/**
 * 风向是否生效（快捷判空，避免 Vector3.Zero() 比较开销）。
 */
export function isWindActive(): boolean {
    return envState.windEnabled && envState.windSpeed > 0.01;
}

// [doc:architecture] Reactivity — 轻量响应式系统
// Proxy 拦截 set → RAF 去抖 → 通知所有订阅者
// 订阅者通常是 SlideMenu.updateControls()

/** 所有活跃的刷新订阅者 */
const _subscribers = new Set<() => void>();

/** RAF 去抖标志 */
let _refreshScheduled = false;

/**
 * 安排一次刷新（RAF 去抖）。
 * 同帧内多次调用只触发一次刷新。
 */
export function scheduleRefresh(): void {
    if (_refreshScheduled) return;
    _refreshScheduled = true;
    requestAnimationFrame(() => {
        _refreshScheduled = false;
        for (const fn of _subscribers) {
            try {
                fn();
            } catch (e) {
                console.error('[reactivity] subscriber error:', e);
            }
        }
    });
}

/**
 * 注册一个刷新订阅者。返回取消订阅函数。
 * 订阅者会在 scheduleRefresh() 触发时被调用。
 */
export function subscribe(fn: () => void): () => void {
    _subscribers.add(fn);
    return () => { _subscribers.delete(fn); };
}

/**
 * 用 Proxy 包裹对象，拦截 set 操作。
 * 任何属性赋值都会自动触发 scheduleRefresh()。
 * 深度代理：嵌套对象也会被包裹。
 */
export function reactive<T extends object>(obj: T): T {
    return new Proxy(obj, {
        get(target, key, receiver): unknown {
            const val = Reflect.get(target, key, receiver);
            // 只代理普通对象（不代理数组/Map/Set/DOM 等）
            if (val && typeof val === 'object' && !Array.isArray(val) && !(val instanceof Map) && !(val instanceof Set)) {
                return reactive(val as object);
            }
            return val;
        },
        set(target, key, value, receiver): boolean {
            const result = Reflect.set(target, key, value, receiver);
            scheduleRefresh();
            return result;
        },
    }) as T;
}

// [doc:architecture] Type-safe ShortcutRegistry — key binding management + dispatch.
// No framework dependency, pure TypeScript module-level state.
// KeyboardEvent.code is used for key matching (e.g. 'Digit1', 'Space', 'Escape', 'KeyA').

export interface ShortcutDef {
    id: string;           // unique, e.g. 'toggle:models'
    label: string;        // Chinese label, e.g. '模型库'
    defaultKey: string;   // KeyboardEvent.code value, e.g. 'Digit1'
    defaultCtrl?: boolean;
    defaultShift?: boolean;
    defaultAlt?: boolean;
    prevent?: boolean;    // call e.preventDefault()
    handler: () => void | Promise<void>;
    scope?: string;       // 'global' | 'menu' | 'dialog' | 'slider' (default 'global')
    group: string;        // UI grouping, e.g. '弹窗导航' '播放控制'
}

// Custom binding overrides stored in-memory (loaded from uiState at init)
export interface KeyBindingOverride {
    key: string;
    ctrl?: boolean;
    shift?: boolean;
    alt?: boolean;
}

// ======== Module-level state ========

const _shortcuts = new Map<string, ShortcutDef>();
const _overrides: Record<string, KeyBindingOverride> = {};
let _initialized = false;
let _keydownHandler: ((e: KeyboardEvent) => void) | null = null;

// ======== Internal helpers ========

interface EffectiveBinding {
    key: string;
    ctrl: boolean;
    shift: boolean;
    alt: boolean;
}

export interface ShortcutWithBinding extends ShortcutDef {
    currentKey: string;
    currentCtrl: boolean;
    currentShift: boolean;
    currentAlt: boolean;
}

function getEffectiveBinding(def: ShortcutDef): EffectiveBinding {
    const ov = _overrides[def.id];
    return {
        key: ov?.key ?? def.defaultKey,
        ctrl: ov?.ctrl ?? def.defaultCtrl ?? false,
        shift: ov?.shift ?? def.defaultShift ?? false,
        alt: ov?.alt ?? def.defaultAlt ?? false,
    };
}

function bindingMatches(e: KeyboardEvent, b: EffectiveBinding): boolean {
    return (
        e.code === b.key
        && e.ctrlKey === b.ctrl
        && e.shiftKey === b.shift
        && e.altKey === b.alt
    );
}

function isInputElement(el: EventTarget | null): boolean {
    if (!el || !(el instanceof HTMLElement)) return false;
    const tag = el.tagName;
    return tag === 'INPUT' || tag === 'TEXTAREA' || el.isContentEditable;
}

function isInsideSlider(el: EventTarget | null): boolean {
    if (!el || !(el instanceof HTMLElement)) return false;
    return !!el.closest('.cs-slider, .color-slider');
}

// ======== Public API ========

/** Register ONE shortcut. */
export function registerShortcut(def: ShortcutDef): void {
    if (!def.handler) {
        console.warn(`[shortcut-registry] Shortcut "${def.id}" has no handler`);
        return;
    }
    _shortcuts.set(def.id, def);
}

/** Register MULTIPLE shortcuts at once. */
export function registerShortcuts(defs: ShortcutDef[]): void {
    for (const def of defs) {
        registerShortcut(def);
    }
}

/** Get all registered shortcuts with their CURRENT effective bindings. */
export function getAllShortcuts(): ShortcutWithBinding[] {
    const result: ShortcutWithBinding[] = [];
    for (const def of _shortcuts.values()) {
        const binding = getEffectiveBinding(def);
        result.push({
            ...def,
            currentKey: binding.key,
            currentCtrl: binding.ctrl,
            currentShift: binding.shift,
            currentAlt: binding.alt,
        });
    }
    return result;
}

/**
 * Set custom key binding for a shortcut ID.
 * Returns { ok: true } on success, or conflict info if the key combo is taken.
 */
export function setKeyBinding(
    id: string,
    key: string,
    ctrl?: boolean,
    shift?: boolean,
    alt?: boolean,
): { ok: true } | { ok: false; conflictId: string; conflictLabel: string } {
    const prospective: EffectiveBinding = {
        key,
        ctrl: ctrl ?? false,
        shift: shift ?? false,
        alt: alt ?? false,
    };

    // Check all other shortcuts for conflict
    for (const [otherId, otherDef] of _shortcuts) {
        if (otherId === id) continue;
        const otherBinding = getEffectiveBinding(otherDef);
        if (
            prospective.key === otherBinding.key
            && prospective.ctrl === otherBinding.ctrl
            && prospective.shift === otherBinding.shift
            && prospective.alt === otherBinding.alt
        ) {
            return {
                ok: false,
                conflictId: otherId,
                conflictLabel: otherDef.label,
            };
        }
    }

    _overrides[id] = { key, ctrl, shift, alt };
    return { ok: true };
}

/** Reset one shortcut to its default binding. */
export function resetKeyBinding(id: string): void {
    delete _overrides[id];
}

/** Reset ALL shortcuts to their default bindings. */
export function resetAllKeyBindings(): void {
    for (const key of Object.keys(_overrides)) {
        delete _overrides[key];
    }
}

/** Load custom bindings from persisted state (call at app init). */
export function loadKeyBindings(bindings: Record<string, KeyBindingOverride>): void {
    for (const [id, override] of Object.entries(bindings)) {
        _overrides[id] = { ...override };
    }
}

/** Get current custom bindings (for saving to uiState). */
export function exportKeyBindings(): Record<string, KeyBindingOverride> {
    const result: Record<string, KeyBindingOverride> = {};
    for (const [id, ov] of Object.entries(_overrides)) {
        result[id] = { ...ov };
    }
    return result;
}

/**
 * Initialize the dispatcher — call once at app startup.
 * Attaches a single window keydown listener that dispatches to matching shortcuts.
 * Scope filter: if element is input/textarea/contentEditable, skip.
 * Arrow key conflict prevention: if target or ancestor has class 'cs-slider' or 'color-slider',
 * skip global ArrowLeft/ArrowRight shortcuts.
 */
export function initShortcutDispatcher(): void {
    if (_initialized) {
        console.warn('[shortcut-registry] Dispatcher already initialized');
        return;
    }
    _initialized = true;

    _keydownHandler = (e: KeyboardEvent) => {
        // Skip if target is an input element
        if (isInputElement(e.target)) return;

        // Skip arrow keys when inside a slider
        if (
            (e.code === 'ArrowLeft' || e.code === 'ArrowRight')
            && isInsideSlider(e.target)
        ) return;

        // Find matching shortcut (first match wins)
        for (const def of _shortcuts.values()) {
            const binding = getEffectiveBinding(def);
            if (bindingMatches(e, binding)) {
                if (def.prevent) {
                    e.preventDefault();
                }
                def.handler();
                return;
            }
        }
    };

    window.addEventListener('keydown', _keydownHandler);
}

// ======== Testing Support ========

/**
 * Reset all internal state — only for use in tests.
 * @internal
 */
export function _resetShortcutRegistry(): void {
    _shortcuts.clear();
    for (const key of Object.keys(_overrides)) {
        delete _overrides[key];
    }
    if (_keydownHandler) {
        window.removeEventListener('keydown', _keydownHandler);
        _keydownHandler = null;
    }
    _initialized = false;
}

