// [doc:architecture] ui-rows — 菜单行控件（toggle/slider/mode）
// addToggleRow / addSliderRow / addModeRow / sliderRow / toggleRow

import { createIconifyIcon } from './icons';
import { getCurrentRenderingMenu } from '../menus/menu';
import { ControlOptions } from './ui-types';
import { slideRow } from './ui-slide-row';

// ===================================================================
// addToggleRow
// ===================================================================

export function addToggleRow(
    container: HTMLElement,
    label: string,
    value: boolean,
    onChange: (v: boolean) => void,
    icon?: string,
    opts?: ControlOptions<boolean>
): void {
    const row = document.createElement('div');
    row.className = 'toggle-row';

    const left = document.createElement('div');
    left.className = 'toggle-left';

    if (icon) {
        const iconBox = document.createElement('span');
        iconBox.className = 'cs-icon';
        const iconEl = createIconifyIcon(icon);
        if (iconEl) {
            iconBox.appendChild(iconEl);
        } else {
            const fb = document.createElement('span');
            fb.className = 'cs-icon-fallback';
            fb.textContent = label.charAt(0) || '?';
            iconBox.appendChild(fb);
        }
        left.appendChild(iconBox);
    }

    const lbl = document.createElement('span');
    lbl.className = 'toggle-label';
    lbl.textContent = label;
    lbl.id = `toggle-${Math.random().toString(36).slice(2, 11)}`;
    left.appendChild(lbl);

    const toggleLabel = document.createElement('label');
    toggleLabel.className = 'toggle';
    const toggle = document.createElement('input');
    toggle.type = 'checkbox';
    toggle.checked = value;
    toggle.setAttribute('role', 'switch');
    toggle.setAttribute('aria-label', label);
    toggle.setAttribute('aria-checked', String(value));
    toggle.setAttribute('aria-labelledby', lbl.id);
    toggle.addEventListener('change', () => {
        toggle.setAttribute('aria-checked', String(toggle.checked));
        onChange(toggle.checked);
    });
    const slider = document.createElement('span');
    slider.className = 'slider';
    toggleLabel.appendChild(toggle);
    toggleLabel.appendChild(slider);
    row.appendChild(left);
    row.appendChild(toggleLabel);

    // 整行点击（除 toggle 开关外）也可切换
    row.addEventListener('click', (e) => {
        if ((e.target as HTMLElement).closest('.toggle')) return;
        toggle.checked = !toggle.checked;
        toggle.setAttribute('aria-checked', String(toggle.checked));
        onChange(toggle.checked);
    });

    container.appendChild(row);

    // === 自更新支持 ===
    initControl(row, opts, value, (v, cached) => {
        const b = !!v;
        if (b === cached) return false;
        toggle.checked = b;
        toggle.setAttribute('aria-checked', String(b));
        return true;
    });
}

// ===================================================================
// initControl — 控件自更新注册 + 立即初始化
// ===================================================================

/**
 * 封装 registerControl + immediate update 模式。
 * `apply` 返回 true 表示值已变更，用于更新缓存。
 */
export function initControl<T>(
    el: HTMLElement,
    opts: ControlOptions<T> | undefined,
    initial: T,
    apply: (v: T, cached: T) => boolean,
): void {
    if (!opts) return;
    let cached = initial;
    const update = (): void => {
        if (opts.onUpdate) {
            opts.onUpdate(el);
            return;
        }
        if (!opts.bind) return;
        const v = opts.bind();
        if (apply(v, cached)) cached = v;
    };
    getCurrentRenderingMenu()?.registerControl(update);
    update();
}

// ===================================================================
// addSliderRow
// ===================================================================

export function addSliderRow(
    container: HTMLElement,
    label: string,
    value: number,
    min: number,
    max: number,
    step: number,
    onChange: (v: number) => void,
    icon?: string,
    onDragEndCb?: (v: number) => void,
    opts?: ControlOptions<number>
): void {
    let currentValue = value;
    const range = max - min;

    const row = document.createElement('div');
    row.className = 'cs-row';

    const top = document.createElement('div');
    top.className = 'cs-top';

    if (icon) {
        const iconBox = document.createElement('span');
        iconBox.className = 'cs-icon';
        const iconEl = createIconifyIcon(icon);
        if (iconEl) {
            iconBox.appendChild(iconEl);
        } else {
            const fb = document.createElement('span');
            fb.className = 'cs-icon-fallback';
            fb.textContent = label.charAt(0) || '?';
            iconBox.appendChild(fb);
        }
        top.appendChild(iconBox);
    }

    const lbl = document.createElement('span');
    lbl.className = 'cs-label';
    lbl.textContent = label;

    const val = document.createElement('span');
    val.className = 'cs-value';
    val.textContent = step < 1 ? currentValue.toFixed(2) : String(Math.round(currentValue));

    top.appendChild(lbl);
    top.appendChild(val);

    const bar = document.createElement('div');
    bar.className = 'cs-bar';
    bar.tabIndex = 0;
    bar.setAttribute('role', 'slider');
    bar.setAttribute('aria-label', label);
    bar.setAttribute('aria-valuenow', String(currentValue));
    bar.setAttribute('aria-valuemin', String(min));
    bar.setAttribute('aria-valuemax', String(max));

    const fill = document.createElement('div');
    fill.className = 'cs-fill';
    const pct = ((currentValue - min) / range) * 100;
    fill.style.width = Math.max(0, Math.min(100, pct)) + '%';

    const thumb = document.createElement('div');
    thumb.className = 'cs-thumb';
    thumb.style.left = Math.max(0, Math.min(100, pct)) + '%';

    bar.appendChild(fill);
    bar.appendChild(thumb);

    function snapToStep(v: number): number {
        if (!step || !Number.isFinite(step)) {
            return v;
        }
        const precision = 1 / step;
        return Math.round(v * precision) / precision;
    }

    function updateDisplay(v: number): void {
        currentValue = v;
        val.textContent = step < 1 ? v.toFixed(2) : String(Math.round(v));
        const newPct = ((v - min) / range) * 100;
        const clamped = Math.max(0, Math.min(100, newPct));
        fill.style.width = clamped + '%';
        thumb.style.left = clamped + '%';
        bar.setAttribute('aria-valuenow', String(v));
    }

    function setValueFromClientX(clientX: number, rect: DOMRect): void {
        const x = (clientX - rect.left) / rect.width;
        const raw = min + Math.max(0, Math.min(1, x)) * range;
        const snapped = snapToStep(raw);
        const clamped = Math.max(min, Math.min(max, snapped));
        if (clamped !== currentValue) {
            updateDisplay(clamped);
            onChange(clamped);
        }
    }

    function handleKeyDown(e: KeyboardEvent): void {
        const shiftMult = e.shiftKey ? 10 : 1;
        let delta = step * shiftMult;
        if (step >= 1) {
            delta = e.shiftKey ? 10 : 1;
        }

        switch (e.key) {
            case 'ArrowLeft':
            case 'ArrowDown': {
                e.preventDefault();
                const lower = Math.max(min, snapToStep(currentValue - delta));
                if (lower !== currentValue) {
                    updateDisplay(lower);
                    onChange(lower);
                    onDragEndCb?.(lower);
                }
                break;
            }
            case 'ArrowRight':
            case 'ArrowUp': {
                e.preventDefault();
                const upper = Math.min(max, snapToStep(currentValue + delta));
                if (upper !== currentValue) {
                    updateDisplay(upper);
                    onChange(upper);
                    onDragEndCb?.(upper);
                }
                break;
            }
            case 'Home':
                e.preventDefault();
                if (min !== currentValue) {
                    updateDisplay(min);
                    onChange(min);
                    onDragEndCb?.(min);
                }
                break;
            case 'End':
                e.preventDefault();
                if (max !== currentValue) {
                    updateDisplay(max);
                    onChange(max);
                    onDragEndCb?.(max);
                }
                break;
        }
    }

    bar.addEventListener('click', (e) => {
        e.preventDefault();
        e.stopPropagation();
        bar.focus();
        const rect = bar.getBoundingClientRect();
        setValueFromClientX(e.clientX, rect);
        onDragEndCb?.(currentValue);
    });

    bar.addEventListener('keydown', handleKeyDown);

    row.addEventListener('click', (e) => {
        const rect = row.getBoundingClientRect();
        const x = (e.clientX - rect.left) / rect.width;
        let delta: number;
        if (x < 0.25) {
            delta = -(range * 0.15);
        } else if (x < 0.5) {
            delta = -(range * 0.05);
        } else if (x < 0.75) {
            delta = range * 0.05;
        } else {
            delta = range * 0.15;
        }
        // 确保 delta 至少为 step，避免小 range + integer step 下 snap 回原值
        if (Math.abs(delta) < step) {
            delta = Math.sign(delta || step) * step;
        }
        let newVal = snapToStep(currentValue + delta);
        newVal = Math.max(min, Math.min(max, newVal));
        if (newVal !== currentValue) {
            updateDisplay(newVal);
            onChange(newVal);
            onDragEndCb?.(newVal);
        }
    });

    row.appendChild(top);
    row.appendChild(bar);
    container.appendChild(row);

    // === 自更新支持 ===
    initControl(row, opts, value, (v, cached) => {
        if (!Number.isFinite(v) || v === cached) return false;
        updateDisplay(v);
        return true;
    });
}

// ===================================================================
// addModeRow
// ===================================================================

export function addModeRow<T extends string | number>(
    container: HTMLElement,
    label: string,
    options: Array<{ value: T; label: string }>,
    currentValue: T,
    onChange: (v: T) => void
): void {
    const row = document.createElement('div');
    row.className = 'type-row';
    const lbl = document.createElement('span');
    lbl.className = 'type-label';
    lbl.textContent = label;
    row.appendChild(lbl);
    for (const opt of options) {
        const btn = document.createElement('button');
        btn.textContent = opt.label;
        btn.className = 'mode-btn' + (currentValue === opt.value ? ' active' : '');
        btn.addEventListener('click', () => onChange(opt.value));
        row.appendChild(btn);
    }
    container.appendChild(row);
}

// ===================================================================
// addEmptyRow — 空状态占位行
// ===================================================================

/**
 * 创建空状态占位行（灰色文字，不可点击），替代手动 `el.style.opacity = '0.5'` 模式
 */
export function addEmptyRow(parent: HTMLElement, text: string): HTMLElement {
    const el = document.createElement('div');
    el.className = 'slide-item slide-item-muted';
    el.textContent = text;
    parent.appendChild(el);
    return el;
}

// ===================================================================
// addDangerRow — 危险/删除操作行
// ===================================================================

/**
 * 创建危险操作行（icon + red label），替代手动拼接 `div.slide-item > icon + label.danger-text`
 */
export function addDangerRow(
    container: HTMLElement,
    icon: string,
    label: string,
    onClick: () => void
): HTMLElement {
    return slideRow(container, icon, label, false, onClick, undefined, undefined, undefined, undefined, {
        variant: 'danger',
    });
}

// ===================================================================
// addFieldRow — 键值字段行
// ===================================================================

/**
 * 创建字段行（左 label + 右 value），替代手动拼接的
 * `div.slide-item > span.slide-label.field-label + span.field-value`
 */
export function addFieldRow(
    container: HTMLElement,
    label: string,
    value: string
): HTMLElement {
    return slideRow(container, '', label, false, () => {}, undefined, undefined, undefined, undefined, {
        rightLabel: value,
    });
}

// ===================================================================
// sliderRow — addSliderRow 的简化版，只保留 onDragEnd
// ===================================================================

export function sliderRow(
    container: HTMLElement,
    label: string,
    value: number,
    min: number,
    max: number,
    step: number,
    icon: string,
    onDragEnd: (v: number) => void
): void {
    addSliderRow(container, label, value, min, max, step, () => {}, icon, onDragEnd);
}

// ===================================================================
// toggleRow — addToggleRow 的简化版，onChange 后自动调用 onSave
// ===================================================================

export function toggleRow(
    container: HTMLElement,
    label: string,
    value: boolean,
    icon: string,
    onChange: (v: boolean) => void,
    onSave?: () => void
): void {
    addToggleRow(container, label, value, (v) => {
        onChange(v);
        onSave?.();
    }, icon);
}

// [doc:architecture] slideRow — 菜单行组件
// 带图标+标签+箭头+可选 sublabel/tag/headerToggle + actionBtn + variant 的通用菜单行

import { createIconifyIcon } from './icons';
import { getCurrentRenderingMenu } from '../menus/menu';

export interface HeaderToggleConfig {
    value: boolean;
    onChange: (v: boolean) => void;
    disabled?: boolean;
    disabledHint?: string;
    onDisabledClick?: () => void;
    /** 声明取值方式，updateControls() 时自动同步 toggle 状态 */
    bind?: () => boolean;
}

export interface SlideAction {
    icon: string;
    title?: string;
    danger?: boolean;
    onClick: (e: MouseEvent) => void;
}

export interface SlideRowExtra {
    /** label 颜色变体：danger(红), accent(主题色) */
    variant?: 'default' | 'danger' | 'accent';
    /** 右侧操作按钮图标（如 '✕', '▶', '✎'）— 单个按钮快捷方式 */
    actionIcon?: string;
    /** 操作按钮点击回调（配合 actionIcon） */
    onActionClick?: (e: MouseEvent) => void;
    /** 多操作按钮数组（与 actionIcon 叠加渲染） */
    actionIcons?: SlideAction[];
    /** 自定义右侧 label（key-value 布局用） */
    rightLabel?: string;
    /** 动态图标工厂函数——替代 icon 字符串参数，每次渲染调用 */
    iconFactory?: () => HTMLElement;
    /** sublabel 内联在 label 后（而非右对齐），适合需要 text-overflow 的场景 */
    inlineSub?: boolean;
}

export function slideRow(
    container: HTMLElement,
    icon: string,
    label: string,
    hasArrow: boolean,
    onClick: () => void,
    sublabel?: string,
    tag?: string,
    focused?: boolean,
    headerToggle?: HeaderToggleConfig,
    extra?: SlideRowExtra
): HTMLElement {
    const row = document.createElement('div');

    if (headerToggle) {
        // 使用 addCollapsible 的 header 样式：图标 + label + toggle + 箭头
        row.className = 'collapsible-header';

        const iconSpan = document.createElement('span');
        iconSpan.className = 'collapsible-icon';
        const iconEl = createIconifyIcon(icon);
        if (iconEl) {
            iconSpan.appendChild(iconEl);
        } else {
            const fb = document.createElement('span');
            fb.className = 'cs-icon-fallback';
            fb.textContent = label.charAt(0) || '?';
            iconSpan.appendChild(fb);
        }
        row.appendChild(iconSpan);

        const labelSpan = document.createElement('span');
        labelSpan.className = 'collapsible-label';
        labelSpan.textContent = label;
        row.appendChild(labelSpan);

        if (sublabel) {
            const sub = document.createElement('span');
            sub.className = 'slide-sublabel';
            sub.textContent = sublabel;
            row.appendChild(sub);
        }

        if (tag) {
            const tagSpan = document.createElement('span');
            tagSpan.className = 'slide-tag';
            tagSpan.textContent = tag;
            row.appendChild(tagSpan);
        }

        // Toggle
        const toggle = document.createElement('label');
        toggle.className = 'toggle header-toggle';
        if (headerToggle.disabled) {
            toggle.classList.add('toggle-disabled');
        }
        const input = document.createElement('input');
        input.type = 'checkbox';
        input.checked = headerToggle.value;
        input.disabled = !!headerToggle.disabled;
        const slider = document.createElement('span');
        slider.className = 'slider';
        toggle.appendChild(input);
        toggle.appendChild(slider);

        if (!headerToggle.disabled) {
            toggle.addEventListener('click', (e) => {
                e.stopPropagation();
                input.checked = !input.checked;
                headerToggle.onChange(input.checked);
            });
        } else if (headerToggle.onDisabledClick) {
            toggle.addEventListener('click', (e) => {
                e.stopPropagation();
                headerToggle.onDisabledClick!();
            });
        }
        row.appendChild(toggle);

        // === headerToggle 自更新支持 ===
        if (headerToggle.bind) {
            let cachedValue = headerToggle.value;
            const update = (): void => {
                const newVal = !!headerToggle!.bind!();
                if (newVal === cachedValue) return;
                cachedValue = newVal;
                input.checked = newVal;
            };
            getCurrentRenderingMenu()?.registerControl(update);
        }

        // Arrow
        if (hasArrow) {
            const arrowSpan = document.createElement('span');
            arrowSpan.className = 'collapsible-arrow';
            arrowSpan.textContent = '▾';
            row.appendChild(arrowSpan);
        }

        row.addEventListener('click', onClick);
    } else {
        // 原始 slide-item 样式（无 toggle）
        const variant = extra?.variant ?? 'default';
        row.className = 'slide-item' + (focused ? ' slide-focused' : '');

        const iconSpan = document.createElement('span');
        iconSpan.className = 'slide-icon';
        if (extra?.iconFactory) {
            const el = extra.iconFactory();
            if (el) iconSpan.appendChild(el);
        } else {
            const iconEl = createIconifyIcon(icon);
            if (iconEl) {
                iconSpan.appendChild(iconEl);
            } else {
                const fb = document.createElement('span');
                fb.className = 'cs-icon-fallback';
                fb.textContent = label.charAt(0) || '?';
                iconSpan.appendChild(fb);
            }
        }
        row.appendChild(iconSpan);

        // 右侧 label（key-value 布局）
        if (extra?.rightLabel !== undefined) {
            // 左侧 label（字段名）
            const leftSpan = document.createElement('span');
            leftSpan.className = 'slide-label field-label';
            leftSpan.textContent = label;
            row.appendChild(leftSpan);
            // 右侧 label（字段值）
            const rightSpan = document.createElement('span');
            rightSpan.className = 'field-value';
            rightSpan.textContent = extra.rightLabel;
            row.appendChild(rightSpan);
        } else {
            const labelSpan = document.createElement('span');
            let labelCls = 'slide-label';
            if (variant === 'danger') labelCls += ' danger-text';
            else if (variant === 'accent') labelCls += ' accent-text';
            labelSpan.className = labelCls;
            labelSpan.textContent = label;
            row.appendChild(labelSpan);
        }

        if (sublabel) {
            const sub = document.createElement('span');
            sub.className = 'slide-sublabel' + (extra?.inlineSub ? ' slide-sublabel-inline' : '');
            sub.textContent = sublabel;
            row.appendChild(sub);
        }

        if (tag) {
            const tagSpan = document.createElement('span');
            tagSpan.className = 'slide-tag';
            tagSpan.textContent = tag;
            row.appendChild(tagSpan);
        }

        // 操作按钮 (actionBtn)
        if (extra?.actionIcon !== undefined) {
            const btn = document.createElement('button');
            btn.className = 'btn btn-ghost btn-sm btn-icon slide-act-btn';
            btn.textContent = extra.actionIcon;
            if (extra.onActionClick) {
                btn.addEventListener('click', (e) => {
                    e.stopPropagation();
                    extra.onActionClick!(e);
                });
            }
            row.appendChild(btn);
        }
        // 多操作按钮数组
        if (extra?.actionIcons?.length) {
            for (const act of extra.actionIcons) {
                const btn = document.createElement('button');
                btn.className = 'btn btn-ghost btn-sm btn-icon slide-act-btn';
                if (act.danger) btn.classList.add('slide-act-danger');
                btn.textContent = act.icon;
                btn.title = act.title || '';
                btn.addEventListener('click', (e) => {
                    e.stopPropagation();
                    act.onClick(e);
                });
                row.appendChild(btn);
            }
        }

        if (hasArrow) {
            const arrowSpan = document.createElement('span');
            arrowSpan.className = 'slide-arrow';
            arrowSpan.textContent = '>';
            row.appendChild(arrowSpan);
        }

        row.addEventListener('click', onClick);
    }

    container.appendChild(row);
    return row;
}

// [doc:architecture] Utility functions for MikuMikuAR.
// Extracted from config.ts — pure helpers, status bar, library refs, menu wrappers.

import { createIconifyIcon } from './icons';
import { dom } from './dom';
import {
    externalPaths,
    libraryRoot,
    overridePaths,
    setPopupOpen,
    setLayerBindingTargetId,
    setMotionBindingTargetId,
} from './state';
import { normPath } from './fileservice';
import type { SlideMenu } from '../menus/menu';
import { getCurrentRenderingMenu } from '../menus/menu';

// Re-export normPath from fileservice; kept here for import compatibility.
export { normPath };

// ======== Card Container ========

/** Card container helper: removes render-card bg, wraps content in an lcard. */
export function cardContainer(container: HTMLElement, fn: (c: HTMLElement) => void): void {
    container.classList.remove('render-card');
    const card = document.createElement('div');
    card.className = 'lcard';
    fn(card);
    container.appendChild(card);
}

// ======== Status Bar ========

let hintActive = false;
let savedStatusText = '';
let savedStatusColor = '';
let _statusTimer: ReturnType<typeof setTimeout> | null = null;

/**
 * 设置状态栏文本。
 * @param ok true=成功(绿色), false=信息/错误(白灰色)
 * @param hold true=持续显示不自动消失(默认 false, 2s/5s 后淡出)
 */
export function setStatus(text: string, ok: boolean, hold = false): void {
    if (!dom.statusText) return;

    // 清除旧定时器
    if (_statusTimer) {
        clearTimeout(_statusTimer);
        _statusTimer = null;
    }

    // hint 激活时仍然更新保存的值，hint 结束后显示最新状态
    if (hintActive) {
        savedStatusText = text;
        savedStatusColor = ok ? 'rgba(111,207,151,0.7)' : 'rgba(255,255,255,0.4)';
        return;
    }

    dom.statusText.textContent = text;
    dom.statusText.style.color = ok ? 'rgba(111,207,151,0.7)' : 'rgba(255,255,255,0.4)';
    dom.statusText.style.opacity = '1';

    // 自动淡出
    if (!hold) {
        const delay = ok ? 2000 : 5000;
        _statusTimer = setTimeout(() => {
            dom.statusText.style.transition = 'opacity 0.5s ease';
            dom.statusText.style.opacity = '0';
            _statusTimer = setTimeout(() => {
                dom.statusText.textContent = '';
                dom.statusText.style.transition = '';
                dom.statusText.style.opacity = '1';
            }, 500);
        }, delay);
    }
}

export function showHint(text: string): void {
    if (!dom.statusText) return;
    if (!hintActive) {
        savedStatusText = dom.statusText.textContent || '';
        savedStatusColor = dom.statusText.style.color || '';
    }
    hintActive = true;
    dom.statusText.textContent = text;
    dom.statusText.style.color = 'rgba(255,255,255,0.4)';
    dom.statusText.style.opacity = '1';
}

export function hideHint(): void {
    hintActive = false;
    if (!dom.statusText) return;
    // 恢复到最新保存的状态（可能已被 setStatus 更新过）
    dom.statusText.textContent = savedStatusText;
    dom.statusText.style.color = savedStatusColor;
    dom.statusText.style.opacity = '1';
}

export function initHints(): void {
    document.querySelectorAll('[data-hint]').forEach((el) => {
        el.addEventListener('mouseenter', () => {
            showHint(el.getAttribute('data-hint') || '暂无提示');
        });
        el.addEventListener('mouseleave', () => hideHint());
    });
}

// ======== Formatting ========

export function formatTime(seconds: number): string {
    const m = Math.floor(seconds / 60);
    const s = Math.floor(seconds % 60);
    const cs = Math.floor((seconds - Math.floor(seconds)) * 100);
    return `${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}.${String(cs).padStart(2, '0')}`;
}

export function formatError(err: unknown, maxLen = 120): string {
    if (err === null || err === undefined) return 'unknown error';
    if (err instanceof Error) {
        const msg = err.message;
        return msg.length > maxLen ? msg.slice(0, maxLen - 3) + '...' : msg;
    }
    if (typeof err === 'string') {
        return err.length > maxLen ? err.slice(0, maxLen - 3) + '...' : err;
    }
    try {
        const s = String(err);
        return s.length > maxLen ? s.slice(0, maxLen - 3) + '...' : s;
    } catch {
        return 'unknown error';
    }
}

export function toBase64(s: string): string {
    const bytes = new TextEncoder().encode(s);
    let binary = '';
    for (let i = 0; i < bytes.length; i++) {
        binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
}

export function escapeHtml(s: string): string {
    return s
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#39;');
}

// ======== Library Reference Utilities ========

export const stackRegistry: {
    modelStack: SlideMenu | null;
    sceneStackGetter: (() => SlideMenu | null) | null;
    buildLevel:
        ((dir: string, label: string, filter?: (m: import('./types').LibraryModel) => boolean) => import('./types').PopupLevel) | null;
} = {
    modelStack: null,
    sceneStackGetter: null,
    buildLevel: null,
};

export function computeLibraryRef(filePath: string): string | null {
    const normalized = normPath(filePath);
    for (const ext of externalPaths) {
        const extPath = normPath(ext.path);
        if (normalized.startsWith(extPath + '/')) {
            return `${ext.name}:${normalized.substring(extPath.length + 1)}`;
        }
    }
    if (libraryRoot) {
        const root = normPath(libraryRoot);
        if (normalized.startsWith(root + '/')) {
            return normalized.substring(root.length + 1);
        }
    }
    return null;
}

function normalizePath(input: string): string {
    let p = input.replace(/\\/g, '/');
    p = p.replace(/\/+/g, '/');
    const parts = p.split('/').filter((s) => s !== '' && s !== '.');
    const result: string[] = [];
    for (const part of parts) {
        if (part === '..') {
            if (result.length > 0 && result[result.length - 1] !== '..') {
                result.pop();
            }
        } else {
            result.push(part);
        }
    }
    return (p.startsWith('/') ? '/' : '') + result.join('/');
}

function isPathWithinRoot(resolved: string, rootPath: string): boolean {
    const norm = normalizePath(resolved);
    const root = normalizePath(rootPath);
    return norm === root || norm.startsWith(root + '/');
}

export function resolveLibraryRef(libraryRef: string): string | null {
    if (!libraryRef) return null;
    if (libraryRef.startsWith('/') || libraryRef.includes('..')) {
        console.warn(`[resolveLibraryRef] suspicious libraryRef rejected: "${libraryRef}"`);
        return null;
    }
    const colonIdx = libraryRef.indexOf(':');
    if (colonIdx > 0) {
        const source = libraryRef.substring(0, colonIdx);
        const relPath = libraryRef.substring(colonIdx + 1);
        if (relPath.startsWith('/') || relPath.includes('..')) {
            console.warn(`[resolveLibraryRef] suspicious external relPath rejected: "${relPath}"`);
            return null;
        }
        const ext = externalPaths.find((e) => e.name === source);
        if (ext) {
            const resolved = normPath(ext.path) + '/' + relPath;
            if (!isPathWithinRoot(resolved, ext.path)) {
                console.warn(`[resolveLibraryRef] path traversal blocked: "${resolved}"`);
                return null;
            }
            return resolved;
        }
        return null;
    }
    if (libraryRoot) {
        const resolved = normPath(libraryRoot) + '/' + libraryRef;
        if (!isPathWithinRoot(resolved, libraryRoot)) {
            console.warn(`[resolveLibraryRef] path traversal blocked: "${resolved}"`);
            return null;
        }
        return resolved;
    }
    return null;
}

// ======== Overlay Management ========

let _onCloseAllOverlays: (() => void) | null = null;

export function setOnCloseAllOverlays(fn: (() => void) | null): void {
    _onCloseAllOverlays = fn;
}

export function closeAllOverlays(): void {
    document.querySelectorAll<HTMLElement>('[data-overlay].visible').forEach((el) => {
        el.classList.remove('visible', 'overlay-fade-out');
    });
    setPopupOpen(false);
    document.querySelectorAll<HTMLElement>('[aria-controls]').forEach((btn) => {
        btn.setAttribute('aria-expanded', 'false');
    });
    _onCloseAllOverlays?.();
    // 清除图层/动作绑定目标，防止残留下次误触发
    setLayerBindingTargetId(null);
    setMotionBindingTargetId(null);
}

// ======== Menu Wrapper Management ========

const _menuWrapperRegistry = new Map<string, HTMLElement>();

export function getMenuWrapper(menuId: string): HTMLElement {
    let wrapper = _menuWrapperRegistry.get(menuId);
    if (!wrapper) {
        wrapper = document.createElement('div');
        wrapper.className = 'menu-wrapper';
        wrapper.dataset.menuId = menuId;
        dom.sceneOverlay.appendChild(wrapper);
        _menuWrapperRegistry.set(menuId, wrapper);
    }
    for (const [id, w] of _menuWrapperRegistry) {
        (w as HTMLElement).style.display = id === menuId ? '' : 'none';
    }
    return wrapper;
}

export function disposeMenuWrapper(menuId: string): void {
    const wrapper = _menuWrapperRegistry.get(menuId);
    if (wrapper) {
        wrapper.remove();
        _menuWrapperRegistry.delete(menuId);
    }
}

export function clearAllMenuWrappers(): void {
    for (const [id] of _menuWrapperRegistry) {
        disposeMenuWrapper(id);
    }
}

// ======== Auto-save Trigger ========

let _triggerAutoSaveImpl: (() => void) | null = null;

export function setTriggerAutoSave(fn: () => void): void {
    _triggerAutoSaveImpl = fn;
}

export function triggerAutoSave(): void {
    if (_triggerAutoSaveImpl) {
        _triggerAutoSaveImpl();
    }
}

// ======== Generic try/catch + status helper ========

/**
 * Execute a function with automatic error handling that shows errors in the status bar.
 * Returns the result of the function, or undefined if an error occurred.
 *
 * @param fn - The function to execute (can be async or sync)
 * @param context - Description of what was being attempted (e.g. "加载模型")
 * @param onError - Optional callback invoked when an error occurs (for recovery logic)
 * @returns The function result, or undefined on error
 */
export async function tryCatchStatus<T>(
    fn: () => T | Promise<T>,
    context: string,
    onError?: (err: unknown) => void
): Promise<T | undefined> {
    try {
        return await fn();
    } catch (err) {
        const msg = err instanceof Error ? err.message : String(err ?? 'unknown error');
        setStatus(`${context}: ${msg}`, false);
        console.warn(`[${context}]`, err);
        onError?.(err);
        return undefined;
    }
}

// ======== Error Toast（轻量小弹窗，含复制按钮） ========

export interface ToastAction {
    label: string;
    onClick: () => void;
}

// ======== Toast Queue ========

const MAX_VISIBLE_TOASTS = 5;
const TOAST_GAP = 8; // px gap between stacked toasts
let _toastIdCounter = 0;
const _activeToasts: Array<{
    id: number;
    el: HTMLElement;
    timer: ReturnType<typeof setTimeout>;
    fadeTimer: ReturnType<typeof setTimeout> | null;
}> = [];

function getToastContainer(): HTMLElement {
    let container = document.getElementById('mmk-toast-container');
    if (container) return container;
    container = document.createElement('div');
    container.id = 'mmk-toast-container';
    container.style.cssText = [
        'position:fixed;top:64px;left:50%;transform:translateX(-50%)',
        'display:flex;flex-direction:column;align-items:center;gap:8px;z-index:9999',
        'pointer-events:none', // container doesn't block clicks, children do
        'max-width:calc(min(80vw,420px));width:max-content',
    ].join(';');
    document.body.appendChild(container);
    return container;
}

function removeToast(id: number): void {
    const idx = _activeToasts.findIndex((t) => t.id === id);
    if (idx === -1) return;
    const entry = _activeToasts[idx];
    if (entry.fadeTimer) clearTimeout(entry.fadeTimer);
    clearTimeout(entry.timer);
    if (entry.el.parentNode) entry.el.remove();
    _activeToasts.splice(idx, 1);
}

function fadeAndRemoveToast(id: number, el: HTMLElement, fadeDuration = 300): void {
    const entry = _activeToasts.find((t) => t.id === id);
    if (!entry) return;
    clearTimeout(entry.timer);
    if (entry.fadeTimer) clearTimeout(entry.fadeTimer);
    entry.fadeTimer = setTimeout(() => {
        if (el.parentNode) {
            el.style.transition = `opacity ${fadeDuration}ms ease,transform ${fadeDuration}ms ease`;
            el.style.opacity = '0';
            el.style.transform = 'translateY(-8px) scale(0.97)';
            setTimeout(() => removeToast(id), fadeDuration);
        }
    }, 50);
}

function buildToastElement(
    title: string,
    detail?: string,
    actions?: ToastAction[],
): HTMLElement {
    const toast = document.createElement('div');
    toast.style.cssText = [
        'pointer-events:auto', // toast itself is interactive
        'background:var(--bg-scene)',
        'border:1px solid rgba(255,80,80,0.3);border-radius:8px',
        'padding:8px 14px;display:flex;align-items:flex-start;gap:10px',
        'font-size:var(--font-ui);box-shadow:0 2px 16px rgba(0,0,0,0.4)',
        'width:100%;backdrop-filter:blur(8px)',
        'transition:opacity 0.3s ease,transform 0.3s ease',
    ].join(';');

    // Body
    const body = document.createElement('div');
    body.style.cssText = 'flex:1;min-width:0';

    const titleEl = document.createElement('div');
    titleEl.style.cssText = 'font-weight:600;color:var(--text-bright);margin-bottom:2px';
    titleEl.textContent = title;
    body.appendChild(titleEl);

    if (detail) {
        const detailEl = document.createElement('div');
        detailEl.style.cssText =
            'color:var(--text-dim);font-size:var(--font-ui-sm);word-break:break-all;line-height:1.3';
        detailEl.textContent = detail;
        body.appendChild(detailEl);
    }
    toast.appendChild(body);

    // Actions area
    const actionsEl = document.createElement('div');
    actionsEl.style.cssText = 'display:flex;gap:6px;flex-shrink:0;align-items:flex-start;padding-top:2px';

    // Copy button (only when there's detail to copy)
    if (detail) {
        const copyText = `${title}\n${detail}`;
        const copyBtn = document.createElement('button');
        copyBtn.textContent = '复制';
        copyBtn.style.cssText =
            'padding:3px 10px;border:none;border-radius:4px;font-size:var(--font-ui-sm);cursor:pointer;' +
            'background:var(--white-08);color:var(--text)';
        copyBtn.addEventListener('click', async () => {
            try {
                await navigator.clipboard.writeText(copyText);
                copyBtn.textContent = '已复制 ✓';
                setTimeout(() => { copyBtn.textContent = '复制'; }, 1500);
            } catch {
                // clipboard unavailable — silently ignore
            }
        });
        actionsEl.appendChild(copyBtn);
    }

    // Custom action buttons
    if (actions) {
        for (const act of actions) {
            const btn = document.createElement('button');
            btn.textContent = act.label;
            btn.style.cssText =
                'padding:3px 10px;border:none;border-radius:4px;font-size:var(--font-ui-sm);' +
                'cursor:pointer;background:var(--accent);color:#fff';
            btn.addEventListener('click', () => { act.onClick(); removeToast(_toastIdCounter); });
            actionsEl.appendChild(btn);
        }
    }

    // Close button (always present)
    const closeBtn = document.createElement('span');
    closeBtn.textContent = '✕';
    closeBtn.style.cssText =
        'font-size:11px;color:var(--text-dim);cursor:pointer;padding:2px 4px;line-height:1';
    closeBtn.addEventListener('click', () => fadeAndRemoveToast(_toastIdCounter, toast, 150));
    actionsEl.appendChild(closeBtn);

    toast.appendChild(actionsEl);
    return toast;
}

/**
 * Show a small non-intrusive toast at the top of the screen.
 * Supports a queue — multiple toasts stack vertically.
 * Oldest toasts are removed when exceeding MAX_VISIBLE_TOASTS.
 *
 * @param title   Bold title line (always visible).
 * @param detail  Optional detail text below the title.
 * @param actions Optional action buttons (e.g. [{ label: '撤销', onClick }]).
 * @param duration  Auto-hide after ms (default 8000).
 *
 * When a copy button should appear, pass the text to copy as the `detail` and
 * the function adds a copy button automatically.
 */
export function showErrorToast(
    title: string,
    detail?: string,
    actions?: ToastAction[],
    duration = 8000,
): void {
    // Enforce max visible — dismiss oldest
    while (_activeToasts.length >= MAX_VISIBLE_TOASTS) {
        const oldest = _activeToasts[0];
        if (oldest) fadeAndRemoveToast(oldest.id, oldest.el, 150);
        else break;
    }

    const id = ++_toastIdCounter;
    const el = buildToastElement(title, detail, actions);
    const container = getToastContainer();
    container.appendChild(el);

    const timer = setTimeout(() => {
        fadeAndRemoveToast(id, el);
    }, duration);

    _activeToasts.push({ id, el, timer, fadeTimer: null });
}

// ======== Resource Path Resolution ========

/** 资源类别到 OverridePaths 键名的映射 */
const CATEGORY_KEY: Record<string, string> = {
    pmx: 'pmx',
    vmd: 'vmd',
    audio: 'audio',
    stage: 'stage',
    prop: 'prop',
    environment: 'environment',
    md_dress: 'md_dress',
    setting: 'setting',
};

/**
 * 统一的资源浏览目录解析。
 * 优先级：overridePaths[category] > libraryRoot/subdir
 * @returns 解析后的目录路径，如果 libraryRoot 未设置则返回空字符串
 */
export function getBrowseDir(category: string): string {
    const key = CATEGORY_KEY[category] ?? category;
    const override = (overridePaths as Record<string, string>)[key];
    if (override) return override;
    if (!libraryRoot) return '';
    return libraryRoot + '/' + category;
}

