export async function reloadConfig(): Promise<void> {
    const cfg = await GetConfig();
    if (cfg) {
        setResourceRoot(cfg.resource_root || '');
        setLibraryRoot(cfg.resource_root || cfg.override_paths?.pmx || ''); // keep in sync, fallback to pmx override
        setOverridePaths(cfg.override_paths || {});
        setExternalPaths(cfg.external_paths || []);
    }
}

function getCurrentBrowsePath(): string[] {
    const stack = stackRegistry.modelStack;
    if (!stack || stack.levelCount === 0) {
        return [];
    }
    const dirs: string[] = [];
    for (let i = 0; i < stack.levelCount; i++) {
        const level = stack.getLevel(i);
        if (level && level.dir && level.dir !== '') {
            dirs.push(level.dir);
        }
    }
    return dirs;
}

function hasSubdir(
    parentDir: string,
    childName: string,
    filter?: (m: LibraryModel) => boolean
): boolean {
    const parent = normPath(parentDir);
    for (const m of allModels) {
        if (filter && !filter(m)) {
            continue;
        }
        const mdir = normPath(m.dir);
        if (!mdir.startsWith(parent + '/')) {
            continue;
        }
        const rel = mdir.substring(parent.length + 1);
        const parts = rel.split('/').filter(Boolean);
        if (parts.length > 0 && parts[0] === childName) {
            return true;
        }
    }
    return false;
}

function restoreBrowsePath(pathDirs: string[]): void {
    const stack = stackRegistry.modelStack;
    if (!stack || pathDirs.length <= 1 || !libraryRoot) {
        return;
    }
    const rootDir = normPath(libraryRoot);
    if (pathDirs[0] !== rootDir) {
        return;
    }
    const filter = (m: LibraryModel) => m.format === 'pmx';
    let currentDir = rootDir;
    for (let i = 1; i < pathDirs.length; i++) {
        const targetDir = normPath(pathDirs[i]);
        if (!targetDir.startsWith(currentDir + '/')) {
            break;
        }
        const childName = targetDir.substring(currentDir.length + 1).split('/')[0];
        if (!childName || !hasSubdir(currentDir, childName, filter)) {
            break;
        }
        const nextDir = currentDir + '/' + childName;
        const nextLevel = buildLevel(nextDir, childName, filter, stack);
        stack.push(nextLevel);
        currentDir = nextDir;
    }
}

export async function refreshLibrary(): Promise<void> {
    const prevPath = getCurrentBrowsePath();
    setStatus('扫描中...', false);
    const models = await tryCatchStatus(async () => {
        await ClearExtractCache();
        const m = await rescanAndSync();
        return m;
    }, '✗ 扫描失败');
    if (models === undefined) return;
    setStatus(`✓ ${(models || []).length} 个条目`, true);
    CleanOrphanCache().catch((err) => console.warn('CleanOrphanCache (background):', err));
    if (
        dom.sceneOverlay.classList.contains('visible') &&
        dom.sceneOverlay.dataset.popupType === 'model'
    ) {
        showModelPopup();
        if (prevPath.length > 0 && libraryRoot) {
            const rootDir = normPath(libraryRoot);
            const rootLevel = buildLevel(
                rootDir,
                '模型库',
                (m) => m.format === 'pmx',
                stackRegistry.modelStack!,
                externalPaths.map((ep) => ({ label: ep.name, path: ep.path }))
            );
            stackRegistry.modelStack!.push(rootLevel);
            restoreBrowsePath(prevPath);
        }
    }
}

// ======== Import file via SAF file picker ========

export async function importFile(): Promise<void> {
    let path: string;
    try {
        path = await SelectImportFile();
    } catch (err) {
        // 用户取消文件选择 — Wails 抛 "cancelled by user"，静默忽略
        const msg = err instanceof Error ? err.message
            : (err && typeof err === 'object' && 'message' in err) ? String((err as { message: unknown }).message)
            : String(err);
        if (/cancelled by user/i.test(msg)) return;
        setStatus('✗ 选择文件失败: ' + formatError(err), false);
        return;
    }
    if (!path) return;
    const lower = path.toLowerCase();
    if (lower.endsWith('.zip')) {
        setStatus('⏳ 导入压缩包...', false);
        try {
            await ImportZip(path);
            setStatus('✓ 压缩包已导入', true);
            await refreshLibrary().catch((err) =>
                console.warn('refresh after zip import:', err)
            );
        } catch (err) {
            setStatus('✗ 导入失败: ' + formatError(err), false);
            console.error('ImportZip failed:', err);
        }
    } else if (lower.endsWith('.pmx')) {
        setStatus('⏳ 加载模型...', false);
        try {
            await loadManager.load({ kind: 'actor', path });
        } catch (err) {
            setStatus('✗ 模型加载失败: ' + formatError(err), false);
            console.error('loadManager actor failed:', err);
        }
    } else if (lower.endsWith('.vmd')) {
        setStatus('⏳ 加载动作...', false);
        try {
            await loadManager.load({ kind: 'vmd', path });
        } catch (err) {
            setStatus('✗ VMD 加载失败: ' + formatError(err), false);
            console.error('loadManager vmd failed:', err);
        }
    } else {
        setStatus('不支持的文件格式（支持 PMX / ZIP / VMD）', false);
    }
}

// ======== Refresh on external model load (drag-drop) ========

document.addEventListener('mmku:modelLoaded', () => {
    // 仅弹窗可见时刷新，避免干扰其他弹窗或后台操作
    if (
        !dom.sceneOverlay.classList.contains('visible') ||
        dom.sceneOverlay.dataset.popupType !== 'model'
    ) {
        return;
    }
    // If the popup is visible, this resets the view to top-level (intentional).
    // If not visible, the stack is pre-built and will show fresh content when opened.
    showModelPopup();
});

// [doc:menu-architecture] Menu Factory — 统一弹窗入口工厂
// 将 4 个 showXxxMenu 的模板代码（class 清理 / dataset / 复用 / reset）压缩为 1 行调用
// 参见 docs/menu-architecture.md §「showXxxMenu 入口模式」

import {
    dom,
    closeAllOverlays,
    getMenuWrapper,
    PopupLevel,
    PopupRow,
} from '../core/config';
import { SlideMenu } from './menu';

/** 不含 container/onClose 的菜单回调（由工厂统一注入） */
export interface PopupMenuHandlers {
    onItemClick?: (row: PopupRow, menu: SlideMenu) => void;
    onFolderEnter?: (row: PopupRow, menu: SlideMenu) => PopupLevel | null;
    onHover?: (row: PopupRow, entering: boolean) => void;
    onAfterRender?: (level: PopupLevel, menu: SlideMenu) => void;
    extraButtonFactory?: () => HTMLElement[];
}

/** 注册式菜单配置——工厂内部维护引用，返回 handle */
export interface RegisteredPopupMenuConfig {
    /** wrapper DOM id（传给 getMenuWrapper） */
    wrapperKey: string;
    /** dataset.popupType 值 */
    popupType: string;
    /** 额外 overlay class（如 'sceneOverlay-settings' / 'sceneOverlay-motion'） */
    overlayClass?: string;
    /** 根级构建器 */
    buildRoot: () => PopupLevel;
    /** 根级 items 构建器（用于 refreshRoot） */
    buildRootItems?: () => PopupRow[];
    /** 业务回调 */
    handlers: PopupMenuHandlers;
    /**
     * 每次 show 时调用的副作用钩子（如注册全局引用）。
     * 每次 show 都会调用——因为 onClose 可能清空引用。
     */
    onShow?: (menu: SlideMenu) => void;
    /**
     * 关闭前的副作用钩子（如清空全局引用）。
     * 在 closeAllOverlays() 之前调用。
     */
    onClose?: () => void;
}

/** 注册后的菜单句柄——提供 get/refresh 能力 */
export interface PopupMenuHandle {
    /** 获取当前菜单实例（可能为 null） */
    getMenu: () => SlideMenu | null;
    /** 重新计算根级 items 并触发 reRender */
    refreshRoot: () => void;
    /** 显示菜单（内部调用 showPopupMenu） */
    show: () => void;
}

/**
 * 注册弹窗菜单——工厂内部维护引用，返回统一的 handle。
 *
 * 相比 showPopupMenu，此模式：
 * 1. 内部维护 menu 引用，不需要调用方声明 let xxxMenu
 * 2. 返回 getMenu/refreshRoot，所有菜单统一暴露能力
 * 3. onClose 时自动清空引用
 *
 * @example
 * const { getMenu, refreshRoot, show } = registerPopupMenu({
 *     wrapperKey: 'settings-menu',
 *     popupType: 'settings',
 *     buildRoot: buildSettingsRoot,
 *     buildRootItems: buildSettingsRootItems,
 *     handlers: { onItemClick, onFolderEnter },
 * });
 * export { getMenu as getSettingsMenu, refreshRoot as refreshSettingsRoot };
 */
export function registerPopupMenu(config: RegisteredPopupMenuConfig): PopupMenuHandle {
    let menu: SlideMenu | null = null;

    const getMenu = (): SlideMenu | null => menu;

    const refreshRoot = (): void => {
        if (!menu) return;
        const root = menu.getLevel(0);
        if (root && config.buildRootItems) {
            root.items = config.buildRootItems();
            menu.reRender();
        }
    };

    const show = (): void => {
        dom.sceneOverlay.classList.remove(
            'sceneOverlay-model',
            'sceneOverlay-motion',
            'sceneOverlay-settings'
        );
        if (config.overlayClass) {
            dom.sceneOverlay.classList.add(config.overlayClass);
        }
        dom.sceneOverlay.dataset.popupType = config.popupType;

        const wrapper = getMenuWrapper(config.wrapperKey);
        if (menu) {
            config.onShow?.(menu);
            menu.resetToRoot();
            menu.reRender();
            return;
        }

        const newMenu = new SlideMenu({
            container: wrapper,
            onClose: () => {
                config.onClose?.();
                newMenu.dispose();
                menu = null;
                closeAllOverlays();
            },
            onItemClick: config.handlers.onItemClick,
            onFolderEnter: config.handlers.onFolderEnter,
            onHover: config.handlers.onHover,
            onAfterRender: config.handlers.onAfterRender,
            extraButtonFactory: config.handlers.extraButtonFactory,
        });
        // 覆写 dispose：确保无论通过何种路径 dispose，menu 引用都会被清空
        const _origDispose = newMenu.dispose.bind(newMenu);
        newMenu.dispose = () => {
            _origDispose();
            menu = null;
        };
        menu = newMenu;
        config.onShow?.(menu);
        menu.reset(config.buildRoot());
    };

    return { getMenu, refreshRoot, show };
}

/**
 * 轻量级弹窗入口：适用于不需要注册 handle 的一次性场景。
 * 调用方自行维护菜单引用。
 */
export interface PopupMenuConfig {
    getMenu: () => SlideMenu | null;
    setMenu: (m: SlideMenu | null) => void;
    wrapperKey: string;
    popupType: string;
    overlayClass?: string;
    buildRoot: () => PopupLevel;
    handlers: PopupMenuHandlers;
    onShow?: (menu: SlideMenu) => void;
    onClose?: () => void;
}

export function showPopupMenu(config: PopupMenuConfig): void {
    dom.sceneOverlay.classList.remove(
        'sceneOverlay-model',
        'sceneOverlay-motion',
        'sceneOverlay-settings'
    );
    if (config.overlayClass) {
        dom.sceneOverlay.classList.add(config.overlayClass);
    }
    dom.sceneOverlay.dataset.popupType = config.popupType;

    const wrapper = getMenuWrapper(config.wrapperKey);
    const existing = config.getMenu();
    if (existing) {
        config.onShow?.(existing);
        existing.resetToRoot();
        existing.reRender();
        return;
    }

    const menu = new SlideMenu({
        container: wrapper,
        onClose: () => {
            config.onClose?.();
            menu.dispose();
            config.setMenu(null);
            closeAllOverlays();
        },
        onItemClick: config.handlers.onItemClick,
        onFolderEnter: config.handlers.onFolderEnter,
        onHover: config.handlers.onHover,
        onAfterRender: config.handlers.onAfterRender,
        extraButtonFactory: config.handlers.extraButtonFactory,
    });
    config.setMenu(menu);
    config.onShow?.(menu);
    menu.reset(config.buildRoot());
}

import { PopupLevel, PopupRow, showHint, hideHint } from '../core/config';
import { createIconifyIcon } from '../core/icons';
import { slideRow, addSliderRow, addToggleRow, addModeSlider } from '../core/ui-helpers';
import { subscribe } from '../core/reactivity';

/** 菜单过渡时间常量（与 app.css :root --menu-transition-duration 同步） */
const TRANSITION_DURATION = '0.15s';
const TRANSITION_DURATION_FAST = '0.12s';

/** 渲染上下文栈 — 控件创建函数通过 getCurrentRenderingMenu() 获得当前菜单 */
const _renderingStack: SlideMenu[] = [];

/** 获取当前正在渲染的 SlideMenu 实例（供 ui-helpers 中的控件函数自动注册） */
export function getCurrentRenderingMenu(): SlideMenu | null {
    return _renderingStack[_renderingStack.length - 1] ?? null;
}

export class SlideMenu {
    private levels: PopupLevel[] = [];
    private container: HTMLElement;
    private viewport: HTMLElement;
    private panel: HTMLElement;
    private headerEl: HTMLElement;
    private focusIndex = -1;
    private transitioning = false;
    /** 跟踪未决的 setTimeout，确保 cancelAnims 能全部清除 */
    private _pendingTimeouts: ReturnType<typeof setTimeout>[] = [];
    /** 缓存的额外按钮，避免每次 updateHeader 重建、旧监听器泄漏 */
    private _cachedExtraBtns: HTMLElement[] | null = null;
    /** 记录未决的 RAF reRender，用于去抖 */
    private _reRenderPending = false;
    /** keydown 监听器引用，供 dispose 清理 */
    private _keydownHandler: ((e: KeyboardEvent) => void) | null = null;
    /** 触屏滑动手势起始坐标 */
    private _swipeStartX = 0;
    private _swipeStartY = 0;
    private _swipeTouchStartHandler: ((e: TouchEvent) => void) | null = null;
    private _swipeTouchEndHandler: ((e: TouchEvent) => void) | null = null;
    /** 自更新控件注册表 — 每个元素有 update() 方法，由 updateControls() 统一调用 */
    private _controls: Array<{ update: () => void }> = [];
    /** 响应式订阅取消函数 — dispose 时调用 */
    private _unsubscribe: (() => void) | null = null;

    onItemClick?: (row: PopupRow, menu: SlideMenu) => void;
    onFolderEnter?: (row: PopupRow, menu: SlideMenu) => PopupLevel | null;
    onHover?: (row: PopupRow, entering: boolean) => void;
    onAfterRender?: (level: PopupLevel, menu: SlideMenu) => void;
    onClose?: () => void;
    extraButtonFactory?: () => HTMLElement[];

    constructor(opts: {
        container: HTMLElement;
        onItemClick?: (row: PopupRow, menu: SlideMenu) => void;
        onFolderEnter?: (row: PopupRow, menu: SlideMenu) => PopupLevel | null;
        onHover?: (row: PopupRow, entering: boolean) => void;
        onAfterRender?: (level: PopupLevel, menu: SlideMenu) => void;
        onClose?: () => void;
        extraButtonFactory?: () => HTMLElement[];
    }) {
        this.container = opts.container;
        this.onItemClick = opts.onItemClick;
        this.onFolderEnter = opts.onFolderEnter;
        this.onHover = opts.onHover;
        this.onAfterRender = opts.onAfterRender;
        this.onClose = opts.onClose;
        this.extraButtonFactory = opts.extraButtonFactory;

        this.container.innerHTML = '';
        this.container.classList.add('slide-menu');

        this.viewport = document.createElement('div');
        this.viewport.className = 'slide-viewport';

        this.panel = document.createElement('div');
        this.panel.className = 'slide-panel';
        // 内联样式由 CSS 控制，只设置必要的过渡
        this.panel.style.transition = `opacity ${TRANSITION_DURATION} ease, transform ${TRANSITION_DURATION} ease`;
        this.panel.style.opacity = '1';
        this.panel.style.transform = 'translateX(0)';
        this.panel.style.display = 'flex';

        this.viewport.appendChild(this.panel);
        this.container.appendChild(this.viewport);

        this.headerEl = document.createElement('div');
        this.headerEl.className = 'slide-header';
        this.container.appendChild(this.headerEl);

        // 键盘导航
        this.container.tabIndex = -1;
        this._keydownHandler = (e) => {
            if (this.transitioning) {
                return;
            }
            switch (e.key) {
                case 'ArrowDown':
                    e.preventDefault();
                    this.focusNext();
                    break;
                case 'ArrowUp':
                    e.preventDefault();
                    this.focusPrev();
                    break;
                case 'ArrowRight':
                case 'Enter':
                    e.preventDefault();
                    this.activateFocused();
                    break;
                case 'ArrowLeft':
                    e.preventDefault();
                    this.pop();
                    break;
            }
        };
        this.container.addEventListener('keydown', this._keydownHandler);

        // 触屏手势：右滑返回上一层级
        this._swipeStartX = 0;
        this._swipeStartY = 0;
        this._swipeTouchStartHandler = (e: TouchEvent) => {
            if (e.touches.length === 1) {
                this._swipeStartX = e.touches[0].clientX;
                this._swipeStartY = e.touches[0].clientY;
            }
        };
        this._swipeTouchEndHandler = (e: TouchEvent) => {
            if (this.transitioning || this.levels.length <= 1) return;
            const ct = e.changedTouches[0];
            if (!ct) return;
            const dx = ct.clientX - this._swipeStartX;
            const dy = Math.abs(ct.clientY - this._swipeStartY);
            // 右滑 > 60px 且垂直偏移 < 40px → 返回
            if (dx > 60 && dy < 40) {
                this.pop();
            }
        };
        this.container.addEventListener('touchstart', this._swipeTouchStartHandler, { passive: true });
        this.container.addEventListener('touchend', this._swipeTouchEndHandler, { passive: true });

        // 响应式订阅：状态变更 → 自动 updateControls
        this._unsubscribe = subscribe(() => this.updateControls());
    }

    // ======== 公共 API ========

    get currentLevel(): PopupLevel | undefined {
        return this.levels[this.levels.length - 1];
    }

    get levelCount(): number {
        return this.levels.length;
    }

    reset(level: PopupLevel): void {
        this._cancelAnim();
        this.levels = [level];
        this.panel.style.transition = 'none';
        this.panel.style.opacity = '1';
        this.panel.style.transform = 'translateX(0)';
        this.buildPanel(level).then(() => {
            this.updateHeader(level);
            this.setupFocus();
            this.onAfterRender?.(level, this);
        });
    }

    push(level: PopupLevel): void {
        if (this.transitioning) {
            return;
        }
        this.transitioning = true;
        this.levels.push(level);

        // 旧内容淡出
        this.panel.style.transition = `opacity ${TRANSITION_DURATION_FAST} ease, transform ${TRANSITION_DURATION_FAST} ease`;
        this.panel.style.opacity = '0';
        this.panel.style.transform = 'translateX(-8px)';

        const onFadeOut = async () => {
            this.panel.removeEventListener('transitionend', onFadeOut);
            await this.buildPanel(level);
            this.updateHeader(level);
            // 新内容从下方淡入
            this.panel.style.transition = 'none';
            this.panel.style.opacity = '0';
            this.panel.style.transform = 'translateX(8px)';
            void this.panel.offsetHeight;
            this.panel.style.transition = `opacity ${TRANSITION_DURATION} ease, transform ${TRANSITION_DURATION} ease`;
            this.panel.style.opacity = '1';
            this.panel.style.transform = 'translateX(0)';

            const onFadeIn = () => {
                this.panel.removeEventListener('transitionend', onFadeIn);
                this._cancelTimeout();
                this.transitioning = false;
                this.setupFocus();
                this.onAfterRender?.(level, this);
            };
            this.panel.addEventListener('transitionend', onFadeIn);
            this._pushTimeout(
                setTimeout(() => {
                    if (this.transitioning) {
                        this.panel.style.opacity = '1';
                        this.panel.style.transform = 'translateX(0)';
                        this.transitioning = false;
                        this.setupFocus();
                        this.onAfterRender?.(level, this);
                    }
                }, 200)
            );
        };

        this.panel.addEventListener('transitionend', onFadeOut);
        this._pushTimeout(
            setTimeout(() => {
                if (this.transitioning) {
                    this.panel.style.opacity = '0';
                    this.panel.style.transform = 'translateX(-8px)';
                    onFadeOut();
                }
            }, 150)
        );
    }

    pop(): void {
        if (this.transitioning || this.levels.length <= 1) {
            return;
        }
        this.transitioning = true;
        this.levels.pop();
        const prevLevel = this.levels[this.levels.length - 1];

        this.panel.style.transition = `opacity ${TRANSITION_DURATION_FAST} ease, transform ${TRANSITION_DURATION_FAST} ease`;
        this.panel.style.opacity = '0';
        this.panel.style.transform = 'translateX(8px)';

        const onFadeOut = async () => {
            this.panel.removeEventListener('transitionend', onFadeOut);
            await this.buildPanel(prevLevel);
            this.updateHeader(prevLevel);
            this.panel.style.transition = 'none';
            this.panel.style.opacity = '0';
            this.panel.style.transform = 'translateX(-8px)';
            void this.panel.offsetHeight;
            this.panel.style.transition = `opacity ${TRANSITION_DURATION} ease, transform ${TRANSITION_DURATION} ease`;
            this.panel.style.opacity = '1';
            this.panel.style.transform = 'translateX(0)';

            const onFadeIn = () => {
                this.panel.removeEventListener('transitionend', onFadeIn);
                this._cancelTimeout();
                this.transitioning = false;
                this.setupFocus();
                this.onAfterRender?.(prevLevel, this);
            };
            this.panel.addEventListener('transitionend', onFadeIn);
            this._pushTimeout(
                setTimeout(() => {
                    if (this.transitioning) {
                        this.panel.style.opacity = '1';
                        this.panel.style.transform = 'translateX(0)';
                        this.transitioning = false;
                        this.setupFocus();
                        this.onAfterRender?.(prevLevel, this);
                    }
                }, 200)
            );
        };

        this.panel.addEventListener('transitionend', onFadeOut);
        this._pushTimeout(
            setTimeout(() => {
                if (this.transitioning) {
                    this.panel.style.opacity = '0';
                    this.panel.style.transform = 'translateX(8px)';
                    onFadeOut();
                }
            }, 150)
        );
    }

    popTo(index: number): void {
        if (index < 0 || index >= this.levels.length || this.transitioning) {
            return;
        }
        if (index === this.levels.length - 1) {
            return;
        }
        this._cancelAnim();
        this.levels = this.levels.slice(0, index + 1);
        const level = this.currentLevel!;
        this.panel.style.transition = 'none';
        this.panel.style.opacity = '1';
        this.panel.style.transform = 'translateX(0)';
        this.buildPanel(level).then(() => {
            this.updateHeader(level);
            this.setupFocus();
            this.onAfterRender?.(level, this);
        });
    }

    reRender(opts?: { preserveFocus?: boolean }): void {
        if (this.transitioning) {
            return;
        }
        // RAF 去抖：同帧内多次 reRender 合并为一次
        if (this._reRenderPending) {
            return;
        }
        this._reRenderPending = true;
        requestAnimationFrame(() => {
            this._reRenderPending = false;
            this._doReRender(opts);
        });
    }

    /** 注册一个自更新控件，由 updateControls() 统一驱动刷新 */
    registerControl(update: () => void): void {
        this._controls.push({ update });
    }

    /** 增量刷新所有已注册的自更新控件（不重建 DOM） */
    updateControls(): void {
        for (const c of this._controls) {
            c.update();
        }
    }

    private _doReRender(opts?: { preserveFocus?: boolean }): void {
        const level = this.currentLevel;
        if (!level) {
            return;
        }
        this._cachedExtraBtns = null;

        const finalize = () => {
            this.updateHeader(level);
            // reRenderCustom 路径是增量更新，不抢焦点
            const preserve = opts?.preserveFocus ?? (level.reRenderCustom !== undefined);
            if (!preserve) {
                this.setupFocus();
            }
            this.onAfterRender?.(level, this);
        };

        if (level.reRenderCustom) {
            // === 增量路径：patch items（非空时）+ reRenderCustom ===
            const list = this.panel.querySelector('.slide-list');
            if (list) {
                if (level.items.length > 0) {
                    this.patchPanel(level.items);
                }
                level.reRenderCustom(list as HTMLElement);
                finalize();
                return;
            }
            // 没有旧 DOM → 退化为全量重建
            this.buildPanel(level).then(finalize);
        } else if (level.renderCustom || level.items.length === 0) {
            // === 自定义渲染 / 空列表 → 全量重建 ===
            this.buildPanel(level).then(finalize);
        } else {
            // === 纯 items → 全量重建（card-per-divider 结构不支持增量 patch） ===
            this.buildPanel(level).then(finalize);
            finalize();
        }
    }

    /** 重置导航栈到根层级，不触发渲染 */
    resetToRoot(): void {
        if (this.levels.length > 1) {
            this.levels = [this.levels[0]];
        }
    }

    getLevel(index: number): PopupLevel | undefined {
        return this.levels[index];
    }

    setLevel(index: number, level: PopupLevel): void {
        if (index >= 0 && index < this.levels.length) {
            this.levels[index] = level;
            // 如果替换的是当前显示层级，自动重绘
            if (index === this.levels.length - 1) {
                this.reRender();
            }
        }
    }

    /**
     * 精准替换第 index 行的 DOM，不走 reRender 全量重建。
     * 常用于单行状态变化（开关、选中态等）。
     */
    updateRow(index: number, row: PopupRow): void {
        const level = this.currentLevel;
        if (!level || index < 0 || index >= level.items.length) return;
        level.items[index] = row;
        const list = this.panel.querySelector('.slide-list');
        if (!list) return;
        const oldChild = list.children[index] as HTMLElement | undefined;
        if (oldChild) {
            const newEl = this.createRow(row);
            if (newEl) oldChild.replaceWith(newEl);
        }
    }

    /** 只刷新标题栏（返回按钮 + 标题 + 额外按钮），不碰面板 */
    refreshHeader(): void {
        const level = this.currentLevel;
        if (!level) return;
        this._cachedExtraBtns = null;
        this.updateHeader(level);
    }

    /** 强制结束当前动画，清除所有未决定时器，重置过渡状态 */
    private _cancelAnim(): void {
        this.transitioning = false;
        this._reRenderPending = false;
        this._cancelTimeout();
        this.panel.style.transition = 'none';
        this.panel.style.opacity = '1';
        this.panel.style.transform = 'translateX(0)';
    }

    /** 记录一个由动画生命周期管理的 setTimeout */
    private _pushTimeout(id: ReturnType<typeof setTimeout>): void {
        this._pendingTimeouts.push(id);
    }

    /** 清除所有未决的动画后备 setTimeout */
    private _cancelTimeout(): void {
        for (const id of this._pendingTimeouts) {
            clearTimeout(id);
        }
        this._pendingTimeouts = [];
    }

    // ======== 内部方法 ========

    private get panelItems(): NodeListOf<HTMLElement> {
        return this.panel.querySelectorAll<HTMLElement>('.slide-item');
    }

    private clearFocus(): void {
        this.panel
            .querySelectorAll('.slide-focused')
            .forEach((el) => el.classList.remove('slide-focused'));
    }

    private applyFocus(): void {
        this.clearFocus();
        const items = this.panelItems;
        if (this.focusIndex < 0 || this.focusIndex >= items.length) {
            return;
        }
        items[this.focusIndex].classList.add('slide-focused');
        items[this.focusIndex].scrollIntoView({ block: 'nearest' });
    }

    private setupFocus(): void {
        this.focusIndex = -1;
        this.clearFocus();
        if (this.panelItems.length > 0) {
            this.focusIndex = 0;
            this.applyFocus();
        }
        this.container.focus({ preventScroll: true });
    }

    private focusPrev(): void {
        const len = this.panelItems.length;
        if (len === 0) {
            return;
        }
        this.focusIndex = this.focusIndex <= 0 ? len - 1 : this.focusIndex - 1;
        this.applyFocus();
    }

    private focusNext(): void {
        const len = this.panelItems.length;
        if (len === 0) {
            return;
        }
        this.focusIndex = this.focusIndex >= len - 1 ? 0 : this.focusIndex + 1;
        this.applyFocus();
    }

    private activateFocused(): void {
        const items = this.panelItems;
        if (this.focusIndex < 0 || this.focusIndex >= items.length) {
            return;
        }
        items[this.focusIndex].click();
    }

    private _buildSeq = 0;

    // ======== 增量渲染 ========

    /** 生成行的稳定标识 key：优先用 row.rowKey，否则按 kind:target 自动推导 */
    private rowKey(row: PopupRow): string {
        if (row.rowKey) return row.rowKey;
        if (row.kind === 'divider') return '__divider__';
        return `${row.kind}:${row.target}`;
    }

    /** 增量 patch 当前 panel：只创建/替换/删除有变化的行 */
    private patchPanel(items: PopupRow[]): void {
        if (items.length === 0) return;
        const list = this.panel.querySelector('.slide-list');
        if (!list) {
            this.buildPanel(this.currentLevel!);
            return;
        }

        // 如果有 lcard 包裹，在 lcard 内部 patch
        const card = list.querySelector('.lcard') as HTMLElement | null;
        const container = card || list;
        const oldChildren = Array.from(container.children) as HTMLElement[];
        const maxLen = Math.max(oldChildren.length, items.length);

        // 1. 删除多余的行（从后往前，避免索引偏移）
        for (let i = oldChildren.length - 1; i >= items.length; i--) {
            oldChildren[i].remove();
        }

        // 2. 逐行比较
        for (let i = 0; i < items.length; i++) {
            const newRow = items[i];
            const newKey = this.rowKey(newRow);

            if (i < oldChildren.length) {
                const oldEl = oldChildren[i];
                const oldKey = oldEl.dataset.rowKey || '';
                if (oldKey !== newKey) {
                    // key 不匹配 → 替换整行
                    const newEl = this.createRow(newRow);
                    if (newEl) oldEl.replaceWith(newEl);
                }
                // key 匹配 → 行不变，跳过 DOM 操作
            } else {
                // 追加新行
                const newEl = this.createRow(newRow);
                if (newEl) container.appendChild(newEl);
            }
        }
    }

    private async buildPanel(level: PopupLevel): Promise<void> {
        const seq = ++this._buildSeq;
        this.panel.innerHTML = '';
        // 每次重建面板，清空旧的控件注册表
        this._controls = [];
        const list = document.createElement('div');
        list.className = 'slide-list';

        if (level.items.length === 0 && !level.renderCustom) {
            list.innerHTML = '<div class="slide-empty">暂无内容</div>';
        } else if (level.items.length > 0 && !level.renderCustom) {
            // 纯 items 菜单：按 divider 分组，每组包一个 lcard
            let card: HTMLElement | null = null;
            for (const row of level.items) {
                if (row.kind === 'divider') {
                    card = null; // 关闭当前组，下一个非 divider 行开启新组
                    continue;
                }
                if (!card) {
                    card = document.createElement('div');
                    card.className = 'lcard';
                    list.appendChild(card);
                }
                const el = this.createRow(row);
                if (el) card.appendChild(el);
            }
        } else {
            // 有 renderCustom：先渲染 items 导航行，再调自定义回调
            for (const row of level.items) {
                const el = this.createRow(row);
                if (el) list.appendChild(el);
            }
            _renderingStack.push(this);
            try {
                await level.renderCustom(list);
            } finally {
                _renderingStack.pop();
            }
        }
        // 只有最新的 build 才 appendChild，防止并发导致重复
        if (seq === this._buildSeq) {
            this.panel.appendChild(list);
        }
    }

    /** 释放所有资源（清除动画定时器、键盘/触摸监听、状态），调用后实例不可再用。 */
    dispose(): void {
        this._cancelAnim();
        if (this._unsubscribe) {
            this._unsubscribe();
            this._unsubscribe = null;
        }
        if (this._keydownHandler) {
            this.container.removeEventListener('keydown', this._keydownHandler);
            this._keydownHandler = null;
        }
        if (this._swipeTouchStartHandler) {
            this.container.removeEventListener('touchstart', this._swipeTouchStartHandler);
            this._swipeTouchStartHandler = null;
        }
        if (this._swipeTouchEndHandler) {
            this.container.removeEventListener('touchend', this._swipeTouchEndHandler);
            this._swipeTouchEndHandler = null;
        }
        this.levels = [];
        this._cachedExtraBtns = null;
    }

    private updateHeader(level: PopupLevel): void {
        this.headerEl.innerHTML = '';
        const backBtn = document.createElement('span');
        backBtn.className = 'slide-back';
        const backIcon = createIconifyIcon(
            this.levels.length > 1 ? 'lucide:chevron-left' : 'lucide:x'
        );
        if (backIcon) {
            backBtn.appendChild(backIcon);
        }
        if (this.levels.length > 1) {
            backBtn.addEventListener('click', () => this.pop());
        } else {
            backBtn.addEventListener('click', () => this.onClose());
        }
        this.headerEl.appendChild(backBtn);

        const title = document.createElement('span');
        title.className = 'slide-title';
        title.textContent = level.label || '';
        this.headerEl.appendChild(title);

        // 复用额外按钮，避免每次重建创建新 DOM + 旧监听器泄漏
        if (!this._cachedExtraBtns) {
            this._cachedExtraBtns = this.extraButtonFactory?.() ?? [];
        }
        for (const btn of this._cachedExtraBtns) {
            this.headerEl.appendChild(btn);
        }
    }

    private createRow(row: PopupRow): HTMLElement | null {
        if (row.kind === 'divider') {
            const el = document.createElement('div');
            el.className = 'slide-divider';
            return el;
        }

        // ======== 新 kind：slider / toggle / modeSlider / chips ========
        // 这些 kind 不是可点击的导航行，而是内嵌控件行。
        // 通过 ui-helpers 渲染，包一层带 rowKey 的 wrapper 以支持增量 patch。
        if (row.kind === 'slider' || row.kind === 'toggle' || row.kind === 'modeSlider' || row.kind === 'chips') {
            const wrapper = document.createElement('div');
            wrapper.dataset.rowKey = this.rowKey(row);
            if (row.kind === 'slider') {
                addSliderRow(
                    wrapper, row.label,
                    row.sliderValue ?? 0,
                    row.sliderMin ?? 0,
                    row.sliderMax ?? 1,
                    row.sliderStep ?? 0.1,
                    row.onSliderChange ?? (() => {}),
                    row.icon || undefined,
                    row.onSliderDragEnd
                );
            } else if (row.kind === 'toggle') {
                addToggleRow(
                    wrapper, row.label,
                    row.toggleValue ?? false,
                    row.onToggleChange ?? (() => {}),
                    row.icon || undefined
                );
            } else if (row.kind === 'modeSlider') {
                addModeSlider(
                    wrapper, row.label,
                    row.modeOptions ?? [],
                    row.modeValue as string & (string | number),
                    row.onModeChange ?? (() => {}),
                    row.icon || undefined
                );
            } else if (row.kind === 'chips') {
                wrapper.className = 'preset-group';
                for (const chip of row.chips ?? []) {
                    const btn = document.createElement('button');
                    btn.textContent = chip.label;
                    btn.className = 'preset-chip' + (chip.active ? ' active' : '');
                    btn.addEventListener('click', chip.onClick);
                    wrapper.appendChild(btn);
                }
            }
            return wrapper;
        }

        // ======== folder / model / action：原有 slide-item 逻辑 ========

        // folder + headerToggle：委托给 slideRow（与 renderCustom 中的视觉一致）
        if (row.kind === 'folder' && row.headerToggle) {
            const wrapper = document.createElement('div');
            slideRow(
                wrapper, row.icon, row.label, true,
                () => {
                    const next = this.onFolderEnter(row, this);
                    if (next) this.push(next);
                },
                row.sublabel, row.catTag, undefined, row.headerToggle
            );
            const el = wrapper.firstChild as HTMLElement | null;
            if (el) {
                el.dataset.rowKey = this.rowKey(row);
                const hint = row.sublabel || '暂无提示';
                el.setAttribute('data-hint', hint);
                el.addEventListener('mouseenter', () => {
                    if (this.focusIndex >= 0) { this.clearFocus(); this.focusIndex = -1; }
                    showHint(hint);
                    this.onHover?.(row, true);
                });
                el.addEventListener('mouseleave', () => {
                    hideHint();
                    this.onHover?.(row, false);
                });
            }
            return el;
        }

        const el = document.createElement('div');
        el.className = 'slide-item';
        el.dataset.rowKey = this.rowKey(row);
        const hint = row.sublabel || (row.model ? '暂无描述' : '暂无提示');
        el.setAttribute('data-hint', hint);

        const iconSpan = document.createElement('span');
        iconSpan.className = 'slide-icon';
        const iconEl = createIconifyIcon(row.icon);
        if (iconEl) {
            iconSpan.appendChild(iconEl);
        } else {
            iconSpan.textContent = row.icon;
        }
        el.appendChild(iconSpan);

        const labelSpan = document.createElement('span');
        labelSpan.className = 'slide-label';
        labelSpan.textContent = row.label;
        el.appendChild(labelSpan);

        if (row.catTag) {
            const tagSpan = document.createElement('span');
            tagSpan.className = 'slide-tag';
            tagSpan.textContent = row.catTag;
            el.appendChild(tagSpan);
        }

        if (row.kind === 'folder') {
            const arrow = document.createElement('span');
            arrow.className = 'slide-arrow';
            arrow.textContent = '>';
            el.appendChild(arrow);
        }

        if (row.onAddClick) {
            const addBtn = document.createElement('span');
            addBtn.className = 'slide-add-btn';
            addBtn.textContent = '+';
            addBtn.addEventListener('click', (e) => {
                e.stopPropagation();
                row.onAddClick!();
            });
            el.appendChild(addBtn);
        }

        if (row.kind === 'folder') {
            el.addEventListener('click', (e) => {
                if ((e.target as HTMLElement).closest('.slide-add-btn')) {
                    return;
                }
                const next = this.onFolderEnter(row, this);
                if (next) {
                    this.push(next);
                }
            });
        } else {
            el.addEventListener('click', () => this.onItemClick(row, this));
        }

        el.addEventListener('mouseenter', () => {
            if (this.focusIndex >= 0) {
                this.clearFocus();
                this.focusIndex = -1;
            }
            showHint(hint);
            this.onHover?.(row, true);
        });
        el.addEventListener('mouseleave', () => {
            hideHint();
            this.onHover?.(row, false);
        });

        return el;
    }
}

// [doc:architecture] Model — 模型子菜单（从 library.ts 提取）
// 职责: 模型各层级构建（外观/信息/标签/表情/材质）

import {
    escapeHtml,
    cardContainer,
    setStatus,
    PopupLevel,
    modelMetaCache,
    computeLibraryRef,
    dom,
    stackRegistry,
} from '../core/config';
import {
    modelManager,
    getModelMorphs,
    setModelMorphWeight,
    resetModelMorphs,
    setModelVisibility,
    setModelOpacity,
} from '../scene/scene';
import { buildTransformCard, buildDangerCard, type ResourceHandle } from './resource-detail-helpers';
import { buildMatRootLevel } from './model-material';
import { createIconifyIcon, softwareKindIcon } from '../core/icons';
import {
    slideRow,
    addModeSlider,
    addCollapsible,
    addFieldRow,
} from '../core/ui-helpers';
import { buildOutfitLevel } from './outfit-ui';
import { savePresetToLibDialog, buildPresetListLevel } from './model-preset';
import {
    GetTagsByModel,
    AddTag,
    RemoveTag,
    GetAllTags,
    OpenWithSoftware,
    ScanSoftwareDir,
} from '../core/wails-bindings';
import type { SoftwareEntry } from '../core/wails-bindings';
import { tryCatchStatus } from '../core/utils';

// ======== Open With (software tools submenu) ========

export function buildOpenWithLevel(id: string): PopupLevel {
    return {
        label: '用…打开',
        dir: '',
        items: [],
        renderCustom: async (container) => {
            container.classList.remove('render-card');
            let entries: SoftwareEntry[];
            try {
                entries = await ScanSoftwareDir();
            } catch {
                entries = [];
            }

            if (entries.length === 0) {
                container.innerHTML =
                    '<div style="font-size:11px;color:var(--text-dim);text-align:center;padding:12px 0;">暂无可用软件<br>请先在设置中添加</div>';
                return;
            }

            cardContainer(container, (c) => {
                for (const sw of entries) {
                    slideRow(c, softwareKindIcon(sw.kind), sw.name, false, async () => {
                        const inst = modelManager.get(id);
                        if (!inst.filePath) {
                            setStatus('✗ 模型无文件路径', false);
                            return;
                        }
                        const _r = await tryCatchStatus(() => OpenWithSoftware(inst.filePath, sw.path, sw.args || ''), '✗ 启动失败');
                        if (_r !== undefined) {
                            setStatus(`✓ 已启动: ${sw.name}`, true);
                        }
                    });
                }

                slideRow(c, 'lucide:plus', '管理软件', false, () => {
                    // Pop model stack first so returning from settings shows root level
                    stackRegistry.modelStack?.popTo(0);
                    import('./library-core').then(m => {
                        stackRegistry.modelStack?.setLevel(0, { label: '模型', dir: '', items: m.buildModelRootItems() });
                        stackRegistry.modelStack?.reRender();
                    });
                    dom.btnSettings.click();
                }, undefined, undefined, undefined, undefined, {
                    variant: 'accent',
                });
            });
        },
    };
}

// ======== Model Detail Root ========

export function buildModelLevel(id: string): PopupLevel {
    const inst = modelManager.get(id);
    if (!inst) {
        return { label: '未知模型', dir: '', items: [] };
    }
    return {
        label: inst.name,
        dir: '',
        items: [],
        renderCustom: (container) => {
            cardContainer(container, (c) => {
                // 外观折叠组
                addCollapsible(c, {
                    title: '外观',
                    icon: 'lucide:palette',
                    defaultOpen: true,
                    renderContent: (inner) => {
                        slideRow(inner, 'lucide:box', '材质调节', true, () => {
                            const level = buildMatRootLevel(id, inst.name);
                            stackRegistry.modelStack.push(level);
                        });
                        slideRow(inner, 'lucide:smile', '表情预览', true, () => {
                            const level = buildMorphPreviewLevel(id);
                            stackRegistry.modelStack.push(level);
                        });
                        slideRow(inner, 'lucide:shirt', '服装变体', true, () => {
                            const level = buildOutfitLevel(id);
                            stackRegistry.modelStack.push(level);
                        });
                    },
                });

                // 信息折叠组
                addCollapsible(c, {
                    title: '信息',
                    icon: 'lucide:info',
                    defaultOpen: false,
                    renderContent: (inner) => {
                        slideRow(inner, 'lucide:info', '基本信息', true, () => {
                            const level = buildModelInfoLevel(id);
                            stackRegistry.modelStack.push(level);
                        });
                        slideRow(inner, 'lucide:git-branch', '骨骼层级', true, () => {
                            const level = buildBoneHierarchyLevel(id);
                            stackRegistry.modelStack.push(level);
                        });
                        slideRow(inner, 'lucide:tag', '标签管理', true, () => {
                            const level = buildModelTagsLevel(id);
                            stackRegistry.modelStack.push(level);
                        });
                        // 可见性直接嵌入信息处
                        let visMode: 'visible' | 'semi' | 'hidden';
                        if (inst.visible && inst.opacity >= 0.99) {
                            visMode = 'visible';
                        } else if (inst.visible && inst.opacity < 0.99) {
                            visMode = 'semi';
                        } else {
                            visMode = 'hidden';
                        }
                        addModeSlider(
                            inner,
                            '可见性',
                            [
                                { value: 'visible', label: '显示' },
                                { value: 'semi', label: '半透明' },
                                { value: 'hidden', label: '隐藏' },
                            ],
                            visMode,
                            (v) => {
                                if (v === 'visible') {
                                    setModelVisibility(id, true);
                                    setModelOpacity(id, 1);
                                } else if (v === 'semi') {
                                    setModelVisibility(id, true);
                                    setModelOpacity(id, 0.5);
                                } else {
                                    setModelVisibility(id, false);
                                }
                                stackRegistry.modelStack.updateControls();
                                setStatus(
                                    v === 'visible' ? '完全可见' : v === 'semi' ? '半透明 50%' : '完全隐藏',
                                    true
                                );
                            },
                            'lucide:eye',
                            undefined,
                            {
                                bind: () => {
                                    const inst = modelManager.get(id);
                                    if (!inst) return 'visible';
                                    if (inst.visible && inst.opacity >= 0.99) return 'visible';
                                    if (inst.visible && inst.opacity < 0.99) return 'semi';
                                    return 'hidden';
                                },
                            }
                        );
                    },
                });

                // 工具折叠组
                addCollapsible(c, {
                    title: '工具',
                    icon: 'lucide:wrench',
                    defaultOpen: false,
                    renderContent: (inner) => {
                        slideRow(inner, 'lucide:save', '保存预设', false, () => {
                            savePresetToLibDialog(id);
                        });
                        slideRow(inner, 'lucide:folder-open', '加载预设', true, () => {
                            const level = buildPresetListLevel(id);
                            stackRegistry.modelStack.push(level);
                        });
                        slideRow(inner, 'lucide:external-link', '用…打开', true, () => {
                            const level = buildOpenWithLevel(id);
                            stackRegistry.modelStack.push(level);
                        });
                    },
                });

            });

            // 变换区块（复用公共构建器）
            const handle: ResourceHandle = { id, kind: 'actor', name: inst.name };
            buildTransformCard(container, handle);

            // 危险区块（复用公共构建器）
            buildDangerCard(container, handle, () => {
                if (stackRegistry.modelStack) {
                    stackRegistry.modelStack.popTo(0);
                    import('./library-core').then(m => {
                        stackRegistry.modelStack?.setLevel(0, { label: '模型', dir: '', items: m.buildModelRootItems() });
                        stackRegistry.modelStack?.reRender();
                    });
                }
            });
        },
    };
}

// ======== Model Info ========

export function buildModelInfoLevel(id: string): PopupLevel {
    const inst = modelManager.get(id);
    if (!inst) {
        return { label: '模型信息', dir: '', items: [] };
    }
    return {
        label: '模型信息',
        dir: '',
        items: [],
        renderCustom: (container) => {
            container.classList.remove('render-card');
            const meta = modelMetaCache.get(inst.filePath) ?? null;
            let vertCount = 0,
                faceCount = 0;
            for (const m of inst.meshes ?? []) {
                vertCount += m.getTotalVertices() || 0;
                faceCount += m.getTotalIndices() || 0;
            }
            const boneCount = inst.mmdModel?.runtimeBones?.length ?? null;
            const morphCount = inst.mmdModel?.morph?.morphs?.length ?? null;
            const fields: Array<{ label: string; value: string }> = [
                { label: '名称', value: inst.name },
                { label: '文件', value: inst.filePath.split('/').pop() || inst.filePath },
                { label: '类型', value: inst.kind === 'actor' ? '角色模型' : '舞台模型' },
                { label: '动作', value: inst.vmdName || '无' },
                { label: '顶点数', value: vertCount.toLocaleString() },
                { label: '面数', value: (faceCount / 3).toLocaleString() },
                { label: '材质数', value: String(inst.meshes?.length ?? 0) },
                { label: '骨骼数', value: boneCount !== null ? boneCount.toLocaleString() : 'N/A' },
                {
                    label: '表情数',
                    value: morphCount !== null ? morphCount.toLocaleString() : 'N/A',
                },
                { label: '日文名', value: meta?.name_jp || '—' },
                { label: '英文名', value: meta?.name_en || '—' },
                { label: '备注', value: meta?.comment ? meta.comment.substring(0, 80) : '—' },
            ];
            cardContainer(container, (c) => {
                for (const f of fields) {
                    addFieldRow(c, f.label, escapeHtml(f.value));
                }
            });
        },
    };
}

// ======== Tags Management ========

export function buildModelTagsLevel(id: string): PopupLevel {
    const inst = modelManager.get(id);
    if (!inst) {
        return { label: '标签', dir: '', items: [] };
    }
    const libRef = inst.filePath ? computeLibraryRef(inst.filePath) : null;
    return {
        label: '模型标签',
        dir: '',
        items: [],
        renderCustom: (container) => {
            container.classList.remove('render-card');

            cardContainer(container, (c) => {
                const favRow = document.createElement('div');
                favRow.className = 'slide-item';
                favRow.setAttribute('data-hint', '收藏此模型到收藏夹');
                const refreshFav = async () => {
                    if (!libRef) {
                        return;
                    }
                    const tags = await GetTagsByModel(libRef);
                    const isFav = tags && tags.includes('收藏');
                    favRow.innerHTML = `<span class="slide-icon"><iconify-icon icon="lucide:star" style="color:${isFav ? 'var(--accent)' : 'var(--text-muted)'};"></iconify-icon></span><span class="slide-label" style="color:${isFav ? 'var(--accent)' : 'var(--text)'};">${isFav ? '★ 已收藏' : '☆ 加入收藏'}</span>`;
                    favRow.onclick = async () => {
                        if (!libRef) {
                            return;
                        }
                        await tryCatchStatus(async () => {
                            if (isFav) {
                                await RemoveTag(libRef, '收藏');
                                setStatus('✓ 已取消收藏', true);
                            } else {
                                await AddTag(libRef, '收藏');
                                setStatus('✓ 已收藏', true);
                            }
                            refreshFav();
                        }, '✗ 收藏操作失败');
                    };
                };
                refreshFav();
                c.appendChild(favRow);
            });

            cardContainer(container, (c) => {
                const tagContainer = document.createElement('div');
                tagContainer.className = 'tag-container';
                c.appendChild(tagContainer);

                function refreshTags(): void {
                    if (!libRef) {
                        tagContainer.innerHTML = '<span class="tag-empty">无法识别模型路径</span>';
                        return;
                    }
                    GetTagsByModel(libRef)
                        .then((tags) => {
                            tagContainer.innerHTML = '';
                            if (!tags || tags.length === 0) {
                                return;
                            }
                            for (const tag of tags) {
                                const chip = document.createElement('span');
                                chip.className = 'tag-chip';
                                chip.innerHTML = `${escapeHtml(tag)} <span class="tag-del">✕</span>`;
                                chip.title = '点击移除标签';
                                chip.addEventListener('click', async () => {
                                    const r = await tryCatchStatus(async () => {
                                        await RemoveTag(libRef, tag);
                                        return true;
                                    }, '✗ 移除标签失败');
                                    if (r) {
                                        refreshTags();
                                        setStatus(`✓ 已移除标签: ${tag}`, true);
                                    }
                                });
                                tagContainer.appendChild(chip);
                            }
                        })
                        .catch(() => {
                            tagContainer.textContent = '加载标签失败';
                        });
                }
                refreshTags();

                const pickerLabel = document.createElement('div');
                pickerLabel.style.cssText =
                    'font-size:11px;color:var(--text-dim);margin:8px 0 4px;';
                pickerLabel.textContent = '添加已有标签';
                c.appendChild(pickerLabel);

                const picker = document.createElement('div');
                picker.className = 'tag-container';
                GetAllTags()
                    .then((allTags) => {
                        const assigned = new Set<string>();
                        GetTagsByModel(libRef!)
                            .then((modelTags) => {
                                (modelTags || []).forEach((t) => assigned.add(t));
                                (allTags || []).forEach((tag) => {
                                    if (tag === '收藏') {
                                        return;
                                    }
                                    const chip = document.createElement('span');
                                    chip.className =
                                        'tag-chip' + (assigned.has(tag) ? ' active' : '');
                                    chip.style.cssText = assigned.has(tag)
                                        ? 'border:1px solid var(--accent);color:var(--accent);background:var(--accent-dim);'
                                        : 'border:1px solid var(--white-08);color:var(--text-dim);background:transparent;cursor:pointer;';
                                    chip.textContent = assigned.has(tag) ? `✓ ${tag}` : `+ ${tag}`;
                                    chip.title = assigned.has(tag)
                                        ? '已添加，点击移除'
                                        : '点击添加此标签';
                                    chip.addEventListener('click', () => {
                                        if (!libRef) {
                                            return;
                                        }
                                        if (assigned.has(tag)) {
                                            RemoveTag(libRef, tag)
                                                .then(() => {
                                                    refreshTags();
                                                })
                                                .catch(() => {});
                                        } else {
                                            AddTag(libRef, tag)
                                                .then(() => {
                                                    refreshTags();
                                                })
                                                .catch(() => {});
                                        }
                                    });
                                    picker.appendChild(chip);
                                });
                                if (!allTags || allTags.filter((t) => t !== '收藏').length === 0) {
                                    picker.innerHTML =
                                        '<span style="color:var(--text-muted);font-size:11px;">暂无全局标签，可返回标签管理创建</span>';
                                }
                            })
                            .catch(() => {});
                    })
                    .catch(() => {});
                c.appendChild(picker);
            });
        },
    };
}

// ======== Morph Preview ========

export function buildMorphPreviewLevel(id: string): PopupLevel {
    const inst = modelManager.get(id);
    const morphs = inst ? (getModelMorphs(id) ?? []) : [];
    const typeLabels: Record<number, string> = {
        0: '组',
        1: '顶点',
        2: '骨骼',
        3: 'UV',
        8: '材质',
    };
    return {
        label: '表情预览',
        dir: '',
        items: [],
        renderCustom: (container) => {
            container.classList.remove('render-card');
            cardContainer(container, (c) => {
                const resetBtn = document.createElement('button');
                resetBtn.className = 'btn btn-sm';
                resetBtn.textContent = '全部重置';
                resetBtn.style.cssText = 'width:100%;margin-bottom:8px;';
                resetBtn.addEventListener('click', () => {
                    resetModelMorphs(id);
                    c.querySelectorAll('.morph-slider').forEach((el) => {
                        (el as HTMLInputElement).value = '0';
                        const valLabel = (el as HTMLElement).parentElement.querySelector(
                            '.morph-val'
                        );
                        if (valLabel) {
                            valLabel.textContent = '0.00';
                        }
                    });
                    setStatus('✓ 已重置所有表情', true);
                });
                c.appendChild(resetBtn);

                const list = document.createElement('div');
                list.className = 'morph-list';
                for (const m of morphs) {
                    const row = document.createElement('div');
                    row.className = 'morph-row';

                    const header = document.createElement('div');
                    header.className = 'morph-header';
                    const name = document.createElement('span');
                    name.className = 'morph-name';
                    name.textContent = m.name;
                    name.title = m.name;
                    const typeTag = document.createElement('span');
                    typeTag.className = 'morph-type';
                    typeTag.textContent = typeLabels[m.type] || `类型${m.type}`;
                    const valLabel = document.createElement('span');
                    valLabel.className = 'morph-val';
                    valLabel.textContent = '0.00';
                    header.appendChild(name);
                    header.appendChild(typeTag);
                    header.appendChild(valLabel);

                    const slider = document.createElement('input');
                    slider.type = 'range';
                    slider.min = '0';
                    slider.max = '1';
                    slider.step = '0.01';
                    slider.value = '0';
                    slider.className = 'morph-slider rng-input';
                    slider.addEventListener('input', () => {
                        const v = parseFloat(slider.value);
                        setModelMorphWeight(id, m.name, v);
                        valLabel.textContent = v.toFixed(2);
