}

// ======== Bone Hierarchy ========

export function buildBoneHierarchyLevel(id: string): PopupLevel {
    const inst = modelManager.get(id);
    if (!inst?.mmdModel) {
        return { label: '骨骼层级', dir: '', items: [] };
    }
    const bones = inst.mmdModel.runtimeBones;
    if (!bones || bones.length === 0) {
        return { label: '骨骼层级', dir: '', items: [] };
    }

    // Build parent→children map
    const childrenMap = new Map<number, number[]>();
    const rootIndices: number[] = [];
    const physicsSet = new Set<number>();
    for (let i = 0; i < bones.length; i++) {
        const bone = bones[i];
        if (bone.rigidBodyIndices.length > 0) {
            physicsSet.add(i);
        }
        const parentBone = bone.parentBone;
        if (parentBone) {
            const parentIdx = bones.indexOf(parentBone);
            if (parentIdx >= 0) {
                const list = childrenMap.get(parentIdx) ?? [];
                list.push(i);
                childrenMap.set(parentIdx, list);
                continue;
            }
        }
        rootIndices.push(i);
    }

    return {
        label: '骨骼层级',
        dir: '',
        items: [],
        renderCustom: (container) => {
            container.classList.remove('render-card');
            cardContainer(container, (c) => {
                const header = document.createElement('div');
                header.style.cssText =
                    'font-size:var(--font-ui-sm);color:var(--text-bright);padding:4px 14px 8px;';
                header.textContent = `共 ${bones.length} 个骨骼`;
                c.appendChild(header);

                function renderBoneTree(
                    parent: HTMLElement,
                    idx: number,
                    depth: number
                ): void {
                    const bone = bones[idx];
                    const row = document.createElement('div');
                    row.style.cssText = `display:flex;align-items:center;padding:2px 14px 2px ${14 + depth * 16}px;font-size:var(--font-ui);color:var(--text);gap:6px;`;

                    // Collapse/expand for non-leaf
                    const hasChildren = (childrenMap.get(idx)?.length ?? 0) > 0;
                    let expanded = depth < 2; // auto-expand top 2 levels
                    if (hasChildren) {
                        const toggle = document.createElement('span');
                        toggle.textContent = expanded ? '▾' : '▸';
                        toggle.style.cssText =
                            'cursor:pointer;flex:none;width:14px;text-align:center;color:var(--text-dim);font-size:var(--font-ui-sm);';
                        row.appendChild(toggle);

                        // Name label (click expands/collapses)
                        const label = document.createElement('span');
                        label.textContent = bone.name;
                        label.style.cssText = 'cursor:pointer;flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;';
                        row.appendChild(label);

                        const childContainer = document.createElement('div');
                        let childrenRendered = false;

                        toggle.addEventListener('click', (e) => {
                            e.stopPropagation();
                            expanded = !expanded;
                            toggle.textContent = expanded ? '▾' : '▸';
                            childContainer.style.display = expanded ? '' : 'none';
                            if (expanded && !childrenRendered) {
                                childrenRendered = true;
                                const childIndices = childrenMap.get(idx) ?? [];
                                for (const ci of childIndices) {
                                    renderBoneTree(childContainer, ci, depth + 1);
                                }
                            }
                        });
                        label.addEventListener('click', () => toggle.click());

                        parent.appendChild(row);
                        childContainer.style.display = expanded ? '' : 'none';
                        parent.appendChild(childContainer);

                        if (expanded) {
                            childrenRendered = true;
                            const childIndices = childrenMap.get(idx) ?? [];
                            for (const ci of childIndices) {
                                renderBoneTree(childContainer, ci, depth + 1);
                            }
                        }
                    } else {
                        // Leaf node
                        row.innerHTML = `<span style="flex:none;width:14px;"></span><span style="flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;color:var(--text);">${escapeHtml(bone.name)}</span>`;
                        parent.appendChild(row);
                    }

                    // Physics badge
                    if (physicsSet.has(idx)) {
                        const badge = document.createElement('span');
                        const iconEl = createIconifyIcon('lucide:zap');
                        if (iconEl) {
                            badge.appendChild(iconEl);
                        }
                        badge.title = '有物理刚体';
                        badge.style.cssText =
                            'font-size:11px;flex:none;color:var(--accent);display:inline-flex;';
                        row.appendChild(badge);
                    }
                }

                for (const ri of rootIndices) {
                    renderBoneTree(c, ri, 0);
                }
            });
        },
    };
}

// [doc:architecture] Model Material — 材质调节 UI 层（batch/per-mat/root/list）

import { Material } from '@babylonjs/core/Materials/material';
import { StandardMaterial } from '@babylonjs/core/Materials/standardMaterial';
import {
    cardContainer,
    setStatus,
    PopupLevel,
    stackRegistry,
    escapeHtml,
} from '../core/config';
import {
    getMatCatGroups,
    getMatCatParams,
    setMatCatParams,
    resetMatCatParams,
    getMatDetailList,
    getMatParams,
    setMatParams,
    resetSingleMatParams,
    resetAllMatParams,
    isMatEnabled,
    setMatEnabled,
    isMatCategoryAllEnabled,
    setMatCategoryEnabled,
    getMaterialMeshes,
} from '../scene/scene';
import { createIconifyIcon } from '../core/icons';
import { slideRow, addSliderRow, addCollapsible } from '../core/ui-helpers';
import type { SlideMenu } from './menu';

let _selectedMat: { cat: string; index: number } | null = null;
/** 参数卡片容器引用（增量更新用，避免 reRender） */
let _paramCardEl: HTMLElement | null = null;

export function buildMatBatchLevel(id: string, modelName: string): PopupLevel {
    const label = '按部位批量 — ' + modelName;
    return {
        label,
        dir: '',
        items: [],
        renderCustom: (container) => {
            const groups = getMatCatGroups(id);
            const detailList = getMatDetailList(id);
            const overrideCount = detailList.filter((d) => d.modified).length;

            cardContainer(container, (c) => {
                if (overrideCount > 0) {
                    const hint = document.createElement('div');
                    hint.style.cssText =
                        'font-size:11px;color:var(--warn);margin-bottom:8px;padding:4px 10px;background:var(--white-04);border-radius:6px;text-align:center;';
                    hint.textContent = `⚠ ${overrideCount} 个材质有单独覆盖（分类调整不影响已覆盖材质）`;
                    c.appendChild(hint);
                }

                const CATEGORY_ICONS: Record<string, string> = {
                    皮肤: 'droplet',
                    头发: 'feather',
                    眼睛: 'eye',
                    服装: 'shirt',
                };

                for (const [cat, mats] of groups) {
                    const params = getMatCatParams(id, cat);
                    addCollapsible(c, {
                        title: `${cat} (${mats.length})`,
                        icon: CATEGORY_ICONS[cat] || 'box',
                        defaultOpen: false,
                        headerToggle: {
                            value: isMatCategoryAllEnabled(id, cat),
                            onChange: (v) => setMatCategoryEnabled(id, cat, v),
                            bind: () => isMatCategoryAllEnabled(id, cat),
                        },
                        renderContent: (panel) => {
                            addSliderRow(panel, '漫反射倍率', params.diffuseMul, 0, 2, 0.05, (v) =>
                                setMatCatParams(id, cat, { diffuseMul: v })
                            );
                            addSliderRow(panel, '高光倍率', params.specularMul, 0, 2, 0.05, (v) =>
                                setMatCatParams(id, cat, { specularMul: v })
                            );
                            addSliderRow(panel, '高光指数', params.shininess, 0, 200, 1, (v) =>
                                setMatCatParams(id, cat, { shininess: v })
                            );
                            addSliderRow(panel, '环境光倍率', params.ambientMul, 0, 2, 0.05, (v) =>
                                setMatCatParams(id, cat, { ambientMul: v })
                            );
                        },
                    });
                }
            });
        },
    };
}

export function buildPerMatLevel(
    id: string,
    modelName: string,
    matName: string,
    mat: Material,
    matIndex: number,
    targetStack?: SlideMenu | null
): PopupLevel {
    const shortName = matName.length > 24 ? matName.slice(0, 24) + '…' : matName;
    return {
        label: shortName,
        dir: '',
        items: [],
        renderCustom: (container) => {
            cardContainer(container, (c) => {
                const nameEl = document.createElement('div');
                nameEl.style.cssText =
                    'font-size:11px;color:var(--text-dim);margin-bottom:8px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;';
                nameEl.textContent = modelName + ' > ' + matName;
                c.appendChild(nameEl);

                const stackingHint = document.createElement('div');
                stackingHint.style.cssText =
                    'font-size:10px;color:var(--text-muted);margin-bottom:10px;padding:4px 8px;background:var(--accent-dim);border-radius:4px;';
                stackingHint.textContent = '覆盖分类设置，分类调整仍生效于其他材质';
                c.appendChild(stackingHint);

                const current = getMatParams(id, matIndex);
                const params = current ?? {
                    diffuseMul: 1,
                    specularMul: 1,
                    shininess: 50,
                    ambientMul: 1,
                };
                const isModified = current !== null;

                addSliderRow(c, '漫反射倍率', params.diffuseMul, 0, 2, 0.05, (v) => {
                    setMatParams(id, matIndex, { diffuseMul: v });
                });
                addSliderRow(c, '高光倍率', params.specularMul, 0, 2, 0.05, (v) => {
                    setMatParams(id, matIndex, { specularMul: v });
                });
                addSliderRow(c, '高光指数', params.shininess, 0, 200, 1, (v) => {
                    setMatParams(id, matIndex, { shininess: v });
                });
                addSliderRow(c, '环境光倍率', params.ambientMul, 0, 2, 0.05, (v) => {
                    setMatParams(id, matIndex, { ambientMul: v });
                });

                if (isModified) {
                    slideRow(c, 'lucide:rotate-ccw', '重置此材质', false, () => {
                        resetSingleMatParams(id, matIndex);
                        (targetStack ?? stackRegistry.modelStack)?.reRender();
                        setStatus(`✓ 已重置: ${matName}`, true);
                    });
                }
            });
        },
    };
}

export function buildMatRootLevel(id: string, modelName: string, targetStack?: SlideMenu | null): PopupLevel {
    _selectedMat = null;
    _paramCardEl = null;
    return {
        label: '材质调节 — ' + modelName,
        dir: '',
        items: [],
        renderCustom: (container) => {
            const groups = getMatCatGroups(id);
            const detailList = getMatDetailList(id);

            // 卡片 1：材质组（折叠列表）
            cardContainer(container, (c) => {
                if (groups.size === 0) {
                    const empty = document.createElement('div');
                    empty.style.cssText =
                        'padding:12px 14px;text-align:center;font-size:11px;color:var(--text-dim);';
                    empty.textContent = '此模型无材质数据';
                    c.appendChild(empty);
                    return;
                }

                for (const [cat, mats] of groups) {
                    const count = mats.length;
                    addCollapsible(c, {
                        title: `${cat} (${count})`,
                        icon: 'lucide:layers',
                        defaultOpen: false,
                        headerToggle: {
                            value: isMatCategoryAllEnabled(id, cat),
                            onChange: (v) => setMatCategoryEnabled(id, cat, v),
                            bind: () => isMatCategoryAllEnabled(id, cat),
                        },
                        renderContent: (inner) => {
                            for (const matInfo of mats) {
                                const detail = detailList.find((d) => d.name === matInfo.mat.name);
                                const idx = detail ? detail.index : -1;
                                if (idx === -1) {
                                    continue;
                                }
                                const matEnabled = isMatEnabled(id, idx);
                                const mat = matInfo.mat as StandardMaterial;

                                const row = document.createElement('div');
                                row.className = `slide-item${!matEnabled ? ' mat-disabled' : ''}`;
                                row.style.cssText = 'padding-left: 28px;';
                                row.dataset.matIdx = String(idx);
                                row.dataset.matCat = cat;

                                // Label
                                const label = document.createElement('span');
                                label.className = 'slide-label';
                                label.textContent = `#${String(idx + 1).padStart(2, '0')} ${matInfo.mat.name}`;
                                row.appendChild(label);

                                if (detail.modified) {
                                    const sub = document.createElement('span');
                                    sub.className = 'slide-sublabel';
                                    sub.style.color = 'var(--accent)';
                                    sub.textContent = '已修改';
                                    row.appendChild(sub);
                                }

                                // Standard toggle 开关（替代小圆点）
                                const toggle = document.createElement('label');
                                toggle.className = 'toggle header-toggle';
                                toggle.style.marginLeft = 'auto';
                                const toggleInput = document.createElement('input');
                                toggleInput.type = 'checkbox';
                                toggleInput.checked = matEnabled;
                                const slider = document.createElement('span');
                                slider.className = 'slider';
                                toggle.appendChild(toggleInput);
                                toggle.appendChild(slider);
                                toggle.addEventListener('click', (e) => {
                                    e.stopPropagation();
                                    const newState = !isMatEnabled(id, idx);
                                    setMatEnabled(id, idx, newState);
                                    // 增量更新当前行 DOM
                                    toggleInput.checked = newState;
                                    row.classList.toggle('mat-disabled', !newState);
                                    setStatus(
                                        newState ? `✓ 已显示: ${matInfo.mat.name}` : `✕ 已隐藏: ${matInfo.mat.name}`,
                                        true
                                    );
                                });
                                row.appendChild(toggle);

                                // 行点击：只更新参数卡片，不重建列表
                                row.addEventListener('click', () => {
                                    // 更新选中高亮
                                    const prev = inner.querySelector('.slide-focused');
                                    if (prev) prev.classList.remove('slide-focused');
                                    row.classList.add('slide-focused');
                                    // 增量更新参数卡片
                                    _selectedMat = { cat, index: idx };
                                    _renderParamCard(id, modelName, cat, idx, detailList, targetStack);
                                });
                                inner.appendChild(row);
                            }
                        },
                    });
                }
            });

            // 卡片 2：参数微调容器（占位，内容由 _renderParamCard 增量填充）
            _paramCardEl = document.createElement('div');
            container.appendChild(_paramCardEl);
            _renderParamCard(id, modelName, null, -1, detailList, targetStack);

            // 卡片 3：重置全部
            cardContainer(container, (c) => {
                slideRow(c, 'lucide:refresh-ccw', '重置全部材质参数', false, () => {
                    resetMatCatParams(id);
                    resetAllMatParams(id);
                    _selectedMat = null;
                    (targetStack ?? stackRegistry.modelStack)?.reRender();
                    setStatus('✓ 全部材质参数已重置', true);
                });
            });
        },
    };
}

/**
 * 增量渲染参数卡片（替代 reRender 全量重建）。
 * 只更新 _paramCardEl 容器的内容，不影响材质列表。
 */
function _renderParamCard(
    id: string,
    modelName: string,
    cat: string | null,
    index: number,
    detailList: { name: string; index: number; modified: boolean }[],
    targetStack?: SlideMenu | null
): void {
    if (!_paramCardEl) return;
    // 防止幽灵引用：容器被销毁后置 null
    if (!_paramCardEl.isConnected) {
        _paramCardEl = null;
        return;
    }
    _paramCardEl.innerHTML = '';

    if (index === -1 || !cat) {
        const hint = document.createElement('div');
        hint.style.cssText =
            'font-size:11px;color:var(--text-dim);padding:12px 14px;text-align:center;';
        hint.textContent = '请从上方材质列表中选择一个材质进行微调';
        _paramCardEl.appendChild(hint);
        return;
    }

    const card = document.createElement('div');
    card.className = 'card';
    card.style.cssText = 'margin:8px;border-radius:var(--radius);background:var(--card-bg);padding:0;';

    const title = document.createElement('div');
    title.style.cssText = 'font-size:11px;color:var(--text-dim);padding:4px 14px;';
    const matName = detailList.find((d) => d.index === index)?.name || '未知材质';
    title.textContent = `参数微调 — ${cat} › ${matName}`;
    card.appendChild(title);

    const current = getMatParams(id, index);
    const params = current ?? {
        diffuseMul: 1,
        specularMul: 1,
        shininess: 50,
        ambientMul: 1,
    };

    addSliderRow(card, '漫反射倍率', params.diffuseMul, 0, 2, 0.05, (v) => {
        setMatParams(id, index, { diffuseMul: v });
    }, 'lucide:droplet');
    addSliderRow(card, '高光倍率', params.specularMul, 0, 2, 0.05, (v) => {
        setMatParams(id, index, { specularMul: v });
    }, 'lucide:sparkle');
    addSliderRow(card, '高光指数', params.shininess, 0, 200, 1, (v) => {
        setMatParams(id, index, { shininess: v });
    }, 'lucide:zap');
    addSliderRow(card, '环境光倍率', params.ambientMul, 0, 2, 0.05, (v) => {
        setMatParams(id, index, { ambientMul: v });
    }, 'lucide:sun');

    if (current !== null) {
        // 重置：批量状态变化 + 预期全量刷新，用 reRender。
        // 色块点击：单点切换，用增量更新（内联 DOM 操作），避免 200+ 行折叠列表重建。
        slideRow(card, 'lucide:rotate-ccw', '重置此材质', false, () => {
            resetSingleMatParams(id, index);
            _selectedMat = null;
            (targetStack ?? stackRegistry.modelStack)?.reRender();
            setStatus(`✓ 已重置: ${matName}`, true);
        });
    }

    _paramCardEl.appendChild(card);
}

export function buildMatListLevel(id: string, modelName: string, targetStack?: SlideMenu | null): PopupLevel {
    return {
        label: '逐材质 — ' + modelName,
        dir: '',
        items: [],
        renderCustom: (container) => {
            const detailList = getMatDetailList(id);
            cardContainer(container, (c) => {
                c.style.padding = '6px 10px';
                for (const detail of detailList) {
                    const meshes = getMaterialMeshes(id);
                    const mat = meshes?.[detail.index]?.material as StandardMaterial;
                    if (!mat) {
                        continue;
                    }

                    const matEnabled = isMatEnabled(id, detail.index);

                    const row = document.createElement('div');
                    row.className = `mat-row${detail.modified ? ' modified' : ''}${!matEnabled ? ' mat-disabled' : ''}`;

                    const idxSpan = document.createElement('span');
                    idxSpan.className = 'mat-index';
                    idxSpan.textContent = `#${String(detail.index + 1).padStart(2, '0')}`;
                    row.appendChild(idxSpan);

                    const nameSpan = document.createElement('span');
                    nameSpan.className = 'mat-name';
                    nameSpan.title = detail.name;
                    nameSpan.textContent = detail.name;
                    row.appendChild(nameSpan);

                    if (detail.modified) {
                        const modSpan = document.createElement('span');
                        modSpan.className = 'mat-modified';
                        const icon = createIconifyIcon('check-circle');
                        if (icon) modSpan.appendChild(icon);
                        row.appendChild(modSpan);
                    }

                    // Standard toggle 开关（替代小圆点）
                    const toggle = document.createElement('label');
                    toggle.className = 'toggle header-toggle';
                    toggle.style.marginLeft = 'auto';
                    const toggleInput = document.createElement('input');
                    toggleInput.type = 'checkbox';
                    toggleInput.checked = matEnabled;
                    const slider = document.createElement('span');
                    slider.className = 'slider';
                    toggle.appendChild(toggleInput);
                    toggle.appendChild(slider);
                    toggle.addEventListener('click', (e) => {
                        e.stopPropagation();
                        const newState = !isMatEnabled(id, detail.index);
                        setMatEnabled(id, detail.index, newState);
                        toggleInput.checked = newState;
                        row.classList.toggle('mat-disabled', !newState);
                        setStatus(
                            newState ? `✓ 已显示: ${detail.name}` : `✕ 已隐藏: ${detail.name}`,
                            true
                        );
                    });
                    row.appendChild(toggle);

                    row.addEventListener('click', () => {
                        (targetStack ?? stackRegistry.modelStack)?.push(
                            buildPerMatLevel(id, modelName, detail.name, mat, detail.index, targetStack)
                        );
                    });
                    c.appendChild(row);
                }
            });
        },
    };
}

// [doc:architecture] Model Preset — 预设序列化/库管理/自动应用

import {
    modelRegistry,
    cardContainer,
    setStatus,
    PopupLevel,
    computeLibraryRef,
    stackRegistry,
    escapeHtml,
    isPlaying,
} from '../core/config';
import { loadManager } from '../core/load-manager';
import {
    setModelPosition,
    setModelScaling,
    setModelRotationY,
    setModelVisibility,
    setModelOpacity,
    setModelWireframe,
    stopVMD,
    getMatState,
    applyMatState,
} from '../scene/scene';
import {
    SelectPresetSaveFile,
    SelectPresetOpenFile,
    SaveModelPreset,
    LoadModelPreset,
    GetModelPresets,
    SaveModelPresetToLib,
    LoadModelPresetFromLib,
    DeleteModelPreset,
} from '../core/wails-bindings';
import {
    clearAudio,
    getAudioPath,
    getAudioName,
    getVolume,
    getAudioOffset,
    setVolume,
    setAudioOffset,
} from '../outfit/audio';
import { showConfirm, showPrompt } from '../core/dialog';
import { tryCatchStatus, showErrorToast } from '../core/utils';

export interface ModelPresetEntry {
    name: string;
    presetName: string;
    modelName: string;
    modelRef: string;
    updatedAt: number;
    autoApply: boolean;
}

export interface ModelPresetFile {
    version: 1;
    presetName?: string;
    autoApply?: boolean;
    model: {
        filePath: string;
        libraryRef?: string;
        name: string;
        kind: 'actor' | 'stage';
    };
    transform: {
        positionX?: number;
        positionY?: number;
        positionZ?: number;
        scaling?: number;
        rotationY?: number;
    };
    visibility: {
        visible?: boolean;
        opacity?: number;
        wireframe?: boolean;
    };
    vmd: {
        path: string | null;
        libraryRef?: string | undefined;
        name: string;
        playing?: boolean;
    };
    audio?: {
        path: string;
        name: string;
        volume: number;
        offset: number;
    };
    materialCategories?: Record<
        string,
        { diffuseMul: number; specularMul: number; shininess: number; ambientMul: number }
    >;
    materialOverrides?: Record<
        number,
        { diffuseMul: number; specularMul: number; shininess: number; ambientMul: number }
    >;
    materialEnabled?: Record<number, boolean>;
}

export function serializeModelPreset(id: string, presetName?: string): string {
    const inst = modelRegistry.get(id);
    if (!inst) {
        return '';
    }
    const matState = getMatState(id);
    const rm = inst.rootMesh;
    const pos = rm?.position ?? { x: 0, y: 0, z: 0 };
    const preset: ModelPresetFile = {
        version: 1,
        presetName: presetName,
        model: {
            filePath: inst.filePath,
            libraryRef: computeLibraryRef(inst.filePath) || undefined,
            name: inst.name,
            kind: inst.kind,
        },
        transform: {
            positionX: pos.x,
            positionY: pos.y,
            positionZ: pos.z,
            scaling: inst.scaling,
            rotationY: inst.rotationY,
        },
        visibility: {
            visible: inst.visible,
            opacity: inst.opacity,
            wireframe: inst.wireframe,
        },
        vmd: {
            path: inst.vmdPath,
            libraryRef: inst.vmdPath ? computeLibraryRef(inst.vmdPath) || undefined : undefined,
            name: inst.vmdName,
            playing: inst.vmdPath ? isPlaying : undefined,
        },
        audio: getAudioPath()
            ? {
                  path: getAudioPath(),
                  name: getAudioName(),
                  volume: getVolume(),
                  offset: getAudioOffset(),
              }
            : undefined,
        materialCategories: matState?.categories ?? {},
        materialOverrides: matState?.overrides ?? {},
        materialEnabled: matState?.enabled ?? {},
    };
    return JSON.stringify(preset, null, 2);
}

export async function applyModelPreset(id: string, jsonStr: string): Promise<void> {
    let preset: ModelPresetFile;
    try {
        preset = JSON.parse(jsonStr);
    } catch {
        setStatus('✗ 预设文件格式错误', false);
        return;
    }
    if (preset.version !== 1) {
        setStatus('✗ 不支持的预设版本', false);
        return;
    }
    if (preset.transform) {
        const t = preset.transform;
        if (t.positionX !== undefined && t.positionY !== undefined && t.positionZ !== undefined) {
            setModelPosition(id, t.positionX, t.positionY, t.positionZ);
        }
        if (t.scaling !== undefined) {
            setModelScaling(id, t.scaling);
        }
        if (t.rotationY !== undefined) {
            setModelRotationY(id, t.rotationY);
        }
    }
    if (preset.visibility) {
        const v = preset.visibility;
        if (v.visible !== undefined) {
            setModelVisibility(id, v.visible);
        }
        if (v.opacity !== undefined) {
            setModelOpacity(id, v.opacity);
        }
        if (v.wireframe !== undefined) {
            setModelWireframe(id, v.wireframe);
        }
    }
    if (preset.vmd) {
        if (preset.vmd.path) {
            stopVMD(id);
            try {
                await loadManager.load({ kind: 'vmd', path: preset.vmd.path, modelId: id });
            } catch (vmdErr) {
                setStatus('⚠ VMD 加载失败，其余预设已应用', false);
                console.warn('applyModelPreset: vmd load failed', vmdErr);
            }
        } else {
            stopVMD(id);
        }
    }
    if (preset.materialCategories || preset.materialOverrides || preset.materialEnabled) {
        applyMatState(id, {
            categories: preset.materialCategories,
            overrides: preset.materialOverrides,
            enabled: preset.materialEnabled,
        });
    }
    if (preset.audio && preset.audio.path) {
        try {
            await loadManager.load({ kind: 'audio', path: preset.audio.path });
            setVolume(preset.audio.volume);
            setAudioOffset(preset.audio.offset);
        } catch (_) {
            /* audio load failed, non-fatal */
        }
    } else if (getAudioPath()) {
        clearAudio();
    }
    setStatus('✓ 预设已应用', true);
}

export async function selectAndSavePreset(id: string): Promise<void> {
    const path = await SelectPresetSaveFile();
    if (!path) {
        return;
    }
    const json = serializeModelPreset(id);
    if (!json) {
        setStatus('✗ 无法序列化模型状态', false);
        return;
    }
    const _r0 = await tryCatchStatus(() => SaveModelPreset(json, path), '✗ 保存失败', (err) => showErrorToast('保存模型预设失败', err instanceof Error ? err.message : String(err)));
    if (_r0 !== undefined) {
        setStatus('✓ 预设已保存', true);
    }
}

const _presetUndoStack = new Map<string, string>();

function showUndoToast(message: string, undoFn: () => void): void {
    showErrorToast(message, undefined, [{ label: '撤销', onClick: undoFn }], 8000);
}

export async function tryAutoApplyPreset(id: string): Promise<void> {
    const inst = modelRegistry.get(id);
    if (!inst) {
        return;
    }
    setStatus('正在加载预设库...', false);
    const entries: ModelPresetEntry[] = (await GetModelPresets()) || [];
    if (entries.length === 0) {
        return;
    }
    const libraryRef = computeLibraryRef(inst.filePath);
    const match = entries.find((e) => {
        if (!e.name) {
            return false;
        }
        if (libraryRef && e.modelRef === libraryRef) {
            return true;
        }
        if (e.modelRef && inst.filePath.replace(/\\/g, '/').endsWith(e.modelRef)) {
            return true;
        }
        return false;
    });
    if (!match) {
        return;
    }
    const json = await LoadModelPresetFromLib(match.name);
    const preset: ModelPresetFile = JSON.parse(json);
    if (preset.autoApply !== true) {
        return;
    }
    _presetUndoStack.set(id, serializeModelPreset(id));
    await applyModelPreset(id, json);
    showUndoToast(`已自动应用预设「${escapeHtml(preset.presetName || match.name)}」`, async () => {
        const snap = _presetUndoStack.get(id);
        _presetUndoStack.delete(id);
        if (snap) {
            await applyModelPreset(id, snap);
        }
        setStatus('✓ 已撤销预设应用', true);
    });
}

export async function selectAndLoadPreset(id: string): Promise<void> {
    const path = await SelectPresetOpenFile();
    if (!path) {
        return;
    }
    await tryCatchStatus(async () => {
        const json = await LoadModelPreset(path);
        await applyModelPreset(id, json);
    }, '✗ 加载失败');
}

export async function togglePresetAutoApply(name: string): Promise<void> {
    await tryCatchStatus(async () => {
        const json = await LoadModelPresetFromLib(name);
        const preset: ModelPresetFile = JSON.parse(json);
        preset.autoApply = !preset.autoApply;
        await SaveModelPresetToLib(name, JSON.stringify(preset, null, 2));
    }, '✗ 切换自动应用失败');
}

export async function applyPresetFromLib(
    presetName: string,
    targetModelId: string | null
): Promise<void> {
    await tryCatchStatus(async () => {
        const json = await LoadModelPresetFromLib(presetName);
        const preset: ModelPresetFile = JSON.parse(json);
        if (targetModelId) {
            await applyModelPreset(targetModelId, json);
        } else {
            const targetRef = computeLibraryRef(preset.model.filePath);
            let matchedId: string | null = null;
            for (const [mid, inst] of modelRegistry) {
                if (inst.filePath === preset.model.filePath) {
                    matchedId = mid;
                    break;
                }
                if (targetRef && computeLibraryRef(inst.filePath) === targetRef) {
                    matchedId = mid;
                    break;
                }
                const baseName = preset.model.filePath.replace(/\\/g, '/').split('/').pop();
                if (baseName && inst.filePath.replace(/\\/g, '/').endsWith(baseName)) {
                    matchedId = mid;
                    break;
                }
            }
            if (matchedId) {
                await applyModelPreset(matchedId, json);
            } else {
                const handle = await loadManager.load({ kind: 'actor', path: preset.model.filePath });
                if (handle) {
                    await applyModelPreset(handle.id, json);
                } else {
                    setStatus('✗ 模型加载失败，无法应用预设', false);
                }
            }
        }
    }, '✗ 应用预设失败');
}

export async function savePresetToLibDialog(id: string): Promise<void> {
    const name = await showPrompt('输入预设名称：');
    if (!name) {
        return;
    }
    const trimmed = name.trim();
    if (!trimmed) {
        setStatus('✗ 名称不能为空', false);
        return;
    }
    let json = serializeModelPreset(id, trimmed);
    if (!json) {
        setStatus('✗ 无法序列化模型状态', false);
        return;
    }
    try {
        const existing = await LoadModelPresetFromLib(trimmed);
        if (existing) {
            const existingPreset: ModelPresetFile = JSON.parse(existing);
            if (existingPreset.autoApply) {
                const merged: ModelPresetFile = JSON.parse(json);
                merged.autoApply = true;
                json = JSON.stringify(merged, null, 2);
            }
        }
    } catch {
        /* no existing preset — fine */
    }
    const _r1 = await tryCatchStatus(() => SaveModelPresetToLib(trimmed, json), '✗ 保存失败', (err) => showErrorToast('保存模型预设失败', err instanceof Error ? err.message : String(err)));
    if (_r1 !== undefined) {
        setStatus('✓ 预设已保存到库', true);
    }
}

export function buildPresetListLevel(id: string | null): PopupLevel {
    return {
        label: '预设库',
        dir: '',
        items: [],
        renderCustom: async (container) => {
            container.classList.remove('render-card');
            setStatus('正在加载预设库...', false);
            const entries: ModelPresetEntry[] = (await GetModelPresets()) || [];
            if (entries.length === 0) {
                const empty = document.createElement('div');
                empty.style.cssText =
                    'font-size:12px;color:var(--text-dim);text-align:center;padding:24px;';
                empty.textContent = '暂无预设';
                container.appendChild(empty);
                return;
            }
            cardContainer(container, (c) => {
                for (const e of entries) {
                    const row = document.createElement('div');
                    row.className = 'slide-item';
                    const iconSpan = document.createElement('span');
                    iconSpan.className = 'slide-icon';
                    const iconify = document.createElement('iconify-icon');
                    iconify.icon = 'lucide:bookmark';
                    iconSpan.appendChild(iconify);
                    row.appendChild(iconSpan);
                    const labelSpan = document.createElement('span');
                    labelSpan.className = 'slide-label';
                    labelSpan.textContent = e.presetName || e.name;
                    row.appendChild(labelSpan);
                    if (e.modelName) {
                        const sub = document.createElement('span');
                        sub.style.cssText =
                            'font-size:11px;color:var(--text-dim);margin-right:4px;';
                        sub.textContent = e.modelName;
                        row.appendChild(sub);
                    }
                    const toggleLabel = document.createElement('label');
                    toggleLabel.className = 'toggle';
                    toggleLabel.title = e.autoApply ? '自动应用：开' : '自动应用：关';
                    const toggleInput = document.createElement('input');
                    toggleInput.type = 'checkbox';
                    toggleInput.checked = e.autoApply;
                    toggleInput.addEventListener('change', async (ev) => {
                        ev.stopPropagation();
                        await togglePresetAutoApply(e.name);
                        stackRegistry.modelStack.reRender();
                    });
                    const slider = document.createElement('span');
                    slider.className = 'slider';
                    toggleLabel.appendChild(toggleInput);
                    toggleLabel.appendChild(slider);
                    row.appendChild(toggleLabel);
                    const delBtn = document.createElement('span');
                    delBtn.textContent = '✕';
                    delBtn.title = '删除此预设';
                    delBtn.style.cssText =
                        'font-size:10px;color:var(--text-dim);cursor:pointer;padding:2px 6px;';
                    delBtn.addEventListener('click', async (ev) => {
                        ev.stopPropagation();
                        if (!(await showConfirm(`确定删除「${e.presetName || e.name}」？`))) {
                            return;
                        }
                        const _r2 = await tryCatchStatus(async () => {
                            await DeleteModelPreset(e.name);
                            stackRegistry.modelStack.reRender();
                        }, '✗ 删除失败');
                        if (_r2 !== undefined) {
                            setStatus('✓ 预设已删除', true);
                        }
                    });
                    row.appendChild(delBtn);
                    row.addEventListener('click', (ev) => {
                        if ((ev.target as HTMLElement).closest('.toggle')) {
                            return;
                        }
                        applyPresetFromLib(e.name, id);
                    });
                    c.appendChild(row);
                }
            });
        },
    };
}

// [doc:architecture] Camera Levels — 相机参数弹窗层级
// 从 scene-menu.ts 迁移到 motion-popup.ts

import { setStatus, cardContainer, libraryRoot, stackRegistry, motionBindingTargetId, setMotionBindingTargetId } from '../core/config';
import type { PopupLevel } from '../core/config';
import { createIconifyIcon } from '../core/icons';
import { slideRow, addSliderRow, addToggleRow, addModeSlider } from '../core/ui-helpers';
import {
    switchCameraMode,
    getCameraMode,
    hasCameraVmd,
    clearCameraVmd,
    getOrbitParams,
    setOrbitParams,
    getFreeflyParams,
    setFreeflyParams,
    getConcertParams,
    setConcertParams,
    getConcertPaused,
    setConcertPaused,
    getFov,
    setFov,
    setAutoCameraEnabled,
    isAutoCameraEnabled,
    setAutoCameraBeatsPerSwitch,
    getAutoCameraBeatsPerSwitch,
    type CameraMode,
} from '../scene/camera/camera';
import { triggerAutoSave } from '../scene/scene';
import { getProcBeatDetector } from '../scene/scene';
import { getMotionMenu } from './motion-popup';

let cameraExpandedMode: CameraMode | null = null;

function refreshCameraLevel(): void {
    const menu = getMotionMenu();
    if (menu) {
        menu.reRender();
    }
}

export function buildCameraLevel(): PopupLevel {
    return {
        label: '相机模式',
        dir: '',
        items: [],
        renderCustom: (container) => {
            const currentMode = getCameraMode();
            const vmdLoaded = hasCameraVmd();

            cardContainer(container, (c) => {
                const modeOptions: Array<{ value: string; label: string }> = [
                    { value: 'orbit', label: '轨道' },
                    { value: 'freefly', label: '自由飞行' },
                    { value: 'concert', label: '演唱会' },
                    { value: 'oneshot', label: '单拍' },
                ];
                if (vmdLoaded) {
                    modeOptions.push({ value: 'vmd', label: 'VMD 相机' });
                }

                addModeSlider(
                    c,
                    '相机模式',
                    modeOptions.map((o) => ({ value: o.value, label: o.label })),
                    currentMode,
                    (v) => {
                        if (v === currentMode) {
                            cameraExpandedMode = cameraExpandedMode ? null : currentMode;
                        } else {
                            switchCameraMode(v as CameraMode);
                            cameraExpandedMode = v === 'oneshot' ? null : v as CameraMode;
                        }
                        refreshCameraLevel();
                    },
                    'lucide:camera',
                    undefined,
                    {
                        bind: () => getCameraMode(),
                    }
                );

                addSliderRow(
                    c,
                    '视场角',
                    getFov(),
                    0.3,
                    2,
                    0.05,
                    () => {},
                    'lucide:maximize-2',
                    (v) => {
                        setFov(v);
                        triggerAutoSave();
                    }
                );
            });

            // Auto Camera
            cardContainer(container, (c) => {
                addToggleRow(c, '自动运镜', isAutoCameraEnabled(), (v) => {
                    const bd = getProcBeatDetector();
                    setAutoCameraEnabled(v, bd ?? undefined);
                    refreshCameraLevel();
                }, 'lucide:video', {
                    bind: () => isAutoCameraEnabled(),
                });
                if (isAutoCameraEnabled()) {
                    addSliderRow(
                        c,
                        '切换间隔（拍）',
                        getAutoCameraBeatsPerSwitch(),
                        1,
                        8,
                        1,
                        (v) => { setAutoCameraBeatsPerSwitch(Math.round(v)); },
                        'lucide:timer',
                        undefined,
                        { bind: () => getAutoCameraBeatsPerSwitch() }
                    );
                }
            });

            // Camera params + VMD
            cardContainer(container, (c) => {
                const paramsContainer = document.createElement('div');
                paramsContainer.className = 'cs-params';
                const modeToExpand = cameraExpandedMode ?? currentMode;
                if (modeToExpand !== 'oneshot' && modeToExpand !== 'vmd') {
                    if (modeToExpand === 'orbit') renderOrbitParams(paramsContainer);
                    else if (modeToExpand === 'freefly') renderFreeflyParams(paramsContainer);
                    else if (modeToExpand === 'concert') renderConcertParams(paramsContainer);
                    c.appendChild(paramsContainer);
                }

                if (vmdLoaded) {
                    slideRow(c, 'lucide:trash-2', '清除相机 VMD', false, () => {
                        clearCameraVmd();
                        refreshCameraLevel();
                        setStatus('✓ 已清除相机 VMD', true);
                    });
                }

                slideRow(c, 'lucide:upload', '加载相机 VMD', false, () => {
                    setMotionBindingTargetId(null);
                    const level = stackRegistry.buildLevel!(libraryRoot, '相机 VMD', (m) => m.format === 'vmd');
                    const menu = getMotionMenu();
                    if (menu) menu.push(level);
                });
            });
        },
    };
}

/** Build a parameter editing submenu for the given camera mode. */
export function buildCameraParamsLevel(mode: CameraMode): PopupLevel {
    return {
        label:
            mode === 'orbit'
                ? '轨道设置'
                : mode === 'freefly'
                  ? '自由飞行设置'
                  : mode === 'concert'
                    ? '演唱会设置'
                    : '相机设置',
        dir: '',
        items: [],
        renderCustom: (container) => {
            cardContainer(container, (c) => {
                if (mode === 'orbit') {
                    renderOrbitParams(c);
                } else if (mode === 'freefly') {
                    renderFreeflyParams(c);
                } else if (mode === 'concert') {
                    renderConcertParams(c);
                }
            });
        },
    };
}

function renderOrbitParams(container: HTMLElement): void {
    const p = getOrbitParams();
    addSliderRow(
        container,
        '目标高度',
        p.targetHeight,
        0,
        30,
        0.5,
        (v) => {
            setOrbitParams({ targetHeight: v });
            triggerAutoSave();
        },
        'lucide:maximize'
    );
    addSliderRow(
        container,
        '距离',
        p.distance,
        2,
        50,
        0.5,
        (v) => {
            setOrbitParams({ distance: v });
            triggerAutoSave();
        },
        'lucide:zoom-in'
    );
    addSliderRow(
        container,
        '俯仰角',
        p.beta,
        0.1,
        Math.PI - 0.1,
        0.05,
        (v) => {
            setOrbitParams({ beta: v });
            triggerAutoSave();
        },
        'lucide:arrow-up-down'
    );
}

function renderFreeflyParams(container: HTMLElement): void {
    const p = getFreeflyParams();
    addSliderRow(
        container,
        '移动速度',
        p.speed,
        0.1,
        5,
        0.1,
        (v) => {
            setFreeflyParams({ speed: v });
            triggerAutoSave();
        },
        'lucide:move'
    );
    addSliderRow(
        container,
        '鼠标灵敏度',
        p.angularSensibility,
        500,
        5000,
        100,
        (v) => {
            setFreeflyParams({ angularSensibility: v });
            triggerAutoSave();
        },
        'lucide:mouse-pointer'
    );
}

function renderConcertParams(container: HTMLElement): void {
    const p = getConcertParams();
    addSliderRow(
        container,
        '轨道半径',
        p.radius,
        2,
        50,
        0.5,
        (v) => {
            setConcertParams({ radius: v });
            triggerAutoSave();
        },
        'lucide:circle'
    );
    addSliderRow(
        container,
        '目标高度',
        p.height,
        0,
        30,
        0.5,
        (v) => {
            setConcertParams({ height: v });
            triggerAutoSave();
        },
        'lucide:maximize'
    );
