// [doc:architecture] Motion Cloth Levels — 布料参数弹窗层级
// 从 motion-popup.ts 拆分

import { envState, cardContainer, setStatus } from '../core/config';
import type { PopupLevel } from '../core/config';
import { slideRow, addSliderRow, addCollapsible, addPresetChip } from '../core/ui-helpers';
import {
    setEnvState, modelManager, scene,
} from '../scene/scene';
import {
    getCollider, getColliderSpecs, setCapsuleRadius, setCapsuleHalfHeight,
    setColliderStiffness, setColliderFriction, recreateCloth, autoFitClothDimensions,
} from '../physics/cloth-manager';
import type { ClothConfig } from '../physics/xpbd-cloth';

/**
 * 布料预设 — 物理材质手感（重力由根页面统控，预设不含 gravityScale）
 *
 * XPBD compliance 说明：
 *   compliance=0 → 完美刚性（不拉伸），值越大约束越软（越容易拉长）
 *   bendCompliance 同理，值越大越容易弯折折叠
 *   damping：每帧速度保留比例，越大越不易停止
 */
const CLOTH_PRESETS: Record<string, Partial<ClothConfig>> = {
    silk:   { compliance: 0.004,  bendCompliance: 0.025, damping: 0.98,  totalMass: 0.25 },
    cotton: { compliance: 0.0015, bendCompliance: 0.008, damping: 0.96,  totalMass: 0.45 },
    leather:{ compliance: 0.0005, bendCompliance: 0.002, damping: 0.92,  totalMass: 0.7 },
    stiff:  { compliance: 0.0002, bendCompliance: 0.0008,damping: 0.88,  totalMass: 0.9 },
};

const CLOTH_PRESET_LABELS: Record<string, string> = {
    silk: '丝绸', cotton: '棉布', leather: '皮革', stiff: '硬质',
};

/** 布料预设 — 常见服装样式（拓扑 + 形状） */
const CLOTH_STYLE_PRESETS: Record<string, Partial<ClothConfig>> = {
    shortSkirt: { topology: 'skirt', length: 0.35, slope: 25, segmentsV: 8, innerRadius: 0.14 },
    longSkirt: { topology: 'skirt', length: 1.1, slope: 8, segmentsV: 16, innerRadius: 0.16 },
    cape: { topology: 'cape', length: 0.7, slope: 30, segmentsV: 10, innerRadius: 0.12 },
    tube: { topology: 'tube', length: 0.5, slope: 5, segmentsV: 12, innerRadius: 0.13 },
    ribbon: { topology: 'rope', length: 1.4, slope: 0, segmentsV: 20, innerRadius: 0.08 },
};

const CLOTH_STYLE_LABELS: Record<string, string> = {
    shortSkirt: '短裙', longSkirt: '长裙', cape: '披风', tube: '筒裙', ribbon: '飘带',
};

export function buildClothParamsLevel(): PopupLevel {
    return {
        label: '布料参数',
        dir: '',
        items: [],
        renderCustom: (container) => {
            cardContainer(container, (c) => {
                let _recreateTimer: ReturnType<typeof setTimeout> | null = null;
                const debouncedRecreate = () => {
                    if (_recreateTimer) clearTimeout(_recreateTimer);
                    _recreateTimer = setTimeout(() => {
                        _recreateTimer = null;
                        recreateCloth();
                    }, 100);
                };

                // 常见样式预设
                const styleLabel = document.createElement('div');
                styleLabel.className = 'cs-top';
                styleLabel.innerHTML = '<span class="cs-label" style="font-size:12px;color:var(--text-muted);">常见样式</span>';
                styleLabel.style.marginBottom = '4px';
                c.appendChild(styleLabel);

                const styleGroup = document.createElement('div');
                styleGroup.className = 'preset-group';
                styleGroup.style.paddingBottom = '6px';
                for (const [key] of Object.entries(CLOTH_STYLE_PRESETS)) {
                    addPresetChip(styleGroup, CLOTH_STYLE_LABELS[key] || key, false, () => {
                        const preset = CLOTH_STYLE_PRESETS[key];
                        if (preset) {
                            setEnvState({ clothConfig: { ...envState.clothConfig, ...preset } });
                            recreateCloth();
                            import('./scene-menu').then(m => m.getSceneMenu()?.reRender());
                        }
                    });
                }
                c.appendChild(styleGroup);

                // 材质手感预设
                const feelLabel = document.createElement('div');
                feelLabel.className = 'cs-top';
                feelLabel.innerHTML = '<span class="cs-label" style="font-size:12px;color:var(--text-muted);">材质手感</span>';
                feelLabel.style.marginBottom = '4px';
                c.appendChild(feelLabel);

                const chipGroup = document.createElement('div');
                chipGroup.className = 'preset-group';
                chipGroup.style.paddingBottom = '6px';
                for (const [key] of Object.entries(CLOTH_PRESETS)) {
                    addPresetChip(chipGroup, CLOTH_PRESET_LABELS[key] || key, false, () => {
                        const preset = CLOTH_PRESETS[key];
                        if (preset) {
                            setEnvState({ clothConfig: { ...envState.clothConfig, ...preset } });
                            recreateCloth();
                            import('./scene-menu').then(m => m.getSceneMenu()?.reRender());
                        }
                    });
                }
                c.appendChild(chipGroup);

                // 自动推算按钮
                slideRow(c, 'lucide:scan', '自动推算尺寸', false, () => {
                    const mmd = modelManager?.focusedMmdModel();
                    if (!mmd) { setStatus('⚠ 请先加载模型', false); return; }
                    const getMat = (name: string) => modelManager?.getBoneWorldMatrix(name) ?? null;
                    const fitted = autoFitClothDimensions(envState.clothConfig.anchorBone || '腰', getMat, mmd.runtimeBones);
                    setEnvState({ clothConfig: { ...envState.clothConfig, ...fitted } });
                    recreateCloth();
                    import('./scene-menu').then(m => m.getSceneMenu()?.reRender());
                    setStatus(`✓ 已推算: 半径 ${fitted.innerRadius.toFixed(3)}, 长度 ${fitted.length.toFixed(2)}`, true);
                });

                addCollapsible(c, {
                    title: '形状', icon: 'lucide:shirt', defaultOpen: false,
                    renderContent: (cc) => {
                        const c2 = envState.clothConfig;
                        addSliderRow(cc, '裙长', c2.length, 0.1, 2.5, 0.05, (v) => { setEnvState({ clothConfig: { ...envState.clothConfig, length: v } }); debouncedRecreate(); }, 'lucide:ruler');
                        addSliderRow(cc, '裙摆角度', c2.slope, 0, 45, 1, (v) => { setEnvState({ clothConfig: { ...envState.clothConfig, slope: v } }); debouncedRecreate(); }, 'lucide:triangle');
                        addSliderRow(cc, '腰部半径', c2.innerRadius, 0.03, 1.0, 0.01, (v) => { setEnvState({ clothConfig: { ...envState.clothConfig, innerRadius: v } }); debouncedRecreate(); }, 'lucide:circle');
                    },
                });

                addCollapsible(c, {
                    title: '物理', icon: 'lucide:wind', defaultOpen: false,
                    renderContent: (cc) => {
                        const c3 = envState.clothConfig;
                        addSliderRow(cc, '布料柔度', c3.compliance, 0, 0.01, 0.0005, (v) => { setEnvState({ clothConfig: { ...envState.clothConfig, compliance: v } }); debouncedRecreate(); }, 'lucide:wind');
                        addSliderRow(cc, '弯曲柔度', c3.bendCompliance, 0, 0.05, 0.002, (v) => { setEnvState({ clothConfig: { ...envState.clothConfig, bendCompliance: v } }); debouncedRecreate(); }, 'lucide:curl');
                        addSliderRow(cc, '阻尼', c3.damping, 0.8, 0.999, 0.01, (v) => { setEnvState({ clothConfig: { ...envState.clothConfig, damping: v } }); debouncedRecreate(); }, 'lucide:droplet');
                        addSliderRow(cc, '重力倍率', c3.gravityScale, 0.1, 3, 0.1, (v) => { setEnvState({ clothConfig: { ...envState.clothConfig, gravityScale: v } }); debouncedRecreate(); }, 'lucide:arrow-down');
                    },
                });

                addCollapsible(c, {
                    title: '细分', icon: 'lucide:grid', defaultOpen: false,
                    renderContent: (cc) => {
                        const c4 = envState.clothConfig;
                        addSliderRow(cc, '水平分段', c4.segmentsH, 12, 36, 2, (v) => { setEnvState({ clothConfig: { ...envState.clothConfig, segmentsH: v } }); debouncedRecreate(); }, 'lucide:grid');
                        addSliderRow(cc, '垂直分段', c4.segmentsV, 6, 24, 2, (v) => { setEnvState({ clothConfig: { ...envState.clothConfig, segmentsV: v } }); debouncedRecreate(); }, 'lucide:grid');
                    },
                });

                addCollapsible(c, {
                    title: '碰撞体', icon: 'lucide:shield', defaultOpen: false,
                    renderContent: (cc) => {
                        const specs = getColliderSpecs();
                        if (specs.length === 0) {
                            const hint = document.createElement('div');
                            hint.style.cssText = 'padding:12px;color:var(--text-muted);font-size:12px;';
                            hint.textContent = '请先启用布料模拟';
                            cc.appendChild(hint);
                            return;
                        }

                        const collider = getCollider();
                        if (collider) {
                            addSliderRow(cc, '碰撞刚度', collider.stiffness, 0, 1, 0.05, (v) => setColliderStiffness(v), 'lucide:zap');
                            addSliderRow(cc, '摩擦系数', collider.friction, 0, 1, 0.05, (v) => setColliderFriction(v), 'lucide:hand');
                        }

                        const groups = [
                            { label: '躯干', items: ['chest', 'waist', 'hip'] },
                            { label: '腿部', items: ['upperLegL', 'upperLegR', 'lowerLegL', 'lowerLegR'] },
                            { label: '手臂', items: ['upperArmL', 'upperArmR', 'lowerArmL', 'lowerArmR'] },
                        ];

                        const CAPSULE_LABELS: Record<string, string> = {
                            head: '头部', neck: '颈部', chest: '胸部', waist: '腰部', hip: '臀部',
                            upperArmL: '左上臂', upperArmR: '右上臂', lowerArmL: '左前臂', lowerArmR: '右前臂',
                            upperLegL: '左大腿', upperLegR: '右大腿', lowerLegL: '左小腿', lowerLegR: '右小腿',
                        };

                        for (const group of groups) {
                            addCollapsible(cc, {
                                title: group.label, icon: 'lucide:box', defaultOpen: false,
                                renderContent: (gc) => {
                                    for (const name of group.items) {
                                        const spec = specs.find((s) => s.name === name);
                                        if (!spec) continue;
                                        const label = CAPSULE_LABELS[name] || name;
                                        addSliderRow(gc, `${label} 半径`, spec.radius, 0.02, 0.3, 0.01, (v) => setCapsuleRadius(name, v), 'lucide:circle');
                                        addSliderRow(gc, `${label} 半高`, spec.halfHeight, 0.02, 0.3, 0.01, (v) => setCapsuleHalfHeight(name, v), 'lucide:move-vertical');
                                    }
                                },
                            });
                        }
                    },
                });

            });
        },
    };
}

// [doc:architecture] Motion Popup — 动作弹窗（核心 + barrel export）
// 拆分后保留: 动作绑定/音乐/动作菜单/入口 + barrel re-export
// 子文件: motion-cloth-levels.ts

import {
    setStatus,
    libraryRoot,
    overridePaths,
    PopupLevel,
    PopupRow,
    escapeHtml,
    isPlaying,
    setIsPlaying,
    mmdRuntime,
    autoLoop,
    setAutoLoop,
    focusedModelId,
    motionBindingTargetId,
    setMotionBindingTargetId,
    layerBindingTargetId,
    setLayerBindingTargetId,
    stackRegistry,
    closeAllOverlays,
    cardContainer,
    envState,
    getRecentMotions,
} from '../core/config';
import { registerPopupMenu } from './menu-factory';
import { slideRow, addToggleRow, addEmptyRow } from '../core/ui-helpers';
import { getCurrentRenderingMenu } from './menu';
import { createIconifyIcon } from '../core/icons';
import { loadManager } from '../core/load-manager';

import {
    loadVPDPose,
    updatePlaybackUI,
    focusModel,
    getPhysicsCategories,
    isPhysicsCategoryEnabled,
    setPhysicsCategory,
    setModelWireframe,
    setModelBoneLinesVis,
    setModelBoneJointsVis,
    modelManager,
} from '../scene/scene';
import {
    getVmdLayers,
    toggleVmdLayer,
    setVmdLayerWeight,
    removeVmdLayer,
    addVmdLayerFromPath,
    addGazeLayer,
    clearVmdLayers,
} from '../scene/motion/vmd-layers';
import {
    clearAudio,
    getAudioName,
} from '../outfit/audio';
import {
    setProcMotionMode,
    setProcMotionAutoSwitch,
    getProcMotionState,
    regenerateProcMotion,
    getLipSyncState,
    setLipSyncEnabled,
} from '../scene/scene';
import type { ProcMotionMode } from '../motion-algos/procedural-motion';
import {
    buildProcMotionLevel, buildProcMotionModeLevel, buildLipSyncLevel,
} from './motion-procmotion-levels';
import { buildCameraLevel } from './motion-camera-levels';
import { setEnvState } from '../scene/scene';

// ======== 从子文件导入 ========
import { buildClothParamsLevel } from './motion-cloth-levels';

// ======== Barrel Re-Exports ========
export { buildClothParamsLevel } from './motion-cloth-levels';

// ======== Build action model row and binding ========

function buildActionBindingLevel(id: string): PopupLevel {
    const inst = modelManager.get(id);
    if (!inst) {
        return { label: '动作绑定', dir: '', items: [] };
    }
    return {
        label: inst.name,
        dir: '',
        items: [],
        renderCustom: (container) => {
            cardContainer(container, (c) => {
                slideRow(c, 'lucide:music', '更换动作', true, () => {
                    setMotionBindingTargetId(id);
                    const level = stackRegistry.buildLevel!(libraryRoot, '动作库', (m) => m.format === 'vmd');
                    level.label = `绑定动作 → ${inst.name}`;
                    if (getMotionMenu()) getMotionMenu()?.push(level);
                }, inst.vmdName || '无');
                const firstRow = c.querySelector('.slide-item');
                if (firstRow) {
                    const sublabelEl = firstRow.querySelector('.slide-sublabel');
                    if (sublabelEl) {
                        getCurrentRenderingMenu()?.registerControl(() => {
                            const currentInst = modelManager.get(id);
                            if (currentInst) {
                                sublabelEl.textContent = currentInst.vmdName || '无';
                            }
                        });
                    }
                }
                slideRow(c, 'lucide:user', '姿势库', true, () => {
                    const level = stackRegistry.buildLevel!(libraryRoot, '姿势库', (m) => m.format === 'vpd');
                    level.label = `姿势 → ${inst.name}`;
                    if (getMotionMenu()) getMotionMenu()?.push(level);
                });
            });

            if (inst.kind === 'actor') {
                const physCategories = getPhysicsCategories(id);
                if (physCategories.length > 0) {
                    cardContainer(container, (c) => {
                        const CAT_LABELS: Record<string, string> = {
                            skirt: '裙子物理', chest: '胸部物理', hair: '头发物理', accessory: '配件物理',
                        };
                        for (const cat of physCategories) {
                            const enabled = isPhysicsCategoryEnabled(id, cat);
                            addToggleRow(c, CAT_LABELS[cat] || cat, enabled, (v) => {
                                setPhysicsCategory(id, cat, v);
                                getMotionMenu()?.updateControls();
                                setStatus(v ? `✓ ${CAT_LABELS[cat] || cat} 已开启` : `✕ ${CAT_LABELS[cat] || cat} 已关闭`, true);
                            }, 'lucide:settings', {
                                bind: () => isPhysicsCategoryEnabled(id, cat),
                            });
                        }
                    });
                }
            }

            cardContainer(container, (c) => {
                const group = document.createElement('div');
                group.className = 'preset-group';
                group.style.padding = '0';
                const focusBtn = document.createElement('button');
                focusBtn.className = 'preset-chip';
                focusBtn.innerHTML = '🎯 聚焦到模型';
                focusBtn.addEventListener('click', () => focusModel(id));
                group.appendChild(focusBtn);
                const clearBtn = document.createElement('button');
                clearBtn.className = 'preset-chip';
                clearBtn.textContent = '🗑 清除 VMD';
                clearBtn.addEventListener('click', async () => {
                    if (inst && inst.mmdModel && mmdRuntime) {
                        inst.mmdModel.setRuntimeAnimation(null);
                        inst.vmdData = null; inst.vmdName = ''; inst.vmdPath = null; inst.animationDuration = 0;
                        if (isPlaying) { mmdRuntime.pauseAnimation(); setIsPlaying(false); }
                        updatePlaybackUI();
                        getMotionMenu()?.updateControls();
                        setStatus('✓ 动作已清除', true);
                    }
                });
                group.appendChild(clearBtn);
                c.appendChild(group);
            });
        },
    };
}

function buildActionMusicLevel(): PopupLevel {
    return {
        label: '音乐',
        dir: '',
        items: [],
        renderCustom: (container) => {
            cardContainer(container, (c) => {
                slideRow(c, 'lucide:folder-open', '浏览音乐库', true, () => {
                    const level = stackRegistry.buildLevel!(libraryRoot, '音乐库', (m) => m.format === 'audio');
                    if (getMotionMenu()) getMotionMenu()?.push(level);
                }, getAudioName() || '无音乐');
                if (getAudioName()) {
                    slideRow(c, 'lucide:trash-2', '移除音乐', false, () => {
                        clearAudio();
                        setStatus('✓ 音乐已移除', true);
                        getMotionMenu()?.reRender();
                    });
                }
            });
        },
    };
}

// ======== Motion Stack ========

const { getMenu: getMotionMenu, refreshRoot: refreshMotionRoot, show: showMotionPopup } = registerPopupMenu({
    wrapperKey: 'motion-popup',
    popupType: 'motion',
    overlayClass: 'sceneOverlay-motion',
    buildRoot: () => buildMotionRootLevel(),
    buildRootItems: () => buildMotionRootItems(),
    handlers: {
        onItemClick: motionOnItemClick,
        onFolderEnter: motionOnFolderEnter,
    },
});

export { getMotionMenu, refreshMotionRoot, showMotionPopup };

/** motion-popup 的 onFolderEnter 路由（从 makeMotionMenu 提取） */
function motionOnFolderEnter(row: PopupRow): PopupLevel | null {
    if (row.target === 'motion:camera') { return buildCameraLevel(); }

    if (row.target && row.target.startsWith('motion:layers:')) {
        const id = row.target.replace('motion:layers:', '');
        return buildLayersLevel(id);
    }

    if (row.target === 'motion:recent') { return buildRecentMotionsLevel(); }
    if (row.target === 'motion:procmotion') { return buildProcMotionLevel(); }
    if (row.target === 'procmotion:mode') { return buildProcMotionModeLevel(); }
    if (row.target === 'lipsync:menu') { return buildLipSyncLevel(); }
    if (row.target && row.target.startsWith('action:binding:')) {
        setMotionBindingTargetId(null);
        return buildActionBindingLevel(row.target.replace('action:binding:', ''));
    }
    if (row.target && row.target.startsWith('action:motion:browse:')) {
        const id = row.target.replace('action:motion:browse:', '');
        setMotionBindingTargetId(id);
        const level = stackRegistry.buildLevel!(libraryRoot, '动作库', (m) => m.format === 'vmd');
        const inst = modelManager.get(id);
        level.label = `绑定动作 → ${inst ? inst.name : '模型'}`;
        return level;
    }
    return null;
}

/** motion-popup 的 onItemClick（从 makeMotionMenu 提取） */
function motionOnItemClick(row: PopupRow): void {
    if (row.model) {
        if (row.model.format === 'vmd' && motionBindingTargetId) {
            hideMotionPopup();
            loadManager.load({ kind: 'vmd', path: row.model.file_path, modelId: motionBindingTargetId }).catch((err) => {
                setStatus('✗ 动作加载失败', false);
                console.warn('motion-popup load vmd:', err);
            });
            setMotionBindingTargetId(null);
            return;
        }
        hideMotionPopup();
        if (row.model.format === 'vmd') {
            if (motionBindingTargetId) {
                loadManager.load({ kind: 'vmd', path: row.model.file_path });
            } else {
                loadManager.load({ kind: 'camera-vmd', path: row.model.file_path }).then(() => {
                    const menu = getMotionMenu();
                    if (menu) menu.reRender();
                }).catch((err) => {
                    console.error('Load camera VMD failed:', err);
                });
            }
            return;
        }
        if (row.model.format === 'audio') {
            loadManager.load({ kind: 'audio', path: row.model.file_path });
            setStatus(`✓ 音乐: ${getAudioName()}`, true);
            if (getMotionMenu()) getMotionMenu()?.reRender();
            return;
        }
        if (row.model.format === 'vpd') {
            loadVPDPose(row.model.file_path);
            return;
        }
        return;
    }
    if (row.target && row.target.startsWith('procmotion:set-mode:')) {
        setProcMotionMode(row.target.replace('procmotion:set-mode:', '') as ProcMotionMode);
        regenerateProcMotion();
        return;
    }
    if (row.target === 'procmotion:autoswitch') {
        setProcMotionAutoSwitch(!getProcMotionState().autoSwitch);
        getMotionMenu()?.reRender();
        return;
    }
    if (row.target === 'lipsync:toggle') {
        setLipSyncEnabled(!getLipSyncState().enabled);
        getMotionMenu()?.reRender();
        return;
    }
    if (row.target && row.target.startsWith('action:motion:')) {
        const parts = row.target.split(':');
        const action = parts[2];
        const id = parts.slice(3).join(':');
        if (!id) return;
        const inst = modelManager.get(id);
        if (!inst) return;
        switch (action) {
            case 'pause':
                if (mmdRuntime) {
                    if (isPlaying) { mmdRuntime.pauseAnimation(); setIsPlaying(false); setAutoLoop(false); }
                    else { setAutoLoop(true); mmdRuntime.playAnimation().then(() => setIsPlaying(true)); }
                    updatePlaybackUI(); getMotionMenu()?.reRender();
                }
                break;
            case 'reset':
                if (inst.mmdModel && mmdRuntime) {
                    inst.mmdModel.setRuntimeAnimation(null);
                    inst.vmdData = null; inst.vmdName = ''; inst.vmdPath = null; inst.animationDuration = 0;
                    if (isPlaying) { mmdRuntime.pauseAnimation(); setIsPlaying(false); }
                    updatePlaybackUI();
                    if (getMotionMenu()) getMotionMenu()?.reRender();
                    setStatus('✓ 动作已重置', true);
                }
                break;
            case 'pose':
                (async () => {
                    const level = stackRegistry.buildLevel!(libraryRoot, '姿势库', (m) => m.format === 'vpd');
                    level.label = `姿势 → ${inst.name}`;
                    if (getMotionMenu()) getMotionMenu()?.push(level);
                })();
                break;
            case 'loop':
                setAutoLoop(!autoLoop);
                getMotionMenu()?.reRender();
                setStatus(`循环: ${autoLoop ? '开' : '关'}`, true);
                break;
        }
        return;
    }
    if (row.target === '__music_browse__') {
        const level = stackRegistry.buildLevel!(libraryRoot, '音乐库', (m) => m.format === 'audio');
        if (getMotionMenu()) getMotionMenu()?.push(level);
        return;
    }
    if (row.target === '__music_clear__') {
        clearAudio();
        setStatus('✓ 音乐已移除', true);
        if (getMotionMenu()) getMotionMenu()?.reRender();
        return;
    }
}

function buildRecentMotionsLevel(): PopupLevel {
    const recent = getRecentMotions();
    return {
        label: '最近使用',
        dir: '',
        items: [],
        renderCustom: (container) => {
            cardContainer(container, (c) => {
                if (recent.length === 0) {
                    addEmptyRow(c, '暂无最近使用动作');
                    return;
                }
                for (const r of recent) {
                    slideRow(c, 'lucide:music', r.name, false, () => {
                        hideMotionPopup();
                        loadManager.load({ kind: 'vmd', path: r.path }).catch((err) => {
                            setStatus('✗ 动作加载失败', false);
                            console.warn('recent motion load:', err);
                        });
                    });
                }
            });
        },
    };
}

// ======== Motion Layers (图层) ========

function buildLayersLevel(id: string): PopupLevel {
    const inst = modelManager.get(id);
    return {
        label: `图层 → ${inst?.name ?? '?'}`,
        dir: '',
        items: [],
        renderCustom: (container) => {
            const layers = getVmdLayers(id);

            // 添加图层按钮
            cardContainer(container, (c) => {
                slideRow(c, 'lucide:plus', '添加图层', true, () => {
                    setLayerBindingTargetId(id);
                    const level = stackRegistry.buildLevel!(libraryRoot, '动作库', (m) => m.format === 'vmd');
                    level.label = `添加图层 → ${inst?.name ?? '?'}`;
                    if (getMotionMenu()) getMotionMenu()?.push(level);
                });
            });

            // 添加视线追踪图层
            cardContainer(container, (c) => {
                slideRow(c, 'lucide:eye', '添加视线追踪', false, async () => {
                    await addGazeLayer(id);
                    getMotionMenu()?.reRender();
                });
            });

            // 图层列表
            if (layers.length === 0) {
                cardContainer(container, (c) => {
                    addEmptyRow(c, '暂无图层 — 添加第二个 VMD 开启叠加');
                });
            } else {
                cardContainer(container, (c) => {
                    for (const layer of layers) {
                        const isGaze = layer.kind === 'gaze';
                        const row = document.createElement('div');
                        row.className = 'slide-item';
                        if (isGaze) {
                            row.style.borderLeft = '3px solid rgba(78, 205, 196, 0.4)';
                            row.style.paddingLeft = 'calc(14px - 3px)';
                            row.style.background = 'rgba(128, 128, 128, 0.06)';
                        }

                        const left = document.createElement('div');
                        left.className = 'slide-left';
                        left.style.flex = '1';
                        left.style.minWidth = '0';

                        const label = document.createElement('div');
                        label.className = 'slide-label';
                        label.textContent = isGaze ? '◎ ' + layer.name : layer.name;
                        label.style.overflow = 'hidden';
                        label.style.textOverflow = 'ellipsis';
                        label.style.whiteSpace = 'nowrap';
                        left.appendChild(label);

                        // 权重滑条
                        const sliderRow = document.createElement('div');
                        sliderRow.style.display = 'flex';
                        sliderRow.style.alignItems = 'center';
                        sliderRow.style.gap = '6px';
                        sliderRow.style.marginTop = '4px';

                        const slider = document.createElement('input');
                        slider.type = 'range';
                        slider.min = '0';
                        slider.max = '1';
                        slider.step = '0.05';
                        slider.value = String(layer.weight);
                        slider.style.flex = '1';
                        slider.style.height = '3px';
                        slider.disabled = !layer.enabled;
                        slider.addEventListener('input', () => {
                            setVmdLayerWeight(layer.id, parseFloat(slider.value), id);
                        });

                        const weightLabel = document.createElement('span');
                        weightLabel.textContent = `${Math.round(layer.weight * 100)}%`;
                        weightLabel.style.fontSize = 'var(--font-ui-sm)';
                        weightLabel.style.opacity = '0.6';
                        weightLabel.style.minWidth = '32px';
                        weightLabel.style.textAlign = 'right';
                        // 实时更新权重显示
                        getCurrentRenderingMenu()?.registerControl(() => {
                            const cur = getVmdLayers(id).find(l => l.id === layer.id);
                            if (cur) {
                                weightLabel.textContent = `${Math.round(cur.weight * 100)}%`;
                                slider.value = String(cur.weight);
                            }
                        });

                        sliderRow.appendChild(slider);
                        sliderRow.appendChild(weightLabel);
                        left.appendChild(sliderRow);

                        row.appendChild(left);

                        // 启用/禁用 toggle
                        const toggle = document.createElement('button');
                        toggle.className = 'slide-action';
                        toggle.textContent = layer.enabled ? '👁' : '🚫';
                        toggle.title = layer.enabled ? '点击禁用' : '点击启用';
                        toggle.style.opacity = layer.enabled ? '1' : '0.4';
                        toggle.addEventListener('click', () => {
                            toggleVmdLayer(layer.id, id);
                            getMotionMenu()?.reRender();
                        });
                        row.appendChild(toggle);

                        // 删除按钮
                        const delBtn = document.createElement('button');
                        delBtn.className = 'slide-action';
                        delBtn.textContent = '✕';
                        delBtn.title = '删除图层';
                        delBtn.style.opacity = '0.5';
                        delBtn.addEventListener('click', () => {
                            removeVmdLayer(layer.id, id);
                            getMotionMenu()?.reRender();
                        });
                        row.appendChild(delBtn);

                        c.appendChild(row);
                    }
                });
            }

            // 全部清除按钮
            if (layers.length > 0) {
                cardContainer(container, (c) => {
                    const group = document.createElement('div');
                    group.className = 'preset-group';
                    group.style.padding = '0';
                    const clearBtn = document.createElement('button');
                    clearBtn.className = 'preset-chip';
                    clearBtn.textContent = '🗑 清除所有图层';
                    clearBtn.addEventListener('click', () => {
                        clearVmdLayers(id);
                        getMotionMenu()?.reRender();
                    });
                    group.appendChild(clearBtn);
                    c.appendChild(group);
                });
            }
        },
    };
}

// ======== Motion Root (items-based) ========

/** 动作弹窗根级 items 构建器——动态反映 modelManager / recent / cloth 状态。 */
function buildMotionRootItems(): PopupRow[] {
    const items: PopupRow[] = [];
    // Card 1: 已加载模型
    if (modelManager.size > 0) {
        const propDir = (overridePaths.prop || (libraryRoot ? libraryRoot + '/prop' : '')).toLowerCase();
        for (const [id, inst] of modelManager.modelRegistry) {
            if (inst.kind !== 'actor') continue;
            // 路径在 prop 目录下的视为道具，不参与动作绑定
            if (propDir && inst.filePath.toLowerCase().startsWith(propDir)) continue;
            items.push({
                kind: 'folder',
                label: inst.name,
                icon: 'tabler:cube-3d-sphere',
                target: `action:binding:${id}`,
                sublabel: inst.vmdName || undefined,
                catTag: '角色',
            });
        }
        // 图层入口（仅角色模型）
        for (const [id, inst] of modelManager.modelRegistry) {
            if (inst.kind === 'actor' && !(propDir && inst.filePath.toLowerCase().startsWith(propDir))) {
                const layerCount = inst.vmdLayers.length;
                items.push({
                    kind: 'folder',
                    label: `${inst.name} 图层`,
                    icon: 'lucide:layers',
                    target: `motion:layers:${id}`,
                    sublabel: layerCount > 0 ? `${layerCount} 层` : undefined,
                });
            }
        }
        items.push({ kind: 'divider', label: '', icon: '', target: '' });
    }
    // Card 2: 最近使用
    if (getRecentMotions().length > 0) {
        items.push({
            kind: 'folder', label: '最近使用', icon: 'lucide:clock', target: 'motion:recent',
        });
        items.push({ kind: 'divider', label: '', icon: '', target: '' });
    }
    // Card 3: 相机 + 音乐库 + 程序化动作
    items.push({ kind: 'folder', label: '相机', icon: 'lucide:video', target: 'motion:camera' });
    items.push({
        kind: 'action',
        label: getAudioName() ? '音乐库' : '浏览音乐库',
        icon: 'lucide:music',
        target: '__music_browse__',
        sublabel: getAudioName() || undefined,
    });
    if (getAudioName()) {
        items.push({ kind: 'action', label: '移除音乐', icon: 'lucide:trash-2', target: '__music_clear__' });
    }
    items.push({ kind: 'folder', label: '程序化动作', icon: 'lucide:wind', target: 'motion:procmotion' });
    return items;
}

function buildMotionRootLevel(): PopupLevel {
    return {
        label: '动作',
        dir: '',
        items: buildMotionRootItems(),
    };
}



export function hideMotionPopup(): void {
    closeAllOverlays();
}

// [doc:architecture] Scene ProcMotion Levels — 程序化动作/LipSync 弹窗层级
// 从 scene-menu.ts 拆分

import { cardContainer } from '../core/config';
import type { PopupLevel } from '../core/config';
import { addSliderRow, addToggleRow, addModeSlider, addCollapsible, addSectionTitle, addPresetChip } from '../core/ui-helpers';
import { showConfirm } from '../core/dialog';
import {
    setProcMotionMode,
    setProcMotionIntensity,
    setProcMotionSpeed,
    setProcMotionAutoSwitch,
    getProcMotionState,
    regenerateProcMotion,
    getLipSyncState,
    setLipSyncEnabled,
    setLipSyncSensitivity,
    setLipSyncIntensity,
    setProcMotionInterpOverride,
    setLifelikeEnabled,
    setLifelikeIntensity,
} from '../scene/scene';
import { setProcMotionBoneToggle, setProcMotionEyeTrackingEnabled, setProcMotionHeadTrackingEnabled } from '../scene/motion/proc-motion-bridge';
import { getProcMotionBoneCategories } from '../motion-algos/procedural-motion';
import { getMmdRuntimeType, setMmdRuntimeType } from '../core/config';
import type { ProcMotionMode } from '../motion-algos/procedural-motion';
import { getMotionMenu } from './motion-popup';

export function buildProcMotionLevel(): PopupLevel {
    const st = getProcMotionState();
    const lipSt = getLipSyncState();
    return {
        label: '程序化动作',
        dir: '',
        items: [],
        renderCustom: (container) => {
            // ======== 快速预设 ========
            cardContainer(container, (c) => {
                const group = document.createElement('div');
                group.className = 'preset-group';
                group.style.padding = '0';
                addPresetChip(group, '待机呼吸', st.mode === 'idle', () => {
                    setProcMotionMode('idle');
                    regenerateProcMotion();
                    getMotionMenu()?.updateControls();
                }, {
                    onUpdate: (btn) => btn.classList.toggle('active', getProcMotionState().mode === 'idle')
                });
                addPresetChip(group, '自动舞蹈', st.mode === 'autodance', () => {
                    setProcMotionMode('autodance');
                    regenerateProcMotion();
                    getMotionMenu()?.updateControls();
                }, {
                    onUpdate: (btn) => btn.classList.toggle('active', getProcMotionState().mode === 'autodance')
                });
                addPresetChip(group, '关闭', st.mode === 'off', () => {
                    setProcMotionMode('off');
                    regenerateProcMotion();
                    getMotionMenu()?.updateControls();
                }, {
                    onUpdate: (btn) => btn.classList.toggle('active', getProcMotionState().mode === 'off')
                });
                c.appendChild(group);
            });

            cardContainer(container, (c) => {
                addModeSlider(
                    c,
                    '程序化动作',
                    [
                        { value: 'off' as const, label: '关闭' },
                        { value: 'idle' as const, label: '待机呼吸' },
                        { value: 'autodance' as const, label: '自动舞蹈' },
                    ],
                    st.mode,
                    (v) => {
                        setProcMotionMode(v);
                        regenerateProcMotion();
                    },
                    'lucide:wind',
                    undefined,
                    {
                        bind: () => getProcMotionState().mode,
                    }
                );
                addToggleRow(c, '自动切换', st.autoSwitch, (v) => {
                    setProcMotionAutoSwitch(v);
                }, 'lucide:repeat', {
                    bind: () => getProcMotionState().autoSwitch,
                });
                addToggleRow(c, 'LipSync', lipSt.enabled, (v) => {
                    setLipSyncEnabled(v);
                    getMotionMenu()?.updateControls();
                }, 'lucide:mic', {
                    bind: () => getLipSyncState().enabled,
                });
                addToggleRow(c, '微动叠加', st.lifelikeEnabled, (v) => {
                    setLifelikeEnabled(v);
                    getMotionMenu()?.updateControls();
                }, 'lucide:sparkles', {
                    bind: () => getProcMotionState().lifelikeEnabled,
                });
            });
            cardContainer(container, (c) => {
                addSliderRow(
                    c,
                    '动作强度',
                    st.intensity,
                    0,
                    1,
                    0.05,
                    (v) => {
                        setProcMotionIntensity(v);
                        regenerateProcMotion();
                    },
                    'lucide:activity',
                    undefined,
                    {
                        bind: () => getProcMotionState().intensity,
                    }
                );
                addSliderRow(
                    c,
                    '速度',
                    st.speed,
                    0.5,
                    2,
                    0.05,
                    (v) => {
                        setProcMotionSpeed(v);
                        regenerateProcMotion();
                    },
                    'lucide:fast-forward',
                    undefined,
                    {
                        bind: () => getProcMotionState().speed,
                    }
                );
            });

            // ======== Lifelike 微动叠加强度 ========
            if (st.lifelikeEnabled) {
                cardContainer(container, (c) => {
                    addSliderRow(
                        c,
                        '微动强度',
                        st.lifelikeIntensity,
                        0,
                        1,
                        0.05,
                        (v) => {
                            setLifelikeIntensity(v);
                        },
                        'lucide:sparkles',
                        undefined,
                        {
                            bind: () => getProcMotionState().lifelikeIntensity,
                        }
                    );
                });
            }

            // ======== 骨骼微动效果（可折叠） ========
            addCollapsible(container, {
                title: '骨骼微动效果',
                icon: 'lucide:activity',
                defaultOpen: false,
                renderContent: (inner) => {
                    const cats = getProcMotionBoneCategories();
                    const labels: Record<string, string> = {
                        center:   '重心弹跳',
                        upper:    '上半身呼吸',
                        upper2:   '上半身2扭转',
                        waist:    '腰部扭胯',
                        head:     '头部点头',
                        arm:      '手臂摆动',
                        groove:   'Groove微晃',
                        shoulder: '肩部耸肩',
                        allParent:'全親微晃',
                        wrist:    '手腕节拍',
                        footIk:   '足IK踏步',
                        blink:    '眨眼',
                        emotion:  '表情情绪轮',
                    };
                    const icons: Record<string, string> = {
                        center:   'lucide:move',
                        upper:    'lucide:activity',
                        upper2:   'lucide:rotate-ccw',
                        waist:    'lucide:uturn-arrow',
                        head:     'lucide:box-select',
                        arm:      'lucide:arm-flex',
                        groove:   'lucide:waves',
                        shoulder: 'lucide:arrow-up-down',
                        allParent:'lucide:dot',
                        wrist:    'lucide:hand',
                        footIk:   'lucide:footprints',
                        blink:    'lucide:eye',
                        emotion:  'lucide:smile',
                    };
                    // 分组：躯干
                    addSectionTitle(inner, '躯干');
                    for (const cat of ['center', 'allParent', 'waist', 'groove'] as const) {
                        if (cats.includes(cat)) {
                            addToggleRow(inner, labels[cat] ?? cat, st.boneToggles[cat], (v) => {
                                setProcMotionBoneToggle(cat, v);
                                regenerateProcMotion();
                            }, icons[cat] ?? 'lucide:circle', {
                                bind: () => getProcMotionState().boneToggles[cat],
                            });
                        }
                    }
                    // 分组：上半身
                    addSectionTitle(inner, '上半身');
                    for (const cat of ['upper', 'upper2', 'shoulder', 'arm'] as const) {
                        if (cats.includes(cat)) {
                            addToggleRow(inner, labels[cat] ?? cat, st.boneToggles[cat], (v) => {
                                setProcMotionBoneToggle(cat, v);
                                regenerateProcMotion();
                            }, icons[cat] ?? 'lucide:circle', {
                                bind: () => getProcMotionState().boneToggles[cat],
                            });
                        }
                    }
                    // 分组：头部
                    addSectionTitle(inner, '头部');
                    for (const cat of ['head', 'blink', 'emotion'] as const) {
                        if (cats.includes(cat)) {
                            addToggleRow(inner, labels[cat] ?? cat, st.boneToggles[cat], (v) => {
                                setProcMotionBoneToggle(cat, v);
                                regenerateProcMotion();
                            }, icons[cat] ?? 'lucide:circle', {
                                bind: () => getProcMotionState().boneToggles[cat],
                            });
                        }
                    }
                    // 分组：末端
                    addSectionTitle(inner, '末端');
                    for (const cat of ['wrist', 'footIk'] as const) {
                        if (cats.includes(cat)) {
                            addToggleRow(inner, labels[cat] ?? cat, st.boneToggles[cat], (v) => {
                                setProcMotionBoneToggle(cat, v);
                                regenerateProcMotion();
                            }, icons[cat] ?? 'lucide:circle', {
                                bind: () => getProcMotionState().boneToggles[cat],
                            });
                        }
                    }
                },
            });

            // ======== 视线追踪（可折叠） ========
            addCollapsible(container, {
                title: '视线追踪',
                icon: 'lucide:eye',
                defaultOpen: false,
                renderContent: (inner) => {
                    addToggleRow(inner, '眼部跟随', st.eyeTrackingEnabled, (v) => {
                        setProcMotionEyeTrackingEnabled(v);
                        getMotionMenu()?.updateControls();
                    }, 'lucide:eye', {
                        bind: () => getProcMotionState().eyeTrackingEnabled,
                    });
                    addToggleRow(inner, '头部跟随', st.headTrackingEnabled, (v) => {
                        setProcMotionHeadTrackingEnabled(v);
                        getMotionMenu()?.updateControls();
                    }, 'lucide:mouse-pointer-2', {
                        bind: () => getProcMotionState().headTrackingEnabled,
                    });
                },
            });

            // ======== 高级设置 ========
            cardContainer(container, (c) => {
                addModeSlider(
                    c,
                    '运行时',
                    [
                        { value: 'wasm' as const, label: 'WASM 物理' },
                        { value: 'js' as const, label: 'JS 调试' },
                    ],
                    getMmdRuntimeType(),
                    (v) => {
                        if (v === getMmdRuntimeType()) return;
                        (async () => {
                            const ok = await showConfirm(
                                v === 'js'
                                    ? '切换到 JS 调试模式将丢失当前场景并重新加载（无物理）。继续？'
                                    : '切换到 WASM 物理模式将丢失当前场景并重新加载。继续？'
                            );
                            if (!ok) {
                                getMotionMenu()?.updateControls();
                                return;
                            }
                            setMmdRuntimeType(v);
                            location.reload();
                        })();
                    },
                    'lucide:cpu',
                    undefined,
                    {
                        bind: () => getMmdRuntimeType(),
                    }
                );
                addModeSlider(
                    c,
                    '插值曲线',
                    [
                        { value: 'auto' as const, label: '自动' },
                        { value: 'sharp' as const, label: '锐利' },
                        { value: 'ease-in-out' as const, label: '缓入缓出' },
                        { value: 'ease-out' as const, label: '缓出' },
                    ],
                    st.interpOverride,
                    (v) => {
                        setProcMotionInterpOverride(v);
                        regenerateProcMotion();
                    },
                    'lucide:sliders',
                    undefined,
                    {
                        bind: () => getProcMotionState().interpOverride,
                    }
                );
            });
        },
    };
}

export function buildProcMotionModeLevel(): PopupLevel {
    const st = getProcMotionState();
    const modes: { mode: ProcMotionMode; label: string; icon: string }[] = [
        { mode: 'off', label: '关闭', icon: st.mode === 'off' ? 'check' : 'circle' },
        { mode: 'idle', label: '待机呼吸', icon: st.mode === 'idle' ? 'check' : 'circle' },
        {
            mode: 'autodance',
            label: '自动舞蹈',
            icon: st.mode === 'autodance' ? 'check' : 'circle',
        },
    ];
    return {
        label: '程序化动作模式',
        dir: '',
        items: modes.map((m) => ({
            kind: 'action' as const,
            label: m.label,
            icon: m.icon,
            target: `procmotion:set-mode:${m.mode}`,
        })),
    };
}

export function buildLipSyncLevel(): PopupLevel {
    const st = getLipSyncState();
    return {
        label: 'LipSync',
        dir: '',
        items: [
            {
                kind: 'action',
                label: '启用',
                icon: st.enabled ? 'check' : 'circle',
                target: 'lipsync:toggle',
                sublabel: st.enabled ? '开' : '关',
            },
        ],
        renderCustom: (container) => {
            cardContainer(container, (c) => {
                addSliderRow(
                    c,
                    '灵敏度',
                    1 - st.sensitivity,
                    0,
                    1,
                    0.05,
                    (v) => {
                        setLipSyncSensitivity(1 - v);
                    },
                    'lucide:volume-2',
                    undefined,
                    {
                        bind: () => 1 - getLipSyncState().sensitivity,
                    }
                );
                addSliderRow(
                    c,
                    '强度',
                    st.intensity,
                    0,
                    1,
                    0.05,
                    (v) => {
                        setLipSyncIntensity(v);
                    },
                    'lucide:activity',
                    undefined,
                    {
                        bind: () => getLipSyncState().intensity,
                    }
                );
            });
        },
    };
}

