// [doc:architecture] Resource Detail Helpers — 资源详情面板公共区块构建器
// 规范文档: docs/adr/adr-045-unified-loading-and-resource.md
// 职责: 抽离 actor/stage/prop 详情面板的公共区块（变换/材质/危险）
// 现状: stage/prop 详情面板改为薄壳调用本模块；model-detail 因结构差异大保持现状

import { cardContainer, setStatus, modelRegistry, propRegistry } from '../core/config';
import { slideRow, addSliderRow, addToggleRow, addModeRow, addDangerRow } from '../core/ui-helpers';
import { showConfirm } from '../core/dialog';
import {
    getModelPosition,
    setModelPosition,
    setModelScaling,
    setModelRotationY,
    setModelVisibility,
    resetModelTransform,
    removeModel,
    getModelOrbit,
    setModelOrbit,
    getModelPositionMode,
    setModelPositionMode,
} from '../scene/manager/model-ops';
import { setPropTransform, removeProp, setPropOrbit, getPropOrbit, setPropPositionMode, getPropPositionMode } from '../scene/scene';
import { buildMatRootLevel } from './model-material';
import type { SlideMenu } from './menu';
import type { ResourceKind } from '../core/load-manager';

export interface ResourceHandle {
    id: string;
    kind: ResourceKind;
    name: string;
}

/** 变换区块：可见性 + 坐标模式（笛卡尔/轨道）+ 对应滑条 + 缩放 + 旋转 Y
 *  按 kind 派发到 model-ops（actor/stage）或 prop-ops（prop）
 *  [doc:adr-049] 轨道模式以方位角/仰角/距离绕原点定位；切换模式时反推对方坐标，无跳变。 */
export function buildTransformCard(container: HTMLElement, handle: ResourceHandle): void {
    const { id, kind } = handle;
    const POSITION_MODE_OPTS = [
        { value: 'cartesian' as const, label: '笛卡尔' },
        { value: 'orbit' as const, label: '轨道' },
    ];

    // 自管理子容器：render() 仅清空本卡片内容，避免误伤同一 container 内
    // 由 buildModelLevel 先追加的折叠组/危险卡（它们共享同一 container）。
    const root = document.createElement('div');
    root.style.display = 'contents';
    container.appendChild(root);

    const render = (): void => {
        root.innerHTML = '';

        if (kind === 'actor' || kind === 'stage') {
            const inst = modelRegistry.get(id);
            if (!inst) return;
            const mode = getModelPositionMode(id);
            const scaling = inst.scaling ?? 1;
            const rotationY = inst.rotationY ?? 0;

            cardContainer(root, (c) => {
                addToggleRow(c, '可见', inst.visible ?? true, (v) => setModelVisibility(id, v), 'lucide:eye');
                addModeRow(c, '坐标模式', POSITION_MODE_OPTS, mode, (v) => {
                    setModelPositionMode(id, v as 'cartesian' | 'orbit');
                    render();
                });
                if (mode === 'orbit') {
                    const o = getModelOrbit(id) ?? { azimuth: 0, elevation: 0, distance: 10 };
                    addSliderRow(c, '方位角', o.azimuth, -180, 180, 1, () => {}, 'lucide:compass', (v) => setModelOrbit(id, v, o.elevation, o.distance));
                    addSliderRow(c, '仰角', o.elevation, -90, 90, 1, () => {}, 'lucide:arrow-up', (v) => setModelOrbit(id, o.azimuth, v, o.distance));
                    addSliderRow(c, '距离', o.distance, 0.1, 100, 0.5, () => {}, 'lucide:move', (v) => setModelOrbit(id, o.azimuth, o.elevation, v));
                } else {
                    const pos = getModelPosition(id);
                    addSliderRow(c, 'X', pos[0], -50, 50, 0.5, () => {}, 'lucide:move-horizontal', (v) => setModelPosition(id, v, pos[1], pos[2]));
                    addSliderRow(c, 'Y', pos[1], -50, 50, 0.5, () => {}, 'lucide:move-vertical', (v) => setModelPosition(id, pos[0], v, pos[2]));
                    addSliderRow(c, 'Z', pos[2], -50, 50, 0.5, () => {}, 'lucide:move', (v) => setModelPosition(id, pos[0], pos[1], v));
                }
                addSliderRow(c, '缩放', scaling, 0.1, 10, 0.1, () => {}, 'lucide:maximize', (v) => setModelScaling(id, v));
                addSliderRow(c, '旋转 Y', rotationY, -Math.PI, Math.PI, 0.05, () => {}, 'lucide:rotate-cw', (v) => setModelRotationY(id, v));
            });
            return;
        }

        if (kind === 'prop') {
            const p = propRegistry.get(id);
            if (!p) return;
            const mode = getPropPositionMode(id);

            cardContainer(root, (c) => {
                addModeRow(c, '坐标模式', POSITION_MODE_OPTS, mode, (v) => {
                    setPropPositionMode(id, v as 'cartesian' | 'orbit');
                    render();
                });
                if (mode === 'orbit') {
                    const o = getPropOrbit(id) ?? { azimuth: 0, elevation: 0, distance: 10 };
                    addSliderRow(c, '方位角', o.azimuth, -180, 180, 1, () => {}, 'lucide:compass', (v) => setPropOrbit(id, v, o.elevation, o.distance));
                    addSliderRow(c, '仰角', o.elevation, -90, 90, 1, () => {}, 'lucide:arrow-up', (v) => setPropOrbit(id, o.azimuth, v, o.distance));
                    addSliderRow(c, '距离', o.distance, 0.1, 100, 0.5, () => {}, 'lucide:move', (v) => setPropOrbit(id, o.azimuth, o.elevation, v));
                } else {
                    addSliderRow(c, '位置 X', p.position[0], -50, 50, 0.5, () => {}, 'lucide:move-horizontal', (v) => setPropTransform(id, { position: [v, p.position[1], p.position[2]] }));
                    addSliderRow(c, '位置 Y', p.position[1], -50, 50, 0.5, () => {}, 'lucide:move-vertical', (v) => setPropTransform(id, { position: [p.position[0], v, p.position[2]] }));
                    addSliderRow(c, '位置 Z', p.position[2], -50, 50, 0.5, () => {}, 'lucide:move', (v) => setPropTransform(id, { position: [p.position[0], p.position[1], v] }));
                }
                addSliderRow(c, '旋转 Y', p.rotationY, -Math.PI, Math.PI, 0.1, () => {}, 'lucide:rotate-cw', (v) => setPropTransform(id, { rotationY: v }));
                addSliderRow(c, '缩放', p.scaling, 0.1, 10, 0.1, () => {}, 'lucide:maximize', (v) => { p.scaling = v; setPropTransform(id, { scaling: v }); });
                addToggleRow(c, '可见', p.visible, (v) => { setPropTransform(id, { visible: v }); p.visible = v; });
            });
        }
    };

    render();
}

/** 材质区块：进入材质调节子层级 */
export function buildMaterialCard(
    container: HTMLElement,
    handle: ResourceHandle,
    targetStack: SlideMenu | null
): void {
    cardContainer(container, (c) => {
        slideRow(c, 'lucide:palette', '材质调节', true, () => {
            const level = buildMatRootLevel(handle.id, handle.name, targetStack);
            targetStack?.push(level);
        });
    });
}

/** 危险区块：卸载资源（带确认对话框）
 *  onRemoved 可选回调，用于卸载后弹窗导航（如 pop 到上一级） */
export function buildDangerCard(
    container: HTMLElement,
    handle: ResourceHandle,
    onRemoved?: () => void
): void {
    const { id, kind, name } = handle;
    cardContainer(container, (c) => {
        // stage/actor 提供"重置变换"
        if (kind === 'actor' || kind === 'stage') {
            slideRow(c, 'lucide:rotate-ccw', '重置变换', false, () => {
                resetModelTransform(id);
                setStatus(`✓ ${kind === 'stage' ? '舞台' : '模型'}变换已重置`, true);
                onRemoved?.();
            });
        }
        addDangerRow(c, 'lucide:trash-2', `卸载此${kind === 'prop' ? '道具' : kind === 'stage' ? '舞台' : '模型'}`, async () => {
            if (!(await showConfirm(`确定卸载${kind === 'prop' ? '道具' : kind === 'stage' ? '舞台' : '模型'}「${name}」？`))) return;
            if (kind === 'prop') {
                removeProp(id);
            } else {
                removeModel(id);
            }
            onRemoved?.();
            setStatus(`✓ 已卸载: ${name}`, true);
        });
    });
}

/** 派发到对应 registry 查 ResourceHandle（供 UI 层从 id+kind 构造 handle） */
export function getResourceHandle(id: string, kind: ResourceKind): ResourceHandle | null {
    if (kind === 'actor' || kind === 'stage') {
        const inst = modelRegistry.get(id);
        if (!inst) return null;
        return { id, kind, name: inst.name };
    }
    if (kind === 'prop') {
        const p = propRegistry.get(id);
        if (!p) return null;
        return { id, kind, name: p.name };
    }
    return null;
}

// [doc:architecture] Scene Menu — 场景弹窗（核心 + barrel export）
// 职责: MenuStack 场景弹窗路由/入口，拆分后只保留根级 + 路由 + 动作处理
// 子文件: scene-render-levels.ts
// 程序化动作/LipSync 已归位 motion-procmotion-levels.ts（动作弹窗域）
// 环境功能归位 env-menu.ts（环境弹窗域）

import {
    dom,
    closeAllOverlays,
    setStatus,
    PopupRow,
    PopupLevel,
    cardContainer,
    modelRegistry,
    focusedModelId,
    setFocusedModelId,
    uiState,
} from '../core/config';
import { registerPopupMenu } from './menu-factory';
import { createIconifyIcon } from '../core/icons';
import { slideRow } from '../core/ui-helpers';
import {
    serializeScene,
} from '../scene/scene';
import {
    SelectDir,
    SaveScreenshot,
    SaveScenePreset,
} from '../core/wails-bindings';
import { tryCatchStatus, showErrorToast } from '../core/utils';
import { focusModel } from '../scene/scene';
import { setModelFormation, getFormationLabels } from '../scene/scene';
import type { FormationType } from '../scene/scene';
import { exportSceneBundle, importSceneBundle } from '../scene/scene-bundle';

// ======== 从子文件导入 ========
import {
    buildRenderLevel, buildPostProcessLevel, buildPresetScenesLevel,
} from './scene-render-levels';
import { buildStageLevel, buildStageTransformLevel } from './scene-stage-levels';
import { buildPropLevel, buildPropDetailLevel } from './scene-prop-levels';
import {
    buildPhysicsLevel,
    buildPhysicsDebugLevel,
    buildCollisionLevel,
    buildWasmPhysicsLevel,
} from './scene-physics-levels';
import { buildClothParamsLevel } from './motion-cloth-levels';

// ======== Barrel Re-Exports ========
// 保持向后兼容——外部文件引用路径不变
export { buildRenderLevel, buildPostProcessLevel, buildPresetScenesLevel } from './scene-render-levels';
export { buildStageLevel, buildStageTransformLevel } from './scene-stage-levels';
export { buildPropLevel, buildPropDetailLevel } from './scene-prop-levels';

// ======== Scene Menu State ========

const { getMenu: getSceneMenu, refreshRoot: refreshSceneRoot, show: showSceneMenu } = registerPopupMenu({
    wrapperKey: 'scene-menu',
    popupType: 'scene',
    buildRoot: () => buildSceneRoot(),
    buildRootItems: () => buildSceneRootItems(),
    handlers: {
        onItemClick: (row) => handleSceneAction(row),
        onFolderEnter: sceneOnFolderEnter,
    },
});

export { getSceneMenu, refreshSceneRoot, showSceneMenu };

/** 安全 reRender：菜单可能正在 async 重建中（showSceneMenu 的 await 期间），此时 sceneMenu 为 null。 */
export function reRenderSceneMenu(): void {
    getSceneMenu()?.reRender();
}

function buildFormationLevel(): PopupLevel {
    const labels = getFormationLabels();
    const formations: FormationType[] = ['line', 'v-shape', 'circle', 'grid', 'diagonal', 'arc'];
    const icons: Record<FormationType, string> = {
        'line': 'lucide:minus',
        'v-shape': 'lucide:chevron-up',
        'circle': 'lucide:circle',
        'grid': 'lucide:grid-3x3',
        'diagonal': 'lucide:trending-up',
        'arc': 'lucide:arrow-up-right',
    };
    return {
        label: '队形',
        dir: '',
        items: formations.map((f) => ({
            kind: 'action' as const,
            label: labels[f],
            icon: icons[f],
            target: `formation:set:${f}`,
        })),
    };
}

function buildScreenshotLevel(): PopupLevel {
    return {
        label: '截图',
        dir: '',
        items: [
            {
                kind: 'action',
                label: '截图当前模型',
                icon: 'camera',
                target: 'screenshot:current',
                sublabel: '保存焦点模型截图',
            },
            {
                kind: 'action',
                label: '批量截图',
                icon: 'images',
                target: 'screenshot:batch',
                sublabel: '逐个模型截图到指定目录',
            },
        ],
    };
}

// ======== Scene Root ========

/** 场景弹窗根级 items 构建器——items-based，支持增量 patch */
function buildSceneRootItems(): PopupRow[] {
    const items: PopupRow[] = [];
    items.push({ kind: 'folder', label: '预设场景', icon: 'lucide:bookmark', target: 'scene:presets' });
    items.push({ kind: 'action', label: '保存场景', icon: 'lucide:save', target: 'scene:save' });
    items.push({ kind: 'divider', label: '', icon: '', target: '' });
    items.push({ kind: 'folder', label: '后处理', icon: 'lucide:sparkles', target: 'scene:render:postprocess' });
    items.push({ kind: 'folder', label: '舞台', icon: 'lucide:monitor', target: 'scene:render:stage' });
    items.push({ kind: 'folder', label: '截图', icon: 'lucide:camera', target: 'scene:screenshot' });
    items.push({ kind: 'divider', label: '', icon: '', target: '' });
    items.push({ kind: 'folder', label: '物理', icon: 'lucide:atom', target: 'scene:physics' });
    if (modelRegistry.size > 1) {
        items.push({ kind: 'folder', label: '队形', icon: 'lucide:layout-grid', target: 'scene:formation' });
    }
    return items;
}

function buildSceneRoot(): PopupLevel {
    return {
        label: '场景',
        dir: '',
        items: buildSceneRootItems(),
    };
}

// ======== onFolderEnter Router ========

function sceneOnFolderEnter(row: PopupRow): PopupLevel | null {
    switch (row.target) {
        case 'scene:presets':
            return buildPresetScenesLevel();
        case 'scene:render':
            return buildRenderLevel();
        case 'scene:screenshot':
            return buildScreenshotLevel();
        case 'scene:render:postprocess':
            return buildPostProcessLevel();
        case 'scene:render:stage':
            return buildStageLevel();
        case 'scene:render:props':
            return buildPropLevel();
        case 'scene:physics':
            return buildPhysicsLevel();
        case 'scene:formation':
            return buildFormationLevel();
        case 'physics:cloth':
            return buildClothParamsLevel();
        case 'physics:debug':
            return buildPhysicsDebugLevel();
        case 'physics:collision':
            return buildCollisionLevel();
        case 'physics:wasm':
            return buildWasmPhysicsLevel();
        default:
            return null;
    }
}

// ======== handleSceneAction ========

/** 截图当前焦点模型 */
async function screenshotCurrent(): Promise<void> {
    const id = focusedModelId;
    if (!id) { setStatus('✗ 无焦点模型', false); return; }
    const inst = modelRegistry.get(id);
    if (!inst) { setStatus('✗ 模型不存在', false); return; }
    const dir = await SelectDir();
    if (!dir) return;
    await new Promise((r) => requestAnimationFrame(r));
    await new Promise((r) => requestAnimationFrame(r));
    const fmt = uiState.screenshotFormat ?? 'image/png';
    const q = uiState.screenshotQuality ?? 0.9;
    const base64 = dom.canvas.toDataURL(fmt, q).replace(/^data:image\/\w+;base64,/, '');
    const ts = Date.now();
    const ext = fmt === 'image/jpeg' ? 'jpg' : fmt === 'image/webp' ? 'webp' : 'png';
    const filename = `${inst.name.replace(/[\\/:*?"<>|]/g, '_')}_${ts}.${ext}`;
    const r = await tryCatchStatus(async () => {
        await SaveScreenshot(dir, filename, base64);
        return true;
    }, '✗ 截图失败');
    if (r) setStatus(`✓ 截图已保存: ${filename}`, true);
}

/** 批量截图所有已加载模型 */
async function screenshotBatch(): Promise<void> {
    if (modelRegistry.size === 0) { setStatus('✗ 场景中无模型', false); return; }
    const dir = await SelectDir();
    if (!dir) return;
    let saved = 0;
    const prevFocused = focusedModelId;
    const batchOk = await tryCatchStatus(async () => {
        for (const [id, inst] of modelRegistry) {
            setFocusedModelId(id);
            focusModel(id);
            await new Promise((r) => requestAnimationFrame(r));
            await new Promise((r) => requestAnimationFrame(r));
            await new Promise((r) => requestAnimationFrame(r));
            const fmt = uiState.screenshotFormat ?? 'image/png';
            const q = uiState.screenshotQuality ?? 0.9;
            const base64 = dom.canvas.toDataURL(fmt, q).replace(/^data:image\/\w+;base64,/, '');
            const ts = Date.now();
            const ext = fmt === 'image/jpeg' ? 'jpg' : fmt === 'image/webp' ? 'webp' : 'png';
            const filename = `${inst.name.replace(/[\\/:*?"<>|]/g, '_')}_${ts}.${ext}`;
            await SaveScreenshot(dir, filename, base64);
            saved++;
            setStatus(`截图中… ${saved}/${modelRegistry.size}`, true);
        }
        if (prevFocused) { setFocusedModelId(prevFocused); focusModel(prevFocused); }
        return true;
    }, '✗ 批量截图失败');
    if (batchOk) {
        setStatus(`✓ 批量截图完成: ${saved} 张`, true);
    }
}

/** 保存场景（自动编号到预设目录） */
async function saveScene(): Promise<void> {
    const json = JSON.stringify(serializeScene(), null, 2);
    try {
        const filename = await SaveScenePreset(json);
        try {
            await navigator.clipboard.writeText(json);
            setStatus(`✓ 场景已保存: ${filename}（已复制到剪贴板）`, true);
        } catch {
            setStatus(`✓ 场景已保存: ${filename}`, true);
        }
        reRenderSceneMenu();
    } catch (err) {
        const msg = err instanceof Error ? err.message : String(err ?? 'unknown error');
        setStatus('✗ 保存失败', false);
        showErrorToast('保存场景失败', msg);
    }
}

/** 场景动作映射表——替代原 handleSceneAction 的 if 链 */
const SCENE_ACTIONS: Record<string, () => void> = {
    'screenshot:current': () => { void screenshotCurrent(); },
    'screenshot:batch': () => { void screenshotBatch(); },
    'scene:save': () => { void saveScene(); },
    'scene:export-bundle': () => { void exportSceneBundle(); },
    'scene:import-bundle': () => { void importSceneBundle(); },
    'formation:set:line': () => { setModelFormation('line'); setStatus('✓ 一字排列', true); },
    'formation:set:v-shape': () => { setModelFormation('v-shape'); setStatus('✓ V 字阵型', true); },
    'formation:set:circle': () => { setModelFormation('circle'); setStatus('✓ 圆形阵型', true); },
    'formation:set:grid': () => { setModelFormation('grid'); setStatus('✓ 网格阵型', true); },
    'formation:set:diagonal': () => { setModelFormation('diagonal'); setStatus('✓ 对角排列', true); },
    'formation:set:arc': () => { setModelFormation('arc'); setStatus('✓ 弧形排列', true); },
};

function handleSceneAction(row: PopupRow): void {
    if (row.target) {
        SCENE_ACTIONS[row.target]?.();
    }
}

// Wire up events in main.ts:243-244 — do NOT re-register here.

// [doc:architecture] Scene Physics Levels — 物理设置子页（场景弹窗域）
// 从 scene-menu.ts 引用，独立管理全局物理参数（WASM Bullet + XPBD 布料）

import type { PopupLevel, PopupRow } from '../core/config';
import { envState, focusedModelId } from '../core/config';
import { getGravityStrength, setGravityStrength } from '../scene/env/env-bridge';
import {
    modelManager,
    setModelWireframe,
    setModelBoneLinesVis,
    setModelBoneJointsVis,
} from '../scene/scene';
import {
    toggleCloth,
    getSolverSubsteps,
    setSolverSubsteps,
    getTimeScale,
    setTimeScale,
    getCollisionEnabled,
    setCollisionEnabled,
    getBodyCollisionEnabled,
    setBodyCollisionEnabled,
    getGroundCollisionEnabled,
    setGroundCollisionEnabled,
    setClothGravity,
    setDebugParticles,
    setDebugConstraints,
    setDebugColliders,
    getDebugState,
} from '../physics/cloth-manager';
import {
    getPhysicsCategories,
    isPhysicsCategoryEnabled,
    setPhysicsCategory,
    setModelPhysics,
} from '../scene/scene';
import { buildClothParamsLevel } from './motion-cloth-levels';
import { getSceneMenu, refreshSceneRoot } from './scene-menu';

/**
 * 增量更新 toggle 行的 DOM 状态（不触发 reRender）。
 * 通过 rowKey 定位行 DOM，翻转 switch 类名。
 */
function _patchToggle(target: string, newValue: boolean): void {
    const row = document.querySelector(`[data-row-key="${target}"]`) as HTMLElement | null;
    if (!row) return;
    const sw = row.querySelector('.switch');
    if (sw) {
        sw.classList.toggle('on', newValue);
        sw.classList.toggle('off', !newValue);
    }
}

/** 构建物理设置子页 */
export function buildPhysicsLevel(): PopupLevel {
    return {
        label: '物理',
        dir: '',
        items: [
            // 重力强度（统控 WASM Bullet + XPBD 布料）
            {
                kind: 'slider',
                label: '重力强度（WASM + 布料）',
                icon: 'lucide:arrow-down',
                target: 'physics:gravity',
                sliderValue: getGravityStrength(),
                sliderMin: 0,
                sliderMax: 2,
                sliderStep: 0.05,
                onSliderChange: (v: number) => {
                    setGravityStrength(v);
                    setClothGravity(v);
                },
            } as PopupRow,
            // WASM 物理（MMD Bullet 骨髁物理）— 通用物理系统，放第二
            {
                kind: 'folder',
                label: 'WASM 物理',
                icon: 'lucide:atom',
                target: 'physics:wasm',
            } as PopupRow,
            // 布料模拟：独立开关（XPBD 附加）
            {
                kind: 'toggle',
                label: '布料模拟',
                icon: 'lucide:shirt',
                target: 'physics:cloth-toggle',
                toggleValue: envState.clothEnabled,
                onToggleChange: (v: boolean) => {
                    envState.clothEnabled = v;
                    toggleCloth(v);
                    refreshSceneRoot();
                    _patchToggle('physics:cloth-toggle', v);
                },
            } as PopupRow,
            // 求解质量（原名 求解迭代）
            {
                kind: 'slider',
                label: '求解质量',
                icon: 'lucide:repeat',
                target: 'physics:substeps',
                sliderValue: getSolverSubsteps(),
                sliderMin: 1,
                sliderMax: 4,
                sliderStep: 1,
                onSliderChange: (v: number) => {
                    setSolverSubsteps(v);
                },
            } as PopupRow,
            // 模拟速度
            {
                kind: 'slider',
                label: '模拟速度',
                icon: 'lucide:clock',
                target: 'physics:timescale',
                sliderValue: getTimeScale(),
                sliderMin: 0.1,
                sliderMax: 5,
                sliderStep: 0.1,
                onSliderChange: (v: number) => {
                    setTimeScale(v);
                },
            } as PopupRow,
            // 碰撞：folder + headerToggle
            {
                kind: 'folder',
                label: '碰撞',
                icon: 'lucide:shield',
                target: 'physics:collision',
                headerToggle: {
                    value: getCollisionEnabled(),
                    onChange: (v) => {
                        setCollisionEnabled(v);
                        refreshSceneRoot();
                    },
                    bind: () => getCollisionEnabled(),
                },
            } as PopupRow,
            // 精细调节 → 布料子页
            {
                kind: 'folder',
                label: '精细调节',
                icon: 'lucide:sliders',
                target: 'physics:cloth',
            } as PopupRow,
            // 调试（材质/骨骼/XPBD 可视化）
            {
                kind: 'folder',
                label: '调试',
                icon: 'lucide:bug',
                target: 'physics:debug',
            } as PopupRow,
        ],
    };
}

/** 构建碰撞子页（地面碰撞 + 身体碰撞） */
export function buildCollisionLevel(): PopupLevel {
    return {
        label: '碰撞',
        dir: '',
        items: [
            {
                kind: 'toggle',
                label: '地面碰撞',
                icon: 'lucide:square',
                target: 'collision:ground',
                toggleValue: getGroundCollisionEnabled(),
                onToggleChange: (v: boolean) => {
                    setGroundCollisionEnabled(v);
                    refreshSceneRoot();
                    _patchToggle('collision:ground', v);
                },
            } as PopupRow,
            {
                kind: 'toggle',
                label: '身体碰撞',
                icon: 'lucide:accessibility',
                target: 'collision:body',
                toggleValue: getBodyCollisionEnabled(),
                onToggleChange: (v: boolean) => {
                    setBodyCollisionEnabled(v);
                    refreshSceneRoot();
                    _patchToggle('collision:body', v);
                },
            } as PopupRow,
        ],
    };
}

/** 构建 WASM 物理子页（Bullet 骨髁物理信息 + 总开关） */
export function buildWasmPhysicsLevel(): PopupLevel {
    const id = focusedModelId;
    const inst = id ? modelManager.get(id) : null;
    const items: PopupRow[] = [];

    if (!id || !inst) {
        items.push({
            kind: 'action' as PopupRow['kind'],
            label: '请先加载模型',
            icon: 'lucide:info',
            target: 'wasm:none',
        } as PopupRow);
        return { label: 'WASM 物理', dir: '', items };
    }

    // 模型名 + 总开关
    items.push({
        kind: 'toggle',
        label: `物理解析（${inst.name}）`,
        icon: 'lucide:atom',
        target: 'wasm:master',
        toggleValue: inst.physicsEnabled,
        onToggleChange: (v) => {
            setModelPhysics(id, v);
            _patchToggle('wasm:master', v);
        },
    } as PopupRow);

    // 物理类别列表
    const categories = getPhysicsCategories(id);
    if (categories.length === 0) {
        items.push({
            kind: 'action' as PopupRow['kind'],
            label: '该模型无物理刚体',
            icon: 'lucide:info',
            target: 'wasm:nobody',
        } as PopupRow);
        return { label: 'WASM 物理', dir: '', items };
    }

    const CAT_LABELS: Record<string, string> = {
        skirt: '裙子', chest: '胸部', hair: '头发', accessory: '配件',
    };
    const CAT_ICONS: Record<string, string> = {
        skirt: 'lucide:shirt', chest: 'lucide:heart', hair: 'lucide:person-standing', accessory: 'lucide:gem',
    };

    for (const cat of categories) {
        const enabled = isPhysicsCategoryEnabled(id, cat);
        items.push({
            kind: 'toggle',
            label: CAT_LABELS[cat] || cat,
            icon: CAT_ICONS[cat] || 'lucide:settings',
            target: `wasm:cat:${cat}`,
            toggleValue: enabled,
            onToggleChange: (v) => {
                setPhysicsCategory(id, cat, v);
                _patchToggle(`wasm:cat:${cat}`, v);
            },
        } as PopupRow);
    }

    return { label: 'WASM 物理', dir: '', items };
}

/** 构建物理调试子页（材质线框/骨骼/XPBD 可视化 toggle） */
export function buildPhysicsDebugLevel(): PopupLevel {
    const id = focusedModelId;
    const inst = id ? modelManager.get(id) : null;
    const dbg = getDebugState();

    return {
        label: '调试',
        dir: '',
        items: [
            {
                kind: 'toggle', label: '材质线框', icon: 'lucide:square',
                target: 'debug:wireframe',
                toggleValue: inst?.wireframe ?? false,
                onToggleChange: (v) => { if (id) setModelWireframe(id, v); _patchToggle('debug:wireframe', v); },
            } as PopupRow,
            {
                kind: 'toggle', label: '骨骼线', icon: 'lucide:git-branch',
                target: 'debug:bonelines',
                toggleValue: inst?.showBoneLines ?? false,
                onToggleChange: (v) => { if (id) setModelBoneLinesVis(id, v); _patchToggle('debug:bonelines', v); },
            } as PopupRow,
            {
                kind: 'toggle', label: '骨骼关节球', icon: 'lucide:circle-dot',
                target: 'debug:bonejoints',
                toggleValue: inst?.showBoneJoints ?? false,
                onToggleChange: (v) => { if (id) setModelBoneJointsVis(id, v); _patchToggle('debug:bonejoints', v); },
            } as PopupRow,
            {
                kind: 'toggle', label: '粒子球', icon: 'lucide:circle',
                target: 'debug:particles',
                toggleValue: dbg.particles,
                onToggleChange: (v) => { setDebugParticles(v); _patchToggle('debug:particles', v); },
            } as PopupRow,
            {
                kind: 'toggle', label: '约束线', icon: 'lucide:minus',
                target: 'debug:constraints',
                toggleValue: dbg.constraints,
                onToggleChange: (v) => { setDebugConstraints(v); _patchToggle('debug:constraints', v); },
            } as PopupRow,
            {
                kind: 'toggle', label: '碰撞体线框', icon: 'lucide:box',
                target: 'debug:colliders',
                toggleValue: dbg.colliders,
                onToggleChange: (v) => { setDebugColliders(v); _patchToggle('debug:colliders', v); },
            } as PopupRow,
        ],
    };
}

// [doc:architecture] Scene Prop Levels — 舞台道具弹窗层级
// 从 env-prop-levels.ts 迁移至舞台域

import { cardContainer, escapeHtml, propRegistry } from '../core/config';
import type { PopupLevel } from '../core/config';
import { slideRow } from '../core/ui-helpers';
import { loadManager } from '../core/load-manager';
import { removeProp, getPropList } from '../scene/scene';
import { SelectPMXFile } from '../core/wails-bindings';
import { getSceneMenu } from './scene-menu';
import { buildTransformCard, buildMaterialCard, buildDangerCard } from './resource-detail-helpers';

export function buildPropLevel(): PopupLevel {
    return {
        label: '道具',
        dir: '',
        items: [],
        renderCustom: (container) => {
            container.classList.remove('render-card');
            container.style.padding = '0';

            // —— 卡片 1：已加载道具列表（上）——
            const props = getPropList();
            if (props.length > 0) {
                cardContainer(container, (c) => {
                    for (const p of props) {
                        const row = document.createElement('div');
                        row.className = 'slide-item';
                        row.innerHTML = `<span class="slide-icon"><iconify-icon icon="lucide:box"></iconify-icon></span><span class="slide-label">${escapeHtml(p.name)}</span><span class="slide-arrow">&gt;</span>`;
                        row.addEventListener('click', () => getSceneMenu()?.push(buildPropDetailLevel(p.id)));
                        const delBtn = document.createElement('span');
                        delBtn.className = 'slide-del-btn';
                        delBtn.textContent = '×';
                        delBtn.title = '删除道具';
                        delBtn.addEventListener('click', (e) => {
                            e.stopPropagation();
                            removeProp(p.id);
                            getSceneMenu()?.reRender();
                        });
                        row.appendChild(delBtn);
                        c.appendChild(row);
                    }
                });
            } else {
                cardContainer(container, (c) => {
                    const empty = document.createElement('div');
                    empty.style.cssText = 'font-size:11px;color:var(--text-dim);padding:8px 4px;text-align:center;';
                    empty.textContent = '暂无道具';
                    c.appendChild(empty);
                });
            }

            // —— 卡片 2：加载入口（下）——
            cardContainer(container, (c) => {
                slideRow(c, 'lucide:plus', '添加道具文件', false, () => {
                    SelectPMXFile().then((path) => {
                        if (path) {
                            loadManager.load({ kind: 'prop', path }).then(() => getSceneMenu()?.reRender()).catch(() => {});
                        }
                    });
                });
            });
        },
    };
}

export function buildPropDetailLevel(propId: string): PopupLevel {
    return {
        label: '道具变换',
        dir: '',
        items: [],
        renderCustom: (container) => {
            const p = propRegistry.get(propId);
            if (!p) {
                const empty = document.createElement('div');
                empty.style.cssText = 'font-size:11px;color:var(--text-dim);padding:8px 4px;';
                empty.textContent = '道具不存在（可能已被删除）';
                container.appendChild(empty);
                return;
            }
            const sm = getSceneMenu();
            const handle = { id: propId, kind: 'prop' as const, name: p.name };

            // —— 标题 + 变换 ——
            cardContainer(container, (c) => {
                const title = document.createElement('div');
                title.style.cssText = 'font-size:12px;color:var(--text);padding:8px 14px 4px;font-weight:600;';
                title.textContent = p.name;
                c.appendChild(title);
            });
            buildTransformCard(container, handle);

            // —— 材质调节 ——
            buildMaterialCard(container, handle, sm);

            // —— 危险操作 ——
            buildDangerCard(container, handle, () => {
                const menu = getSceneMenu();
                if (menu) { menu.pop(); menu.reRender(); }
            });
        },
    };
}

