// [doc:architecture] Scene Render Levels — 渲染/后处理/预设场景弹窗层级
// 从 scene-render-levels.ts 拆分
// 子文件: scene-stage-lights.ts, scene-stage-levels.ts, scene-render-presets.ts

import { setStatus, cardContainer } from '../core/config';
import type { PopupLevel } from '../core/config';
import type { RenderState } from '../scene/scene';
import { createIconifyIcon } from '../core/icons';
import { showConfirm } from '../core/dialog';
import { tryCatchStatus } from '../core/utils';
import {
    addSliderRow,
    addToggleRow,
    addModeSlider,
    addCollapsible,
    sliderRow,
    slideRow,
    addPresetChip,
} from '../core/ui-helpers';
import { exportSceneBundle, importSceneBundle } from '../scene/scene-bundle';
import {
    triggerAutoSave,
    deserializeScene,
    getRenderState,
    setRenderState,
    transitionRenderState,
    defaultRenderState,
} from '../scene/scene';
import {
    GetPresetScenes,
    GetPresetScenesDir,
    DeletePresetScene,
    LoadSceneFile,
} from '../core/wails-bindings';
import { reRenderSceneMenu } from './scene-menu';
import { FILTER_PRESET_LABELS, getFilterPreset } from './scene-render-presets';

// ======== Scene Preset ========

let currentPresetIndex = -1;
let _presetScenes: string[] = [];

async function _loadPresetScene(name: string): Promise<boolean> {
    const r = await tryCatchStatus(async () => {
        const dir = await GetPresetScenesDir();
        const json = await LoadSceneFile(dir + '/' + name);
        await deserializeScene(JSON.parse(json));
        return true;
    }, '✗ 加载预设场景失败');
    if (r) return true;
    return false;
}

export function buildPresetScenesLevel(): PopupLevel {
    return {
        label: '预设场景',
        dir: '',
        items: [],
        renderCustom: async (container) => {
            container.classList.remove('render-card');

            // 导出/导入场景包 action
            const bundleActions = document.createElement('div');
            bundleActions.className = 'lcard';
            slideRow(bundleActions, 'lucide:package-export', '导出场景包', false, () => { void exportSceneBundle(); });
            slideRow(bundleActions, 'lucide:package-import', '导入场景包', false, () => { void importSceneBundle(); });
            const bundleDivider = document.createElement('div');
            bundleDivider.className = 'slide-divider';
            container.appendChild(bundleActions);
            container.appendChild(bundleDivider);

            const loading = document.createElement('div');
            loading.style.cssText = 'font-size:12px;color:#fff;text-align:center;padding:24px;';
            loading.textContent = '加载中…';
            container.appendChild(loading);
            currentPresetIndex = -1;
            _presetScenes = (await GetPresetScenes()) || [];
            container.innerHTML = '';
            const scenes = _presetScenes;

            // 快速渲染滤镜芯片组
            cardContainer(container, (c) => {
                const chipGroup = document.createElement('div');
                chipGroup.className = 'preset-group';
                chipGroup.style.paddingBottom = '6px';
                for (const [key, label] of Object.entries(FILTER_PRESET_LABELS)) {
                    addPresetChip(chipGroup, label, false, () => {
                        const preset = getFilterPreset(key);
                        if (preset) transitionRenderState({ ...defaultRenderState(), ...preset }, 2000);
                        setStatus(`✓ 滤镜: ${label}`, true);
                    });
                }
                c.appendChild(chipGroup);
            });

            if (scenes.length === 0) {
                const empty = document.createElement('div');
                empty.style.cssText = 'font-size:12px;color:#fff;text-align:center;padding:24px;';
                empty.textContent = '暂无预设场景，保存场景时自动生成';
                container.appendChild(empty);
                return;
            }

            cardContainer(container, (c) => {
                for (let i = 0; i < scenes.length; i++) {
                    const name = scenes[i];
                    const isActive = i === currentPresetIndex;
                    const row = document.createElement('div');
                    row.className = 'slide-item';
                    const is = document.createElement('span');
                    is.className = 'slide-icon';
                    const ie = createIconifyIcon(isActive ? 'lucide:play-circle' : 'lucide:bookmark');
                    if (ie) is.appendChild(ie);
                    row.appendChild(is);
                    const ls = document.createElement('span');
                    ls.className = 'slide-label';
                    ls.textContent = name;
                    row.appendChild(ls);
                    const delBtn = document.createElement('span');
                    delBtn.textContent = '✕';
                    delBtn.title = '删除此预设场景';
                    delBtn.style.cssText = 'font-size:10px;color:var(--text-dim);cursor:pointer;padding:2px 4px;';
                    delBtn.addEventListener('click', async (e) => {
                        e.stopPropagation();
                        if (!(await showConfirm(`确定删除「${name}」？`))) return;
                        const r = await tryCatchStatus(async () => {
                            await DeletePresetScene(name);
                            return true;
                        }, '✗ 删除失败');
                        if (r) {
                            if (currentPresetIndex === i) currentPresetIndex = -1;
                            else if (currentPresetIndex > i) currentPresetIndex--;
                            reRenderSceneMenu();
                            setStatus(`✓ 已删除: ${name}`, true);
                        }
                    });
                    row.appendChild(delBtn);
                    row.addEventListener('click', async () => {
                        currentPresetIndex = i;
                        if (await _loadPresetScene(name)) {
                            reRenderSceneMenu();
                            setStatus(`✓ 已加载: ${name}`, true);
                        }
                    });
                    c.appendChild(row);
                }
            });
        },
    };
}



// ======== Render Menu Levels ========

export function buildRenderLevel(): PopupLevel {
    return {
        label: '渲染',
        dir: '',
        items: [
            { kind: 'folder', label: '后处理', icon: 'sparkles', target: 'scene:render:postprocess' },
            { kind: 'folder', label: '舞台', icon: 'monitor', target: 'scene:render:stage' },
            { kind: 'folder', label: '渲染预设', icon: 'palette', target: 'scene:render:presets' },
        ],
    };
}

export function buildPostProcessLevel(): PopupLevel {
    return {
        label: '后处理',
        dir: '',
        items: [],
        renderCustom: (container) => {
            const state = getRenderState();
            cardContainer(container, (c) => {
                addCollapsible(c, {
                    title: '泛光',
                    icon: 'lucide:sun',
                    defaultOpen: false,
                    headerToggle: {
                        value: state.bloomEnabled,
                        onChange: (v) => {
                            setRenderState({ bloomEnabled: v });
                            triggerAutoSave();
                        },
                        bind: () => getRenderState().bloomEnabled,
                    },
                    renderContent: (inner) => {
                        sliderRow(inner, '强度', state.bloomWeight, 0, 1, 0.05, 'lucide:sun',
                            (v) => { setRenderState({ bloomWeight: v }); triggerAutoSave(); });
                        sliderRow(inner, '阈值', state.bloomThreshold, 0, 1, 0.05, 'lucide:sliders',
                            (v) => { setRenderState({ bloomThreshold: v }); triggerAutoSave(); });
                        sliderRow(inner, '核大小', state.bloomKernel, 16, 256, 2, 'lucide:circle',
                            (v) => { setRenderState({ bloomKernel: v }); triggerAutoSave(); });
                    },
                });

                addToggleRow(c, '边缘高亮', state.outlineEnabled, (v) => {
                    setRenderState({ outlineEnabled: v });
                    triggerAutoSave();
                }, 'lucide:square', {
                    bind: () => getRenderState().outlineEnabled,
                });

                addModeSlider(c, '抗锯齿', [
                    { value: 'off', label: '关闭' },
                    { value: 'fxaa', label: 'FXAA' },
                    { value: '2x', label: '2x' },
                    { value: '4x', label: '4x' },
                    { value: '8x', label: '8x' },
                ], state.msaaSamples > 1 ? `${state.msaaSamples}x` : state.fxaaEnabled ? 'fxaa' : 'off',
                (v) => {
                    const updates: Partial<RenderState> = {};
                    if (v === 'off') { updates.fxaaEnabled = false; updates.msaaSamples = 1; }
                    else if (v === 'fxaa') { updates.fxaaEnabled = true; updates.msaaSamples = 1; }
                    else { updates.fxaaEnabled = false; updates.msaaSamples = parseInt(v); }
                    setRenderState(updates);
                    triggerAutoSave();
                }, 'lucide:scan-line', undefined, {
                    bind: () => {
                        const s = getRenderState();
                        return s.msaaSamples > 1 ? `${s.msaaSamples}x` : s.fxaaEnabled ? 'fxaa' : 'off';
                    },
                });

                sliderRow(c, '景深', state.dofAperture, 0, 1, 0.05, 'lucide:camera',
                    (v) => { setRenderState({ dofEnabled: v > 0, dofAperture: v }); triggerAutoSave(); });
                sliderRow(c, '暗角', state.vignetteDarkness, 0, 1, 0.05, 'lucide:circle-dot',
                    (v) => { setRenderState({ vignetteEnabled: v > 0, vignetteDarkness: v }); triggerAutoSave(); });
                sliderRow(c, '色差', state.chromaticAberrationAmount, 0, 1, 0.05, 'lucide:rainbow',
                    (v) => { setRenderState({ chromaticAberrationEnabled: v > 0, chromaticAberrationAmount: v }); triggerAutoSave(); });
                sliderRow(c, '颗粒', state.grainIntensity, 0, 1, 0.05, 'lucide:grid-3x3',
                    (v) => { setRenderState({ grainEnabled: v > 0, grainIntensity: v }); triggerAutoSave(); });
                sliderRow(c, '锐化', state.sharpenAmount, 0, 1, 0.05, 'lucide:focus',
                    (v) => { setRenderState({ sharpenAmount: v }); triggerAutoSave(); });
                sliderRow(c, '辉光', state.glowIntensity, 0, 1, 0.05, 'lucide:sparkles',
                    (v) => { setRenderState({ glowEnabled: v > 0, glowIntensity: v }); triggerAutoSave(); });
                // SSR — 屏幕空间反射
                addToggleRow(c, '屏幕空间反射', state.ssrEnabled,
                    (v) => { setRenderState({ ssrEnabled: v }); triggerAutoSave(); reRenderSceneMenu(); }, 'lucide:reflect', {
                    bind: () => getRenderState().ssrEnabled,
                });
                if (state.ssrEnabled) {
                    sliderRow(c, '反射强度', state.ssrStrength, 0, 1, 0.05, 'lucide:opacity',
                        (v) => { setRenderState({ ssrStrength: v }); triggerAutoSave(); });
                    sliderRow(c, '边缘衰减', state.ssrFalloff, 0, 1, 0.05, 'lucide:border',
                        (v) => { setRenderState({ ssrFalloff: v }); triggerAutoSave(); });
                    sliderRow(c, '步长', state.ssrStep, 1, 32, 1, 'lucide:ruler',
                        (v) => { setRenderState({ ssrStep: v }); triggerAutoSave(); });
                    sliderRow(c, '厚度容差', state.ssrThickness, 0, 2, 0.1, 'lucide:layers',
                        (v) => { setRenderState({ ssrThickness: v }); triggerAutoSave(); });
                }
                // Reflection Probe — 环境反射探针
                addToggleRow(c, '环境反射', state.reflectionProbeEnabled,
                    (v) => { setRenderState({ reflectionProbeEnabled: v, reflectionIntensity: v ? 1 : 0 }); triggerAutoSave(); }, 'lucide:scan', {
                    bind: () => getRenderState().reflectionProbeEnabled,
                });
                // SSAO — 屏幕空间环境遮蔽
                addToggleRow(c, '环境遮蔽 (SSAO)', state.ssaoEnabled,
                    (v) => { setRenderState({ ssaoEnabled: v }); triggerAutoSave(); reRenderSceneMenu(); }, 'lucide:shadow', {
                    bind: () => getRenderState().ssaoEnabled,
                });
                if (state.ssaoEnabled) {
                    sliderRow(c, '遮蔽强度', state.ssaoStrength, 0, 1, 0.05, 'lucide:circle-half',
                        (v) => { setRenderState({ ssaoStrength: v }); triggerAutoSave(); });
                    sliderRow(c, '遮蔽半径', state.ssaoRadius, 0, 1, 0.05, 'lucide:circle-dot',
                        (v) => { setRenderState({ ssaoRadius: v }); triggerAutoSave(); });
                    sliderRow(c, '采样数', state.ssaoSamples, 4, 32, 1, 'lucide:grid-3x3',
                        (v) => { setRenderState({ ssaoSamples: v }); triggerAutoSave(); });
                }
            });

            // 色调映射 — 后处理色彩环节，影响整体画面风格
            cardContainer(container, (c) => {
                addCollapsible(c, {
                    title: '色调映射',
                    icon: 'lucide:palette',
                    defaultOpen: false,
                    renderContent: (inner) => {
                        addModeSlider(inner, '模式', [
                            { value: 0, label: '关闭' },
                            { value: 1, label: 'ACES' },
                            { value: 2, label: 'Reinhard' },
                            { value: 3, label: 'Cineon' },
                            { value: 4, label: 'Neutral' },
                        ], state.toneMapping, (v) => {
                            setRenderState({ toneMapping: v });
                            triggerAutoSave();
                        }, 'lucide:palette', undefined, {
                            bind: () => getRenderState().toneMapping,
                        });
                        addSliderRow(inner, '曝光', state.exposure, 0, 4, 0.05, () => {}, 'lucide:lightbulb',
                            (v) => { setRenderState({ exposure: v }); triggerAutoSave(); }, {
                            bind: () => getRenderState().exposure,
                        });
                        addSliderRow(inner, '对比度', state.contrast, 0, 4, 0.05, () => {}, 'lucide:contrast',
                            (v) => { setRenderState({ contrast: v }); triggerAutoSave(); }, {
                            bind: () => getRenderState().contrast,
                        });
                    },
                });
            });
        },
    };
}

// [doc:architecture] Scene Render Presets — 渲染预设弹窗层级
// 从 scene-render-levels.ts 拆分

import { setStatus } from '../core/config';
import type { PopupLevel } from '../core/config';
import type { RenderState } from '../scene/scene';
import { showPrompt } from '../core/dialog';
import { tryCatchStatus, showErrorToast } from '../core/utils';
import {
    slideRow,
} from '../core/ui-helpers';
import {
    getRenderState,
    setRenderState,
    transitionRenderState,
    defaultRenderState,
} from '../scene/scene';
import {
    GetRenderPresets,
    SaveRenderPreset,
} from '../core/wails-bindings';
import { reRenderSceneMenu, getSceneMenu } from './scene-menu';

// ======== Render Presets ========

//
// 内置渲染预设 — 6 套，各有独立色调映射模式 + 匹配曝光/后处理
//
// 设计原则：
//   - 曝光 ≥1.5 将亮度推入 HDR 域，使不同 tone mapping 曲线的高光压缩差异可见
//   - 开启 Bloom → 产生 HDR 高亮像素 → tone mapping 的高光滚降特性充分展示
//   - 每套预设锁定一个色调映射模式，配合互补后处理形成鲜明视觉风格
//
const FILTER_PRESETS: Record<string, Partial<RenderState>> = {
    // --- reference：Standard 色调映射，保守曝光作为基准 ---
    standard: {
        bloomEnabled: true, bloomWeight: 0.3, bloomThreshold: 0.6, bloomKernel: 64,
        fxaaEnabled: true, outlineEnabled: false,
        toneMapping: 0, exposure: 1.0, contrast: 1.0,
    },
    // --- ACES 电影曲线 — 自然高光滚降，暗角增加电影感 ---
    cinematic: {
        bloomEnabled: true, bloomWeight: 0.4, bloomThreshold: 0.5, bloomKernel: 64,
        fxaaEnabled: true, outlineEnabled: false,
        toneMapping: 1, exposure: 2.0, contrast: 1.2,
        vignetteEnabled: true, vignetteDarkness: 0.35,
        ssrEnabled: true, ssrStrength: 0.5, ssrFalloff: 0.3,
        reflectionProbeEnabled: true, reflectionIntensity: 0.8,
        ssaoEnabled: true, ssaoStrength: 0.6, ssaoRadius: 0.5,
    },
    // --- Reinhard — 高饱和·高对比·边缘线框 = 卡通风格 ---
    cartoon: {
        bloomEnabled: true, bloomWeight: 0.5, bloomThreshold: 0.3, bloomKernel: 128,
        fxaaEnabled: true, outlineEnabled: true, outlineColor: [0, 0, 0],
        toneMapping: 2, exposure: 2.0, contrast: 1.5,
    },
    // --- ACES + 景深/暗角 — 浅景深电影写实 ---
    realistic: {
        bloomEnabled: true, bloomWeight: 0.25, bloomThreshold: 0.7, bloomKernel: 64,
        fxaaEnabled: true, outlineEnabled: false,
        toneMapping: 1, exposure: 1.5, contrast: 1.15,
        vignetteEnabled: true, vignetteDarkness: 0.5,
        dofEnabled: true, dofAperture: 0.15,
        ssrEnabled: true, ssrStrength: 0.3, ssrFalloff: 0.2,
        reflectionProbeEnabled: true, reflectionIntensity: 0.6,
        ssaoEnabled: true, ssaoStrength: 0.5, ssaoRadius: 0.4,
    },
    // --- Cineon 胶片曲线 + 暖色调背景 ---
    warm: {
        bloomEnabled: true, bloomWeight: 0.45, bloomThreshold: 0.4, bloomKernel: 96,
        fxaaEnabled: true, outlineEnabled: false,
        toneMapping: 3, exposure: 2.2, contrast: 1.3,
        reflectionProbeEnabled: true, reflectionIntensity: 0.5,
    },
    // --- Neutral + 极端后处理 — 赛博朋克风格 ---
    cyberpunk: {
        bloomEnabled: true, bloomWeight: 0.7, bloomThreshold: 0.2, bloomKernel: 192,
        fxaaEnabled: true, outlineEnabled: true, outlineColor: [1, 0, 1],
        toneMapping: 4, exposure: 3.0, contrast: 1.6,
        vignetteEnabled: true, vignetteDarkness: 0.6,
        chromaticAberrationEnabled: true, chromaticAberrationAmount: 0.3,
        grainEnabled: true, grainIntensity: 0.4,
        ssrEnabled: true, ssrStrength: 0.4, ssrFalloff: 0.15,
        reflectionProbeEnabled: true, reflectionIntensity: 0.9,
        ssaoEnabled: true, ssaoStrength: 0.7, ssaoRadius: 0.6,
    },
};

export const FILTER_PRESET_LABELS: Record<string, string> = {
    standard: '标准', cinematic: '电影', cartoon: '卡通',
    realistic: '写实', warm: '暖光', cyberpunk: '赛博朋克',
};

const FILTER_PRESET_DESCS: Record<string, string> = {
    standard: 'Standard 色调映射 · 基准参考',
    cinematic: 'ACES 色调映射 · 电影胶片曲线 · 自然高光滚降',
    cartoon: 'Reinhard 色调映射 · 高饱和高对比 · 黑色线框',
    realistic: 'ACES 色调映射 · 浅景深 · 电影暗角',
    warm: 'Cineon 色调映射 · 暖色背景 · 胶片感',
    cyberpunk: 'Neutral 色调映射 · 高光溢出 · 极端后处理',
};

export function getFilterPreset(name: string): Partial<RenderState> | undefined {
    return FILTER_PRESETS[name];
}

export function getFilterPresetName(name: string): string {
    return FILTER_PRESET_LABELS[name] || name;
}

export function buildPresetsLevel(): PopupLevel {
    return {
        label: '渲染预设',
        dir: '',
        items: [],
        renderCustom: (container) => {
            container.classList.remove('render-card');
            const chipGroup = document.createElement('div');
            chipGroup.className = 'preset-group';
            chipGroup.style.paddingBottom = '6px';
            for (const [key] of Object.entries(FILTER_PRESETS)) {
                const wrapper = document.createElement('div');
                wrapper.style.cssText = 'display:flex;flex-direction:column;align-items:center;gap:2px;';

                const btn = document.createElement('button');
                btn.className = 'preset-chip';
                btn.textContent = FILTER_PRESET_LABELS[key] || key;
                btn.addEventListener('click', () => {
                    const preset = getFilterPreset(key);
                    if (preset) transitionRenderState({ ...defaultRenderState(), ...preset }, 2000);
                    setStatus(`✓ 预设: ${FILTER_PRESET_LABELS[key]}`, true);
                });
                wrapper.appendChild(btn);

                const desc = document.createElement('span');
                desc.textContent = FILTER_PRESET_DESCS[key] || '';
                desc.style.cssText = 'font-size:9px;color:var(--text-dim);opacity:0.7;white-space:nowrap;line-height:1.2;';
                wrapper.appendChild(desc);

                chipGroup.appendChild(wrapper);
            }
            container.appendChild(chipGroup);
            slideRow(container, 'lucide:save', '保存当前为预设', false, showPresetSaveDialog);
            if (Object.keys(USER_FILTER_PRESETS).length > 0) {
                const userChipGroup = document.createElement('div');
                userChipGroup.className = 'preset-group';
                userChipGroup.style.paddingBottom = '6px';
                for (const [name] of Object.entries(USER_FILTER_PRESETS)) {
                    const btn = document.createElement('button');
                    btn.className = 'preset-chip';
                    btn.textContent = name;
                    btn.addEventListener('click', () => {
                        setRenderState(USER_FILTER_PRESETS[name]);
                        setStatus(`✓ 预设: ${name}`, true);
                    });
                    userChipGroup.appendChild(btn);
                }
                container.appendChild(userChipGroup);
            }
        },
    };
}

export async function showPresetSaveDialog(): Promise<void> {
    const name = await showPrompt('输入预设名称：');
    if (!name || !name.trim()) return;
    const trimmed = name.trim();
    const state = getRenderState();
    const r = await tryCatchStatus(async () => {
        await SaveRenderPreset(trimmed, JSON.stringify(state));
        return true;
    }, '✗ 保存预设失败', (err) => showErrorToast('保存渲染预设失败', err instanceof Error ? err.message : String(err)));
    if (r) {
        USER_FILTER_PRESETS[trimmed] = state;
        setStatus(`✓ 预设已保存: ${trimmed}`, true);
        const menu = getSceneMenu();
        if (menu) {
            menu.setLevel(menu.levelCount - 1, buildPresetsLevel());
            reRenderSceneMenu();
        }
    }
}

export const USER_FILTER_PRESETS: Record<string, Partial<RenderState>> = {};

let _presetsLoaded = false;

export async function loadUserPresets(): Promise<void> {
    if (_presetsLoaded) return;
    _presetsLoaded = true;
    try {
        const presets = await GetRenderPresets();
        if (presets) {
            for (const p of presets) {
                USER_FILTER_PRESETS[p.name] = p.params as unknown as Partial<RenderState>;
            }
        }
    } catch (err) {
        console.warn('loadUserPresets:', err);
    }
}

// [doc:architecture] Scene Stage Levels — 舞台管理/舞台变换弹窗层级
// 从 scene-render-levels.ts 拆分

import { setStatus, cardContainer, modelRegistry, overridePaths, libraryRoot, escapeHtml, propRegistry } from '../core/config';
import type { PopupLevel } from '../core/config';
import { createIconifyIcon } from '../core/icons';
import { showConfirm } from '../core/dialog';
import {
    slideRow,
    addSectionTitle,
} from '../core/ui-helpers';
import {
    removeModel,
    setModelVisibility,
} from '../scene/manager/model-ops';
import { loadManager } from '../core/load-manager';
import { getPropList, removeProp, modelManager } from '../scene/scene';
import { reRenderSceneMenu, getSceneMenu } from './scene-menu';
import { buildStageLightLevel } from './scene-stage-lights';
import { buildTransformCard, buildMaterialCard, buildDangerCard } from './resource-detail-helpers';

import { buildPropDetailLevel } from './scene-prop-levels';

// ======== 舞台根面板：舞台加载、灯光、道具 ========

export function buildStageLevel(): PopupLevel {
    return {
        label: '舞台',
        dir: '',
        items: [],
        renderCustom: (container) => {
            container.classList.remove('render-card');

            // —— 卡片 1：已加载舞台列表（上）——
            const stageModels = Array.from(modelRegistry.entries())
                .filter(([, inst]) => inst.kind === 'stage');

            if (stageModels.length > 0) {
                cardContainer(container, (c) => {
                    addSectionTitle(c, '已加载舞台');

                    for (const [id, inst] of stageModels) {
                        const row = document.createElement('div');
                        row.className = 'slide-item';
                        row.style.cursor = 'pointer';

                        // 眼睛 toggle
                        const eyeSpan = document.createElement('span');
                        eyeSpan.className = 'slide-icon';
                        const eyeIcon = createIconifyIcon(
                            inst.visible ? 'lucide:eye' : 'lucide:eye-off'
                        );
                        if (eyeIcon) eyeSpan.appendChild(eyeIcon);
                        eyeSpan.style.cursor = 'pointer';
                        eyeSpan.addEventListener('click', (e) => {
                            e.stopPropagation();
                            const newVis = !inst.visible;
                            setModelVisibility(id, newVis);
                            reRenderSceneMenu();
                            setStatus(newVis ? '✓ 舞台已显示' : '✓ 舞台已隐藏', true);
                        });
                        row.appendChild(eyeSpan);

                        // 名称
                        const label = document.createElement('span');
                        label.className = 'slide-label';
                        label.textContent = inst.name;
                        row.appendChild(label);

                        // 箭头
                        const arrow = document.createElement('span');
                        arrow.className = 'slide-arrow';
                        arrow.textContent = '>';
                        row.appendChild(arrow);

                        // 删除按钮
                        const del = document.createElement('span');
                        del.textContent = '✕';
                        del.style.cssText = 'font-size:10px;color:var(--text-dim);cursor:pointer;padding:2px 4px;margin-left:4px;';
                        del.title = '卸载此舞台';
                        del.addEventListener('click', async (e) => {
                            e.stopPropagation();
                            if (!(await showConfirm(`确定卸载舞台「${inst.name}」？`))) return;
                            removeModel(id);
                            reRenderSceneMenu();
                            setStatus(`✓ 已卸载: ${inst.name}`, true);
                        });
                        row.appendChild(del);

                        // 点击进入变换面板
                        row.addEventListener('click', () => {
                            const sm = getSceneMenu();
                            if (sm) sm.push(buildStageTransformLevel(id));
                        });

                        c.appendChild(row);
                    }
                });
            } else {
                cardContainer(container, (c) => {
                    const empty = document.createElement('div');
                    empty.style.cssText = 'font-size:11px;color:var(--text-dim);text-align:center;padding:8px 0;';
                    empty.textContent = '暂无已加载舞台';
                    c.appendChild(empty);
                });
            }

            // —— 卡片 2：已加载道具列表（始终显示） ——
            {
                // 合并 propRegistry + modelRegistry 中 prop 目录下的模型
                const propDir = (overridePaths.prop || (libraryRoot ? libraryRoot + '/prop' : '')).toLowerCase();
                const propModels = Array.from(modelManager.modelRegistry.entries())
                    .filter(([, inst]) => inst.kind === 'actor' && propDir && inst.filePath.toLowerCase().startsWith(propDir));
                const propItems = [
                    ...getPropList().map(p => ({ id: p.id, name: p.name, fromPropRegistry: true })),
                    ...propModels.map(([id, inst]) => ({ id, name: inst.name, fromPropRegistry: false })),
                ];
                cardContainer(container, (c) => {
                    if (propItems.length > 0) {
                        for (const item of propItems) {
                            const row = document.createElement('div');
                            row.className = 'slide-item';
                            row.style.cursor = 'pointer';
                            row.innerHTML = `<span class="slide-icon"><iconify-icon icon="lucide:box"></iconify-icon></span><span class="slide-label">${escapeHtml(item.name)}</span><span class="slide-arrow">&gt;</span>`;
                            row.addEventListener('click', () => getSceneMenu()?.push(buildPropDetailLevel(item.id)));
                            const delBtn = document.createElement('span');
                            delBtn.className = 'slide-del-btn';
                            delBtn.textContent = '×';
                            delBtn.title = '删除道具';
                            delBtn.addEventListener('click', (e) => {
                                e.stopPropagation();
                                if (item.fromPropRegistry) {
                                    removeProp(item.id);
                                } else {
                                    removeModel(item.id);
                                }
                                reRenderSceneMenu();
                            });
                            row.appendChild(delBtn);
                            c.appendChild(row);
                        }
                    } else {
                        const empty = document.createElement('div');
                        empty.style.cssText = 'font-size:11px;color:var(--text-dim);text-align:center;padding:8px 0;';
                        empty.textContent = '暂无道具';
                        c.appendChild(empty);
                    }
                });
            }

            // —— 卡片 3：功能入口（下）——
            cardContainer(container, (c) => {
                slideRow(c, 'lucide:upload', '加载舞台', true, () => {
                    (async () => {
                        try {
                            const { getBrowseDir } = await import('../core/utils');
                            const browseDir = getBrowseDir('stage');
                            if (!browseDir) {
                                setStatus('✗ 请先在设置中配置模型库目录', false);
                                return;
                            }
                            const { buildLevel } = await import('./library-core');
                            const sm = getSceneMenu();
                            if (!sm) return;
                            const level = buildLevel(
                                browseDir,
                                '舞台',
                                (m) => m.type === 'stage' || m.type === 'scene',
                                sm
                            );
                            sm.push(level);
                        } catch (err) {
                            setStatus('✗ 打开舞台库失败', false);
                            console.error('Stage library error:', err);
                        }
                    })();
                });
                slideRow(c, 'lucide:lightbulb', '舞台灯光', true, () => {
                    const sm = getSceneMenu();
                    if (sm) sm.push(buildStageLightLevel());
                });
                slideRow(c, 'lucide:box', '加载道具', true, () => {
                    (async () => {
                        try {
                            const { getBrowseDir } = await import('../core/utils');
                            const browseDir = getBrowseDir('prop');
                            if (!browseDir) {
                                setStatus('✗ 请先在设置中配置道具库目录', false);
                                return;
                            }
                            const { buildLevel } = await import('./library-core');
                            const sm = getSceneMenu();
                            if (!sm) return;
                            const level = buildLevel(
                                browseDir,
                                '道具库',
                                (m) => m.format === 'pmx',
                                sm
                            );
                            sm.push(level);
                        } catch (err) {
                            setStatus('✗ 打开道具库失败', false);
                            console.error('Prop library error:', err);
                        }
                    })();
                });
            });
        },
    };
}

// ======== Stage Transform Panel ========

export function buildStageTransformLevel(id: string): PopupLevel {
    const inst = modelRegistry.get(id);
    const name = inst?.name ?? id;

    return {
        label: `舞台: ${name}`,
        dir: '',
        items: [],
        renderCustom: (container) => {
            const sm = getSceneMenu();
            const handle = { id, kind: 'stage' as const, name };

            // —— 变换 + 可见性 ——
            buildTransformCard(container, handle);

            // —— 材质调节 ——
            buildMaterialCard(container, handle, sm);

            // —— 重置 + 卸载 ——
            buildDangerCard(container, handle, () => {
                reRenderSceneMenu();
                // 卸载后回到舞台根面板
                const menu = getSceneMenu();
                if (menu) menu.pop();
            });
        },
    };
}

