            // —— 参数卡片（按类型动态）——
            if (state.type === 'spot') {
                addCollapsible(container, {
                    title: '参数',
                    icon: 'lucide:sliders',
                    defaultOpen: false,
                    renderContent: (inner) => {
                        addSliderRow(inner, '锥角', state.angle, 0.1, 2.0, 0.05, () => {}, 'lucide:circle',
