                        addCollapsible(inner, {
                            title: '目标点',
                            icon: 'lucide:target',
                            defaultOpen: false,
                            renderContent: (inner2) => {
                                addSliderRow(inner2, '目标 X', state.targetX, -10, 10, 0.1, () => {}, 'lucide:move-horizontal',
