            } else if (state.type === 'point') {
                addCollapsible(container, {
                    title: '参数',
                    icon: 'lucide:sliders',
                    defaultOpen: false,
                    renderContent: (inner) => {
                        addSliderRow(inner, '衰减距离', state.range, 1, 100, 0.5, () => {}, 'lucide:ruler',
