    kind: 'action',
    label: '',
    icon: '',
    target: SETTINGS_ACTION.CLEAR_EXTRACT_CACHE,
})

handleSettingsAction({
    kind: 'action',
    label: '',
    icon: '',
    target: SETTINGS_ACTION.CLEAR_THUMBNAIL,
})

