    [SETTINGS_ACTION.CLEAR_ALL_CACHE]: () => {
        (async () => {
            if (await showConfirm('确定要清除全部缓存吗？包括提取缓存、缩略图、HTTP 隔离目录。下次加载模型时将重新生成。')) {
                ClearAllCaches()
                    .then(() => {
