// beat-detector.ts — Web Audio API 节拍检测
// [doc:architecture] 程序化动作子系统 — 节拍检测
// 能量峰值法：低频能量 > 1.3× 滑动均值 且 距上次 beat > 250ms → 触发

const BASS_BIN_COUNT = 10; // 前 10 个频段 (~0-430Hz @ 44100/256 fft)
const ENERGY_HISTORY_SIZE = 43; // ~1s @ 43fps update
const BEAT_THRESHOLD = 1.3;
const MIN_BEAT_INTERVAL_MS = 250;
const BPM_WINDOW = 8; // 最近 8 次 beat 间隔求均值

// BPM 量化：偏差 ±5 BPM 内吸附到常见值，大偏差保留原始值
const COMMON_BPMS = [80, 90, 100, 110, 120, 130, 140, 150, 160, 170, 180];
const QUANTIZE_THRESHOLD = 5;
function quantizeBpm(raw: number): number {
    for (const bpm of COMMON_BPMS) {
        if (Math.abs(raw - bpm) <= QUANTIZE_THRESHOLD) {
            return bpm;
        }
    }
    return raw;
}

export class BeatDetector {
    private ctx: AudioContext | null = null;
    private analyser: AnalyserNode | null = null;
    private source: MediaElementAudioSourceNode | null = null;
    /** GainNode：连接 analyser → gain → destination，使音量独立于 audioElement.volume */
    private gain: GainNode | null = null;
    private freqData: Uint8Array<ArrayBuffer> = new Uint8Array(0);
    private energyHistory: number[] = [];
    private energySum = 0; // running sum for avg
    private lastBeatTime = 0;
    private beatTimes: number[] = []; // 最近 beat 时间戳 (ms)
    private currentBpm = 120;
    private phaseStartTime = 0;
    private phaseInterval = 500; // ms per beat
    private bpmQuantizeEnabled = true; // P1 开关：BPM 量化（默认开）
    private _onBeatCallbacks: Array<() => void> = [];

    /** 接入音频元素。惰性创建 AudioContext + GainNode。
     *  注意：createMediaElementSource 后音频路由经 AudioContext，
     *  须 resume() 否则浏览器自动播放策略下静音。 */
    attach(audioElement: HTMLAudioElement): void {
        if (this.ctx) {
            return;
        }
        const AudioCtx =
            window.AudioContext ||
            (window as unknown as { webkitAudioContext: typeof AudioContext }).webkitAudioContext;
        if (!AudioCtx) {
            return;
        }
        try {
            this.ctx = new AudioCtx();
        } catch (err) {
            console.warn('BeatDetector: AudioContext creation failed:', err);
            return;
        }
        if (this.ctx.state === 'suspended') {
            this.ctx.resume().catch(() => {});
        }
        this.source = this.ctx.createMediaElementSource(audioElement);
        this.analyser = this.ctx.createAnalyser();
        this.analyser.fftSize = 256;
        this.analyser.smoothingTimeConstant = 0.3;
        this.freqData = new Uint8Array(this.analyser.frequencyBinCount);
        // GainNode：使音量控制独立于 audioElement.volume（被 createMediaElementSource 旁路）
        this.gain = this.ctx.createGain();
        this.gain.gain.value = 1;
        this.source.connect(this.analyser);
        this.analyser.connect(this.gain);
        this.gain.connect(this.ctx.destination);
    }

    /** 设置输出音量 (0~1)。通过 GainNode 控制，独立于 audioElement.volume。 */
    setVolume(value: number): void {
        if (this.gain) {
            this.gain.gain.value = Math.max(0, Math.min(1, value));
        }
    }

    /** 释放所有 AudioContext 资源。 */
    dispose(): void {
        if (this.gain) {
            this.gain.disconnect();
            this.gain = null;
        }
        if (this.analyser) {
            this.analyser.disconnect();
            this.analyser = null;
        }
        if (this.source) {
            this.source.disconnect();
            this.source = null;
        }
        if (this.ctx) {
            this.ctx.close();
            this.ctx = null;
        }
        this.freqData = new Uint8Array(0);
        this.energyHistory = [];
        this.energySum = 0;
        this.beatTimes = [];
        this.lastBeatTime = 0;
        this.currentBpm = 120;
        this.phaseInterval = 500;
        this.phaseStartTime = 0;
        this._onBeatCallbacks = [];
    }

    /** 注册 beat 回调。返回取消注册函数。 */
    onBeat(cb: () => void): () => void {
        this._onBeatCallbacks.push(cb);
        return () => {
            const idx = this._onBeatCallbacks.indexOf(cb);
            if (idx >= 0) this._onBeatCallbacks.splice(idx, 1);
        };
    }

    /** 每帧调用。更新能量历史、检测 beat、估计 BPM。 */
    update(): void {
        if (!this.analyser) {
            return;
        }
        this.analyser.getByteFrequencyData(this.freqData);

        let sum = 0;
        const bins = Math.min(BASS_BIN_COUNT, this.freqData.length);
        for (let i = 0; i < bins; i++) {
            sum += this.freqData[i];
        }
        const energy = bins > 0 ? sum / bins : 0;

        // 滑动窗口：维护 running sum 避免全量 reduce
        this.energyHistory.push(energy);
        this.energySum += energy;
        if (this.energyHistory.length > ENERGY_HISTORY_SIZE) {
            this.energySum -= this.energyHistory.shift()!;
        }

        const avg = this.energySum / this.energyHistory.length;

        const now = performance.now();
        if (
            energy > avg * BEAT_THRESHOLD &&
            energy > 30 &&
            now - this.lastBeatTime > MIN_BEAT_INTERVAL_MS
        ) {
            this.lastBeatTime = now;
            this.beatTimes.push(now);
            if (this.beatTimes.length > BPM_WINDOW + 1) {
                this.beatTimes.shift();
            }
            this.phaseStartTime = now;
            // 触发 beat 回调
            for (const cb of this._onBeatCallbacks) {
                try { cb(); } catch (e) { console.warn('[BeatDetector] onBeat callback error:', e); }
            }
            if (this.beatTimes.length >= 2) {
                const intervals: number[] = [];
                for (let i = 1; i < this.beatTimes.length; i++) {
                    intervals.push(this.beatTimes[i] - this.beatTimes[i - 1]);
                }
                const avgInterval = intervals.reduce((a, b) => a + b, 0) / intervals.length;
                if (avgInterval > 0) {
                    const rawBpm = Math.round(60000 / avgInterval);
                    this.currentBpm = this.bpmQuantizeEnabled ? quantizeBpm(rawBpm) : rawBpm;
                    this.phaseInterval = 60000 / this.currentBpm;
                }
            }
        }
    }

    /** 重置状态（音频停止/切换时调用）。 */
    reset(): void {
        this.energyHistory = [];
        this.energySum = 0;
        this.beatTimes = [];
        this.lastBeatTime = 0;
        this.currentBpm = 120;
        this.phaseInterval = 500;
        this.phaseStartTime = performance.now();
    }

    getBPM(): number {
        return this.currentBpm;
    }

    /** 获取/设置 BPM 量化开关（默认 true）。关闭后使用原始 BPM 值。 */
    getBpmQuantizeEnabled(): boolean {
        return this.bpmQuantizeEnabled;
    }
    setBpmQuantizeEnabled(v: boolean): void {
        this.bpmQuantizeEnabled = v;
    }

    /** 当前 beat 周期内的相位 0..1。 */
    getBeatPhase(): number {
        const elapsed = performance.now() - this.phaseStartTime;
        return Math.min(1, elapsed / Math.max(1, this.phaseInterval));
    }

    /** 当前帧指定频段的平均能量 (0..1)。须在 update() 之后调用。 */
    getLevel(startBin = 0, endBin?: number): number {
        if (!this.analyser) {
            return 0;
        }
        return BeatDetector.getLevel(this.freqData, startBin, endBin);
    }

    hasAudio(): boolean {
        return this.analyser !== null;
    }

    /** 纯逻辑：给定能量序列，返回 beat 触发帧索引。供测试用。 */
    static detectBeatsFromEnergies(
        energies: number[],
        threshold = BEAT_THRESHOLD,
        minInterval = 6
    ): number[] {
        const beats: number[] = [];
        const history: number[] = [];
        let sum = 0;
        for (let i = 0; i < energies.length; i++) {
            history.push(energies[i]);
            sum += energies[i];
            if (history.length > ENERGY_HISTORY_SIZE) {
                sum -= history.shift()!;
            }
            const avg = sum / history.length;
            const lastBeat = beats.length > 0 ? beats[beats.length - 1] : -minInterval;
            if (energies[i] > avg * threshold && energies[i] > 30 && i - lastBeat >= minInterval) {
                beats.push(i);
            }
        }
        return beats;
    }

    /** 纯逻辑：从 beat 时间戳数组计算 BPM。 */
    static bpmFromIntervals(intervalsMs: number[]): number {
        if (intervalsMs.length === 0) {
            return 120;
        }
        const avg = intervalsMs.reduce((a, b) => a + b, 0) / intervalsMs.length;
        return avg > 0 ? Math.round(60000 / avg) : 120;
    }

    /** 纯逻辑：从频谱数据计算指定频段平均能量 (0..1)。 */
    static getLevel(freqData: Uint8Array, startBin = 0, endBin?: number): number {
        if (freqData.length === 0) {
            return 0;
        }
        const start = Math.max(0, startBin);
        const end = Math.min(endBin ?? freqData.length, freqData.length);
        if (end <= start) {
            return 0;
        }
        let sum = 0;
        for (let i = start; i < end; i++) {
            sum += freqData[i];
        }
        return sum / (end - start) / 255;
    }
}

// lipsync.ts — 实时振幅驱动 LipSync
// [doc:architecture] LipSync 子系统 — 振幅→口型 morph
//
// 每帧从 BeatDetector.getLevel 取人声频段能量 → amplitudeToWeight 映射 →
// setModelMorphWeight 直写焦点模型的「あ」morph。
// 与 procedural motion 不冲突：前者只控「まばたき」(VMD 帧)，本模块只控「あ」(实时直写)。

export interface LipSyncState {
    enabled: boolean;
    sensitivity: number; // 0..1，振幅阈值（低于此值视为静音，越大越不敏感）
    intensity: number; // 0..1，最大张嘴幅度
    multiMorphEnabled: boolean; // true=驱动多口型 morph（P0 开关）
}

export const DEFAULT_LIPSYNC_STATE: LipSyncState = {
    enabled: false,
    sensitivity: 0.2,
    intensity: 0.8,
    multiMorphEnabled: false,
};

/** 标准 MMD 口型 morph 候选名（按优先级降序）。
 *  绝大多数 MMD 模型使用「あ」；少数使用片假名「ア」或拉丁字母。 */
const LIP_MORPH_CANDIDATES = ['あ', 'ア', 'A', 'a', '口', 'mouth', 'open'];

/** 在模型 morph 列表中查找口型 morph，返回首个匹配名。
 *  @param morphNames 模型可用 morph 名集合
 *  @returns 匹配的 morph 名；无匹配返回 null */
export function findLipMorph(morphNames: string[]): string | null {
    const set = new Set(morphNames);
    for (const name of LIP_MORPH_CANDIDATES) {
        if (set.has(name)) {
            return name;
        }
    }
    return null;
}

// ========== 多 Morph LipSync 扩展 ==========

/** 多口型 morph 候选（按音素分类） */
const MOUTH_MORPHS: Record<string, string[]> = {
    open:   ['あ', 'ア', 'A', 'a', '口', 'mouth', 'open'],
    close:  ['い', 'イ', 'I', 'i', 'close'],
    pucker: ['う', 'ウ', 'U', 'u', 'pucker'],
    smile:  ['え', 'エ', 'E', 'e', 'smile', 'にこり', '笑い'],
};

export interface LipSyncMorphSet {
    open: string | null;
    close: string | null;
    pucker: string | null;
    smile: string | null;
}

/** 查找模型中所有可用的口型相关 morph。
 *  @param morphNames 模型可用 morph 名列表
 *  @returns 各音素对应的 morph 名（无匹配为 null） */
export function findAllLipMorphs(morphNames: string[]): LipSyncMorphSet {
    const set = new Set(morphNames);
    return {
        open:   MOUTH_MORPHS.open.find((n) => set.has(n)) ?? null,
        close:  MOUTH_MORPHS.close.find((n) => set.has(n)) ?? null,
        pucker: MOUTH_MORPHS.pucker.find((n) => set.has(n)) ?? null,
        smile:  MOUTH_MORPHS.smile.find((n) => set.has(n)) ?? null,
    };
}

/** 振幅 → morph 权重映射。
 *  低于 sensitivity 阈值 → 0；否则线性映射到 0..intensity。
 *  @param amplitude 0..1 音频能量（可 >1，会被钳制）
 *  @param sensitivity 0..1 阈值（< 阈值视为静音）
 *  @param intensity 0..1 最大张嘴幅度
 *  @returns 0..intensity 的 morph 权重 */
export function amplitudeToWeight(
    amplitude: number,
    sensitivity: number,
    intensity: number
): number {
    if (amplitude < sensitivity) {
        return 0;
    }
    const range = 1 - sensitivity;
    if (range <= 0) {
        // sensitivity=1 边界：仅振幅满时张嘴，避免口型常开
        return amplitude >= 1.0 ? intensity : 0;
    }
    const t = Math.max(0, Math.min(1, (amplitude - sensitivity) / range));
    return t * intensity;
}

// procedural-motion.ts — 程序化动作管理器（Idle + Auto Dance）
// [doc:architecture] 程序化动作子系统
// 生成 procedural VMD（骨骼+morph 关键帧），通过现有 loadVMDMotion 管道加载。
// 无音乐 → Idle（呼吸+眨眼）；有音乐 → Auto Dance（节拍驱动律动）。

import {
    buildVmd,
    canEncodeName,
    type BoneKeyFrame,
    type MorphKeyFrame,
    INTERP_EASE_IN_OUT,
    INTERP_EASE_OUT,
    INTERP_SHARP,
} from './vmd-writer';

export type ProcMotionMode = 'off' | 'idle' | 'autodance';

/** 程序化 VMD 动画名，用于 vmd-loader 区分用户文件 vs 程序化生成。 */
export const PROC_VMD_NAME_IDLE = 'IdleMotion';
export const PROC_VMD_NAME_AUTODANCE = 'AutoDance';
export const PROC_VMD_NAME_LIFELIKE = 'LifelikeMotion';

/** 程序化动作微动效果类别（用于 boneToggles 开关） */
export const PROC_MOTION_BONE_CATEGORIES = [
    'center',        // センター（重心弹跳/摇摆）
    'upper',         // 上半身（呼吸/前倾）
    'upper2',        // 上半身2（扭转）
    'waist',         // 腰（扭胯）
    'head',          // 頭（点头）
    'arm',           // 手臂（外展+前后甩动）
    'groove',        // グルーブ
    'shoulder',      // 肩部（耸肩）
    'allParent',     // 全ての親（微晃）
    'wrist',         // 手腕（节拍下压）
    'footIk',        // 足IK（踏步）
    'blink',         // 眨眼（待机模式）
    'emotion',       // 表情情绪轮（AutoDance 模式）
] as const;
export type ProcMotionBoneCategory = (typeof PROC_MOTION_BONE_CATEGORIES)[number];

/** 获取所有微动类别（供 UI 遍历） */
export function getProcMotionBoneCategories(): ProcMotionBoneCategory[] {
    return [...PROC_MOTION_BONE_CATEGORIES];
}

export interface ProcMotionState {
    mode: ProcMotionMode;
    intensity: number; // 0..1，默认 0.5
    speed: number; // 0.5..2，默认 1.0
    autoSwitch: boolean; // true=根据音乐自动切换 Idle/AutoDance
    /** 各微动效果的开关（key=骨骼类别，value=是否启用） */
    boneToggles: Record<ProcMotionBoneCategory, boolean>;
    bpmQuantizeEnabled: boolean; // true=BPM 量化开（P1 开关）
    vpdApplyEnabled: boolean; // true=将 VPD 表情混入程序化 VMD（P1 开关）
    interpOverride: 'auto' | 'sharp' | 'ease-in-out' | 'ease-out'; // 插值曲线覆盖（P1 开关）
    multiMorphEnabled: boolean; // true=多 Morph LipSync（P0 开关）
    eyeTrackingEnabled: boolean; // true=眼部跟随（视线追踪，实时效果）
    headTrackingEnabled: boolean; // true=头部跟随（实时效果）
    lifelikeEnabled: boolean; // true=微动叠加层（叠加在任何动画上）
    lifelikeIntensity: number; // 0..1，默认 0.3
}

const _defaultBoneToggles: Record<ProcMotionBoneCategory, boolean> = {
    center: true,
    upper: true,
    upper2: true,
    waist: true,
    head: true,
    arm: true,
    groove: true,
    shoulder: true,
    allParent: true,
    wrist: true,
    footIk: true,
    blink: true,
    emotion: true,
};

export const DEFAULT_PROC_STATE: ProcMotionState = {
    mode: 'off',
    intensity: 0.5,
    speed: 1.0,
    autoSwitch: true,
    boneToggles: { ..._defaultBoneToggles },
    bpmQuantizeEnabled: true,
    vpdApplyEnabled: false,
    interpOverride: 'auto',
    multiMorphEnabled: false,
    eyeTrackingEnabled: true,  // 默认开启（视线追踪）
    headTrackingEnabled: false, // 默认关闭（头部跟随较影响动画）
    lifelikeEnabled: false,    // 默认关闭（用户手动开启）
    lifelikeIntensity: 0.3,    // 默认强度偏低（微动不宜过强）
};

// ============ 骨骼候选名 ============
const BONE_CENTER_CANDIDATES = ['センター', '全ての親', 'center', 'Center', 'Root', 'root'];
const BONE_UPPER_CANDIDATES = ['上半身', 'upper', 'Upper', '上半', '上半身2'];
const BONE_UPPER2_CANDIDATES = ['上半身2', 'upper2', 'Upper2', '上半身２'];
const BONE_NECK_CANDIDATES = ['首', 'neck', 'Neck', '首元'];
const BONE_HEAD_CANDIDATES = ['頭', 'head', 'Head', '頭頂'];

// 手臂 —— 加入 W 后缀变体
const BONE_LARM_CANDIDATES = [
    '左腕', '左腕W', '左arm', '左腕捩', 'left arm', 'LeftArm', 'Left Arm'
];
const BONE_RARM_CANDIDATES = [
    '右腕', '右腕W', '右arm', '右腕捩', 'right arm', 'RightArm', 'Right Arm'
];

// 手腕（手首）—— 若有则驱动
const BONE_WRIST_L_CANDIDATES = ['左手首', '左リスト', 'left wrist', 'LeftWrist'];
const BONE_WRIST_R_CANDIDATES = ['右手首', '右リスト', 'right wrist', 'RightWrist'];

// 肩部（包含 P / C 变体）
const BONE_SHOULDER_L_CANDIDATES = [
    '左肩', '左肩P', '左肩C', '左肩捩', 'left shoulder', 'LeftShoulder', 'LeftShoulderP', 'LeftShoulderC'
];
const BONE_SHOULDER_R_CANDIDATES = [
    '右肩', '右肩P', '右肩C', '右肩捩', 'right shoulder', 'RightShoulder', 'RightShoulderP', 'RightShoulderC'
];

// 躯干辅助
const BONE_WAIST_CANDIDATES = ['腰', 'waist', 'Waist', 'hips', 'Hips', 'hip'];
const BONE_ALLPARENT_CANDIDATES = ['全ての親', 'AllParent', 'all parent', 'root', 'Root'];
const BONE_GROOVE_CANDIDATES = ['グルーブ', 'groove', 'Groove'];

// 预留足IK（未启用）
const BONE_LEG_IK_L_CANDIDATES = ['左足IK', 'left leg ik', 'LeftLegIK'];
const BONE_LEG_IK_R_CANDIDATES = ['右足IK', 'right leg ik', 'RightLegIK'];

/** 从模型骨骼名列表中查找首个匹配且可 SJIS 编码的候选名，未找到时返回 null（跳过该骨骼）。 */
function _matchBone(actualBones: string[], candidates: string[]): string | null {
    for (const c of candidates) {
        if (actualBones.includes(c)) {
            if (canEncodeName(c)) return c;
            console.warn(`[procedural-motion] 骨骼 "${c}" 无法编码为 Shift-JIS，跳过`);
            return null; // 不继续 fallback 到其他候选（名不同，对应不同骨骼）
        }
    }
    return null;
}

// ============ Morph 候选名（扩充眨眼） ============
const MORPH_BLINK_CANDIDATES = [
    'まばたき', 'blink', 'Blink', '眨眼', 'wink',
    'eye close', 'EyeClose', '眼', '目', '閉眼'
];

const FPS = 30;
const MAX_FRAMES = 600; // 硬上限 20s，防止极端 speed/bpm 组合导致内存爆炸

/** 钳位旋转分量的安全辅助（四元数 w 计算前） */
const _clamp1 = (v: number) => Math.max(-1, Math.min(1, v));

// ============================================================================
//  Idle 生成（保持不变，柔和呼吸）
// ============================================================================
export function generateIdleVmd(
    state: ProcMotionState,
    morphNames: string[] = [],
    boneNames: string[] = []
): ArrayBuffer {
    const safeSpeed = Math.max(0.1, Math.min(10, state.speed));
    const loopFrames = Math.min(MAX_FRAMES, Math.round(120 / safeSpeed)); // 4s @ 30fps
    const intensity = state.intensity;
    const bones: BoneKeyFrame[] = [];
    const morphs: MorphKeyFrame[] = [];

    // ---------- 眨眼（伪随机间隔 2~8s，自然频率） ----------
    const blinkMorph = state.boneToggles.blink ? MORPH_BLINK_CANDIDATES.find((c) => morphNames.includes(c)) : null;
    if (blinkMorph) {
        const blinkA = Math.round(60 / safeSpeed);
        const blinkB = Math.round(240 / safeSpeed);
        for (let t = blinkA, i = 0; t + 5 <= loopFrames; i++) {
            morphs.push({ name: blinkMorph, frame: t, weight: 0 });
            morphs.push({ name: blinkMorph, frame: t + 2, weight: 1 });
            morphs.push({ name: blinkMorph, frame: t + 5, weight: 0 });
            const step = blinkA + ((i * 17 + 3) % (blinkB - blinkA));
            t += Math.max(blinkA, step);
        }
        morphs.push({ name: blinkMorph, frame: loopFrames, weight: 0 });
    }

    // ---------- 骨骼匹配 ----------
    const centerBone = _matchBone(boneNames, BONE_CENTER_CANDIDATES);
    const upperBone = _matchBone(boneNames, BONE_UPPER_CANDIDATES);
    const upper2Bone = _matchBone(boneNames, BONE_UPPER2_CANDIDATES);
    const neckBone = _matchBone(boneNames, BONE_NECK_CANDIDATES);
    const headBone = _matchBone(boneNames, BONE_HEAD_CANDIDATES);
    const waistBone = _matchBone(boneNames, BONE_WAIST_CANDIDATES);
    const allParentBone = _matchBone(boneNames, BONE_ALLPARENT_CANDIDATES);
    const shoulderLBone = _matchBone(boneNames, BONE_SHOULDER_L_CANDIDATES);
    const shoulderRBone = _matchBone(boneNames, BONE_SHOULDER_R_CANDIDATES);
    const larmBone = _matchBone(boneNames, BONE_LARM_CANDIDATES);
    const rarmBone = _matchBone(boneNames, BONE_RARM_CANDIDATES);
    const wristLBone = _matchBone(boneNames, BONE_WRIST_L_CANDIDATES);
    const wristRBone = _matchBone(boneNames, BONE_WRIST_R_CANDIDATES);

    // ---------- 上半身呼吸 ----------
    const breathAmp = 0.03 * intensity;
    if ((upperBone || neckBone) && state.boneToggles.upper) {
        for (let f = 0; f <= loopFrames; f += 4) {
            const phase = (f / loopFrames) * Math.PI * 2;
            const rx = _clamp1(Math.sin(phase) * breathAmp);
            const w = Math.sqrt(Math.max(0, 1 - rx * rx));
            if (upperBone) {
                bones.push({ name: upperBone, frame: f, position: [0, 0, 0], rotation: [rx, 0, 0, w] });
            }
            if (neckBone) {
                const nrx = _clamp1(Math.sin(phase) * breathAmp * 0.6);
                const nw = Math.sqrt(Math.max(0, 1 - nrx * nrx));
                bones.push({ name: neckBone, frame: f, position: [0, 0, 0], rotation: [nrx, 0, 0, nw] });
            }
        }
        if (upperBone) bones.push({ name: upperBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
        if (neckBone) bones.push({ name: neckBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
    }

    // ---------- 上半身2 ----------
    if (upper2Bone && state.boneToggles.upper2) {
        const amp2 = 0.015 * intensity;
        for (let f = 0; f <= loopFrames; f += 4) {
            const phase = (f / loopFrames) * Math.PI * 2;
            const rx = _clamp1(Math.sin(phase * 0.7 + 0.3) * amp2);
            const w = Math.sqrt(Math.max(0, 1 - rx * rx));
            bones.push({ name: upper2Bone, frame: f, position: [0, 0, 0], rotation: [rx, 0, 0, w] });
        }
        bones.push({ name: upper2Bone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
    }

    // ---------- 腰 ----------
    if (waistBone && state.boneToggles.waist) {
        const waistAmp = 0.02 * intensity;
        for (let f = 0; f <= loopFrames; f += 4) {
            const phase = (f / loopFrames) * Math.PI * 2;
            const rz = _clamp1(Math.sin(phase + 0.5) * waistAmp);
            const w = Math.sqrt(Math.max(0, 1 - rz * rz));
            bones.push({ name: waistBone, frame: f, position: [0, 0, 0], rotation: [0, 0, rz, w] });
        }
        bones.push({ name: waistBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
    }

    // ---------- 全ての親 ----------
    if (allParentBone && state.boneToggles.allParent) {
        const parentAmp = 0.005 * intensity;
        for (let f = 0; f <= loopFrames; f += 6) {
            const t = (f / loopFrames) * Math.PI * 2;
            const rx = _clamp1(Math.sin(t * 0.2 + 1.1) * parentAmp);
            const rz = _clamp1(Math.sin(t * 0.3 + 2.3) * parentAmp);
            const w = Math.sqrt(Math.max(0, 1 - rx*rx - rz*rz));
            bones.push({ name: allParentBone, frame: f, position: [0, 0, 0], rotation: [rx, 0, rz, w] });
        }
        bones.push({ name: allParentBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
    }

    // ---------- センター ----------
    if (centerBone && state.boneToggles.center) {
        const hasBreath = !!(upperBone || neckBone);
        const swayAmp = (hasBreath ? 0.04 : 0.1) * intensity;
        const microAmp = 0.03 * intensity;
        const bobAmp = (hasBreath ? 0.005 : 0.04) * intensity;
        for (let f = 0; f <= loopFrames; f += 4) {
            const phase = (f / loopFrames) * Math.PI * 2;
            const slowPhase = phase * 0.5;
            const rz = _clamp1(Math.sin(slowPhase) * swayAmp);
            const rw = Math.sqrt(Math.max(0, 1 - rz * rz));
            const rx = _clamp1(Math.sin(phase * 0.37 + 0.5) * microAmp);
            const w = _clamp1(Math.sqrt(Math.max(0, 1 - rx * rx - rz * rz)));
            const bobY = Math.sin(phase) * bobAmp;
            bones.push({
                name: centerBone,
                frame: f,
                position: [0, bobY, 0],
                rotation: [rx, 0, rz, w],
            });
        }
        bones.push({
            name: centerBone,
            frame: loopFrames,
            position: [0, 0, 0],
            rotation: [0, 0, 0, 1],
        });
    }

    // ---------- 頭 ----------
    if (headBone) {
        const headMicroAmp = 0.02 * intensity;
        for (let f = 0; f <= loopFrames; f += 6) {
            const t = (f / loopFrames) * Math.PI * 2;
            const rz = _clamp1(Math.sin(t * 0.43 + 1.2) * headMicroAmp);
            const rx = _clamp1(Math.sin(t * 0.29 + 3.7) * headMicroAmp * 0.7);
            const ry = _clamp1(Math.sin(t * 0.19 + 0.8) * headMicroAmp * 0.4);
            const w = Math.sqrt(Math.max(0, 1 - rz * rz - rx * rx - ry * ry));
            bones.push({ name: headBone, frame: f, position: [0, 0, 0], rotation: [rx, ry, rz, w] });
        }
        bones.push({ name: headBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
    }

    // ---------- 手臂（自然钟摆） ----------
    if (larmBone || rarmBone) {
        const armAmp = 0.04 * intensity;
        for (let f = 0; f <= loopFrames; f += 4) {
            const phase = (f / loopFrames) * Math.PI * 2;
            const rz = _clamp1(Math.sin(phase + 1.5) * armAmp);
            const w = Math.sqrt(Math.max(0, 1 - rz * rz));
            if (larmBone) {
                bones.push({ name: larmBone, frame: f, position: [0, 0, 0], rotation: [0, 0, rz, w] });
            }
            if (rarmBone) {
                bones.push({ name: rarmBone, frame: f, position: [0, 0, 0], rotation: [0, 0, -rz, w] });
            }
        }
        if (larmBone) bones.push({ name: larmBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
        if (rarmBone) bones.push({ name: rarmBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
    }

    // ---------- 肩部 ----------
    if (shoulderLBone || shoulderRBone) {
        const shoulderAmp = 0.015 * intensity;
        const rotAmp = 0.01 * intensity;
        for (let f = 0; f <= loopFrames; f += 4) {
            const phase = (f / loopFrames) * Math.PI * 2;
            const breath = Math.sin(phase + 0.3);
            const yOffset = breath * shoulderAmp;
            const rz = _clamp1(Math.sin(phase + 0.1) * rotAmp);
            const w = Math.sqrt(Math.max(0, 1 - rz * rz));
            if (shoulderLBone) {
                bones.push({ name: shoulderLBone, frame: f, position: [0, yOffset, 0], rotation: [0, 0, rz, w] });
            }
            if (shoulderRBone) {
                const rOffset = Math.sin(phase + 0.5) * shoulderAmp;
                const rrz = _clamp1(Math.sin(phase + 0.4) * rotAmp);
                const rw = Math.sqrt(Math.max(0, 1 - rrz * rrz));
                bones.push({ name: shoulderRBone, frame: f, position: [0, rOffset, 0], rotation: [0, 0, rrz, rw] });
            }
        }
        if (shoulderLBone) bones.push({ name: shoulderLBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
        if (shoulderRBone) bones.push({ name: shoulderRBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
    }

    // ---------- 手腕（若有） ----------
    if (wristLBone || wristRBone) {
        const wristAmp = 0.015 * intensity;
        for (let f = 0; f <= loopFrames; f += 4) {
            const phase = (f / loopFrames) * Math.PI * 2;
            const rx = _clamp1(Math.sin(phase + 0.8) * wristAmp);
            const w = Math.sqrt(Math.max(0, 1 - rx * rx));
            if (wristLBone) {
                bones.push({ name: wristLBone, frame: f, position: [0, 0, 0], rotation: [rx, 0, 0, w] });
            }
            if (wristRBone) {
                const rxR = _clamp1(Math.sin(phase + 1.1) * wristAmp);
                const wR = Math.sqrt(Math.max(0, 1 - rxR * rxR));
                bones.push({ name: wristRBone, frame: f, position: [0, 0, 0], rotation: [rxR, 0, 0, wR] });
            }
        }
        if (wristLBone) bones.push({ name: wristLBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
        if (wristRBone) bones.push({ name: wristRBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
    }

    // Idle 全部用 EASE_IN_OUT（柔和呼吸感）
    for (const b of bones) {
        b.interp = INTERP_EASE_IN_OUT;
    }
    return buildVmd(bones, morphs, PROC_VMD_NAME_IDLE);
}

// ============================================================================
//  Auto Dance 生成（显眼增强版）
// ============================================================================
export function generateAutoDanceVmd(
    state: ProcMotionState,
    bpm: number,
    morphNames: string[] = [],
    boneNames: string[] = []
): ArrayBuffer {
    const safeSpeed = Math.max(0.1, Math.min(10, state.speed));
    const clampedBpm = Math.max(60, Math.min(200, bpm));
    const beatFrames = Math.min(MAX_FRAMES, Math.round(((60 / clampedBpm) * FPS) / safeSpeed));
    const loopFrames = beatFrames * 8; // 8 拍循环（2 小节）
    const intensity = state.intensity;
    const bones: BoneKeyFrame[] = [];
    const morphs: MorphKeyFrame[] = [];

    // ---------- 眨眼（伪随机间隔 2~8s，同 idle） ----------
    const blinkMorph = MORPH_BLINK_CANDIDATES.find((c) => morphNames.includes(c));
    if (blinkMorph) {
        const blinkA = Math.round(60 / safeSpeed);  // ~2s
        const blinkB = Math.round(240 / safeSpeed); // ~8s
        for (let t = blinkA, i = 0; t + 5 <= loopFrames; i++) {
            morphs.push({ name: blinkMorph, frame: t, weight: 0 });
            morphs.push({ name: blinkMorph, frame: t + 2, weight: 1 });
            morphs.push({ name: blinkMorph, frame: t + 5, weight: 0 });
            const step = blinkA + ((i * 17 + 3) % (blinkB - blinkA));
            t += Math.max(blinkA, step);
        }
        morphs.push({ name: blinkMorph, frame: loopFrames, weight: 0 });
    }

    // ---------- 骨骼匹配 ----------
    const centerBone = _matchBone(boneNames, BONE_CENTER_CANDIDATES);
    const upperBone = _matchBone(boneNames, BONE_UPPER_CANDIDATES);
    const upper2Bone = _matchBone(boneNames, BONE_UPPER2_CANDIDATES);
    const waistBone = _matchBone(boneNames, BONE_WAIST_CANDIDATES);
    const grooveBone = _matchBone(boneNames, BONE_GROOVE_CANDIDATES);
    const headBone = _matchBone(boneNames, BONE_HEAD_CANDIDATES);
    const larmBone = _matchBone(boneNames, BONE_LARM_CANDIDATES);
    const rarmBone = _matchBone(boneNames, BONE_RARM_CANDIDATES);
    const shoulderLBone = _matchBone(boneNames, BONE_SHOULDER_L_CANDIDATES);
    const shoulderRBone = _matchBone(boneNames, BONE_SHOULDER_R_CANDIDATES);
    const allParentBone = _matchBone(boneNames, BONE_ALLPARENT_CANDIDATES);
    const wristLBone = _matchBone(boneNames, BONE_WRIST_L_CANDIDATES);
    const wristRBone = _matchBone(boneNames, BONE_WRIST_R_CANDIDATES);
    const legIkLBone = _matchBone(boneNames, BONE_LEG_IK_L_CANDIDATES);
    const legIkRBone = _matchBone(boneNames, BONE_LEG_IK_R_CANDIDATES);

    // 预计算 sin/cos
    const sinVals: number[] = [];
    const cosVals: number[] = [];
    for (let f = 0; f <= loopFrames; f += 3) {
        const angle = (f / beatFrames) * Math.PI;
        sinVals[f] = Math.sin(angle);
        cosVals[f] = Math.cos(angle);
    }

    // ---------- 1. センター（大幅侧摆 + 旋转 + 弹跳） ----------
    if (centerBone && state.boneToggles.center) {
        const bodyAmp = 0.20 * intensity;      // Y轴扭动
        const sideAmp = 0.12 * intensity;      // Z轴侧摆（新增）
        const bobAmp = 0.06 * intensity;       // 弹跳
        for (let f = 0; f <= loopFrames; f += 3) {
            const s = sinVals[f];
            const c = cosVals[f];
            const ry = _clamp1(s * bodyAmp);
            const rz = _clamp1(c * sideAmp);
            const w = Math.sqrt(Math.max(0, 1 - ry*ry - rz*rz));
            const bob = Math.abs(s) * bobAmp;
            bones.push({
                name: centerBone,
                frame: f,
                position: [0, bob, 0],
                rotation: [0, ry, rz, w],
            });
        }
        bones.push({ name: centerBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
    }

    // ---------- 2. 上半身（前倾后仰） ----------
    if (upperBone && state.boneToggles.upper) {
        const upperAmp = 0.15 * intensity;
        for (let f = 0; f <= loopFrames; f += 3) {
            const s = sinVals[f + Math.round(beatFrames / 2)] || 0;
            const rx = _clamp1(s * upperAmp);
            const w = Math.sqrt(Math.max(0, 1 - rx * rx));
            bones.push({ name: upperBone, frame: f, position: [0, 0, 0], rotation: [rx, 0, 0, w] });
        }
        bones.push({ name: upperBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
    }

    // ---------- 3. 上半身2（扭转） ----------
    if (upper2Bone && state.boneToggles.upper2) {
        const amp2 = 0.06 * intensity;
        for (let f = 0; f <= loopFrames; f += 3) {
            const s = sinVals[f];
            const ry = _clamp1(s * 0.6 * amp2);
            const w = Math.sqrt(Math.max(0, 1 - ry * ry));
            bones.push({ name: upper2Bone, frame: f, position: [0, 0, 0], rotation: [0, ry, 0, w] });
        }
        bones.push({ name: upper2Bone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
    }

    // ---------- 4. 腰（扭胯） ----------
    if (waistBone && state.boneToggles.waist) {
        const waistAmp = 0.20 * intensity;
        for (let f = 0; f <= loopFrames; f += 3) {
            const s = sinVals[f + Math.round(beatFrames / 4)] || 0;
            const rz = _clamp1(-s * waistAmp);
            const w = Math.sqrt(Math.max(0, 1 - rz * rz));
            bones.push({ name: waistBone, frame: f, position: [0, 0, 0], rotation: [0, 0, rz, w] });
        }
        bones.push({ name: waistBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
    }

    // ---------- 5. 頭 ----------
    if (headBone && state.boneToggles.head) {
        const headAmp = 0.12 * intensity;
        for (let f = 0; f <= loopFrames; f += 3) {
            const s = sinVals[f];
            const rz = _clamp1(-s * headAmp);
            const w = Math.sqrt(Math.max(0, 1 - rz * rz));
            bones.push({ name: headBone, frame: f, position: [0, 0, 0], rotation: [0, 0, rz, w] });
        }
        bones.push({ name: headBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
    }

    // ---------- 6. 手臂（大幅外展 + 前后甩动） ----------
    if ((larmBone || rarmBone) && state.boneToggles.arm) {
        const armAmpZ = 0.55 * intensity;      // 外展幅度（Z轴）
        const armAmpX = 0.30 * intensity;      // 前后甩动（X轴）
        for (let f = 0; f <= loopFrames; f += 3) {
            const s = sinVals[f];
            const phase2 = cosVals[f + Math.round(beatFrames / 4)] || 0;
            if (larmBone) {
                const lz = _clamp1(s * armAmpZ);
                const lx = _clamp1(phase2 * armAmpX);
                const w = Math.sqrt(Math.max(0, 1 - lz*lz - lx*lx));
                bones.push({ name: larmBone, frame: f, position: [0, 0, 0], rotation: [lx, 0, lz, w] });
            }
            if (rarmBone) {
                const rz = _clamp1(-s * armAmpZ);
                const rx = _clamp1(phase2 * armAmpX);
                const w = Math.sqrt(Math.max(0, 1 - rz*rz - rx*rx));
                bones.push({ name: rarmBone, frame: f, position: [0, 0, 0], rotation: [rx, 0, rz, w] });
            }
        }
        if (larmBone) bones.push({ name: larmBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
        if (rarmBone) bones.push({ name: rarmBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
    }

    // ---------- 7. グルーブ ----------
    if (grooveBone && state.boneToggles.groove) {
        const grooveAmp = 0.15 * intensity;
        for (let f = 0; f <= loopFrames; f += 3) {
            const s = sinVals[f];
            const bob = Math.abs(s) * 0.08 * intensity;
            const ry = _clamp1(s * grooveAmp);
            const w = Math.sqrt(Math.max(0, 1 - ry * ry));
            bones.push({ name: grooveBone, frame: f, position: [0, bob, 0], rotation: [0, ry, 0, w] });
        }
        bones.push({ name: grooveBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
    }

    // ---------- 8. 肩部（耸肩） ----------
    if ((shoulderLBone || shoulderRBone) && state.boneToggles.shoulder) {
        const shoulderUpAmp = 0.10 * intensity;
        const shoulderRotAmp = 0.15 * intensity;
        for (let f = 0; f <= loopFrames; f += 3) {
            const s = sinVals[f];
            const up = Math.abs(s) * shoulderUpAmp;
            const rot = _clamp1(s * shoulderRotAmp);
            const w = Math.sqrt(Math.max(0, 1 - rot * rot));
            if (shoulderLBone) {
                bones.push({ name: shoulderLBone, frame: f, position: [0, up, 0], rotation: [0, 0, rot, w] });
            }
            if (shoulderRBone) {
                bones.push({ name: shoulderRBone, frame: f, position: [0, up, 0], rotation: [0, 0, rot, w] });
            }
        }
        if (shoulderLBone) bones.push({ name: shoulderLBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
        if (shoulderRBone) bones.push({ name: shoulderRBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
    }

    // ---------- 9. 全ての親 ----------
    if (allParentBone && state.boneToggles.allParent) {
        const parentAmp = 0.02 * intensity;
        for (let f = 0; f <= loopFrames; f += 6) {
            const t = (f / loopFrames) * Math.PI * 2;
            const rx = _clamp1(Math.sin(t * 0.7 + 1.1) * parentAmp);
            const rz = _clamp1(Math.sin(t * 0.5 + 2.3) * parentAmp);
            const w = Math.sqrt(Math.max(0, 1 - rx*rx - rz*rz));
            bones.push({ name: allParentBone, frame: f, position: [0, 0, 0], rotation: [rx, 0, rz, w] });
        }
        bones.push({ name: allParentBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
    }

    // ---------- 10. 手腕（节拍下压 + 侧摆） ----------
    if ((wristLBone || wristRBone) && state.boneToggles.wrist) {
        const wristAmpX = 0.35 * intensity;
        const wristAmpZ = 0.15 * intensity;
        for (let f = 0; f <= loopFrames; f += 3) {
            const s = sinVals[f];
            const rx = _clamp1(Math.abs(s) * wristAmpX);
            const rz = _clamp1(cosVals[f] * wristAmpZ);
            const w = Math.sqrt(Math.max(0, 1 - rx*rx - rz*rz));
            if (wristLBone) {
                bones.push({ name: wristLBone, frame: f, position: [0, 0, 0], rotation: [rx, 0, rz, w] });
            }
            if (wristRBone) {
                const rzR = _clamp1(-cosVals[f] * wristAmpZ);
                const wR = Math.sqrt(Math.max(0, 1 - rx*rx - rzR*rzR));
                bones.push({ name: wristRBone, frame: f, position: [0, 0, 0], rotation: [rx, 0, rzR, wR] });
            }
        }
        if (wristLBone) bones.push({ name: wristLBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
        if (wristRBone) bones.push({ name: wristRBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
    }

    // ---------- 11. 足IK（基础踏步） ----------
    if (state.boneToggles.footIk && (legIkLBone || legIkRBone)) {
        const stepAmp = 0.08 * intensity;  // Z轴前后位移
        const liftAmp = 0.03 * intensity;  // Y轴抬脚（只抬不沉，防穿地）
        for (let f = 0; f <= loopFrames; f += 3) {
            const s = sinVals[f];
            if (legIkLBone) {
                const lz = _clamp1(s * stepAmp);
                const ly = Math.max(0, s) * liftAmp; // 只抬不沉
                bones.push({ name: legIkLBone, frame: f, position: [0, ly, lz], rotation: [0, 0, 0, 1] });
            }
            if (legIkRBone) {
                const rz = _clamp1(-s * stepAmp);
                const ry = Math.max(0, -s) * liftAmp; // 反相
                bones.push({ name: legIkRBone, frame: f, position: [0, ry, rz], rotation: [0, 0, 0, 1] });
            }
        }
        if (legIkLBone) bones.push({ name: legIkLBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
        if (legIkRBone) bones.push({ name: legIkRBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
    }

      // ========== 🎭 表情情绪轮（动态扫描可用 morph） ==========
    // 不再硬编码少数模型专有名字，而是按语义自动分类可用 morph
    if (!state.boneToggles.emotion) {
        // 表情情绪轮已关闭，跳过
    } else {

    // 忽略纯口型/音素/眨眼 morph，专注表情 morph
    const BLACKLIST_PATTERNS = [
        'まばたき', 'blink', '眨眼', 'wink', 'ウィンク', 'あ', 'い', 'う', 'え', 'お',
        'a ', 'i ', 'u ', 'e ', 'o ',
    ];

    // 按候选关键词给每个 morph 打分，选出最可能的"表情型" morph
    function _scoreMorph(name: string, keywords: string[]): number {
        const nameLC = name.toLowerCase();
        let score = 0;
        for (const kw of keywords) {
            if (name.includes(kw) || nameLC.includes(kw.toLowerCase())) {
                score += 10;
            }
        }
        // 惩罚音素/眨眼这类非表情 morph
        for (const bp of BLACKLIST_PATTERNS) {
            if (name.includes(bp)) score -= 10;
        }
        return score;
    }

    // 候选表情映射：luc (表情类别) → 候选关键词列表
    const EMOTION_CANDIDATES: Record<string, string[]> = {
        smile:   ['にこり', '笑い', 'smile', 'えがお', 'happy', '喜び', '嬉しい', 'よろこび'],
        sad:     ['悲しみ', 'sad', 'cry', '泣き', '哀しみ', 'かなしみ'],
        angry:   ['怒り', 'angry', 'いかり', 'むっ', 'まゆ'],
        surprise: ['びっくり', 'surprise', 'おどろき', '驚き', 'wonder', 'わお'],
        worry:   ['困る', 'worry', 'こまる', '悩み', 'なやみ', '困惑'],
        serious: ['真面目', 'serious', 'まじめ', 'じと目', 'じと'],
        shy:     ['照れ', 'shy', 'てれ', 'はにかみ', '恥ずかしい'],
        wink:    ['ウィンク', 'wink', 'ういんく', 'win'],
    };

    // 为每个表情类别选出得分最高的 morph
    const emotionMorphs = new Map<string, string>();
    for (const [category, keywords] of Object.entries(EMOTION_CANDIDATES)) {
        let bestName: string | null = null;
        let bestScore = 0;
        for (const mName of morphNames) {
            const score = _scoreMorph(mName, keywords);
            if (score > bestScore) {
                bestScore = score;
                bestName = mName;
            }
        }
        if (bestName) {
            emotionMorphs.set(category, bestName);
        }
    }

    // 验证 morph 名能否被 Shift-JIS 编码（不能编码的在 VMD 中会乱码，babylon-mmd 找不到匹配）
    for (const [k, n] of emotionMorphs) {
        if (!canEncodeName(n)) {
            console.log(`[procedural-motion] 表情 morph "${k}=${n}" 无法编码为 Shift-JIS，跳过`);
            emotionMorphs.delete(k);
        }
    }

    // 如果没有找到任何表情 morph，跳过所有情绪逻辑
    const foundEmotions = Array.from(emotionMorphs.entries()).filter(([k]) => k !== 'wink');
    if (foundEmotions.length > 0) {
        console.log(`[procedural-motion] 表情 morph 匹配: [${foundEmotions.map(([k, n]) => `${k}=${n}`).join(', ')}]`);
        // 微表情专用（surprise 和 wink 短闪用，不加入主轮换）
        const surpriseMorph = emotionMorphs.get('surprise') ?? null;
        const winkMorph = emotionMorphs.get('wink') ?? null;

        // 1. 主表情轮换：每 1 小节（4 拍）切换一种情绪，权重 0.5~0.8
        const cycleBeats = 4; // 4 拍切换一次
        const cycleFrames = beatFrames * cycleBeats;
        const cycleCount = Math.min(foundEmotions.length, Math.floor(loopFrames / cycleFrames));
        const availEmo = foundEmotions.slice(0, cycleCount);

        for (let ci = 0; ci < availEmo.length; ci++) {
            const [_, morphName] = availEmo[ci];
            const start = cycleFrames * ci;
            const end = Math.min(start + cycleFrames - 1, loopFrames);
            // 顺滑切入切出：1/4 周期淡入，1/4 周期淡出
            const fadeIn = Math.floor(beatFrames * 0.3);
            const fadeOut = Math.max(end - Math.floor(beatFrames * 0.3), start + fadeIn);
            const weight = 0.5 + 0.3 * intensity;
            // 淡入段
            morphs.push({ name: morphName, frame: start, weight: 0 });
            morphs.push({ name: morphName, frame: start + fadeIn, weight: weight });
            // 维持段
            morphs.push({ name: morphName, frame: fadeOut, weight: weight });
            // 淡出段
            morphs.push({ name: morphName, frame: end, weight: 0 });
        }

        // 2. 微表情点缀：在每小节强拍附近随机闪现 surprise 或 wink（仅 6~8 帧）
        const accentMorph = surpriseMorph ?? winkMorph;
        if (accentMorph) {
            const measureCount = Math.min(4, Math.floor(loopFrames / (beatFrames * 2)));
            for (let m = 0; m < measureCount; m++) {
                const base = m * beatFrames * 2;
                const rand = (m * 7 + 3) % 10;
                if (rand < 3) {
                    const t = base + Math.floor(beatFrames * 0.2);
                    if (t + 6 <= loopFrames) {
                        const w = 0.5 + 0.3 * intensity;
                        morphs.push({ name: accentMorph, frame: t, weight: 0 });
                        morphs.push({ name: accentMorph, frame: t + 1, weight: w });
                        morphs.push({ name: accentMorph, frame: t + 3, weight: w });
                        morphs.push({ name: accentMorph, frame: t + 6, weight: 0 });
                    }
                }
            }
        }

        // 3. 害羞表情在副歌位置（倒数 2 小节）插入
        const shyMorph = emotionMorphs.get('shy') ?? null;
        if (shyMorph) {
            const shyStart = loopFrames - beatFrames * 4;
            if (shyStart > 0) {
                morphs.push({ name: shyMorph, frame: shyStart, weight: 0 });
                morphs.push({ name: shyMorph, frame: shyStart + Math.floor(beatFrames * 0.5), weight: 0.6 * intensity });
                morphs.push({ name: shyMorph, frame: shyStart + beatFrames * 2, weight: 0.6 * intensity });
                morphs.push({ name: shyMorph, frame: shyStart + beatFrames * 2 + 2, weight: 0 });
            }
        }
    } else {
        console.warn('[procedural-motion] 未找到任何表情 morph，跳过情绪轮');
    }
    } // ← 表情情绪轮 else 块结束
    // 按骨骼类型分配插值曲线（受 interpOverride 控制）
    const _override = state.interpOverride;
    let _overrideInterp: typeof INTERP_SHARP | null = null;
    if (_override === 'sharp') _overrideInterp = INTERP_SHARP;
    else if (_override === 'ease-in-out') _overrideInterp = INTERP_EASE_IN_OUT;
    else if (_override === 'ease-out') _overrideInterp = INTERP_EASE_OUT;

    for (const b of bones) {
        if (_overrideInterp) {
            b.interp = _overrideInterp;
            continue;
        }
        const n = b.name;
        // 手臂摆动 → EASE_OUT（快速启动慢停）
        if (n === larmBone || n === rarmBone) {
            b.interp = INTERP_EASE_OUT;
        }
        // 中心弹跳 / 腰扭转 / 足IK踏步 → SHARP（锐利节拍感）
        else if (n === centerBone || n === waistBone || n === legIkLBone || n === legIkRBone) {
            b.interp = INTERP_SHARP;
        }
        // 其余（肩/手腕/头/上半身/上半身2/全親/グルーブ）→ EASE_IN_OUT
        else {
            b.interp = INTERP_EASE_IN_OUT;
        }
    }
    return buildVmd(bones, morphs, PROC_VMD_NAME_AUTODANCE);
}

// ============================================================================
//  Lifelike 生成（极微叠加层 — 叠加在任何动画上增加生命力）
//  与 Idle 的区别：Idle 替换动画，Lifelike 叠加在已有动画上。
//  特点：幅度极小、多频率叠加、不干扰主动画。
// ============================================================================
export function generateLifelikeVmd(
    state: ProcMotionState,
    morphNames: string[] = [],
    boneNames: string[] = []
): ArrayBuffer {
    const safeSpeed = Math.max(0.1, Math.min(10, state.speed));
    const intensity = state.lifelikeIntensity;
    // 10s 循环（足够长避免明显循环感）
    const loopFrames = Math.min(MAX_FRAMES, Math.round(300 / safeSpeed));
    const bones: BoneKeyFrame[] = [];
    const morphs: MorphKeyFrame[] = [];

    // ---------- 骨骼匹配 ----------
    const centerBone = _matchBone(boneNames, BONE_CENTER_CANDIDATES);
    const upperBone = _matchBone(boneNames, BONE_UPPER_CANDIDATES);
    const upper2Bone = _matchBone(boneNames, BONE_UPPER2_CANDIDATES);
    const neckBone = _matchBone(boneNames, BONE_NECK_CANDIDATES);
    const headBone = _matchBone(boneNames, BONE_HEAD_CANDIDATES);
    const waistBone = _matchBone(boneNames, BONE_WAIST_CANDIDATES);
    const allParentBone = _matchBone(boneNames, BONE_ALLPARENT_CANDIDATES);
    const shoulderLBone = _matchBone(boneNames, BONE_SHOULDER_L_CANDIDATES);
    const shoulderRBone = _matchBone(boneNames, BONE_SHOULDER_R_CANDIDATES);
    const larmBone = _matchBone(boneNames, BONE_LARM_CANDIDATES);
    const rarmBone = _matchBone(boneNames, BONE_RARM_CANDIDATES);
    const wristLBone = _matchBone(boneNames, BONE_WRIST_L_CANDIDATES);
    const wristRBone = _matchBone(boneNames, BONE_WRIST_R_CANDIDATES);

    // ---- 呼吸（上半身 + 颈部，双频叠加更自然） ----
    if ((upperBone || neckBone) && state.boneToggles.upper) {
        const breathAmp = 0.015 * intensity; // 比 idle 的 0.03 小一半
        for (let f = 0; f <= loopFrames; f += 3) {
            const t = f / loopFrames;
            // 双频叠加：主呼吸 ~4s + 次呼吸 ~6s
            const breathMain = Math.sin(t * Math.PI * 2) * breathAmp;
            const breathSub = Math.sin(t * Math.PI * 2 * 0.67 + 0.8) * breathAmp * 0.4;
            const rx = _clamp1(breathMain + breathSub);
            const w = Math.sqrt(Math.max(0, 1 - rx * rx));
            if (upperBone) {
                bones.push({ name: upperBone, frame: f, position: [0, 0, 0], rotation: [rx, 0, 0, w] });
            }
            if (neckBone) {
                const nrx = _clamp1(rx * 0.5);
                const nw = Math.sqrt(Math.max(0, 1 - nrx * nrx));
                bones.push({ name: neckBone, frame: f, position: [0, 0, 0], rotation: [nrx, 0, 0, nw] });
            }
        }
        if (upperBone) bones.push({ name: upperBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
        if (neckBone) bones.push({ name: neckBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
    }

    // ---- 上半身2（微扭转，不规则频率） ----
    if (upper2Bone && state.boneToggles.upper2) {
        const amp2 = 0.008 * intensity;
        for (let f = 0; f <= loopFrames; f += 3) {
            const t = f / loopFrames;
            const rx = _clamp1(Math.sin(t * Math.PI * 2 * 0.43 + 1.2) * amp2);
            const ry = _clamp1(Math.sin(t * Math.PI * 2 * 0.31 + 0.5) * amp2 * 0.6);
            const w = Math.sqrt(Math.max(0, 1 - rx * rx - ry * ry));
            bones.push({ name: upper2Bone, frame: f, position: [0, 0, 0], rotation: [rx, ry, 0, w] });
        }
        bones.push({ name: upper2Bone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
    }

    // ---- 重心漂移（极慢不规则漂移，像真人站立时的重心调整） ----
    if (centerBone && state.boneToggles.center) {
        const driftAmp = 0.012 * intensity;
        const bobAmp = 0.003 * intensity;
        for (let f = 0; f <= loopFrames; f += 3) {
            const t = f / loopFrames;
            // 三个不相干频率叠加，避免周期感
            const rz = _clamp1(
                Math.sin(t * Math.PI * 2 * 0.15 + 0.3) * driftAmp * 0.6 +
                Math.sin(t * Math.PI * 2 * 0.23 + 1.7) * driftAmp * 0.3 +
                Math.sin(t * Math.PI * 2 * 0.37 + 2.9) * driftAmp * 0.1
            );
            const rx = _clamp1(Math.sin(t * Math.PI * 2 * 0.11 + 0.9) * driftAmp * 0.3);
            const w = Math.sqrt(Math.max(0, 1 - rx * rx - rz * rz));
            const bobY = Math.sin(t * Math.PI * 2 * 0.5) * bobAmp;
            bones.push({ name: centerBone, frame: f, position: [0, bobY, 0], rotation: [rx, 0, rz, w] });
        }
        bones.push({ name: centerBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
    }

    // ---- 头部（微摆，多频不规则） ----
    if (headBone && state.boneToggles.head) {
        const headAmp = 0.01 * intensity;
        for (let f = 0; f <= loopFrames; f += 3) {
            const t = f / loopFrames;
            const rz = _clamp1(Math.sin(t * Math.PI * 2 * 0.19 + 0.7) * headAmp * 0.5 +
                               Math.sin(t * Math.PI * 2 * 0.31 + 2.1) * headAmp * 0.3);
            const rx = _clamp1(Math.sin(t * Math.PI * 2 * 0.13 + 1.4) * headAmp * 0.3);
            const ry = _clamp1(Math.sin(t * Math.PI * 2 * 0.09 + 0.3) * headAmp * 0.2);
            const w = Math.sqrt(Math.max(0, 1 - rz * rz - rx * rx - ry * ry));
            bones.push({ name: headBone, frame: f, position: [0, 0, 0], rotation: [rx, ry, rz, w] });
        }
        bones.push({ name: headBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
    }

    // ---- 腰（微扭，极低频） ----
    if (waistBone && state.boneToggles.waist) {
        const waistAmp = 0.008 * intensity;
        for (let f = 0; f <= loopFrames; f += 3) {
            const t = f / loopFrames;
            const rz = _clamp1(Math.sin(t * Math.PI * 2 * 0.17 + 1.1) * waistAmp);
            const w = Math.sqrt(Math.max(0, 1 - rz * rz));
            bones.push({ name: waistBone, frame: f, position: [0, 0, 0], rotation: [0, 0, rz, w] });
        }
        bones.push({ name: waistBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
    }

    // ---- 肩部（微起伏，模拟呼吸联动） ----
    if ((shoulderLBone || shoulderRBone) && state.boneToggles.shoulder) {
        const shoulderAmp = 0.006 * intensity;
        for (let f = 0; f <= loopFrames; f += 3) {
            const t = f / loopFrames;
            const yL = Math.sin(t * Math.PI * 2 + 0.3) * shoulderAmp;
            const yR = Math.sin(t * Math.PI * 2 + 0.7) * shoulderAmp * 0.8;
            const rzL = _clamp1(Math.sin(t * Math.PI * 2 * 0.5 + 0.1) * shoulderAmp * 0.3);
            const rzR = _clamp1(Math.sin(t * Math.PI * 2 * 0.5 + 0.5) * shoulderAmp * 0.3);
            const wL = Math.sqrt(Math.max(0, 1 - rzL * rzL));
            const wR = Math.sqrt(Math.max(0, 1 - rzR * rzR));
            if (shoulderLBone) {
                bones.push({ name: shoulderLBone, frame: f, position: [0, yL, 0], rotation: [0, 0, rzL, wL] });
            }
            if (shoulderRBone) {
                bones.push({ name: shoulderRBone, frame: f, position: [0, yR, 0], rotation: [0, 0, rzR, wR] });
            }
        }
        if (shoulderLBone) bones.push({ name: shoulderLBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
        if (shoulderRBone) bones.push({ name: shoulderRBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
    }

    // ---- 手臂（极微自然钟摆，不干扰主动画） ----
    if ((larmBone || rarmBone) && state.boneToggles.arm) {
        const armAmp = 0.012 * intensity;
        for (let f = 0; f <= loopFrames; f += 3) {
            const t = f / loopFrames;
            const rz = _clamp1(Math.sin(t * Math.PI * 2 * 0.25 + 1.5) * armAmp);
            const w = Math.sqrt(Math.max(0, 1 - rz * rz));
            if (larmBone) {
                bones.push({ name: larmBone, frame: f, position: [0, 0, 0], rotation: [0, 0, rz, w] });
            }
            if (rarmBone) {
                bones.push({ name: rarmBone, frame: f, position: [0, 0, 0], rotation: [0, 0, -rz, w] });
            }
        }
        if (larmBone) bones.push({ name: larmBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
        if (rarmBone) bones.push({ name: rarmBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
    }

    // ---- 手腕（极微晃动） ----
    if ((wristLBone || wristRBone) && state.boneToggles.wrist) {
        const wristAmp = 0.008 * intensity;
        for (let f = 0; f <= loopFrames; f += 3) {
            const t = f / loopFrames;
            const rx = _clamp1(Math.sin(t * Math.PI * 2 * 0.33 + 0.8) * wristAmp);
            const w = Math.sqrt(Math.max(0, 1 - rx * rx));
            if (wristLBone) {
                bones.push({ name: wristLBone, frame: f, position: [0, 0, 0], rotation: [rx, 0, 0, w] });
            }
            if (wristRBone) {
                const rxR = _clamp1(Math.sin(t * Math.PI * 2 * 0.33 + 1.1) * wristAmp);
                const wR = Math.sqrt(Math.max(0, 1 - rxR * rxR));
                bones.push({ name: wristRBone, frame: f, position: [0, 0, 0], rotation: [rxR, 0, 0, wR] });
            }
        }
        if (wristLBone) bones.push({ name: wristLBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
        if (wristRBone) bones.push({ name: wristRBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
    }

    // ---- 全ての親（极微整体晃动） ----
    if (allParentBone && state.boneToggles.allParent) {
        const parentAmp = 0.003 * intensity;
        for (let f = 0; f <= loopFrames; f += 4) {
            const t = f / loopFrames;
            const rx = _clamp1(Math.sin(t * Math.PI * 2 * 0.08 + 1.1) * parentAmp);
            const rz = _clamp1(Math.sin(t * Math.PI * 2 * 0.12 + 2.3) * parentAmp);
            const w = Math.sqrt(Math.max(0, 1 - rx * rx - rz * rz));
            bones.push({ name: allParentBone, frame: f, position: [0, 0, 0], rotation: [rx, 0, rz, w] });
        }
        bones.push({ name: allParentBone, frame: loopFrames, position: [0, 0, 0], rotation: [0, 0, 0, 1] });
    }

    // ---- 微表情（偶尔的极微 morph 变化） ----
    if (state.boneToggles.emotion) {
        const BLINK_BLACKLIST = ['まばたき', 'blink', '眨眼', 'wink'];
        const emotionCandidates = morphNames.filter(m => !BLINK_BLACKLIST.some(b => m.includes(b)));
        // 选取前 3 个可用 morph 做极微闪烁
        const selected = emotionCandidates.slice(0, 3);
        for (let mi = 0; mi < selected.length; mi++) {
            const mName = selected[mi];
            // 每个 morph 在不同时间点做极短闪烁（2~4帧）
            const offset = (mi * loopFrames / selected.length);
            const flickerStart = Math.round(offset + loopFrames * 0.1);
            if (flickerStart + 4 <= loopFrames) {
                const w = 0.15 * intensity;
                morphs.push({ name: mName, frame: flickerStart, weight: 0 });
                morphs.push({ name: mName, frame: flickerStart + 1, weight: w });
                morphs.push({ name: mName, frame: flickerStart + 3, weight: w });
                morphs.push({ name: mName, frame: flickerStart + 4, weight: 0 });
            }
        }
    }

    // 全部用 EASE_IN_OUT（柔和）
    for (const b of bones) {
        b.interp = INTERP_EASE_IN_OUT;
    }
    return buildVmd(bones, morphs, PROC_VMD_NAME_LIFELIKE);
}

// ============================================================================
//  状态判断函数（不变）
// ============================================================================
export function shouldAutoDance(audioPlaying: boolean, mode: ProcMotionMode): boolean {
    if (mode === 'idle') {
        return false;
    }
    if (mode === 'autodance') {
        return true;
    }
    return audioPlaying; // 'off' = auto mode
}

export function shouldIdle(
    audioPlaying: boolean,
    hasUserVmd: boolean,
    mode: ProcMotionMode
): boolean {
    return (
        !audioPlaying && !hasUserVmd && (mode === 'idle' || mode === 'off' || mode === 'autodance')
    );
}

// vmd-writer.ts — 正确的二进制 VMD 写入器
// [doc:architecture] 程序化动作子系统 — VMD 二进制生成
// 帧格式确认自 babylon-mmd/esm/Loader/Parser/vmdObject.js:
//   BoneKeyFrameBytes = 15+4+12+16+64 = 111
//   MorphKeyFrameBytes = 15+4+4 = 23

import Encoding from 'encoding-japanese';

export interface BoneKeyFrame {
    name: string; // 骨骼名（Shift-JIS 编码）
    frame: number; // 帧号 (30fps)
    position: [number, number, number];
    rotation: [number, number, number, number]; // 四元数 (x,y,z,w)
    interp?: InterpCurve; // 插值曲线，默认 LINEAR
}

export interface MorphKeyFrame {
    name: string; // morph 名
    frame: number;
    weight: number; // 0..1
}

// VMD 插值曲线预设（64 字节 = 16 组 × 4 字节 [x1,y1,x2,y2]，值域 0-127）
export interface InterpCurve {
    x1: number; y1: number;
    x2: number; y2: number;
}
export const INTERP_LINEAR: InterpCurve = { x1: 20, y1: 20, x2: 107, y2: 107 };
export const INTERP_EASE_IN_OUT: InterpCurve = { x1: 20, y1: 40, x2: 80, y2: 107 };
export const INTERP_EASE_OUT: InterpCurve = { x1: 20, y1: 80, x2: 107, y2: 107 };
export const INTERP_EASE_IN: InterpCurve = { x1: 20, y1: 20, x2: 40, y2: 107 };
export const INTERP_SHARP: InterpCurve = { x1: 30, y1: 10, x2: 90, y2: 107 };

export const BONE_FRAME_SIZE = 111;
export const MORPH_FRAME_SIZE = 23;
const SIGNATURE = 'Vocaloid Motion Data 0002\0'; // 30 bytes
const DEFAULT_MODEL_NAME = 'Procedural'; // ≤20 bytes

/** 将字符串编码为 Shift-JIS 字节数组，截断/填充至 maxBytes。使用 encoding-japanese 完整覆盖 JIS X 0208。 */
function encodeShiftJis(str: string, maxBytes: number): Uint8Array {
    const sjisArr = Encoding.convert(str, {
        to: 'SJIS',
        from: 'UNICODE',
        type: 'array',
    });
    const clamped = sjisArr.slice(0, maxBytes);
    const result = new Uint8Array(maxBytes);
    result.set(clamped);
    return result;
}

/** Shift-JIS 编码字符串到 15 字节（空字节 0x00 填充）。 */
function encodeBoneName(name: string): Uint8Array {
    return encodeShiftJis(name, 15);
}

/** Shift-JIS 编码字符串到 20 字节（模型名字段用）。 */
function encodeModelName(name: string): Uint8Array {
    return encodeShiftJis(name, 20);
}

/** 检查名称能否被完整编码为 Shift-JIS（round-trip 无误）。 */
export function canEncodeName(name: string): boolean {
    const sjisArr = Encoding.convert(name, {
        to: 'SJIS',
        from: 'UNICODE',
        type: 'array',
    });
    const roundTrip = Encoding.convert(sjisArr, {
        to: 'UNICODE',
        from: 'SJIS',
        type: 'string',
    });
    return roundTrip === name;
}

/** 构建单个骨骼关键帧 (111 bytes)。插值用线性默认值。 */
export function buildBoneFrame(frame: BoneKeyFrame): ArrayBuffer {
    const buf = new ArrayBuffer(BONE_FRAME_SIZE);
    const view = new DataView(buf);
    let off = 0;
    const nameBytes = encodeBoneName(frame.name);
    for (let i = 0; i < 15; i++) {
        view.setUint8(off++, nameBytes[i]);
    }
    view.setUint32(off, frame.frame, true);
    off += 4;
    view.setFloat32(off, frame.position[0], true);
    off += 4;
    view.setFloat32(off, frame.position[1], true);
    off += 4;
    view.setFloat32(off, frame.position[2], true);
    off += 4;
    view.setFloat32(off, frame.rotation[0], true);
    off += 4;
    view.setFloat32(off, frame.rotation[1], true);
    off += 4;
    view.setFloat32(off, frame.rotation[2], true);
    off += 4;
    view.setFloat32(off, frame.rotation[3], true);
    off += 4;
    // 64 bytes 插值：16 组 × 4 字节 [x1,y1,x2,y2]，默认 LINEAR
    const interp = frame.interp ?? INTERP_LINEAR;
    for (let i = 0; i < 16; i++) {
        view.setUint8(off++, interp.x1);
        view.setUint8(off++, interp.y1);
        view.setUint8(off++, interp.x2);
        view.setUint8(off++, interp.y2);
    }
    return buf;
}

/** 构建单个 morph 关键帧 (23 bytes)。 */
export function buildMorphFrame(frame: MorphKeyFrame): ArrayBuffer {
    const buf = new ArrayBuffer(MORPH_FRAME_SIZE);
    const view = new DataView(buf);
    let off = 0;
    const nameBytes = encodeBoneName(frame.name);
    for (let i = 0; i < 15; i++) {
        view.setUint8(off++, nameBytes[i]);
    }
    view.setUint32(off, frame.frame, true);
    off += 4;
    view.setFloat32(off, frame.weight, true);
    off += 4;
    return buf;
}

/** 构建完整 VMD ArrayBuffer。
 *  结构: 30(sig) + 20(model) + 4(boneCount) + boneFrames + 4(morphCount) + morphFrames
 *       + 4(cameraCount=0) + 4(lightCount=0) + 4(selfShadowCount=0) + 4(ikCount=0) */
export function buildVmd(
    boneFrames: BoneKeyFrame[],
    morphFrames: MorphKeyFrame[] = [],
    modelName: string = DEFAULT_MODEL_NAME
): ArrayBuffer {
    // 确保帧按帧号排序，防止解析器插值异常
    boneFrames.sort((a, b) => a.frame - b.frame);
    morphFrames.sort((a, b) => a.frame - b.frame);

    const headerSize = 30 + 20 + 4;
    const boneSize = boneFrames.length * BONE_FRAME_SIZE;
    const morphSize = morphFrames.length * MORPH_FRAME_SIZE;
    const trailer = 4 + 4 + 4 + 4; // camera + light + selfShadow + ik counts (all 0)
    const total = headerSize + boneSize + 4 + morphSize + trailer;
    const buf = new ArrayBuffer(total);
    const view = new DataView(buf);
    const u8 = new Uint8Array(buf);
    let off = 0;

    // Signature (30 bytes)
    const sig = new TextEncoder().encode(SIGNATURE);
    for (let i = 0; i < 30; i++) {
        u8[off++] = sig[i] ?? 0;
    }

    // Model name (20 bytes, Shift-JIS 编码)
    const modelNameBytes = encodeModelName(modelName);
    for (let i = 0; i < 20; i++) {
        u8[off++] = modelNameBytes[i];
    }

    // Bone frame count + frames
    view.setUint32(off, boneFrames.length, true);
    off += 4;
    for (const f of boneFrames) {
        u8.set(new Uint8Array(buildBoneFrame(f)), off);
        off += BONE_FRAME_SIZE;
    }

    // Morph frame count + frames
    view.setUint32(off, morphFrames.length, true);
    off += 4;
    for (const f of morphFrames) {
        u8.set(new Uint8Array(buildMorphFrame(f)), off);
        off += MORPH_FRAME_SIZE;
    }

    // Trailer: camera / light / selfShadow / ik counts = 0
    for (let i = 0; i < 4; i++) {
        view.setUint32(off, 0, true);
        off += 4;
    }

    return buf;
}

// vpd-parser.ts — VPD 文本姿势文件解析器
// [doc:architecture] 程序化动作子系统 — VPD 解析 + VMD 生成
// VPD 格式：MMD 导出姿势文件，纯文本，记录骨骼变换。
// 本模块解析 VPD 并转换为 VMD 二进制，供 loadVMDMotion 加载。
// VMD 生成委托给 vmd-writer.ts（标准 111/23 字节帧格式）。

import { buildVmd, type BoneKeyFrame, type MorphKeyFrame } from './vmd-writer';

// VPD 解析结果
export interface VPDBoneData {
    name: string;
    position: [number, number, number];
    rotation: [number, number, number, number]; // 四元数
}

export interface VPDMorphData {
    name: string;
    weight: number;
}

export interface VPDPoseData {
    modelName: string;
    bones: VPDBoneData[];
    morphs: VPDMorphData[];
}

// ========== VPD 文本解析 ==========

/** Clean a potential VPD numeric line: remove // comments, ; terminators, and commas.
 *  Returns the cleaned string with space-separated numbers, ready for splitting. */
function _cleanNumericLine(line: string): string {
    return line.replace(/\/\/.*$/, '').replace(/[;,]/g, ' ').trim();
}

/** 解码 VPD 文本（支持 UTF-8 / Shift-JIS 兜底）。
 *  @param buffer 文件原始字节
 *  @returns 解码后的文本字符串 */
export function decodeVPDData(buffer: ArrayBuffer): string {
    const u8 = new Uint8Array(buffer);
    // UTF-8 BOM (0xEF 0xBB 0xBF)
    if (u8[0] === 0xef && u8[1] === 0xbb && u8[2] === 0xbf) {
        return new TextDecoder('utf-8').decode(buffer.slice(3));
    }
    // UTF-16LE BOM (0xFF 0xFE)
    if (u8[0] === 0xff && u8[1] === 0xfe) {
        return new TextDecoder('utf-16le').decode(buffer);
    }
    // 无 BOM → 尝试 UTF-8；若含无效 UTF-8 序列则回退 Shift-JIS
    try {
        const text = new TextDecoder('utf-8', { fatal: true }).decode(buffer);
        return text;
    } catch {
        // Shift-JIS 兜底（部分 MMD 模型导出 VPD 使用 Shift-JIS）
        return new TextDecoder('shift-jis').decode(buffer);
    }
}

/** 解析 VPD 文本为结构化数据。
 *  VPD 格式：骨骼名独立一行，下一行为位置 (x y z)，再下一行为旋转 (x y z w)。*/
export function parseVPDText(text: string): VPDPoseData {
    const lines = text
        .split('\n')
        .map((l) => l.trim())
        .filter((l) => l.length > 0);
    const bones: VPDBoneData[] = [];
    const morphs: VPDMorphData[] = [];
    let modelName = '';
    let i = 0;

    // 匹配骨骼名行：格式 "BoneN:名稱" 或纯名称，且后缀两行是数字
    // 排除已知元数据关键字，防止误匹配
    const _nonBonePrefix = /^(?:Vocaloid|model|\/\/|;|\{|\}|Bone\d+\s|\s*$)/;
    // 仅含数字的行（位置/旋转数据行）
    const _numericLine = /^[-\d.eE\s]+$/;
    // Morph 行格式：MorphN:名称
    const _morphLine = /^Morph\d+(?::|\{)(.+)$/;

    while (i < lines.length) {
        const line = lines[i];

        // 跳过元数据行
        if (_nonBonePrefix.test(line)) {
            if (line.startsWith('model')) {
                const m = line.match(/model\s+"([^"]+)"/);
                if (m) {
                    modelName = m[1];
                }
            }
            i++;
            continue;
        }

        // Morph 解析：MorphN:名称 下一行是单个浮点数 weight
        const morphMatch = line.match(_morphLine);
        if (morphMatch && i + 1 < lines.length) {
            const mName = morphMatch[1].trim();
            const wLine = lines[i + 1].trim();
            const w = Number(wLine);
            if (isFinite(w)) {
                morphs.push({ name: mName, weight: w });
                i += 2;
                continue;
            }
        }

        // 骨骼名匹配：需要后两行都是纯数字行且解析成功
        const nameMatch = line.match(/^(?:Bone\d+(?::|\{))?(.+)$/);
        if (nameMatch && i + 2 < lines.length) {
            const name = nameMatch[1].trim();
            // 清理数字行（移除 // 注释、; 终止符、逗号），兼容两种 VPD 格式
            const posClean = _cleanNumericLine(lines[i + 1]);
            const rotClean = _cleanNumericLine(lines[i + 2]);
            if (_numericLine.test(posClean) && _numericLine.test(rotClean)) {
                const posParts = posClean.split(/\s+/).map(Number);
                const rotParts = rotClean.split(/\s+/).map(Number);
                if (
                    posParts.length >= 3 &&
                    rotParts.length >= 4 &&
                    posParts.every((v: number) => isFinite(v)) &&
                    rotParts.every((v: number) => isFinite(v))
                ) {
                    bones.push({
                        name,
                        position: [posParts[0], posParts[1], posParts[2]],
                        rotation: [rotParts[0], rotParts[1], rotParts[2], rotParts[3]],
                    });
                    i += 3;
                    continue;
                }
            }
        }
        i++;
    }
    return { modelName, bones, morphs };
}

// ========== VMD 生成（委托 vmd-writer.ts）==========

/** 将 VPD 姿势数据转换为标准 VMD 二进制数据。
 *  所有骨骼帧写入帧号 0（静止姿势）。
 *  @param pose VPD 解析结果
 *  @returns 标准 VMD ArrayBuffer */
export function poseDataToVmdBuffer(pose: VPDPoseData): ArrayBuffer {
    const boneFrames: BoneKeyFrame[] = pose.bones.map((b) => ({
        name: b.name,
        frame: 0, // VPD 是静止姿势，所有帧在帧 0
        position: b.position,
        rotation: b.rotation,
    }));
    const morphFrames: MorphKeyFrame[] = (pose.morphs || []).map((m) => ({
        name: m.name,
        frame: 0,
        weight: m.weight,
    }));
    return buildVmd(boneFrames, morphFrames, pose.modelName || 'VPDPose');
}

/** 从 ArrayBuffer（VPD 文件内容）解析并生成 VMD。
 *  @param buffer VPD 文件原始字节
 *  @returns 标准 VMD ArrayBuffer */
export function loadVPDFromBuffer(buffer: ArrayBuffer): ArrayBuffer {
    const text = decodeVPDData(buffer);
    const pose = parseVPDText(text);
    if (pose.bones.length === 0) {
        throw new Error('VPD: no bone data found');
    }
    return poseDataToVmdBuffer(pose);
}

// [doc:architecture] Outfit Overlay — FBX 布料叠加层加载/骨骼重定向/生命周期
// 职责: 从 MD 导出的 FBX 加载叠加 mesh，绑定到 PMX skeleton，管理隐藏/恢复

import { Mesh } from '@babylonjs/core/Meshes/mesh';
import { Skeleton } from '@babylonjs/core/Bones/skeleton';
import { ImportMeshAsync } from '@babylonjs/core/Loading/sceneLoader';
import type { Scene } from '@babylonjs/core/scene';

import { type ModelInstance } from '../core/config';

// ============================================================
// URL helpers
// ============================================================

function _encodePath(path: string): string {
    return path
        .replace(/\\/g, '/')
        .split('/')
        .map((p) => encodeURIComponent(p))
        .join('/');
}

// ============================================================
// Skeleton retargeting
// ============================================================

/**
 * 将 FBX skeleton 的 bone 按 name 匹配到 PMX runtimeBones，
 * 重建 bone weight index 映射，使 FBX mesh 跟随 PMX 骨骼动画。
 *
 * @returns true = 成功重定向，false = 匹配率过低，应降级为静态叠加
 */
function retargetSkeleton(
    inst: ModelInstance,
    fbxMeshes: Mesh[]
): boolean {
    const pmxModel = inst.mmdModel;
    if (!pmxModel) return false;
    // 找到第一个有 skeleton 的 FBX mesh
    const skinned = fbxMeshes.find((m) => m.skeleton != null);
    if (!skinned || !skinned.skeleton) {
        return false;
    }
    const fbxSkeleton = skinned.skeleton;

    // 建立 FBX bone name → PMX runtimeBone 索引的映射
    const pmxRuntimeBones = pmxModel.runtimeBones;
    const pmxBoneNameToIdx = new Map<string, number>();
    for (let i = 0; i < pmxRuntimeBones.length; i++) {
        pmxBoneNameToIdx.set(pmxRuntimeBones[i].name, i);
    }

    // 匹配 FBX bones 到 PMX bones
    const fbxToPmxBoneIdx = new Map<number, number>(); // fbx bone index → pmx bone index
    let matchCount = 0;
    for (let i = 0; i < fbxSkeleton.bones.length; i++) {
        const fbxBone = fbxSkeleton.bones[i];
        const pmxIdx = pmxBoneNameToIdx.get(fbxBone.name);
        if (pmxIdx !== undefined) {
            fbxToPmxBoneIdx.set(i, pmxIdx);
            matchCount++;
        }
    }

    const matchRate = matchCount / fbxSkeleton.bones.length;
    if (matchRate < 0.5) {
        console.warn(
            `[outfit-overlay] Skeleton retarget failed: only ${matchCount}/${fbxSkeleton.bones.length} bones matched (${Math.round(matchRate * 100)}%)`
        );
        return false;
    }

    console.info(
        `[outfit-overlay] Skeleton retarget: ${matchCount}/${fbxSkeleton.bones.length} bones matched (${Math.round(matchRate * 100)}%)`
    );

    // 获取 PMX 的 Babylon.js skeleton（从 rootMesh metadata 获取）
    const rootMeta = inst.rootMesh.metadata as { skeleton?: Skeleton } | undefined;
    const pmxSkeleton = rootMeta?.skeleton;
    if (!pmxSkeleton) {
        console.warn('[outfit-overlay] PMX model has no skeleton in metadata');
        return false;
    }

    // 对每个 skinned mesh：重建 bone weight index 映射
    for (const mesh of fbxMeshes) {
        if (!mesh.skeleton) continue;

        // 获取 mesh 的 bone weight buffer
        const matricesWeights = mesh.getVerticesData('matricesWeights');
        const matricesIndices = mesh.getVerticesData('matricesIndices');
        if (!matricesWeights || !matricesIndices) continue;

        // 重建 matricesIndices：FBX bone index → PMX bone index
        const newIndices = new Float32Array(matricesIndices.length);
        let remapped = 0;
        for (let i = 0; i < matricesIndices.length; i++) {
            const fbxIdx = matricesIndices[i];
            const pmxIdx = fbxToPmxBoneIdx.get(fbxIdx);
            if (pmxIdx !== undefined) {
                newIndices[i] = pmxIdx;
                remapped++;
            } else {
                // 未匹配的 bone → 映射到根 bone (index 0)
                newIndices[i] = 0;
            }
        }

        // 更新 vertex buffer
        mesh.setVerticesData('matricesIndices', newIndices);

        // 切换 skeleton 引用
        mesh.skeleton = pmxSkeleton;
    }

    // 释放 FBX 原 skeleton（不再被任何 mesh 引用）
    try {
        fbxSkeleton.dispose();
    } catch {
        // ignore disposal errors
    }

    return true;
}

// ============================================================
// Load overlay
// ============================================================

/**
 * 加载 FBX overlay 并尝试绑定到模型 skeleton。
 * @param inst 模型实例
 * @param meshFile FBX 相对路径（相对模型目录）
 * @param scene Babylon scene
 * @returns 加载的 mesh 列表，失败返回空数组
 */
export async function loadOverlay(
    inst: ModelInstance,
    meshFile: string,
    scene: Scene
): Promise<Mesh[]> {
    const url = `http://127.0.0.1:${inst.port}/${_encodePath(meshFile)}`;
    console.info(`[outfit-overlay] Loading FBX overlay: ${meshFile}`);

    try {
        const result = await ImportMeshAsync(url, scene);
        const meshes = result.meshes.filter((m): m is Mesh => m instanceof Mesh);

        if (meshes.length === 0) {
            console.warn('[outfit-overlay] FBX loaded but no meshes found');
            return [];
        }

        // 尝试骨骼重定向
        let skeletonOk = false;
        if (inst.mmdModel) {
            skeletonOk = retargetSkeleton(inst, meshes);
        }

        if (!skeletonOk) {
            // 降级：静态叠加，parent 到 rootMesh
            console.info('[outfit-overlay] Falling back to static overlay (parent rootMesh)');
            for (const m of meshes) {
                m.parent = inst.rootMesh;
            }
        }

        // 标记为 overlay（避免被 outfit 纹理替换逻辑处理）
        for (const m of meshes) {
            m.metadata = { ...(m.metadata ?? {}), outfitOverlay: true };
        }

        inst._overlayMeshes = meshes;
        return meshes;
    } catch (err) {
        console.error('[outfit-overlay] Failed to load FBX overlay:', err);
        return [];
    }
}

// ============================================================
// Material hide/restore
// ============================================================

/**
 * 隐藏指定材质名的 PMX mesh（保存原始可见性用于恢复）。
 */
export function hideMaterials(inst: ModelInstance, materialNames: string[]): void {
    if (!materialNames || materialNames.length === 0) return;

    const nameSet = new Set(materialNames.map((n) => n.toLowerCase()));

    if (!inst._origMaterialVisibility) {
        inst._origMaterialVisibility = new Map();
    }

    for (let i = 0; i < inst.meshes.length; i++) {
        const mesh = inst.meshes[i];
        const mat = mesh.material;
        if (!mat) continue;

        // 按材质名匹配
        if (nameSet.has(mat.name.toLowerCase())) {
            // 只在第一次保存原始可见性
            if (!inst._origMaterialVisibility.has(i)) {
                inst._origMaterialVisibility.set(i, mesh.isEnabled());
            }
            mesh.setEnabled(false);
        }
    }
}

/**
 * 恢复被 hideMaterials 隐藏的 PMX mesh 可见性。
 */
export function restoreMaterials(inst: ModelInstance): void {
    if (!inst._origMaterialVisibility) return;

    for (const [idx, wasVisible] of inst._origMaterialVisibility) {
        if (idx < inst.meshes.length) {
            inst.meshes[idx].setEnabled(wasVisible);
        }
    }
    inst._origMaterialVisibility = undefined;
}

// ============================================================
// Dispose
// ============================================================

/**
 * 释放 overlay mesh 并清理引用。
 */
export function disposeOverlay(inst: ModelInstance): void {
    if (!inst._overlayMeshes) return;

    // 获取 PMX skeleton 用于比较（避免误释放共享 skeleton）
    const rootMeta = inst.rootMesh.metadata as { skeleton?: Skeleton } | undefined;
    const pmxSkeleton = rootMeta?.skeleton;

    const disposedSkeletons = new Set<Skeleton>();
    for (const mesh of inst._overlayMeshes) {
        try {
            // 如果 mesh 有独立 skeleton（未重定向成功），先释放
            if (mesh.skeleton && mesh.skeleton !== pmxSkeleton && !disposedSkeletons.has(mesh.skeleton)) {
                disposedSkeletons.add(mesh.skeleton);
                mesh.skeleton.dispose();
            }
            mesh.dispose();
        } catch {
            // ignore disposal errors
        }
    }
    inst._overlayMeshes = undefined;
}

// [doc:architecture] Outfit — 换装系统核心逻辑（load/apply/reset + 自动发现）

import { Texture } from '@babylonjs/core/Materials/Textures/texture';
import { StandardMaterial } from '@babylonjs/core/Materials/standardMaterial';
import { Color3 } from '@babylonjs/core/Maths/math.color';
import { LoadOutfitFile, ListSubDirs } from '../core/wails-bindings';
import {
    modelRegistry,
    setStatus,
    OutfitFile,
    OutfitVariant,
    OutfitSlot,
    ModelInstance,
} from '../core/config';
import { scene, _catOf } from '../scene/scene';
import { triggerAutoSave } from '../core/config';
import { loadOverlay, hideMaterials, restoreMaterials, disposeOverlay } from './outfit-overlay';

interface MmdStandardMaterial extends StandardMaterial {
    toonTexture: Texture | null;
    sphereTexture: Texture | null;
}

type TextureSlotKey = 'diffuseTexture' | 'toonTexture' | 'sphereTexture' | 'bumpTexture' | 'emissiveTexture';

type OutfitTextureSlot = 'diffuse' | 'toon' | 'spa' | 'normal' | 'emissive';

interface _SlotMapping {
    matName: string;
    slot: string;
    basename: string;
}

function _isSharedTexture(basename: string): boolean {
    const lower = basename.toLowerCase();
    if (lower.startsWith('shared_toon_texture_')) {
        return true;
    }
    return false;
}

function _collectSlotMappings(inst: ModelInstance): _SlotMapping[] {
    const result: _SlotMapping[] = [];
    const seen = new Set<string>();
    for (const mesh of inst.meshes) {
        const sm = mesh.material as StandardMaterial;
        if (!sm) {
            continue;
        }
        const matName = sm.name;
        const mmdSm = sm as MmdStandardMaterial;
        for (const [slot, tex] of [
            ['diffuse', sm.diffuseTexture],
            ['toon', mmdSm.toonTexture],
            ['spa', mmdSm.sphereTexture],
            ['normal', sm.bumpTexture],
            ['emissive', sm.emissiveTexture],
        ] as const) {
            if (!tex) {
                continue;
            }
            const url = (tex as Texture).name || (tex as Texture).url || '';
            const base = url.split('/').pop().split('?')[0] || '';
            if (!base) {
                continue;
            }
            if (_isSharedTexture(base)) {
                continue;
            }
            const key = matName + '|' + slot + '|' + base;
            if (seen.has(key)) {
                continue;
            }
            seen.add(key);
            result.push({ matName, slot, basename: base });
        }
    }
    return result;
}

function _encodePath(path: string): string {
    return path
        .replace(/\\/g, '/')
        .split('/')
        .map((p) => encodeURIComponent(p))
        .join('/');
}

export async function loadOutfits(id: string): Promise<OutfitFile | null> {
    const inst = modelRegistry.get(id);
    if (!inst.filePath) {
        return null;
    }
    try {
        const json = await LoadOutfitFile(inst.filePath);
        if (json) {
            const outfit: OutfitFile = JSON.parse(json);
            if (outfit.version && Array.isArray(outfit.variants)) {
                inst.outfitFile = outfit;
                return outfit;
            }
        }
    } catch {
        /* fall through */
    }

    try {
        const mappings = _collectSlotMappings(inst);
        if (mappings.length === 0) {
            inst.outfitFile = undefined;
            return null;
        }
        const modelDir = inst.filePath.replace(/\\/g, '/').replace(/\/[^/]*$/, '');
        const subdirs = await ListSubDirs(modelDir);
        if (!subdirs || subdirs.length === 0) {
            inst.outfitFile = undefined;
            return null;
        }
        interface _Probe {
            subdir: string;
            matName: string;
            slot: string;
            relPath: string;
            url: string;
        }
        const seenUrl = new Set<string>();
        const probes: _Probe[] = [];
        for (const subdir of subdirs) {
            for (const m of mappings) {
                const relPath = subdir + '/' + m.basename;
                const url = `http://127.0.0.1:${inst.port}/${_encodePath(relPath)}`;
                if (seenUrl.has(url)) {
                    continue;
                }
                seenUrl.add(url);
                probes.push({ subdir, matName: m.matName, slot: m.slot, relPath, url });
            }
        }
        const headCache = new Map<string, boolean>();
        // 并发限制：避免对大量子目录同时发起数百个 HEAD 请求
        const HEAD_CONCURRENCY = 6;
        const semaphore = { count: 0 };
        const withLimit = async <T>(fn: () => Promise<T>): Promise<T> => {
            while (semaphore.count >= HEAD_CONCURRENCY) {
                await new Promise((r) => setTimeout(r, 10));
            }
            semaphore.count++;
            try {
                return await fn();
            } finally {
                semaphore.count--;
            }
        };
        const results = await Promise.all(
            subdirs.map(async (subdir): Promise<OutfitVariant | null> => {
                const byMaterial: Record<string, OutfitSlot> = {};
                let hasAny = false;
                const subdirProbes = probes.filter((p) => p.subdir === subdir);
                await Promise.all(
                    subdirProbes.map(async (p) => {
                        let ok: boolean;
                        if (headCache.has(p.url)) {
                            ok = headCache.get(p.url)!;
                        } else {
                            ok = await withLimit(async () => {
                                try {
                                    const resp = await fetch(p.url, { method: 'HEAD' });
                                    return resp.ok;
                                } catch {
                                    return false;
                                }
                            });
                            headCache.set(p.url, ok);
                        }
                        if (!ok) {
                            return;
                        }
                        if (!byMaterial[p.matName]) {
                            byMaterial[p.matName] = {};
                        }
                        (byMaterial[p.matName] as Record<string, string>)[p.slot] = p.relPath;
                        hasAny = true;
                    })
                );
                return hasAny ? { name: subdir, byMaterial } : null;
            })
        );
        const variantList: OutfitVariant[] = results.filter(Boolean) as OutfitVariant[];
        if (variantList.length === 0) {
            inst.outfitFile = undefined;
            return null;
        }
        const outfit: OutfitFile = { version: 1, variants: variantList };
        inst.outfitFile = outfit;
        return outfit;
    } catch {
        inst.outfitFile = undefined;
        return null;
    }
}

async function _applySlot(
    sm: StandardMaterial,
    slot: TextureSlotKey,
    newPath: string | null,
    origTex: Texture | null,
    port: number
): Promise<void> {
    const mmdSm = sm as MmdStandardMaterial & Record<TextureSlotKey, Texture | null>;
    const cur = mmdSm[slot];
    if (newPath) {
        const url = `http://127.0.0.1:${port}/${_encodePath(newPath)}`;
        const newTex = new Texture(url, scene);
        let loaded = false;
        await new Promise<void>((resolve) => {
            if (newTex.isReady()) {
                loaded = true;
                resolve();
                return;
            }
            const obs = newTex.onLoadObservable.add(() => {
                newTex.onLoadObservable.remove(obs);
                loaded = true;
                resolve();
            });
            setTimeout(() => {
                newTex.onLoadObservable.remove(obs);
                resolve(); // 超时：loaded 保持 false
            }, 5000);
        });
        // 仅加载成功时才替换纹理；超时则 dispose 并保留原纹理
        if (loaded) {
            if (cur && cur !== origTex) {
                cur.dispose();
            }
            mmdSm[slot] = newTex;
        } else {
            newTex.dispose();
        }
    } else {
        if (origTex) {
            if (cur && cur !== origTex) {
                cur.dispose();
            }
            mmdSm[slot] = origTex;
        }
    }
}

function _getSlotFor(
    variant: OutfitVariant | undefined,
    smName: string,
    cat: string,
    slotKey: OutfitTextureSlot
): string | null {
    if (!variant) {
        return null;
    }
    const v =
        variant.byMaterial?.[smName]?.[slotKey] ??
        variant.byCategory?.[cat]?.[slotKey] ??
        variant.all?.[slotKey];
    return v ?? null;
}

function _getParamsFor(
    variant: OutfitVariant | undefined,
    smName: string,
    cat: string
): OutfitSlot['params'] | undefined {
    if (!variant) {
        return undefined;
    }
    return (
        variant.byMaterial?.[smName]?.params ??
        variant.byCategory?.[cat]?.params ??
        variant.all?.params
    );
}

function _getTintFor(
    variant: OutfitVariant | undefined,
    smName: string,
    cat: string
): [number, number, number] | undefined {
    if (!variant) {
        return undefined;
    }
    const t =
        variant.byMaterial?.[smName]?.tint ??
        variant.byCategory?.[cat]?.tint ??
        variant.all?.tint;
    return t;
}

function _applyOutfitParams(
    sm: StandardMaterial,
    params: OutfitSlot['params'],
    orig: {
        diffuseR: number;
        diffuseG: number;
        diffuseB: number;
        specularR: number;
        specularG: number;
        specularB: number;
        specularPower: number;
        ambientR: number;
        ambientG: number;
        ambientB: number;
    }
): void {
    if (!params) {
        return;
    }
    if (params.diffuseMul !== undefined) {
        sm.diffuseColor.set(
            orig.diffuseR * params.diffuseMul,
            orig.diffuseG * params.diffuseMul,
            orig.diffuseB * params.diffuseMul
        );
    }
    if (params.specularMul !== undefined) {
        sm.specularColor.set(
            orig.specularR * params.specularMul,
            orig.specularG * params.specularMul,
            orig.specularB * params.specularMul
        );
    }
    if (params.shininess !== undefined) {
        sm.specularPower = params.shininess;
    }
    if (params.ambientMul !== undefined) {
        sm.ambientColor.set(
            orig.ambientR * params.ambientMul,
            orig.ambientG * params.ambientMul,
            orig.ambientB * params.ambientMul
        );
    }
}

function _applyOutfitTint(sm: StandardMaterial, tint: [number, number, number]): void {
    sm.diffuseColor.multiplyInPlace(new Color3(tint[0], tint[1], tint[2]));
}

function _captureOrigParams(inst: ModelInstance): void {
    if (inst._origParams) {
        return;
    }
    inst._origParams = new Map();
    for (let mi = 0; mi < inst.meshes.length; mi++) {
        const sm = inst.meshes[mi].material as StandardMaterial;
        if (!sm) {
            continue;
        }
        inst._origParams.set(mi, {
            diffuseR: sm.diffuseColor.r,
            diffuseG: sm.diffuseColor.g,
            diffuseB: sm.diffuseColor.b,
            specularR: sm.specularColor.r,
            specularG: sm.specularColor.g,
            specularB: sm.specularColor.b,
            specularPower: sm.specularPower,
            ambientR: sm.ambientColor.r,
            ambientG: sm.ambientColor.g,
            ambientB: sm.ambientColor.b,
        });
    }
}

export async function applyOutfitVariant(id: string, variantName: string): Promise<void> {
    const inst = modelRegistry.get(id);
    if (!inst.outfitFile) {
        return;
    }
    const variant =
        variantName === '默认'
            ? undefined
            : inst.outfitFile.variants.find((v) => v.name === variantName);
    if (!variant && variantName !== '默认') {
        return;
    }

    if (!inst._origTextures) {
        inst._origTextures = new Map();
        for (let mi = 0; mi < inst.meshes.length; mi++) {
            const sm = inst.meshes[mi].material as StandardMaterial;
            if (!sm) {
                continue;
            }
            const mmdSm = sm as MmdStandardMaterial;
            inst._origTextures.set(mi, {
                diffuse: sm.diffuseTexture as Texture | null,
                toon: mmdSm.toonTexture,
                spa: mmdSm.sphereTexture,
                normal: sm.bumpTexture as Texture | null,
                emissive: sm.emissiveTexture as Texture | null,
            });
        }
    }
    _captureOrigParams(inst);

    const promises: Promise<void>[] = [];

    // overlay 处理（与纹理替换并行）：清理旧 overlay → 加载新 overlay → 隐藏 PMX 布料
    promises.push(
        (async () => {
            if (inst._overlayMeshes) {
                disposeOverlay(inst);
                restoreMaterials(inst);
            }
            if (variant?.meshFile) {
                const meshes = await loadOverlay(inst, variant.meshFile, scene);
                if (meshes.length > 0 && variant.hideMaterials) {
                    hideMaterials(inst, variant.hideMaterials);
                }
            }
        })()
    );

    for (let mi = 0; mi < inst.meshes.length; mi++) {
        const sm = inst.meshes[mi].material as StandardMaterial;
        if (!sm) {
            continue;
        }
        const origTex = inst._origTextures.get(mi);
        if (!origTex) {
            continue;
        }
        const origParams = inst._origParams.get(mi)!;
        const cat = _catOf(sm.name);

        promises.push(
            _applySlot(
                sm,
                'diffuseTexture',
                _getSlotFor(variant, sm.name, cat, 'diffuse'),
                origTex.diffuse,
                inst.port
            )
        );
        promises.push(
            _applySlot(
                sm,
                'toonTexture',
                _getSlotFor(variant, sm.name, cat, 'toon'),
                origTex.toon,
                inst.port
            )
        );
        promises.push(
            _applySlot(
                sm,
                'sphereTexture',
                _getSlotFor(variant, sm.name, cat, 'spa'),
                origTex.spa,
                inst.port
            )
        );
        promises.push(
            _applySlot(
                sm,
                'bumpTexture',
                _getSlotFor(variant, sm.name, cat, 'normal'),
                origTex.normal,
                inst.port
            )
        );
        promises.push(
            _applySlot(
                sm,
                'emissiveTexture',
                _getSlotFor(variant, sm.name, cat, 'emissive'),
                origTex.emissive,
                inst.port
            )
        );

        const slotParams = _getParamsFor(variant, sm.name, cat);
        if (slotParams) {
            _applyOutfitParams(sm, slotParams, origParams);
        }

        const tint = _getTintFor(variant, sm.name, cat);
        if (tint) {
            _applyOutfitTint(sm, tint);
        }
    }

    await Promise.all(promises);
    inst.activeVariant = variantName;
    setStatus(`✓ 已切换服装: ${variantName}`, true);
    triggerAutoSave();
}

export function resetOutfit(id: string): void {
    const inst = modelRegistry.get(id);
    if (!inst) {
        return;
    }
    if (inst._origTextures) {
        for (let mi = 0; mi < inst.meshes.length; mi++) {
            const sm = inst.meshes[mi].material as StandardMaterial;
            if (!sm) {
                continue;
            }
            const orig = inst._origTextures.get(mi);
            if (!orig) {
                continue;
            }
            _applySlot(sm, 'diffuseTexture', null, orig.diffuse, inst.port);
            _applySlot(sm, 'toonTexture', null, orig.toon, inst.port);
            _applySlot(sm, 'sphereTexture', null, orig.spa, inst.port);
            _applySlot(sm, 'bumpTexture', null, orig.normal, inst.port);
            _applySlot(sm, 'emissiveTexture', null, orig.emissive, inst.port);
        }
    }
    if (inst._origParams) {
        for (let mi = 0; mi < inst.meshes.length; mi++) {
            const sm = inst.meshes[mi].material as StandardMaterial;
            if (!sm) {
                continue;
            }
            const p = inst._origParams.get(mi);
            if (!p) {
                continue;
            }
            sm.diffuseColor.set(p.diffuseR, p.diffuseG, p.diffuseB);
            sm.specularColor.set(p.specularR, p.specularG, p.specularB);
            sm.specularPower = p.specularPower;
            sm.ambientColor.set(p.ambientR, p.ambientG, p.ambientB);
        }
    }
    // 清理 overlay mesh 并恢复被隐藏的 PMX 材质
    disposeOverlay(inst);
    restoreMaterials(inst);

    inst.activeVariant = undefined;
    inst.outfitFile = undefined;
    inst._origTextures = undefined;
    inst._origParams = undefined;
    triggerAutoSave();
}

