// ======== 诊断 API ========

/** 布料状态诊断信息 */
export interface ClothDiagnostics {
    enabled: boolean;
    instanceCount: number;
    activeModelIds: string[];
    currentMeshVisible: boolean;
    particleCount: number;
    constraintCount: number;
}

/** 获取当前布料诊断信息 */
export function getClothDiagnostics(): ClothDiagnostics {
    const instances = modelManager ? Array.from(modelManager.clothInstances.entries()) : [];
    const focusedId = focusedModelId || '';
    const focusedCloth = modelManager?.clothInstances.get(focusedId);
    return {
        enabled: envState.clothEnabled,
        instanceCount: instances.length,
        activeModelIds: instances.map(([id]) => id),
        currentMeshVisible: focusedCloth?.mesh?.isVisible ?? false,
        particleCount: focusedCloth?.solver?.particles?.length ?? 0,
        constraintCount: focusedCloth?.solver?.constraints?.length ?? 0,
    };
}

/** 在状态栏报告布料状态 */
function _reportClothStatus(): void {
    const diag = getClothDiagnostics();
    if (diag.enabled) {
        if (diag.instanceCount > 0) {
            setStatus(
                `✓ 布料模拟已启用 (${diag.instanceCount} 例, ${diag.particleCount} 粒子, ${diag.constraintCount} 约束)`,
                true,
            );
        } else {
            setStatus('⚠ 布料已启用但未找到活跃实例', false);
        }
    } else {
        setStatus('布料模拟已关闭', true);
    }
}

/**
 * XPBD 布料模拟 — 程序化网格生成 + 物理模拟 + Babylon.js Mesh 更新
 *
 * 从锚定骨骼出发，生成环形粒子网格，用 XPBD 约束模拟布料运动。
 * 每帧：
 *   1. 将最上层粒子固定到骨骼世界位置
 *   2. solver.step(dt)
 *   3. 更新 Babylon.js mesh 顶点 + 法线
 *
 * 职能纯粹：接收 Babylon Scene + XPBD Solver + SDF Collider → 产出布料对象。
 */

import { XpbdSolver } from './xpbd-solver';
import type { SdfCollider } from './xpbd-collider';

import { Scene } from '@babylonjs/core/scene';
import { Mesh } from '@babylonjs/core/Meshes/mesh';
import { VertexData } from '@babylonjs/core/Meshes/mesh.vertexData';
import { VertexBuffer } from '@babylonjs/core/Buffers/buffer';
import { StandardMaterial } from '@babylonjs/core/Materials/standardMaterial';
import { Color3 } from '@babylonjs/core/Maths/math.color';

// ============================================================
// 类型
// ============================================================

/** 调试更新回调类型 */
let _debugUpdateFn: ((solver: XpbdSolver, collider: SdfCollider | null) => void) | null = null;

/** 设置调试更新回调（由 cloth-manager 调用） */
export function setDebugUpdateFn(fn: ((solver: XpbdSolver, collider: SdfCollider | null) => void) | null): void {
    _debugUpdateFn = fn;
}

/** 布料拓扑类型 */
export type ClothTopology = 'skirt' | 'tube' | 'cape' | 'rope';

/** 布料配置（生成参数） */
export interface ClothConfig {
    /** 锚定骨骼名（如 "腰"），用于外部查询世界矩阵 */
    anchorBone: string;
    /** 拓扑类型 */
    topology: ClothTopology;
    /** 内半径（腰部开口半径），default 0.12 */
    innerRadius: number;
    /** 裙长/布料长度（从锚点向下），default 0.6 */
    length: number;
    /** 裙摆角度（度），0=直筒 | 90=最大扩张，default 15 */
    slope: number;
    /** 水平分段数，default 24 */
    segmentsH: number;
    /** 垂直分段数（层数），default 12 */
    segmentsV: number;
    /** 粒子碰撞半径，default 0.03 */
    particleRadius: number;
    /** 布料柔度（compliance），0=完全刚性，default 0.001 */
    compliance: number;
    /** 布料总质量，均分给非固定粒子，default 0.5 */
    totalMass: number;
    /** 布料阻尼（覆盖 solver 默认值），0~1，default 0.96 */
    damping: number;
    /** 重力倍率，default 1.0 */
    gravityScale: number;
    /** 弯曲约束柔度，default = compliance * 5（比距离约束更软） */
    bendCompliance: number;
    /**
     * 骨骼碰撞过滤列表。
     * 空数组 = 检测所有骨骼碰撞体；非空 = 仅检测列出的骨骼名。
     * 与 VmdLayer.boneFilter 语义一致，用于防止布料穿透特定骨骼。
     * 可选，默认值在 DEFAULT_CLOTH_CONFIG 中为 []。
     */
    boneFilter?: string[];

    /**
     * 风场启用标志。
     * 当为 true 且 windStrength > 0 时，每子步对非固定粒子施加风场力。
     * 默认 false（无风），保持向后兼容。
     */
    windEnabled: boolean;

    /** 风向单位向量 [x, y, z]，默认 [0, 0, 0]。 */
    windDirection: [number, number, number];

    /** 风力强度，越大风越强，默认 0（无风）。 */
    windStrength: number;
}

export const DEFAULT_CLOTH_CONFIG: ClothConfig = {
    anchorBone: '腰',
    topology: 'skirt',
    innerRadius: 0.12,
    length: 0.6,
    slope: 15,
    segmentsH: 24,
    segmentsV: 12,
    particleRadius: 0.03,
    compliance: 0.001,
    totalMass: 0.5,
    damping: 0.96,
    gravityScale: 1.0,
    bendCompliance: 0.005,
    boneFilter: [],
    windEnabled: false,
    windDirection: [0, 0, 0],
    windStrength: 0,
};

/** 布料实例（运行时对象） */
export interface ClothInstance {
    config: ClothConfig;
    solver: XpbdSolver;
    /** 粒子索引 → 网格 (segmentsH × segmentsV) */
    particleGrid: number[];
    /** 锚定粒子索引（最上层整环），这些粒子 mass=0 */
    anchorIndices: number[];
    /** 每层粒子数 = segmentsH */
    ringSize: number;
    /** 总层数 = segmentsV */
    ringCount: number;
    /** Babylon.js Mesh（程序化生成的独立网格） */
    mesh: Mesh | null;
    /** 网格三角形索引（缓存用于每帧 ComputeNormals） */
    meshIndices: Int32Array;
    /** 顶点位置缓存（每帧复用，避免 GC） */
    _positionCache?: Float32Array;
    /** 法线缓存（每帧复用，避免 GC） */
    _normalCache?: Float32Array;
    /** UV 缓存（创建后不变，仅作记录） */
    _uvCache?: Float32Array;
    /** 是否启用模拟 */
    enabled: boolean;
    /** 锚定骨骼未找到时是否已警告过（只打印一次） */
    _anchorMissingWarned: boolean;
    /** 包围盒是否已刷新过（首帧后刷新一次） */
    _boundingRefreshed: boolean;
    /**
     * 每帧更新回调（由 buildClothUpdateFn 生成后设置）。
     * 接收 deltaTime（秒），由 ModelManager 的渲染观察者每帧调用。
     */
    updateFn?: (deltaTime: number) => void;
}

// ============================================================
// 主工厂函数
// ============================================================

/**
 * 创建布料实例
 *
 * @param scene Babylon.js Scene 对象
 * @param config 布料配置
 * @param collider SDF 胶囊碰撞器（可选，如需身体碰撞）
 * @returns ClothInstance
 */
export function createCloth(
    scene: Scene,
    config: Partial<ClothConfig> = {},
    _collider?: SdfCollider | null
): ClothInstance {
    const cfg = { ...DEFAULT_CLOTH_CONFIG, ...config };
    // 防御: 当 deserializeScene 用旧场景覆盖 clothConfig 后,
    // config.anchorBone 可能为 undefined 或空字符串,
    // spread 会覆盖掉 DEFAULT_CLOTH_CONFIG 中的 '腰' 导致锚定失效。
    if (!cfg.anchorBone) {
        cfg.anchorBone = DEFAULT_CLOTH_CONFIG.anchorBone;
    }
    const solver = new XpbdSolver({
        substeps: 4,
        damping: cfg.damping,
    });
    solver.setGravity(0, -9.8 * cfg.gravityScale, 0);

    // 防御: segmentsH/segmentsV 为 0 或无效时会导致 particleGrid 为空
    const ringSize = Math.max(cfg.segmentsH || DEFAULT_CLOTH_CONFIG.segmentsH, 8);
    const ringCount = Math.max(cfg.segmentsV || DEFAULT_CLOTH_CONFIG.segmentsV, 4);

    // ---- 粒子放置 ----
    const particleGrid: number[] = []; // ringCount × ringSize
    const anchorIndices: number[] = [];
    const nonAnchorMass = cfg.totalMass / (ringSize * (ringCount - 1)); // 顶层固定，其余均分

    for (let row = 0; row < ringCount; row++) {
        const t = row / (ringCount - 1); // 0 (top) → 1 (bottom)
        const y = -t * cfg.length; // Y 向下

        // 半径：top = innerRadius, bottom = innerRadius + length * tan(slopeDeg)
        const slopeRad = (cfg.slope * Math.PI) / 180;
        const r = cfg.innerRadius + t * cfg.length * Math.tan(slopeRad);

        for (let col = 0; col < ringSize; col++) {
            const angle = (col / ringSize) * Math.PI * 2;
            const x = Math.cos(angle) * r;
            const z = Math.sin(angle) * r;

            const mass = row === 0 ? Infinity : nonAnchorMass;
            const idx = solver.addParticle([x, y, z], mass, cfg.particleRadius);
            particleGrid.push(idx);

            if (row === 0) {
                anchorIndices.push(idx);
            }
        }
    }

    // ---- 约束建立 ----

    // 距离约束：水平（同层相邻）+ 垂直（不同层）
    for (let row = 0; row < ringCount; row++) {
        for (let col = 0; col < ringSize; col++) {
            const i = particleGrid[row * ringSize + col];

            // 水平：当前 → 右邻居
            const nextCol = (col + 1) % ringSize;
            const h = particleGrid[row * ringSize + nextCol];
            solver.addDistanceConstraint(i, h, cfg.compliance);

            // 垂直：当前 → 下方
            if (row + 1 < ringCount) {
                const v = particleGrid[(row + 1) * ringSize + col];
                solver.addDistanceConstraint(i, v, cfg.compliance);
            }
        }
    }

    // 弯曲约束：水平 + 垂直 skip-1
    const bendC = cfg.bendCompliance;
    for (let row = 0; row < ringCount; row++) {
        for (let col = 0; col < ringSize; col++) {
            const i = particleGrid[row * ringSize + col];

            // 水平弯曲：skip-1
            const bendH = particleGrid[row * ringSize + ((col + 2) % ringSize)];
            const midH = particleGrid[row * ringSize + ((col + 1) % ringSize)];
            solver.addBendConstraint(i, midH, bendH, bendC);

            // 垂直弯曲：skip-1
            if (row + 2 < ringCount) {
                const bendV = particleGrid[(row + 2) * ringSize + col];
                const midV = particleGrid[(row + 1) * ringSize + col];
                solver.addBendConstraint(i, midV, bendV, bendC);
            }
        }
    }

    // 地面碰撞（默认在很低的位置，防止掉出场景）
    solver.addGroundCollision(-5);

    // ---- Mesh 创建 ----
    const {
        mesh,
        indices: meshIndices,
        uvCache,
        positionCache,
        normalCache,
    } = _createClothMesh(scene, cfg, particleGrid, solver, ringSize, ringCount);

    const instance: ClothInstance = {
        config: cfg,
        solver,
        particleGrid,
        anchorIndices,
        ringSize,
        ringCount,
        mesh,
        meshIndices,
        _positionCache: positionCache,
        _normalCache: normalCache,
        _uvCache: uvCache,
        enabled: true,
        _anchorMissingWarned: false,
        _boundingRefreshed: false,
    };

    return instance;
}

// ============================================================
// 每帧更新
// ============================================================

/**
 * 构建布料更新闭包（在 scene.registerBeforeRender 中调用）
 *
 * @param cloth 布料实例
 * @param anchorMatrixFn 获取骨骼世界矩阵的函数 (boneName → Float32Array[16] 列主序)
 *   同时用于锚定骨骼和碰撞胶囊的骨骼位置更新。
 * @param collider SDF 碰撞器（null 则跳过）
 * @returns beforeRender 回调函数 (deltaTime: number)
 */
export function buildClothUpdateFn(
    cloth: ClothInstance,
    anchorMatrixFn: (boneName: string) => Float32Array | null,
    collider?: SdfCollider | null,
    getTimeScale?: () => number,
): (dt: number) => void {
    // 所有粒子在创建时的局部位置缓存（相对于 anchor bone 初始位置）
    const localOffsets: [number, number, number][] = [];
    // 以第一行锚点粒子的平均位置作为局部原点
    let originX = 0, originY = 0, originZ = 0;
    for (const idx of cloth.anchorIndices) {
        const p = cloth.solver.particles[idx];
        originX += p.p[0];
        originY += p.p[1];
        originZ += p.p[2];
    }
    const n = cloth.anchorIndices.length || 1;
    originX /= n;
    originY /= n;
    originZ /= n;

    for (let i = 0; i < cloth.solver.particles.length; i++) {
        const p = cloth.solver.particles[i];
        localOffsets.push([p.p[0] - originX, p.p[1] - originY, p.p[2] - originZ]);
    }

    let _initialized = false;

    return (dt: number) => {
        if (!cloth.enabled) {
            return;
        }

        const solver = cloth.solver;

        // 1. 锚定粒子跟随骨骼
        const mat = anchorMatrixFn(cloth.config.anchorBone);
        if (mat) {
            cloth._anchorMissingWarned = false;
            const tx = mat[12],
                ty = mat[13],
                tz = mat[14];

            // 首帧：将所有粒子定位到骨骼世界坐标，避免从原点弹跳
            // 需等骨骼矩阵有效（平移不全为零）再执行，否则 MMD runtime 尚未更新
            if (!_initialized) {
                // 检测单位矩阵：平移分量全为零说明骨骼还没算好
                if (tx === 0 && ty === 0 && tz === 0) {
                    return;
                }
                _initialized = true;
                for (let i = 0; i < solver.particles.length; i++) {
                    const [ox, oy, oz] = localOffsets[i];
                    const p = solver.particles[i];
                    p.p[0] = mat[0] * ox + mat[4] * oy + mat[8] * oz + tx;
                    p.p[1] = mat[1] * ox + mat[5] * oy + mat[9] * oz + ty;
                    p.p[2] = mat[2] * ox + mat[6] * oy + mat[10] * oz + tz;
                    p.prevP[0] = p.p[0];
                    p.prevP[1] = p.p[1];
                    p.prevP[2] = p.p[2];
                }
            } else {
                // 后续帧：仅更新锚点粒子
                for (let i = 0; i < cloth.anchorIndices.length; i++) {
                    const idx = cloth.anchorIndices[i];
                    const [lx, ly, lz] = localOffsets[idx];

                    const wx = mat[0] * lx + mat[4] * ly + mat[8] * lz + tx;
                    const wy = mat[1] * lx + mat[5] * ly + mat[9] * lz + ty;
                    const wz = mat[2] * lx + mat[6] * ly + mat[10] * lz + tz;

                    const p = solver.particles[idx];
                    p.p[0] = wx;
                    p.p[1] = wy;
                    p.p[2] = wz;
                }
            }
        } else if (!cloth._anchorMissingWarned) {
            console.warn(
                `[xpbd-cloth] anchor bone "${cloth.config.anchorBone}" not found. ` +
                    'Anchor particles will hold their last position.'
            );
            cloth._anchorMissingWarned = true;
        }

        // 2. 更新碰撞胶囊位置（从骨骼矩阵）
        if (collider) {
            const matrices: (Float32Array | null)[] = [];
            let missingBones = 0;
            for (const cap of collider.capsules) {
                const boneMat = anchorMatrixFn(cap.boneName);
                if (!boneMat) {
                    missingBones++;
                    matrices.push(null); // 标记跳过，避免使用单位矩阵导致胶囊留在原点误碰撞
                } else {
                    matrices.push(boneMat);
                }
            }
            if (missingBones > 0 && !cloth._anchorMissingWarned) {
                console.warn(
                    `[xpbd-cloth] ${missingBones} collision capsule bone(s) not found, ` +
                        'affected capsules will skip collision this frame.'
                );
            }
            collider.updateMatrices(matrices);
            collider.solve(solver);

            // 2.5 同步骨骼碰撞体数据到 solver（用于子步内穿透检测）
            // 拷贝胶囊体引用（center/direction 的 Float32Array 在 updateMatrices 后自动更新）
            solver.boneCollisionEnabled = true;
            solver.collisionCapsules = collider.capsules;
            // 从布料配置传递 boneFilter（空数组 = 检查所有碰撞体）
            solver.boneFilter = cloth.config.boneFilter ?? [];
        } else {
            solver.boneCollisionEnabled = false;
            solver.collisionCapsules = [];
            solver.boneFilter = [];
        }

        // 3. XPBD 步进（支持模拟速度倍率）
        const adjustedDt = getTimeScale ? dt * getTimeScale() : dt;

        // 3.1 从布料配置同步风场参数到求解器
        // 风场力在 solver.step() 内部每子步 Verlet 积分中施加，
        // 此处仅同步配置，使求解器自身的 windEnabled/windDirection/windStrength 生效。
        solver.windEnabled = cloth.config.windEnabled;
        solver.windDirection = cloth.config.windDirection;
        solver.windStrength = cloth.config.windStrength;

        solver.step(adjustedDt);

        // 4. 更新 Mesh 顶点
        _updateClothMesh(cloth);

        // 5. 更新调试可视化（如果启用）
        if (_debugUpdateFn) {
            _debugUpdateFn(solver, collider);
        }
    };
}

// ============================================================
// Mesh 创建 & 更新
// ============================================================

/**
 * 从粒子网格创建可更新的 Babylon.js Mesh
 *
 * 网格拓扑: ringCount 个环，每个环 ringSize 个顶点
 * 三角形: 每个 {row, col} → 两个三角形:
 *   (row,col), (row+1,col), (row,col+1)  上三角
 *   (row+1,col), (row+1,col+1), (row,col+1)  下三角
 */
function _createClothMesh(
    scene: Scene,
    cfg: ClothConfig,
    particleGrid: number[],
    solver: XpbdSolver,
    ringSize: number,
    ringCount: number
): {
    mesh: Mesh | null;
    indices: Int32Array;
    uvCache: Float32Array;
    positionCache: Float32Array;
    normalCache: Float32Array;
} {
    // 收集顶点位置（从粒子读取初始 position）
    const positions: number[] = [];
    // UV: 按柱面展开，u = col/ringSize, v = row/(ringCount-1)
    const uvs: number[] = [];

    for (let row = 0; row < ringCount; row++) {
        const v = row / (ringCount - 1);
        for (let col = 0; col < ringSize; col++) {
            const u = col / ringSize;
            const pIdx = particleGrid[row * ringSize + col];
            const p = solver.particles[pIdx];
            positions.push(p.p[0], p.p[1], p.p[2]);
            uvs.push(u, v);
        }
    }

    // 索引
    const indexArray: number[] = [];
    for (let row = 0; row < ringCount - 1; row++) {
        for (let col = 0; col < ringSize; col++) {
            const a = row * ringSize + col;
            const b = (row + 1) * ringSize + col;
            const c = row * ringSize + ((col + 1) % ringSize);
            const d = (row + 1) * ringSize + ((col + 1) % ringSize);

            // 上三角 (a, b, c)
            indexArray.push(a, b, c);
            // 下三角 (b, d, c)
            indexArray.push(b, d, c);
        }
    }

    // 用 ComputeNormals 计算初始法线
    const posArr = new Float32Array(positions);
    const normals = new Float32Array(positions.length);
    VertexData.ComputeNormals(posArr, new Int32Array(indexArray), normals);

    // 创建 Mesh
    const mesh = new Mesh('xpbd_cloth', scene);

    const vertexData = new VertexData();
    vertexData.positions = positions;
    vertexData.indices = indexArray;
    vertexData.normals = Array.from(normals);
    vertexData.uvs = uvs;
    vertexData.applyToMesh(mesh);

    // 材质
    const mat = new StandardMaterial('xpbd_cloth_mat', scene);
    mat.diffuseColor = new Color3(0.2, 0.3, 0.8);
    mat.alpha = 0.85;
    mat.backFaceCulling = false;
    mat.specularColor = new Color3(0.1, 0.1, 0.1);
    mesh.material = mat;

    return {
        mesh,
        indices: new Int32Array(indexArray),
        uvCache: new Float32Array(uvs),
        positionCache: posArr,
        normalCache: normals,
    };
}

/**
 * 每帧更新 Mesh 顶点位置 + 用 ComputeNormals 重算法线
 * 复用 Float32Array 缓存，避免每帧分配内存导致 GC 压力
 */
function _updateClothMesh(cloth: ClothInstance): void {
    if (!cloth.mesh) {
        return;
    }

    const { solver, particleGrid, meshIndices } = cloth;
    const count = particleGrid.length;
    const floatCount = count * 3;

    // 复用或分配位置缓存
    let positions = cloth._positionCache;
    if (!positions || positions.length !== floatCount) {
        positions = new Float32Array(floatCount);
        cloth._positionCache = positions;
    }

    // 更新位置
    for (let i = 0; i < count; i++) {
        const pIdx = particleGrid[i];
        const p = solver.particles[pIdx];
        const off = i * 3;
        positions[off] = p.p[0];
        positions[off + 1] = p.p[1];
        positions[off + 2] = p.p[2];
    }

    // 复用或分配法线缓存
    let normals = cloth._normalCache;
    if (!normals || normals.length !== floatCount) {
        normals = new Float32Array(floatCount);
        cloth._normalCache = normals;
    }

    // 根据当前顶点位置 + 三角形索引，用 Babylon 工具重算法线
    VertexData.ComputeNormals(positions, meshIndices, normals);

    cloth.mesh.updateVerticesData(VertexBuffer.PositionKind, positions, false, true);
    cloth.mesh.updateVerticesData(VertexBuffer.NormalKind, normals, false, true);

    // 首帧后刷新包围盒，防止 Babylon.js 因旧包围盒剔除 mesh
    if (!cloth._boundingRefreshed) {
        cloth._boundingRefreshed = true;
        cloth.mesh.refreshBoundingInfo?.();
    }
}

// ============================================================
// 销毁
// ============================================================

/**
 * 销毁布料实例（释放 solver 资源和 mesh）
 */
export function disposeCloth(cloth: ClothInstance): void {
    cloth.solver.reset();
    cloth.mesh?.material?.dispose?.();
    cloth.mesh?.dispose?.();
    cloth.enabled = false;
}

/**
 * XPBD 粒子/mesh 可视化调试 (XPBD Renderer)
 *
 * 在 Babylon.js 场景中渲染调试几何：
 * - 粒子小球体
 * - 约束彩色线段（复用 LinesMesh，每帧更新顶点）
 * - 胶囊碰撞体线框（四元数对齐方向）
 * - 布料/软体变形 mesh
 *
 * 职能纯粹：接收 Babylon Scene + XPBD 数据 → 更新可视化对象。
 * 不参与物理计算。
 */

import { Scene } from '@babylonjs/core/scene';
import { Mesh } from '@babylonjs/core/Meshes/mesh';
import { LinesMesh } from '@babylonjs/core/Meshes/linesMesh';
import { MeshBuilder } from '@babylonjs/core/Meshes/meshBuilder';
import { StandardMaterial } from '@babylonjs/core/Materials/standardMaterial';
import { Color3 } from '@babylonjs/core/Maths/math.color';
import { Vector3, Quaternion } from '@babylonjs/core/Maths/math.vector';
import type { XpbdSolver } from './xpbd-solver';
import type { SdfCollider } from './xpbd-collider';

// ============================================================
// 接口
// ============================================================

export interface XpbdRendererConfig {
    particleColor: [number, number, number, number];
    constraintColor: [number, number, number, number];
    colliderColor: [number, number, number, number];
    particleSphereRadius: number;
    constraintLineRadius: number;
}

const DEFAULT_CONFIG: XpbdRendererConfig = {
    particleColor: [0, 1, 0.5, 0.8],
    constraintColor: [0.3, 0.6, 1, 0.6],
    colliderColor: [1, 0.3, 0.3, 0.5],
    particleSphereRadius: 0.03,
    constraintLineRadius: 0.01,
};

// ============================================================
// 可视化对象管理器
// ============================================================

export class XpbdRenderer {
    private scene: Scene;

    // 粒子可视化
    private particleMeshes: Mesh[] = [];
    private particleVisible = false;

    // 约束可视化（复用单条 LinesMesh，每帧 updateVerticesData）
    private constraintLines: LinesMesh | null = null;
    private bendLines: LinesMesh | null = null;
    private constraintVisible = false;

    // 胶囊可视化
    private colliderMeshes: Mesh[] = [];
    private colliderVisible = false;

    // 材质缓存
    private particleMat: StandardMaterial | null = null;
    private constraintMat: StandardMaterial | null = null;
    private colliderMat: StandardMaterial | null = null;

    // 缓存 Vector3 / Quaternion 避免每帧分配
    private _tmpVec = new Vector3();
    private _tmpQuat = new Quaternion();
    private _yAxis = new Vector3(0, 1, 0);

    config: XpbdRendererConfig;

    constructor(scene: Scene, config?: Partial<XpbdRendererConfig>) {
        this.scene = scene;
        this.config = { ...DEFAULT_CONFIG, ...config };
        this._initMaterials();
    }

    // ---- 材质初始化 ----

    private _initMaterials(): void {
        const [pr, pg, pb, pa] = this.config.particleColor;
        this.particleMat = new StandardMaterial('xpbd_particle', this.scene);
        this.particleMat.diffuseColor = new Color3(pr, pg, pb);
        this.particleMat.alpha = pa;
        this.particleMat.emissiveColor = new Color3(pr * 0.5, pg * 0.5, pb * 0.5);
        this.particleMat.backFaceCulling = false;

        const [cr, cg, cb, ca] = this.config.constraintColor;
        this.constraintMat = new StandardMaterial('xpbd_constraint', this.scene);
        this.constraintMat.diffuseColor = new Color3(cr, cg, cb);
        this.constraintMat.alpha = ca;
        this.constraintMat.emissiveColor = new Color3(cr, cg, cb);
        this.constraintMat.backFaceCulling = false;

        const [sr, sg, sb, sa] = this.config.colliderColor;
        this.colliderMat = new StandardMaterial('xpbd_collider', this.scene);
        this.colliderMat.diffuseColor = new Color3(sr, sg, sb);
        this.colliderMat.alpha = sa;
        this.colliderMat.wireframe = true;
        this.colliderMat.backFaceCulling = false;
    }

    // ---- 粒子可视化 ----

    updateParticles(solver: XpbdSolver): void {
        // 确保有足够的 mesh
        while (this.particleMeshes.length < solver.particles.length) {
            const sphere = MeshBuilder.CreateSphere(
                `xpbd_particle_${this.particleMeshes.length}`,
                { diameter: this.config.particleSphereRadius * 2, segments: 8 },
                this.scene
            );
            if (this.particleMat) {
                sphere.material = this.particleMat;
            }
            sphere.isVisible = this.particleVisible;
            this.particleMeshes.push(sphere);
        }

        // 清理多余的
        while (this.particleMeshes.length > solver.particles.length) {
            const m = this.particleMeshes.pop();
            m?.dispose();
        }

        // 更新位置
        for (let i = 0; i < solver.particles.length; i++) {
            const p = solver.particles[i];
            const mesh = this.particleMeshes[i];
            if (mesh) {
                mesh.position.x = p.p[0];
                mesh.position.y = p.p[1];
                mesh.position.z = p.p[2];
            }
        }
    }

    showParticles(visible: boolean): void {
        this.particleVisible = visible;
        for (const m of this.particleMeshes) {
            m.isVisible = visible;
        }
    }

    // ---- 约束可视化 ----

    /**
     * 渲染线条约束。首帧创建 with updatable:true 的 LinesMesh，
     * 后续帧仅通过 updateVerticesData 更新顶点，避免 GC。
     */
    updateConstraints(solver: XpbdSolver): void {
        if (!this.constraintVisible) {
            if (this.constraintLines) {
                this.constraintLines.dispose();
                this.constraintLines = null;
            }
            return;
        }

        const distancePositions: number[] = [];
        const bendPositions: number[] = [];
        for (const c of solver.constraints) {
            if (c.type === 'volume' || c.type === 'ground') {
                continue;
            }
            const i = c.indices[0];
            const k = c.indices[c.indices.length - 1];
            const pi = solver.particles[i];
            const pk = solver.particles[k];
            if (!pi || !pk) {
                continue;
            }
            if (c.type === 'bend') {
                bendPositions.push(pi.p[0], pi.p[1], pi.p[2]);
                bendPositions.push(pk.p[0], pk.p[1], pk.p[2]);
            } else {
                distancePositions.push(pi.p[0], pi.p[1], pi.p[2]);
                distancePositions.push(pk.p[0], pk.p[1], pk.p[2]);
            }
        }

        // 距离约束用蓝色，弯曲约束用黄色
        this._updateConstraintLines(distancePositions, [0.3, 0.6, 1]);
        this._updateBendLines(bendPositions, [1, 0.8, 0.2]);
    }

    private _updateConstraintLines(positions: number[], color: [number, number, number]): void {
        if (positions.length === 0) {
            if (this.constraintLines) {
                this.constraintLines.dispose();
                this.constraintLines = null;
            }
            return;
        }

        const pointCount = positions.length / 3;
        if (!this.constraintLines || this.constraintLines.getTotalVertices() !== pointCount) {
            if (this.constraintLines) {
                this.constraintLines.dispose();
            }
            const pts: Vector3[] = [];
            for (let i = 0; i < positions.length; i += 3) {
                pts.push(new Vector3(positions[i], positions[i + 1], positions[i + 2]));
            }
            this.constraintLines = MeshBuilder.CreateLines(
                'xpbd_constraints',
                { points: pts, updatable: true },
                this.scene
            ) as LinesMesh;
            this.constraintLines.color = new Color3(color[0], color[1], color[2]);
        } else {
            this.constraintLines.updateVerticesData(
                'position',
                new Float32Array(positions),
                false,
                true
            );
        }
    }

    private _updateBendLines(positions: number[], color: [number, number, number]): void {
        if (positions.length === 0) {
            if (this.bendLines) {
                this.bendLines.dispose();
                this.bendLines = null;
            }
            return;
        }

        const pointCount = positions.length / 3;
        if (!this.bendLines || this.bendLines.getTotalVertices() !== pointCount) {
            if (this.bendLines) {
                this.bendLines.dispose();
            }
            const pts: Vector3[] = [];
            for (let i = 0; i < positions.length; i += 3) {
                pts.push(new Vector3(positions[i], positions[i + 1], positions[i + 2]));
            }
            this.bendLines = MeshBuilder.CreateLines(
                'xpbd_bend',
                { points: pts, updatable: true },
                this.scene
            ) as LinesMesh;
            this.bendLines.color = new Color3(color[0], color[1], color[2]);
        } else {
            this.bendLines.updateVerticesData(
                'position',
                new Float32Array(positions),
                false,
                true
            );
        }
    }

    showConstraints(visible: boolean): void {
        this.constraintVisible = visible;
    }

    // ---- 胶囊碰撞体可视化 ----

    /**
     * 创建胶囊碰撞体线框。圆柱体用 Quaternion 对齐 direction。
     * 每帧销毁重建（调试用，非性能敏感路径）。
     */
    updateColliders(collider: SdfCollider): void {
        for (const m of this.colliderMeshes) {
            m.dispose();
        }
        this.colliderMeshes = [];

        if (!this.colliderVisible) {
            return;
        }

        for (const cap of collider.capsules) {
            if (!cap.enabled) {
                continue;
            }

            const sphere1 = MeshBuilder.CreateSphere(
                `xpbd_collider_${cap.name}`,
                { diameter: cap.radius * 2, segments: 16 },
                this.scene
            );
            const cylinder = MeshBuilder.CreateCylinder(
                `xpbd_collider_cyl_${cap.name}`,
                { height: cap.halfHeight * 2, diameter: cap.radius * 2, tessellation: 16 },
                this.scene
            );
            const sphere2 = MeshBuilder.CreateSphere(
                `xpbd_collider_${cap.name}_bot`,
                { diameter: cap.radius * 2, segments: 16 },
                this.scene
            );

            if (this.colliderMat) {
                sphere1.material = this.colliderMat;
                cylinder.material = this.colliderMat;
                sphere2.material = this.colliderMat;
            }

            // 两端球体位置
            const hh = cap.halfHeight;
            const dir = this._tmpVec.set(cap.direction[0], cap.direction[1], cap.direction[2]);
            sphere1.position.set(
                cap.center[0] + dir.x * hh,
                cap.center[1] + dir.y * hh,
                cap.center[2] + dir.z * hh
            );
            cylinder.position.set(cap.center[0], cap.center[1], cap.center[2]);
            sphere2.position.set(
                cap.center[0] - dir.x * hh,
                cap.center[1] - dir.y * hh,
                cap.center[2] - dir.z * hh
            );

            // 使用四元数对齐圆柱体到 direction（默认沿 Y 轴）
            Quaternion.RotationYawPitchRollToRef(0, 0, 0, this._tmpQuat);
            Quaternion.FromUnitVectorsToRef(this._yAxis, dir, this._tmpQuat);
            cylinder.rotationQuaternion = this._tmpQuat.clone();

            this.colliderMeshes.push(sphere1, cylinder, sphere2);
        }
    }

    showColliders(visible: boolean): void {
        this.colliderVisible = visible;
        for (const m of this.colliderMeshes) {
            m.isVisible = visible;
        }
    }

    // ---- 清理 ----

    dispose(): void {
        this.constraintLines?.dispose();
        this.constraintLines = null;
        this.bendLines?.dispose();
        this.bendLines = null;
        for (const m of this.particleMeshes) {
            m.dispose();
        }
        for (const m of this.colliderMeshes) {
            m.dispose();
        }
        this.particleMeshes = [];
        this.colliderMeshes = [];
        this.particleMat?.dispose();
        this.constraintMat?.dispose();
        this.colliderMat?.dispose();
    }
}

/**
 * XPBD (Extended Position Based Dynamics) 核心引擎
 *
 * 纯 TypeScript 实现，不依赖 WASM Bullet。
 * 用于布料模拟和软体物理，与 PMX 内建刚体链独立运行。
 *
 * 参考: Miles Macklin "XPBD: Position-Based Simulation of Compliant Constrained Dynamics"
 */

// ============================================================
// 接口
// ============================================================

/** 单个 XPBD 粒子 */
export interface XpbdParticle {
    /** 当前位置 [x, y, z] */
    p: Float32Array;
    /** 上一帧位置（Verlet 积分用） */
    prevP: Float32Array;
    /** 速度 [x, y, z] */
    v: Float32Array;
    /** 质量倒数 (1/mass)，0 = 固定/无限质量 */
    invMass: number;
    /** 碰撞半径 */
    radius: number;
}

/** 约束类型 */
export type ConstraintType = 'distance' | 'bend' | 'volume' | 'ground';

/** XPBD 约束 */
export interface XpbdConstraint {
    type: ConstraintType;
    /** 涉及的粒子索引 */
    indices: number[];
    /** 柔度 (compliance)，0 = 完全硬，值越大越软（逆刚度） */
    compliance: number;
    /** 静止值（距离 / 体积） */
    restValue: number;
    /** 拉格朗日乘子累积 */
    lambda: Float32Array;
    /**
     * 刚度 (0~1)，约束修正力度缩放因子。
     * 1.0 = 完全修正（默认），0.0 = 无修正。
     * 与 compliance 独立：compliance 控制弹性，stiffness 缩放单帧修正量。
     */
    stiffness: number;
    /**
     * 约束方向阻尼 (0~1)，沿约束方向的速度衰减系数。
     * 0.0 = 无阻尼（默认），值越大振动衰减越快。
     * 对 Volume 约束暂不生效。
     */
    damping: number;
}

/**
 * 单个骨骼胶囊碰撞体（运行时数据，从 SdfCollider 同步）。
 * 与 xpbd-collider.ts 的 SdfCapsule 一致但不依赖 SdfCollider 类型，
 * 允许 XpbdSolver 在无外部依赖的情况下处理骨骼碰撞。
 */
export interface SolverCapsule {
    /** 胶囊名称（如 "chest"） */
    name: string;
    /** 关联的骨骼名（用于 boneFilter 匹配） */
    boneName: string;
    /** 半径 */
    radius: number;
    /** 半高（中心到端点的距离） */
    halfHeight: number;
    /** 世界空间中心位置 [x, y, z] */
    center: Float32Array;
    /** 世界空间方向（单位向量）[x, y, z] */
    direction: Float32Array;
    /** 启用标志 */
    enabled: boolean;
}

/** 求解器配置 */
export interface XpbdSolverConfig {
    /** 重力 [x, y, z]，默认 [0, -9.8, 0] */
    gravity: [number, number, number];
    /** 子步数，默认 4 */
    substeps: number;
    /** 速度阻尼 (0~1)，每帧衰减，默认 0.98 */
    damping: number;
    /** 地面 Y 坐标，用于默认地面碰撞 */
    groundY: number;
    /** 风场启用标志（默认 false，无风） */
    windEnabled?: boolean;
    /** 风向单位向量 [x, y, z]（默认 [0,0,0]） */
    windDirection?: [number, number, number];
    /** 风速 / 风力强度（默认 0，无风） */
    windStrength?: number;
}

const DEFAULT_CONFIG: XpbdSolverConfig = {
    gravity: [0, -9.8, 0],
    substeps: 4,
    damping: 0.98,
    groundY: -10,
    windEnabled: false,
    windDirection: [0, 0, 0],
    windStrength: 0,
};

/**
 * 使用例（stiffness / damping 参数）：
 *
 * ```ts
 * // 软弹簧（stiffness=0.3 只修正 30%）
 * solver.addDistanceConstraint(a, b, 0, 1.0, 0.3);
 *
 * // 带阻尼的距离约束（damping=0.5 减振）
 * solver.addDistanceConstraint(a, b, 0.01, 0.5, 1.0, 0.5);
 *
 * // 默认值=完全刚性无阻尼（老代码向后兼容）
 * solver.addDistanceConstraint(a, b);    // compliance=0, stiffness=1, damping=0
 * ```
 */

// ============================================================
// XpbdSolver
// ============================================================

export class XpbdSolver {
    particles: XpbdParticle[] = [];
    constraints: XpbdConstraint[] = [];
    gravity: Float32Array;
    substeps: number;
    damping: number;
    groundY: number;

    /** 地面碰撞启用标志 */
    groundCollisionEnabled = false;

    /** 地面弹性系数（0=完全非弹性, 1=完全弹性），default 0.1 */
    restitution = 0.1;

    // ---- 骨骼碰撞体（从 SdfCollider 同步，用于子步内穿透检测） ----

    /** 骨骼碰撞体数组（每帧从 SdfCollider 同步），空数组 = 跳过骨骼碰撞 */
    collisionCapsules: SolverCapsule[] = [];

    /** 骨骼碰撞过滤列表。
     *  空数组 = 检查所有碰撞体；非空 = 仅检查 boneName 在此列表中的碰撞体。
     *  与 VmdLayer.boneFilter 语义一致。 */
    boneFilter: string[] = [];

    /** 主开关：启用后在 _resolvePenetrations() 中子步级别检测粒子-骨骼碰撞 */
    boneCollisionEnabled = false;

    // ---- 风场配置 ----

    /** 风场启用标志（默认 false） */
    windEnabled = false;

    /** 风向单位向量 [x, y, z]（默认 [0, 0, 0] = 无方向） */
    windDirection: [number, number, number] = [0, 0, 0];

    /** 风力强度（越大风越强，默认 0 = 无风） */
    windStrength = 0;

    /** 粒子计数器（用于调试/统计） */
    private _particleCount = 0;

    constructor(config: Partial<XpbdSolverConfig> = {}) {
        const cfg = { ...DEFAULT_CONFIG, ...config };
        this.gravity = new Float32Array(cfg.gravity);
        this.substeps = cfg.substeps;
        this.damping = cfg.damping;
        this.groundY = cfg.groundY;
        // 风场配置（默认值由 DEFAULT_CONFIG 提供，windEnabled=false 则无风）
        this.windEnabled = cfg.windEnabled ?? false;
        this.windDirection = cfg.windDirection ?? [0, 0, 0];
        this.windStrength = cfg.windStrength ?? 0;
    }

    // ---- 粒子管理 ----

    /**
     * 添加一个粒子
     * @returns 粒子索引
     */
    addParticle(pos: [number, number, number] = [0, 0, 0], mass = 0.01, radius = 0.05): number {
        // mass <= 0 或 Infinity → invMass = 0（固定粒子）；NaN → 也视为固定
        const invMass = isFinite(mass) && mass > 0 ? 1.0 / mass : 0;
        const particle: XpbdParticle = {
            p: new Float32Array(pos),
            prevP: new Float32Array(pos),
            v: new Float32Array([0, 0, 0]),
            invMass,
            radius,
        };
        const idx = this.particles.length;
        this.particles.push(particle);
        this._particleCount++;
        return idx;
    }

    /** 批量添加多个粒子 */
    addParticles(
        positions: [number, number, number][],
        masses: number[],
        radii: number[]
    ): number[] {
        const count = positions.length;
        const indices: number[] = [];
        for (let i = 0; i < count; i++) {
            const m = masses[i] ?? 0.01;
            const r = radii[i] ?? 0.05;
            indices.push(this.addParticle(positions[i], m, r));
        }
        return indices;
    }

    /**
     * 软删除粒子——将 invMass 置 0，物理忽略但保持网格占位。
     *
     * 粒子设为固定后，所有涉及该粒子的约束被移除（无需再求解）。
     * 不使用 splice 的原因：外部持有 particleGrid 索引，splice 会导致索引失效。
     */
    removeParticle(idx: number): void {
        if (idx < 0 || idx >= this.particles.length) {
            return;
        }
        const p = this.particles[idx];
        if (p.invMass === 0) {
            return;
        }
        p.invMass = 0;
        this.constraints = this.constraints.filter((c) => !c.indices.includes(idx));
    }

    /** 清空所有粒子和约束 */
    reset(): void {
        this.particles = [];
        this.constraints = [];
        this._particleCount = 0;
    }

    // ---- 约束管理 ----

    /**
     * 添加距离约束（两个粒子之间的固定距离）
     * @param i 粒子 1 索引
     * @param j 粒子 2 索引
     * @param compliance 柔度 (0~1)，默认 0（完全刚性）
     * @param restLength 静止长度，不传则自动使用当前距离
     * @param stiffness 刚度 (0~1)，修正量缩放，默认 1.0（完全修正）
     * @param damping 约束方向阻尼 (0~1)，默认 0.0（无阻尼）
     */
    addDistanceConstraint(
        i: number,
        j: number,
        compliance = 0.0,
        restLength?: number,
        stiffness = 1.0,
        damping = 0.0
    ): void {
        const pi = this.particles[i].p;
        const pj = this.particles[j].p;
        const dx = pi[0] - pj[0];
        const dy = pi[1] - pj[1];
        const dz = pi[2] - pj[2];
        const d = restLength ?? Math.sqrt(dx * dx + dy * dy + dz * dz);

        this.constraints.push({
            type: 'distance',
            indices: [i, j],
            compliance: Math.max(0, compliance),
            restValue: d,
            lambda: new Float32Array(1),
            stiffness: Math.max(0, Math.min(1, stiffness)),
            damping: Math.max(0, Math.min(1, damping)),
        });
    }

    /**
     * 添加弯曲约束（连续三个粒子，保持 i 到 k 的距离）
     * 防止布料过度折叠
     * @param stiffness 刚度 (0~1)，修正量缩放，默认 1.0
     * @param damping 约束方向阻尼 (0~1)，默认 0.0
     */
    addBendConstraint(
        i: number,
        j: number,
        k: number,
        compliance = 0.0,
        restLength?: number,
        stiffness = 1.0,
        damping = 0.0
    ): void {
        const pi = this.particles[i].p;
        const pk = this.particles[k].p;
        const dx = pi[0] - pk[0];
        const dy = pi[1] - pk[1];
        const dz = pi[2] - pk[2];
        const d = restLength ?? Math.sqrt(dx * dx + dy * dy + dz * dz);

        this.constraints.push({
            type: 'bend',
            indices: [i, j, k],
            compliance: Math.max(0, compliance),
            restValue: d,
            lambda: new Float32Array(1),
            stiffness: Math.max(0, Math.min(1, stiffness)),
            damping: Math.max(0, Math.min(1, damping)),
        });
    }

    /**
     * 添加体积约束（四面体体积保持）
     * @param indices 4 个粒子索引（四面体的四个顶点）
     * @param compliance 柔度
     * @param restVolume 静止体积，不传则自动计算
     * @param stiffness 刚度 (0~1)，修正量缩放，默认 1.0
     * @param damping 约束方向阻尼 (0~1)，默认 0.0（对体积约束暂不生效）
     */
    addVolumeConstraint(indices: number[], compliance = 0.0, restVolume?: number, stiffness = 1.0, _damping = 0.0): void {
        if (indices.length !== 4) {
            throw new Error('Volume constraint requires exactly 4 particles');
        }

        const [i0, i1, i2, i3] = indices;
        const p0 = this.particles[i0].p;
        const p1 = this.particles[i1].p;
        const p2 = this.particles[i2].p;
        const p3 = this.particles[i3].p;

        // 四面体体积 = |(p1-p0)·((p2-p0)×(p3-p0))| / 6
        const v = restVolume ?? this._tetraVolume(p0, p1, p2, p3);

        this.constraints.push({
            type: 'volume',
            indices: [...indices],
            compliance: Math.max(0, compliance),
            restValue: v,
            lambda: new Float32Array(1),
            stiffness: Math.max(0, Math.min(1, stiffness)),
            damping: Math.max(0, Math.min(1, _damping)),
        });
    }

    /** 启用地面碰撞（Y 轴向上） */
    addGroundCollision(groundY?: number): void {
        if (groundY !== undefined) {
            this.groundY = groundY;
        }
        this.groundCollisionEnabled = true;
    }

    /** 关闭地面碰撞 */
    disableGroundCollision(): void {
        this.groundCollisionEnabled = false;
    }

    // ---- 核心求解器 ----

    /**
     * 主步进函数，每帧调用一次。
     *
     * 标准 XPBD 流程：每个子步内完成 Verlet 积分 → 约束求解 → 地面碰撞，
     * 确保外力和约束在同一时间尺度（subDt）上交互，子步数增加可提升精度。
     *
     * @param dt 时间步长（秒），如 1/60
     */
    step(dt: number): void {
        if (this.particles.length === 0) {
            return;
        }

        const invDt = 1.0 / dt;
        const subDt = dt / this.substeps;
        const alphaTilde = 1.0 / (subDt * subDt); // compliance → α̃ 转换因子

        // 每个子步：Verlet 积分 + 约束求解 + 地面碰撞
        for (let s = 0; s < this.substeps; s++) {
            // ---- 子步内 Verlet 积分 ----
            for (let i = 0; i < this.particles.length; i++) {
                const p = this.particles[i];
                if (p.invMass === 0) {
                    continue;
                }

                const px = p.p[0],
                    py = p.p[1],
                    pz = p.p[2];
                const prevX = p.prevP[0],
                    prevY = p.prevP[1],
                    prevZ = p.prevP[2];

                // 速度（带阻尼）: v = (p - prevP) * damping / subDt
                let vx = ((px - prevX) * this.damping) / subDt;
                let vy = ((py - prevY) * this.damping) / subDt;
                let vz = ((pz - prevZ) * this.damping) / subDt;

                // 重力: v += gravity * subDt
                vx += this.gravity[0] * subDt;
                vy += this.gravity[1] * subDt;
                vz += this.gravity[2] * subDt;

                // 风场力: v += windDirection * windStrength * subDt（带随机扰动产生自然飘动）
                // 仅在 windEnabled=true 且 windStrength>0 时生效
                if (this.windEnabled && this.windStrength > 0) {
                    // 每粒子随机因子 0.6~1.4，使布料产生自然起伏/飘动效果
                    const flutter = 0.6 + Math.random() * 0.8;
                    vx += this.windDirection[0] * this.windStrength * subDt * flutter;
                    vy += this.windDirection[1] * this.windStrength * subDt * flutter;
                    vz += this.windDirection[2] * this.windStrength * subDt * flutter;
                }

                // 保存旧位置
                p.prevP[0] = px;
                p.prevP[1] = py;
                p.prevP[2] = pz;

                // p += v * subDt
                p.p[0] = px + vx * subDt;
                p.p[1] = py + vy * subDt;
                p.p[2] = pz + vz * subDt;
            }

            // ---- 约束求解 ----
            for (const c of this.constraints) {
                this._solveConstraint(c, alphaTilde, subDt);
            }

            // ---- 粒子间穿透检测 ----
            this._resolvePenetrations();

            // ---- 地面碰撞 ----
            if (this.groundCollisionEnabled) {
                for (let i = 0; i < this.particles.length; i++) {
                    const p = this.particles[i];
                    if (p.invMass === 0) {
                        continue;
                    }
                    const ground = this.groundY + p.radius;
                    if (p.p[1] < ground) {
                        // 垂直速度 = (p - prevP) / subDt，反弹部分速度
                        const vy = (p.p[1] - p.prevP[1]) / subDt;
                        p.p[1] = ground;
                        // prevP: 产生反弹速度（restitution）的反向分量
                        p.prevP[1] = p.p[1] + vy * this.restitution * subDt;
                    }
                }
            }
        }

        // ---- 最终速度更新 ----
        for (let i = 0; i < this.particles.length; i++) {
            const p = this.particles[i];
            if (p.invMass === 0) {
                p.v[0] = 0;
                p.v[1] = 0;
                p.v[2] = 0;
                continue;
            }
            p.v[0] = (p.p[0] - p.prevP[0]) * invDt;
            p.v[1] = (p.p[1] - p.prevP[1]) * invDt;
            p.v[2] = (p.p[2] - p.prevP[2]) * invDt;
        }
    }

    // ---- 内部约束求解 ----

    /**
     * 求解单个约束（XPBD 公式）
     *
     * 距离约束: C(p_i, p_j) = |p_i - p_j| - restLength
     * 弯曲约束: C(p_i, p_k) = |p_i - p_k| - restLength  (skip j in distance)
     * 体积约束: C = 6 * V - restVolume
     *
     * @param subDt 子步时间步长，用于约束阻尼计算
     */
    private _solveConstraint(c: XpbdConstraint, alphaTilde: number, subDt: number): void {
        switch (c.type) {
            case 'distance':
            case 'bend':
                this._solveDistanceConstraint(c, alphaTilde, subDt);
                break;
            case 'volume':
                this._solveVolumeConstraint(c, alphaTilde, subDt);
                break;
        }
    }

    /** 距离/弯曲约束求解 */
    private _solveDistanceConstraint(c: XpbdConstraint, alphaTilde: number, subDt: number): void {
        // 距离约束和弯曲约束都使用两个端点粒子：i 和最后一个粒子 k
        const i = c.indices[0];
        const k = c.indices[c.indices.length - 1];

        const pi = this.particles[i];
        const pk = this.particles[k];

        const dx = pi.p[0] - pk.p[0];
        const dy = pi.p[1] - pk.p[1];
        const dz = pi.p[2] - pk.p[2];
        const dist = Math.sqrt(dx * dx + dy * dy + dz * dz);

        if (dist < 1e-10) {
            return;
        } // 避免除零

        const wSum = pi.invMass + pk.invMass;
        if (wSum < 1e-10) {
            return;
        } // 两个粒子都固定

        // C = dist - restLength
        const C = dist - c.restValue;

        // ∇C·M⁻¹·∇C = pi.invMass + pk.invMass = wSum
        // (梯度是单位方向向量，点乘自身 = 1)
        const denom = wSum + c.compliance * alphaTilde;

        // Δλ = -(C + α̃ * λ) / (∇C·M⁻¹·∇C + α̃)
        const dLambda = -(C + c.compliance * alphaTilde * c.lambda[0]) / denom;
        c.lambda[0] += dLambda;

        // ∇C direction: (pi - pk) / dist
        const nx = dx / dist;
        const ny = dy / dist;
        const nz = dz / dist;

        // ---- 刚度缩放 ----
        // stiffness 缩放修正量：1.0 = 完全修正，0.5 = 半修正，0.0 = 无修正
        const s = c.stiffness;

        // Δp = dLambda * M⁻¹ * ∇C * stiffness
        // ∇C_i = (pi - pk) / dist, ∇C_k = (pk - pi) / dist = -∇C_i
        pi.p[0] += dLambda * pi.invMass * nx * s;
        pi.p[1] += dLambda * pi.invMass * ny * s;
        pi.p[2] += dLambda * pi.invMass * nz * s;

        pk.p[0] -= dLambda * pk.invMass * nx * s;
        pk.p[1] -= dLambda * pk.invMass * ny * s;
        pk.p[2] -= dLambda * pk.invMass * nz * s;

        // ---- 约束方向阻尼 ----
        // 沿约束方向阻尼相对速度，减少振荡
        if (c.damping > 0) {
            // 当前相对速度沿约束方向 (from verlet: v = (p - prevP) / subDt)
            const vix = (pi.p[0] - pi.prevP[0]) / subDt;
            const viy = (pi.p[1] - pi.prevP[1]) / subDt;
            const viz = (pi.p[2] - pi.prevP[2]) / subDt;
            const vkx = (pk.p[0] - pk.prevP[0]) / subDt;
            const vky = (pk.p[1] - pk.prevP[1]) / subDt;
            const vkz = (pk.p[2] - pk.prevP[2]) / subDt;

            // 相对速度沿法线分量
            const relVn = (vix - vkx) * nx + (viy - vky) * ny + (viz - vkz) * nz;

            // 阻尼修正：修改 prevP 以影响下一帧速度
            // impulse = -damping * relVn / wSum
            const dampFactor = c.damping / (wSum + 1e-10);
            const dampDelta = -dampFactor * relVn * subDt;

            pi.prevP[0] += dampDelta * pi.invMass * nx;
            pi.prevP[1] += dampDelta * pi.invMass * ny;
            pi.prevP[2] += dampDelta * pi.invMass * nz;
            pk.prevP[0] -= dampDelta * pk.invMass * nx;
            pk.prevP[1] -= dampDelta * pk.invMass * ny;
            pk.prevP[2] -= dampDelta * pk.invMass * nz;
        }
    }

    /** 体积约束求解（四面体） */
    private _solveVolumeConstraint(c: XpbdConstraint, alphaTilde: number, _subDt: number): void {
        const [i0, i1, i2, i3] = c.indices;
        const p0 = this.particles[i0];
        const p1 = this.particles[i1];
        const p2 = this.particles[i2];
        const p3 = this.particles[i3];

        // 当前体积
        const V = this._tetraVolume(p0.p, p1.p, p2.p, p3.p);

        // 计算梯度（每个顶点的面积法向量 / 3）
        const grads = this._tetraVolumeGradients(p0.p, p1.p, p2.p, p3.p);
        const particles = [p0, p1, p2, p3];

        // ∇C·M⁻¹·∇C = Σ invMass_i * |grad_i|²
        let wSum = 0;
        for (let i = 0; i < 4; i++) {
            const g = grads[i];
            wSum += particles[i].invMass * (g[0] * g[0] + g[1] * g[1] + g[2] * g[2]);
        }
        if (wSum < 1e-10) {
            return;
        }

        const C = 6.0 * V - c.restValue; // 乘以 6 免得梯度太小
        const denom = wSum + c.compliance * alphaTilde;
        const dLambda = -(C + c.compliance * alphaTilde * c.lambda[0]) / denom;
        c.lambda[0] += dLambda;

        // Δp_i = dLambda * invMass_i * ∇C_i * stiffness
        const s = c.stiffness;
        for (let i = 0; i < 4; i++) {
            const g = grads[i];
            const mass = particles[i].invMass;
            particles[i].p[0] += dLambda * mass * g[0] * s;
            particles[i].p[1] += dLambda * mass * g[1] * s;
            particles[i].p[2] += dLambda * mass * g[2] * s;
        }
    }

    // ---- 穿透检测 ----

    /**
     * 检测并解决粒子间以及粒子-骨骼碰撞体间的相互穿透。
     *
     * 第一部分（原有）：遍历所有距离/弯曲约束的端点对，如果粒子间距离小于半径和，
     * 说明发生了穿透（快速运动或大时间步导致约束未能阻止重叠），
     * 将粒子沿分离方向推开消除重叠。
     *
     * 第二部分（boneFilter 骨骼碰撞）：当 boneCollisionEnabled 为 true 时，
     * 检查每个粒子与 collisionCapsules 中每个启用胶囊体的穿透。
     * 如果 boneFilter 非空，仅检测 boneName 在 filter 中的胶囊体。
     * 穿透后沿胶囊体法线方向推开粒子，不修改胶囊体位置（胶囊体视为静态碰撞体）。
     */
    private _resolvePenetrations(): void {
        // ---- 粒子-粒子穿透检测（原有逻辑） ----
        const visited = new Set<string>();

        for (const c of this.constraints) {
            if (c.type === 'distance' || c.type === 'bend') {
                const i = c.indices[0];
                const k = c.indices[c.indices.length - 1];

                // 避免重复处理同一对 (a,b)
                const key = i < k ? `${i},${k}` : `${k},${i}`;
                if (visited.has(key)) {
                    continue;
                }
                visited.add(key);

                const pi = this.particles[i];
                const pk = this.particles[k];

                const dx = pi.p[0] - pk.p[0];
                const dy = pi.p[1] - pk.p[1];
                const dz = pi.p[2] - pk.p[2];
                const dist = Math.sqrt(dx * dx + dy * dy + dz * dz);

                const minDist = pi.radius + pk.radius;
                if (dist >= minDist || dist < 1e-10) {
                    continue;
                }

                const nx = dx / dist;
                const ny = dy / dist;
                const nz = dz / dist;

                const wSum = pi.invMass + pk.invMass;
                if (wSum < 1e-10) {
                    continue;
                }

                // 穿透深度
                const overlap = minDist - dist;
                // 按质量倒数比例推开
                const push = overlap / wSum;

                pi.p[0] += push * pi.invMass * nx;
                pi.p[1] += push * pi.invMass * ny;
                pi.p[2] += push * pi.invMass * nz;
                pk.p[0] -= push * pk.invMass * nx;
                pk.p[1] -= push * pk.invMass * ny;
                pk.p[2] -= push * pk.invMass * nz;
            }
        }

        // ---- 粒子-骨骼碰撞体穿透检测（boneFilter 过滤） ----
        if (!this.boneCollisionEnabled || this.collisionCapsules.length === 0) {
            return;
        }

        // 预构建 boneFilter 查找集（仅一次）
        const filterSet = this.boneFilter.length > 0 ? new Set(this.boneFilter) : null;

        for (let ci = 0; ci < this.collisionCapsules.length; ci++) {
            const cap = this.collisionCapsules[ci];
            if (!cap.enabled) {
                continue;
            }

            // boneFilter 过滤：非空时仅检查列出的骨骼
            if (filterSet && !filterSet.has(cap.boneName)) {
                continue;
            }

            // 胶囊参数：端点 c ± direction * halfHeight
            const cx = cap.center[0];
            const cy = cap.center[1];
            const cz = cap.center[2];
            const dx = cap.direction[0];
            const dy = cap.direction[1];
            const dz = cap.direction[2];
            const radius = cap.radius;
            const hh = cap.halfHeight;

            const topX = cx + dx * hh;
            const topY = cy + dy * hh;
            const topZ = cz + dz * hh;
            const botX = cx - dx * hh;
            const botY = cy - dy * hh;
            const botZ = cz - dz * hh;

            const segX = topX - botX;
            const segY = topY - botY;
            const segZ = topZ - botZ;
            const segLenSq = segX * segX + segY * segY + segZ * segZ;

            for (let pi = 0; pi < this.particles.length; pi++) {
                const p = this.particles[pi];
                if (p.invMass === 0) {
                    continue; // 固定粒子不碰撞
                }

                const px = p.p[0];
                const py = p.p[1];
                const pz = p.p[2];

                // 点到胶囊线段最近点
                const toBotX = px - botX;
                const toBotY = py - botY;
                const toBotZ = pz - botZ;

                let t: number;
                if (segLenSq < 1e-12) {
                    t = 0; // 退化为球体
                } else {
                    t = (toBotX * segX + toBotY * segY + toBotZ * segZ) / segLenSq;
                    t = Math.max(0, Math.min(1, t));
                }

                const nearX = botX + segX * t;
                const nearY = botY + segY * t;
                const nearZ = botZ + segZ * t;

                const diffX = px - nearX;
                const diffY = py - nearY;
                const diffZ = pz - nearZ;
                const dist = Math.sqrt(diffX * diffX + diffY * diffY + diffZ * diffZ);

                const minDist = radius + p.radius;
                if (dist >= minDist || dist < 1e-10) {
                    continue; // 未穿透
                }

                // 穿透深度
                const penetration = minDist - dist;

                // 单位法线（粒子指向胶囊表面外侧）
                const nx = diffX / dist;
                const ny = diffY / dist;
                const nz = diffZ / dist;

                // 沿法线推开粒子（胶囊体视为刚性，不移动）
                p.p[0] += nx * penetration;
                p.p[1] += ny * penetration;
                p.p[2] += nz * penetration;
            }
        }
    }

    // ---- 几何工具 ----

    /** 计算四面体体积（有符号） */
    private _tetraVolume(
        p0: Float32Array,
        p1: Float32Array,
        p2: Float32Array,
        p3: Float32Array
    ): number {
        // V = (p1-p0)·((p2-p0)×(p3-p0)) / 6
        const e10 = [p1[0] - p0[0], p1[1] - p0[1], p1[2] - p0[2]];
        const e20 = [p2[0] - p0[0], p2[1] - p0[1], p2[2] - p0[2]];
        const e30 = [p3[0] - p0[0], p3[1] - p0[1], p3[2] - p0[2]];

        const cx = e20[1] * e30[2] - e20[2] * e30[1];
        const cy = e20[2] * e30[0] - e20[0] * e30[2];
        const cz = e20[0] * e30[1] - e20[1] * e30[0];

        return (e10[0] * cx + e10[1] * cy + e10[2] * cz) / 6.0;
    }

    /**
     * 计算四面体四个顶点的体积梯度。
     *
     * 四面体体积 V = 1/6 * |(p1-p0)·((p2-p0)×(p3-p0))|
     *
     * 对顶点 i 的梯度 ∇_i V = -1/6 * (对边的面积法向量)
     * 即 grad_i = -1/6 * ((p_j - p_k) × (p_l - p_k))，其中 j,k,l 是其余三个顶点
     *
     * 返回 [grad0, grad1, grad2, grad3]
     * 每个 grad 是 [x, y, z]
     */
    private _tetraVolumeGradients(
        p0: Float32Array,
        p1: Float32Array,
        p2: Float32Array,
        p3: Float32Array
    ): [number, number, number][] {
        const pts = [p0, p1, p2, p3];
        const grads: [number, number, number][] = [];

        // 顶点排列：(0,1,2,3)
        // 对顶点 i：取 j=(i+1)%4, k=(i+2)%4, l=(i+3)%4
        // grad_i = -1/6 * ((p_j - p_k) × (p_l - p_k))
        for (let i = 0; i < 4; i++) {
            const pj = pts[(i + 1) % 4];
            const pk = pts[(i + 2) % 4];
            const pl = pts[(i + 3) % 4];

            const e1x = pj[0] - pk[0],
                e1y = pj[1] - pk[1],
                e1z = pj[2] - pk[2];
            const e2x = pl[0] - pk[0],
                e2y = pl[1] - pk[1],
                e2z = pl[2] - pk[2];

            // cross(e1, e2)
            const cx = e1y * e2z - e1z * e2y;
            const cy = e1z * e2x - e1x * e2z;
            const cz = e1x * e2y - e1y * e2x;

            // grad_i = -1/6 * cross
            grads.push([-cx / 6, -cy / 6, -cz / 6]);
        }

        return grads;
    }

    // ---- 查询 ----

    /** 粒子总数 */
    get particleCount(): number {
        return this._particleCount;
    }

    /** 约束总数 */
    get constraintCount(): number {
        return this.constraints.length;
    }

    /** 获取当前总动能（调试用） */
    getKineticEnergy(): number {
        let ke = 0;
        for (const p of this.particles) {
            if (p.invMass === 0) {
                continue;
            }
            const mass = 1.0 / p.invMass;
            ke += 0.5 * mass * (p.v[0] * p.v[0] + p.v[1] * p.v[1] + p.v[2] * p.v[2]);
        }
        return ke;
    }

    /** 设置重力 */
    setGravity(x: number, y: number, z: number): void {
        this.gravity[0] = x;
        this.gravity[1] = y;
        this.gravity[2] = z;
    }
}

// ============================================================
// 风场工具函数
// ============================================================

/**
 * 对求解器中所有非固定粒子施加风场力。
 *
 * 使用求解器的 windEnabled / windDirection / windStrength 属性。
 * 每粒子添加随机扰动因子 (0.6~1.4) 以产生自然的布料起伏效果。
 *
 * 可在 step() 前调用作为预置风场，或由 step() 内部每子步自动调用。
 *
 * @param solver  XPBD 求解器实例
 * @param dt      时间步长（秒）
 */
export function applyWind(solver: XpbdSolver, dt: number): void {
    if (!solver.windEnabled || solver.windStrength <= 0) {
        return;
    }

    const [wx, wy, wz] = solver.windDirection;
    const strength = solver.windStrength;

    for (let i = 0; i < solver.particles.length; i++) {
        const p = solver.particles[i];
        if (p.invMass === 0) {
            continue; // 固定粒子不受风场影响
        }

        // 随机扰动因子 0.6~1.4，为每粒子产生不同的受力，形成自然飘动
        const flutter = 0.6 + Math.random() * 0.8;

        // Verlet 积分中，修改 prevP 等价于施加速度脉冲：
        //   v = (p - prevP) / dt  →  prevP 减去 impulse 后 v 增加 impulse/dt
        const impulse = wx * strength * dt * flutter;
        const impulseY = wy * strength * dt * flutter;
        const impulseZ = wz * strength * dt * flutter;

        p.prevP[0] -= impulse;
        p.prevP[1] -= impulseY;
        p.prevP[2] -= impulseZ;
    }
}

// [doc:architecture] Camera — 相机模式管理系统
// 规范文档: docs/architecture.md §渲染环节
// 职责: 相机模式切换（orbit/freefly/oneshot/concert）、自动构图、自由飞行输入
// Camera mode manager for MikuMikuAR
// Handles Orbit, Freefly, Concert, and One-shot camera modes.

import { Camera } from '@babylonjs/core/Cameras/camera';
import { ArcRotateCamera } from '@babylonjs/core/Cameras/arcRotateCamera';
import { UniversalCamera } from '@babylonjs/core/Cameras/universalCamera';
import { Vector3 } from '@babylonjs/core/Maths/math.vector';
import { Scene } from '@babylonjs/core/scene';
import { MmdCamera } from 'babylon-mmd/esm/Runtime/mmdCamera';
import type { MmdAnimation } from 'babylon-mmd/esm/Loader/Animation/mmdAnimation';
import { focusedModelId, modelRegistry, uiState } from '../../core/config';
import { focusModel, reattachPipeline } from '../scene';

// ======== Types ========
export type CameraMode = 'orbit' | 'freefly' | 'concert' | 'oneshot' | 'vmd';

/** Orbit camera parameters. */
export interface OrbitParams {
    targetHeight: number;
    distance: number;
    beta: number;
}

/** Freefly camera parameters. */
export interface FreeflyParams {
    speed: number;
    angularSensibility: number;
}

/** Concert camera parameters — continuous orbit around target. */
export interface ConcertParams {
    radius: number;
    height: number;
    speed: number;
}

/** Per-mode parameter bundle, persisted with scene files. */
export interface CameraPreset {
    mode?: CameraMode;
    orbit: OrbitParams;
    freefly: FreeflyParams;
    concert: ConcertParams;
}

export function defaultCameraPreset(): CameraPreset {
    return {
        mode: 'orbit',
        orbit: { targetHeight: 8, distance: 16, beta: Math.PI / 3 },
        freefly: { speed: 0.5, angularSensibility: 2000 },
        concert: { radius: 12, height: 8, speed: 0.3 },
    };
}

// ======== Runtime Preset State ========
let _currentPreset: CameraPreset = defaultCameraPreset();

export function getCameraPreset(): CameraPreset {
    return _currentPreset;
}
export function setCameraPreset(p: CameraPreset): void {
    _currentPreset = p;
}

export function getOrbitParams(): OrbitParams {
    return _currentPreset.orbit;
}
export function getFreeflyParams(): FreeflyParams {
    return _currentPreset.freefly;
}
export function getConcertParams(): ConcertParams {
    return _currentPreset.concert;
}

export function setOrbitParams(p: Partial<OrbitParams>): void {
    Object.assign(_currentPreset.orbit, p);
    // Sync to live camera if orbit mode is active
    if (_cameraMode === 'orbit' && _currentCamera instanceof ArcRotateCamera) {
        if (p.distance !== undefined) {
            _currentCamera.radius = p.distance;
        }
        if (p.beta !== undefined) {
            _currentCamera.beta = p.beta;
        }
        if (p.targetHeight !== undefined) {
            _currentCamera.target.y = p.targetHeight;
        }
    }
}
export function setFreeflyParams(p: Partial<FreeflyParams>): void {
    Object.assign(_currentPreset.freefly, p);
    if (_cameraMode === 'freefly' && _currentCamera instanceof UniversalCamera) {
        if (p.speed !== undefined) {
            (_currentCamera as UniversalCamera).speed = p.speed;
        }
        if (p.angularSensibility !== undefined) {
            (_currentCamera as UniversalCamera).angularSensibility = p.angularSensibility;
        }
    }
}
export function setConcertParams(p: Partial<ConcertParams>): void {
    Object.assign(_currentPreset.concert, p);
}

// ======== Internal State ========
let _scene: Scene | null = null;
let _canvas: HTMLCanvasElement | null = null;
let _cameraMode: CameraMode = 'orbit';
let _currentCamera: Camera | null = null;
let _fov = 0.8; // default FOV, migrated from RenderState in Phase 9

/** Detect touch-capable device for camera parameter tuning. */
export function isTouchDevice(): boolean {
    return (
        'ontouchstart' in window ||
        navigator.maxTouchPoints > 0 ||
        window.matchMedia('(pointer: coarse)').matches
    );
}

function clampFov(v: number): number {
    return Math.max(0.1, Math.min(3, v));
}
let _concertUpdateFn: (() => void) | null = null;
let _concertAngle = 0;
let _concertPaused = false;
// Cached target vector for concert mode (avoids per-frame Vector3 allocation)
const _concertTarget = new Vector3(0, 8, 0);

export function getConcertPaused(): boolean {
    return _concertPaused;
}
export function setConcertPaused(paused: boolean): void {
    _concertPaused = paused;
}

// ======== Camera VMD ========
let _mmdCamera: MmdCamera | null = null;
let _cameraVmdName = '';
let _cameraVmdPath = '';
let _cameraAnimationHandle: number | null = null;

export function getCameraVmdName(): string {
    return _cameraVmdName;
}
export function getCameraVmdPath(): string {
    return _cameraVmdPath;
}
export function hasCameraVmd(): boolean {
    return _mmdCamera !== null && _cameraAnimationHandle !== null;
}

/** Load camera animation from a VMD (MmdAnimation) and create an MmdCamera. */
export function loadCameraVmd(mmdAnimation: MmdAnimation, vmdPath: string, vmdName: string): void {
    if (!_scene) {
        return;
    }

    if (_mmdCamera) {
        _scene.removeCamera(_mmdCamera);
        _mmdCamera.dispose(); // 释放 GPU 资源（渲染目标、贴图等）
        _mmdCamera = null;
        _cameraAnimationHandle = null;
    }

    const mmdCam = new MmdCamera('mmdCam', new Vector3(0, 10, 0), _scene, false);
    const handle = mmdCam.createRuntimeAnimation(mmdAnimation);
    mmdCam.setRuntimeAnimation(handle);

    _mmdCamera = mmdCam;
    _cameraAnimationHandle = handle;
    _cameraVmdName = vmdName;
    _cameraVmdPath = vmdPath;
}

export function clearCameraVmd(): void {
    if (_mmdCamera && _scene) {
        if (_cameraMode === 'vmd' && _scene) {
            switchCameraMode('orbit');
        }
        _scene.removeCamera(_mmdCamera);
        _mmdCamera.dispose(); // 释放 GPU 资源，避免反复加载/清除相机 VMD 时内存泄漏
        _mmdCamera = null;
        _cameraAnimationHandle = null;
        _cameraVmdName = '';
        _cameraVmdPath = '';
    }
}

/** Animate the VMD camera to a given 30fps frame time. Called every tick by scene.ts. */
export function animateCameraVmd(frameTime: number): void {
    if (_mmdCamera && _cameraMode === 'vmd') {
        _mmdCamera.animate(frameTime);
    }
}

function createVmdCamera(scene: Scene): MmdCamera {
    if (_mmdCamera) {
        return _mmdCamera;
    }
    const cam = new MmdCamera('mmdCam', new Vector3(0, 10, 0), scene, false);
    _mmdCamera = cam;
    return cam;
}

// Stored observer callback references so we can remove them later
let _freeflyUpdateFn: (() => void) | null = null;
const _concertStartFn: (() => void) | null = null;

// ======== Public Getters ========
export function getCurrentCamera(): Camera | null {
    return _currentCamera;
}
export function getCameraMode(): CameraMode {
    return _cameraMode;
}

export function getFov(): number {
    return _fov;
}

export function setFov(v: number): void {
    _fov = clampFov(v);
    if (_currentCamera) {
        _currentCamera.fov = _fov;
    }
}

// ======== Freefly Input State ========
// Set by main.ts keyboard handlers, consumed by the freefly render observer.
export const freeflyInput = {
    forward: false,
    backward: false,
    left: false,
    right: false,
    up: false,
    down: false,
};

// ======== Camera Factory Functions ========

// ======== 用户相机输入设置（灵敏度）========
// 基准值取自 Babylon 默认值与本项目既有设定；sens 越大越灵敏（数值越小=反应越快）
const CAM_BASE = { angular: 2000, wheel: 3, pan: 50, speed: 0.5 };

/** 将用户灵敏度设置应用到相机实例（orbit/oneshot: ArcRotate；freefly: Universal） */
export function applyCameraUserSettings(cam: Camera): void {
    const sens = uiState.cameraSensitivity ?? 1;
    if (cam instanceof ArcRotateCamera) {
        cam.angularSensibilityX = CAM_BASE.angular / sens;
        cam.angularSensibilityY = CAM_BASE.angular / sens;
        cam.wheelPrecision = CAM_BASE.wheel / sens;
        cam.panningSensibility = CAM_BASE.pan / sens;
    } else if (cam instanceof UniversalCamera) {
        cam.angularSensibility = CAM_BASE.angular / sens;
        cam.speed = CAM_BASE.speed * sens;
    }
}

/** 设置变更后重新应用到当前活动相机 */
export function refreshCameraUserSettings(): void {
    if (_currentCamera) applyCameraUserSettings(_currentCamera);
}

function createOrbitCamera(scene: Scene, canvas: HTMLCanvasElement): ArcRotateCamera {
    const p = _currentPreset.orbit;
    const cam = new ArcRotateCamera(
        'camera',
        -Math.PI / 2,
        p.beta,
        p.distance,
        new Vector3(0, p.targetHeight, 0),
        scene
    );
    cam.lowerRadiusLimit = 2;
    cam.upperRadiusLimit = 50;
    cam.attachControl(canvas, true);
    applyCameraUserSettings(cam);
    // 触屏设备：降低捏合精度（更灵敏）、降低平移灵敏度（更容易拖动）
    if (isTouchDevice()) {
        cam.pinchPrecision = 32;
        cam.panningSensibility = 20;
    } else {
        cam.panningSensibility = 50;
    }
    return cam;
}

function createFreeflyCamera(scene: Scene, canvas: HTMLCanvasElement): UniversalCamera {
    const p = _currentPreset.freefly;
    const cam = new UniversalCamera('freeflyCam', new Vector3(0, 8, 16), scene);
    cam.speed = p.speed;
    cam.angularSensibility = p.angularSensibility;
    cam.attachControl(canvas, true);
    applyCameraUserSettings(cam);
    cam.keysUp = [];
    cam.keysDown = [];
    cam.keysLeft = [];
    cam.keysRight = [];
    return cam;
}

function createConcertCamera(scene: Scene): ArcRotateCamera {
    const cam = new ArcRotateCamera(
        'concertCam',
        -Math.PI / 2,
        Math.PI / 3,
        16,
        new Vector3(0, 8, 0),
        scene
    );
    cam.lowerRadiusLimit = 2;
    cam.upperRadiusLimit = 50;
    cam.panningSensibility = 50;
    // No attachControl — we animate programmatically; mouse would interfere
    return cam;
}

function createOneshotCamera(scene: Scene, canvas: HTMLCanvasElement): ArcRotateCamera {
    // Placeholder — same as orbit for now; animation data applied later
    const cam = new ArcRotateCamera(
        'oneshotCam',
        -Math.PI / 2,
        Math.PI / 3,
        16,
        new Vector3(0, 8, 0),
        scene
    );
    cam.lowerRadiusLimit = 2;
    cam.upperRadiusLimit = 50;
    cam.attachControl(canvas, true);
    applyCameraUserSettings(cam);
    if (isTouchDevice()) {
        cam.pinchPrecision = 32;
        cam.panningSensibility = 20;
    } else {
        cam.panningSensibility = 50;
    }
    return cam;
}

// ======== Initialization ========

/** Initialise the camera system and create the default Orbit camera. */
export function initCameraSystem(scene: Scene, canvas: HTMLCanvasElement): Camera {
    _scene = scene;
    _canvas = canvas;
    const cam = createOrbitCamera(scene, canvas);
    _currentCamera = cam;
    _cameraMode = 'orbit';
    scene.activeCamera = cam;
    return cam;
}

// ======== Mode Switch ========

/** Switch to a different camera mode, preserving position as much as possible. */
export function switchCameraMode(mode: CameraMode): void {
    if (mode === _cameraMode && _currentCamera) {
        return;
    }
    if (!_scene || !_canvas) {
        return;
    }

    const scene = _scene;
    const canvas = _canvas;

    // Stop current mode's side-effects
    if (_cameraMode === 'freefly') {
        stopFreefly();
    }
    if (_cameraMode === 'concert') {
        stopConcert();
    }

    // Save old camera state
    const oldCam = _currentCamera;
    let oldPos: Vector3 | null = null;
    let oldTarget: Vector3 | null = null;

    if (oldCam) {
        oldPos = oldCam.position.clone();
        if (oldCam instanceof ArcRotateCamera) {
            oldTarget = oldCam.target.clone();
        } else {
            // Derive a look-at target from the forward direction
            const dir = oldCam.getDirection(new Vector3(0, 0, 1));
            oldTarget = oldPos.add(dir);
        }
        oldCam.detachControl();
        scene.removeCamera(oldCam);
    }

    // Create new camera
    let newCam: Camera;
    switch (mode) {
        case 'orbit':
            newCam = createOrbitCamera(scene, canvas);
            break;
        case 'freefly':
            newCam = createFreeflyCamera(scene, canvas);
            break;
        case 'concert':
            newCam = createConcertCamera(scene);
            break;
        case 'oneshot':
            newCam = createOneshotCamera(scene, canvas);
            break;
        case 'vmd':
            // Pre-check: refuse switch if no camera VMD is loaded
            if (_cameraAnimationHandle === null) {
                console.warn(
                    '[camera] Cannot switch to VMD mode: no camera VMD loaded, falling back to orbit'
                );
                mode = 'orbit';
                newCam = createOrbitCamera(scene, canvas);
                break;
            }
            newCam = createVmdCamera(scene);
            break;
        default:
            newCam = createOrbitCamera(scene, canvas);
            break;
    }

    // Restore position (best-effort)
    if (oldPos) {
        newCam.position = oldPos;
        if (newCam instanceof ArcRotateCamera && oldTarget) {
            newCam.setTarget(oldTarget);
        }
    }

    scene.activeCamera = newCam;
    _currentCamera = newCam;
    _cameraMode = mode;
    // Persist camera mode for scene auto-save (skip oneshot — it's a transient action)
    if (mode !== 'oneshot') {
        _currentPreset.mode = mode;
    }

    // Start new mode's side-effects
    if (mode === 'freefly') {
        initFreeflyUpdate(scene);
        initFreeflyTouch(canvas);
    }
    if (mode === 'concert') {
        startConcert(scene);
    }

    // Auto-frame on focused model when switching to orbit
    if (mode === 'orbit' && focusedModelId) {
        const inst = modelRegistry.get(focusedModelId);
        if (inst) {
            focusModel(focusedModelId);
        }
    }

    // Re-attach post-processing pipeline to the new camera
    reattachPipeline();
    // Apply FOV to the new camera
    newCam.fov = clampFov(_fov);
}

// ======== Auto Frame ========

/** Auto-frame the camera to centre on a bounding box. */
export function autoFrame(center: Vector3, extent: number): void {
    const cam = _currentCamera;
    if (!cam) {
        return;
    }

    if (cam instanceof ArcRotateCamera) {
        cam.setTarget(center);
        cam.radius = extent * 0.75 + 2;
        cam.beta = Math.PI / 2.2;
    } else if (cam instanceof UniversalCamera) {
        const dist = extent * 0.75 + 2;
        cam.position = new Vector3(center.x, center.y + dist * 0.5, center.z + dist);
        cam.setTarget(center);
    }
}

// ======== Freefly ========

function initFreeflyUpdate(scene: Scene): void {
    // Remove any previous freefly observer
    if (_freeflyUpdateFn) {
        scene.onBeforeRenderObservable.removeCallback(_freeflyUpdateFn);
    }

    _freeflyUpdateFn = () => {
        const cam = _currentCamera;
        if (!cam || !(cam instanceof UniversalCamera)) {
            return;
        }
        const speed = 0.3 * scene.getAnimationRatio();

        // Read input state set by main.ts keydown/keyup
        // Use explicit temp variable for readability (getDirection returns a new Vector3 each call)
        if (freeflyInput.forward) {
            const dir = cam.getDirection(new Vector3(0, 0, 1)).scaleInPlace(speed);
            cam.position.addInPlace(dir);
        }
        if (freeflyInput.backward) {
            const dir = cam.getDirection(new Vector3(0, 0, -1)).scaleInPlace(speed);
            cam.position.addInPlace(dir);
        }
        if (freeflyInput.left) {
            const dir = cam.getDirection(new Vector3(-1, 0, 0)).scaleInPlace(speed);
            cam.position.addInPlace(dir);
        }
        if (freeflyInput.right) {
            const dir = cam.getDirection(new Vector3(1, 0, 0)).scaleInPlace(speed);
            cam.position.addInPlace(dir);
        }
        if (freeflyInput.up) {
            cam.position.y += speed;
        }
        if (freeflyInput.down) {
            cam.position.y -= speed;
        }
    };

    scene.onBeforeRenderObservable.add(_freeflyUpdateFn);
}

// ======== Freefly Touch Controls ========
// 双指滑动：上下 = 前后移动，左右 = 平移
// 双指捏合：前进/后退
let _freeflyTouchHandler: ((e: TouchEvent) => void) | null = null;
let _freeflyTouchEndHandler: (() => void) | null = null;
let _touchPrevDist = 0;
let _touchPrevMidX = 0;
let _touchPrevMidY = 0;

function initFreeflyTouch(canvas: HTMLCanvasElement): void {
    if (!isTouchDevice()) return;

    _freeflyTouchHandler = (e: TouchEvent) => {
        if (_cameraMode !== 'freefly') return;
        if (e.touches.length < 2) return;
        e.preventDefault();

        const t0 = e.touches[0];
        const t1 = e.touches[1];
        const midX = (t0.clientX + t1.clientX) / 2;
        const midY = (t0.clientY + t1.clientY) / 2;
        const dx = t1.clientX - t0.clientX;
        const dy = t1.clientY - t0.clientY;
        const dist = Math.sqrt(dx * dx + dy * dy);

        if (_touchPrevDist > 0) {
            const dDist = dist - _touchPrevDist;
            const dMidX = midX - _touchPrevMidX;
            const dMidY = midY - _touchPrevMidY;

            // 捏合 → 前进/后退（dist 增大 = 后退，减小 = 前进）
            freeflyInput.forward = dDist < -3;
            freeflyInput.backward = dDist > 3;

            // 双指水平滑动 → 左右平移
            freeflyInput.left = dMidX > 4;
            freeflyInput.right = dMidX < -4;

            // 双指垂直滑动 → 上下移动
            freeflyInput.up = dMidY > 4;
            freeflyInput.down = dMidY < -4;
        }

        _touchPrevDist = dist;
        _touchPrevMidX = midX;
        _touchPrevMidY = midY;
    };

    _freeflyTouchEndHandler = () => {
        freeflyInput.forward = false;
        freeflyInput.backward = false;
        freeflyInput.left = false;
        freeflyInput.right = false;
        freeflyInput.up = false;
        freeflyInput.down = false;
        _touchPrevDist = 0;
    };

    canvas.addEventListener('touchmove', _freeflyTouchHandler, { passive: false });
    canvas.addEventListener('touchend', _freeflyTouchEndHandler);
    canvas.addEventListener('touchcancel', _freeflyTouchEndHandler);
}

function stopFreeflyTouch(): void {
    if (_canvas && _freeflyTouchHandler) {
        _canvas.removeEventListener('touchmove', _freeflyTouchHandler);
        _canvas.removeEventListener('touchend', _freeflyTouchEndHandler!);
        _canvas.removeEventListener('touchcancel', _freeflyTouchEndHandler!);
        _freeflyTouchHandler = null;
        _freeflyTouchEndHandler = null;
    }
    _touchPrevDist = 0;
}

function stopFreefly(): void {
    // Reset input state
    freeflyInput.forward = false;
    freeflyInput.backward = false;
    freeflyInput.left = false;
    freeflyInput.right = false;
    freeflyInput.up = false;
    freeflyInput.down = false;

    stopFreeflyTouch();

    if (_freeflyUpdateFn && _scene) {
        _scene.onBeforeRenderObservable.removeCallback(_freeflyUpdateFn);
        _freeflyUpdateFn = null;
    }
}

// ======== Concert ========

function startConcert(scene: Scene): void {
    _concertAngle = 0;
    if (_concertUpdateFn) {
        scene.onBeforeRenderObservable.removeCallback(_concertUpdateFn);
    }
    _concertUpdateFn = () => {
        const cam = _currentCamera;
        if (!cam || !(cam instanceof ArcRotateCamera)) {
            return;
        }
        const p = _currentPreset.concert;
        if (!_concertPaused) {
            const delta = scene.getAnimationRatio() * p.speed * (scene.deltaTime / 1000);
            _concertAngle += delta;
        }
        cam.alpha = -Math.PI / 2 + _concertAngle;
        cam.radius = p.radius;
        cam.beta = Math.PI / 3;
        const focusedId = focusedModelId;
        if (focusedId) {
            const inst = modelRegistry.get(focusedId);
            if (inst && inst.meshes.length > 0) {
                const root = inst.rootMesh;
                _concertTarget.set(root.position.x, p.height, root.position.z);
            } else {
                _concertTarget.set(0, p.height, 0);
            }
        } else {
            _concertTarget.set(0, p.height, 0);
        }
        cam.setTarget(_concertTarget);
    };
    scene.onBeforeRenderObservable.add(_concertUpdateFn);
}

function stopConcert(): void {
    if (_concertUpdateFn && _scene) {
        _scene.onBeforeRenderObservable.removeCallback(_concertUpdateFn);
        _concertUpdateFn = null;
    }
}

// ======== Camera State Serialization ========

export interface CameraState {
    mode: CameraMode;
    preset: CameraPreset;
    fov?: number; // FOV in radians, default 0.8 (migrated from RenderState in Phase 9)
    alpha: number;
    beta: number;
    radius: number;
    targetX: number;
    targetY: number;
    targetZ: number;
    positionX?: number;
    positionY?: number;
    positionZ?: number;
}

export function getCameraState(): CameraState {
    const cam = _currentCamera;
    const isArc = cam instanceof ArcRotateCamera;
    const alpha = isArc ? cam.alpha : 0;
    const beta = isArc ? cam.beta : 0;
    const radius = isArc ? cam.radius : 16;
    const target = isArc ? cam.target : null;
    return {
        mode: _cameraMode,
        preset: JSON.parse(JSON.stringify(_currentPreset)),
        fov: _fov,
        alpha,
        beta,
        radius,
        targetX: target?.x ?? 0,
        targetY: target?.y ?? 8,
        targetZ: target?.z ?? 0,
        positionX: cam!.position.x,
        positionY: cam!.position.y,
        positionZ: cam!.position.z,
    };
}

export function setCameraState(s: CameraState): void {
    // Switch to the saved mode first (creates the right camera type),
    // then restore the preset over the live state.
    const mode = s.mode || s.preset.mode;
    if (mode) {
        switchCameraMode(mode);
    }
    if (s.preset) {
        _currentPreset = JSON.parse(JSON.stringify(s.preset));
    }
    // Restore FOV (from new scene files; old scenes store it in render.fov)
    if (s.fov !== undefined) {
        setFov(s.fov);
    }
    const cam = _currentCamera;
    if (!cam) {
        return;
    }
    if (cam instanceof ArcRotateCamera) {
        cam.alpha = s.alpha ?? cam.alpha;
        cam.beta = s.beta ?? cam.beta;
        cam.radius = s.radius ?? cam.radius;
        cam.setTarget(new Vector3(s.targetX, s.targetY, s.targetZ));
    } else if (cam instanceof UniversalCamera) {
        if (s.positionX !== undefined) {
            cam.position = new Vector3(s.positionX, s.positionY ?? 8, s.positionZ ?? 16);
        }
        cam.setTarget(new Vector3(s.targetX, s.targetY, s.targetZ));
    }
}

// ======== Auto Camera（节拍驱动运镜） ========

interface AutoCameraPreset {
    alpha: number;   // 水平角度 (rad)
    beta: number;    // 垂直角度 (rad)
    radius: number;  // 距离
}

const AUTO_CAMERA_PRESETS: AutoCameraPreset[] = [
    { alpha: -Math.PI / 2,  beta: Math.PI / 3,      radius: 16 },  // 正面标准
    { alpha: -Math.PI / 4,  beta: Math.PI / 3.5,    radius: 14 },  // 右前 45°
    { alpha: -Math.PI * 3/4, beta: Math.PI / 3.5,   radius: 14 },  // 左前 45°
    { alpha: -Math.PI / 2,  beta: Math.PI / 6,      radius: 18 },  // 高角度俯拍
    { alpha: -Math.PI / 2,  beta: Math.PI / 2.5,    radius: 10 },  // 近距离正面
    { alpha: 0,             beta: Math.PI / 3,      radius: 16 },  // 右侧 90°
    { alpha: -Math.PI,      beta: Math.PI / 3,      radius: 16 },  // 左侧 90°
    { alpha: -Math.PI / 2,  beta: Math.PI / 4,      radius: 22 },  // 远景
];

let _autoCameraEnabled = false;
let _autoCameraBeatCount = 0;
let _autoCameraPresetIdx = 0;
let _autoCameraBeatsPerSwitch = 4; // 每 4 拍切换一次
let _autoCameraUnsub: (() => void) | null = null;

/** 从 UIState 恢复自动机位状态 */
export function restoreAutoCameraState(): void {
    const s = uiState;
    if (s.autoCameraEnabled) {
        _autoCameraEnabled = true;
        _autoCameraBeatsPerSwitch = s.autoCameraBeatsPerSwitch || 4;
    }
}

/** 设置 Auto Camera 开关。启用时注册 beat 回调，禁用时移除。 */
export function setAutoCameraEnabled(v: boolean, beatDetector?: { onBeat: (cb: () => void) => () => void } | null): void {
    if (v === _autoCameraEnabled) return;
    _autoCameraEnabled = v;
    uiState.autoCameraEnabled = v;
    if (v) {
        _autoCameraBeatCount = 0;
        _autoCameraPresetIdx = 0;
        if (beatDetector) {
            _autoCameraUnsub = beatDetector.onBeat(_onAutoCameraBeat);
        }
    } else {
        if (_autoCameraUnsub) {
            _autoCameraUnsub();
            _autoCameraUnsub = null;
        }
    }
}

export function isAutoCameraEnabled(): boolean {
    return _autoCameraEnabled;
}

/** 设置每多少拍切换一次镜头。 */
export function setAutoCameraBeatsPerSwitch(n: number): void {
    _autoCameraBeatsPerSwitch = Math.max(1, Math.min(16, Math.round(n)));
    uiState.autoCameraBeatsPerSwitch = _autoCameraBeatsPerSwitch;
}

export function getAutoCameraBeatsPerSwitch(): number {
    return _autoCameraBeatsPerSwitch;
}

function _onAutoCameraBeat(): void {
    if (!_autoCameraEnabled) return;
    _autoCameraBeatCount++;
    if (_autoCameraBeatCount < _autoCameraBeatsPerSwitch) return;
    _autoCameraBeatCount = 0;

    const cam = _currentCamera;
    if (!cam || !(cam instanceof ArcRotateCamera)) return;
    if (_cameraMode !== 'orbit' && _cameraMode !== 'concert') return;

    // 切到下一个预设（避免连续重复）
    let nextIdx = (_autoCameraPresetIdx + 1 + Math.floor(Math.random() * (AUTO_CAMERA_PRESETS.length - 1))) % AUTO_CAMERA_PRESETS.length;
    if (nextIdx === _autoCameraPresetIdx) nextIdx = (nextIdx + 1) % AUTO_CAMERA_PRESETS.length;
    _autoCameraPresetIdx = nextIdx;

    const preset = AUTO_CAMERA_PRESETS[nextIdx];

    // 平滑过渡到新预设（逐帧插值，~0.5s 完成）
    const startAlpha = cam.alpha;
    const startBeta = cam.beta;
    const startRadius = cam.radius;
    let t = 0;
    const duration = 500;
    const startTime = performance.now();

    const cleanup = _scene.onBeforeRenderObservable.add(() => {
      const elapsed = performance.now() - startTime;
      t = Math.min(1, elapsed / duration);
      const ease = t * t * (3 - 2 * t); // smoothstep
      cam.alpha = startAlpha + (preset.alpha - startAlpha) * ease;
      cam.beta = startBeta + (preset.beta - startBeta) * ease;
      cam.radius = startRadius + (preset.radius - startRadius) * ease;
      if (t >= 1) {
        _scene.onBeforeRenderObservable.remove(cleanup);
      }
    });
if (!_scene) {
  // fallback: no scene reference, complete instantly
  cam.alpha = preset.alpha;
  cam.beta = preset.beta;
  cam.radius = preset.radius;
}
}

