/** 将当前 EnvPreset 序列化为 JSON 字符串（.env 格式）。 */
export function exportEnvPreset(p: EnvPreset): string {
    return JSON.stringify(
        {
            version: 2,
            label: p.label,
            skyColorTop: p.skyColorTop,
            skyColorBot: p.skyColorBot,
            sunAngle: p.sunAngle,
            azimuth: p.azimuth ?? -45,
        },
        null,
        2
    );
}

/** 从 .env JSON 字符串反序列化 EnvPreset，失败返回 null。 */
export function importEnvPreset(json: string): (EnvPreset & DerivedLighting) | null {
    try {
        const raw = JSON.parse(json);
        if (
            !raw.label ||
            !raw.skyColorTop ||
            !raw.skyColorBot ||
            typeof raw.sunAngle !== 'number'
        ) {
            return null;
        }
        const azimuth = typeof raw.azimuth === 'number' ? raw.azimuth : -45;
        return {
            label: raw.label,
            skyColorTop: raw.skyColorTop,
            skyColorBot: raw.skyColorBot,
            sunAngle: raw.sunAngle,
            azimuth,
            ...deriveLighting(raw.skyColorTop, raw.sunAngle, azimuth),
        };
    } catch {
        return null;
    }
}

import {
    Color4,
    Vector3,
    Texture,
    GPUParticleSystem,
    ParticleSystem,
} from '@babylonjs/core';
import { EnvState, envState } from '../../core/config';
import { getWindVector } from '../../core/physics/wind-utils';
import { _envSys, getScene, addRipple } from './env-impl';

// ======== Particle System ========
let _currentParticleType: EnvState['particleType'] = 'none';
const _particleTextures = new Map<string, Texture>();

// ======== Splash System (Phase B) ========
let _splashSystem: GPUParticleSystem | null = null;

// 保存粒子系统创建时的初始发射方向，风力基于此计算，避免叠加
let _initialDir1: Vector3 | null = null;
let _initialDir2: Vector3 | null = null;

// 保存基础参数值（未乘 multiplier 前的值），供运行时滑条更新使用
let _baseEmitRate = 0;
let _baseMinSize = 0;
let _baseMaxSize = 0;
let _baseMinEmitPower = 0;
let _baseMaxEmitPower = 0;

// ---------- 全景天气 vs 局部效果参数 ----------
// 全景天气（雨/雪/樱花/落叶）：粒子出生在世界地面以上固定高度，XZ 大幅覆盖
const WEATHER_HEIGHT_ABOVE_GROUND = 25; // 发射器在 groundLevel 以上 25 单位
const WEATHER_BOX_Y_RANGE = 5; // box emitter 垂直带宽度（出生 Y 偏移范围）
const WEATHER_BOX_XZ_HALF = 40; // XZ 半宽（80×80 覆盖区）

// 局部效果：相对于 groundLevel 的偏移
const FIREFLY_HEIGHT_OFFSET = 1.5;
const FIREWORK_HEIGHT_OFFSET = 8;

function makeParticleTexture(kind: string, externalUrl?: string): Texture {
    const scene = getScene();

    // 自定义纹理优先：从外部图片加载
    if (externalUrl) {
        const cacheKey = `_custom_${externalUrl}`;
        const cached = _particleTextures.get(cacheKey);
        if (cached) {
            return cached;
        }
        const tex = new Texture(externalUrl, scene, false, false);
        tex.hasAlpha = true;
        _particleTextures.set(cacheKey, tex);
        return tex;
    }

    const cached = _particleTextures.get(kind);
    if (cached) {
        return cached;
    }
    const canvas = document.createElement('canvas');
    canvas.width = 64;
    canvas.height = 64;
    const ctx = canvas.getContext('2d')!;
    drawParticleShape(ctx, kind);
    const tex = new Texture(canvas.toDataURL(), scene, false, false);
    tex.hasAlpha = true;
    _particleTextures.set(kind, tex);
    return tex;
}

function drawParticleShape(ctx: CanvasRenderingContext2D, kind: string): void {
    ctx.clearRect(0, 0, 64, 64);
    const cx = 32,
        cy = 32;
    switch (kind) {
        case 'sakura': {
            ctx.fillStyle = '#ffb7c5';
            for (let i = 0; i < 5; i++) {
                ctx.save();
                ctx.translate(cx, cy);
                ctx.rotate((i * Math.PI * 2) / 5);
                ctx.beginPath();
                ctx.ellipse(0, -15, 7, 13, 0, 0, Math.PI * 2);
                ctx.fill();
                ctx.restore();
            }
            ctx.fillStyle = '#ffe080';
            ctx.beginPath();
            ctx.arc(cx, cy, 5, 0, Math.PI * 2);
            ctx.fill();
            break;
        }
        case 'rain': {
            const grad = ctx.createLinearGradient(32, 6, 32, 58);
            grad.addColorStop(0, 'rgba(180,210,255,0)');
            grad.addColorStop(0.5, 'rgba(200,225,255,0.95)');
            grad.addColorStop(1, 'rgba(220,235,255,0)');
            ctx.fillStyle = grad;
            ctx.fillRect(30, 6, 4, 52);
            break;
        }
        case 'snow': {
            ctx.strokeStyle = 'rgba(255,255,255,0.95)';
            ctx.lineWidth = 2.5;
            ctx.lineCap = 'round';
            for (let i = 0; i < 6; i++) {
                ctx.save();
                ctx.translate(cx, cy);
                ctx.rotate((i * Math.PI) / 3);
                ctx.beginPath();
                ctx.moveTo(0, 0);
                ctx.lineTo(0, -24);
                ctx.moveTo(0, -15);
                ctx.lineTo(-5, -21);
                ctx.moveTo(0, -15);
                ctx.lineTo(5, -21);
                ctx.stroke();
                ctx.restore();
            }
            break;
        }
        case 'fireworks': {
            const grad = ctx.createRadialGradient(cx, cy, 0, cx, cy, 30);
            grad.addColorStop(0, 'rgba(255,240,180,1)');
            grad.addColorStop(0.3, 'rgba(255,200,100,0.6)');
            grad.addColorStop(1, 'rgba(255,150,50,0)');
            ctx.fillStyle = grad;
            ctx.fillRect(0, 0, 64, 64);
            ctx.strokeStyle = 'rgba(255,255,220,0.9)';
            ctx.lineWidth = 2;
            ctx.beginPath();
            ctx.moveTo(cx, 4);
            ctx.lineTo(cx, 60);
            ctx.moveTo(4, cy);
            ctx.lineTo(60, cy);
            ctx.stroke();
            break;
        }
        case 'fireflies': {
            const grad = ctx.createRadialGradient(cx, cy, 0, cx, cy, 28);
            grad.addColorStop(0, 'rgba(210,255,130,1)');
            grad.addColorStop(0.4, 'rgba(150,255,80,0.6)');
            grad.addColorStop(1, 'rgba(100,200,50,0)');
            ctx.fillStyle = grad;
            ctx.fillRect(0, 0, 64, 64);
            break;
        }
        case 'leaves': {
            ctx.fillStyle = '#c9742a';
            ctx.save();
            ctx.translate(cx, cy);
            ctx.rotate(-0.3);
            ctx.beginPath();
            ctx.ellipse(0, 0, 9, 21, 0, 0, Math.PI * 2);
            ctx.fill();
            ctx.strokeStyle = '#8a4a18';
            ctx.lineWidth = 1.5;
            ctx.beginPath();
            ctx.moveTo(0, -19);
            ctx.lineTo(0, 19);
            ctx.stroke();
            ctx.restore();
            break;
        }
        case 'splash': {
            // 溅射水滴：小圆形白色粒子
            const grad = ctx.createRadialGradient(cx, cy, 0, cx, cy, 12);
            grad.addColorStop(0, 'rgba(220,235,255,0.9)');
            grad.addColorStop(0.5, 'rgba(200,220,255,0.5)');
            grad.addColorStop(1, 'rgba(180,210,255,0)');
            ctx.fillStyle = grad;
            ctx.fillRect(0, 0, 64, 64);
            break;
        }
        default: {
            console.warn('[drawParticleShape] unknown particle kind: ' + kind);
            ctx.fillStyle = '#ff00ff';
            ctx.fillRect(0, 0, 64, 64);
            break;
        }
    }
}

export function createParticleEmitter(type: EnvState['particleType'], windEnabled: boolean): void {
    if (_envSys.particles.system && _currentParticleType === type) {
        return;
    }

    if (_envSys.particles.system) {
        disposeParticles();
    }
    _currentParticleType = type;
    if (type === 'none') {
        return;
    }

    const scene = getScene();

    // capacity >= max(emitRate) * max(maxLifeTime) * 2.5
    // 雨上限：1000 * 2 * 2.5 = 5000；particleEmitRate 放大时需要同步扩大
    const ps = new GPUParticleSystem('envParticles', { capacity: 10000 }, scene);
    ps.particleTexture = makeParticleTexture(type, envState.particleCustomTexture || undefined);
    _prevCustomTexKey = envState.particleCustomTexture ? `_custom_${envState.particleCustomTexture}` : null;
    ps.updateSpeed = 0.01;
    // 初始 emitter 占位（实际位置在 followObserver 中设置）
    ps.emitter = new Vector3(0, 0, 0);

    // 判断当前类型是全景天气还是局部效果
    const isWeather = ['sakura', 'rain', 'snow', 'leaves'].includes(type);

    switch (type) {
        case 'sakura': {
            ps.blendMode = ParticleSystem.BLENDMODE_STANDARD;
            ps.emitRate = 40;
            ps.gravity = new Vector3(0, -0.8, 0);
            ps.minLifeTime = 8;
            ps.maxLifeTime = 15;
            ps.minEmitPower = 0.5;
            ps.maxEmitPower = 1.5;
            ps.minAngularSpeed = -1;
            ps.maxAngularSpeed = 1;
            ps.minSize = 0.15;
            ps.maxSize = 0.35;
            if (isWeather) {
                // 全景天气：XZ 大幅覆盖，出生 Y 在 emitter 附近窄带
                ps.createBoxEmitter(
                    new Vector3(-0.5, -0.2, -0.5),
                    new Vector3(0.5, 0.2, 0.5),
                    new Vector3(-WEATHER_BOX_XZ_HALF, 0, -WEATHER_BOX_XZ_HALF),
                    new Vector3(WEATHER_BOX_XZ_HALF, WEATHER_BOX_Y_RANGE, WEATHER_BOX_XZ_HALF)
                );
            }
            ps.addColorGradient(0, new Color4(1, 0.72, 0.78, 1), new Color4(1, 0.8, 0.85, 1));
            ps.addColorGradient(0.8, new Color4(1, 0.72, 0.78, 1), new Color4(1, 0.8, 0.85, 1));
            ps.addColorGradient(1, new Color4(1, 0.72, 0.78, 0), new Color4(1, 0.8, 0.85, 0));
            break;
        }
        case 'rain': {
            ps.blendMode = ParticleSystem.BLENDMODE_STANDARD;
            ps.emitRate = 1000;
            ps.gravity = new Vector3(0, -25, 0);
            ps.minLifeTime = 1;
            ps.maxLifeTime = 2;
            ps.minEmitPower = 15;
            ps.maxEmitPower = 20;
            ps.minSize = 0.1;
            ps.maxSize = 0.2;
            if (isWeather) {
                ps.createBoxEmitter(
                    new Vector3(-0.1, -1, -0.1),
                    new Vector3(0.1, -1, 0.1),
                    new Vector3(-WEATHER_BOX_XZ_HALF, 0, -WEATHER_BOX_XZ_HALF),
                    new Vector3(WEATHER_BOX_XZ_HALF, WEATHER_BOX_Y_RANGE, WEATHER_BOX_XZ_HALF)
                );
            }
            ps.addColorGradient(0, new Color4(0.7, 0.8, 1, 0.6), new Color4(0.8, 0.9, 1, 0.8));
            ps.addColorGradient(1, new Color4(0.7, 0.8, 1, 0), new Color4(0.8, 0.9, 1, 0));
            break;
        }
        case 'snow': {
            ps.blendMode = ParticleSystem.BLENDMODE_STANDARD;
            ps.emitRate = 250;
            ps.gravity = new Vector3(0, -1.5, 0);
            ps.minLifeTime = 6;
            ps.maxLifeTime = 12;
            ps.minEmitPower = 0.3;
            ps.maxEmitPower = 0.8;
            ps.minAngularSpeed = -0.5;
            ps.maxAngularSpeed = 0.5;
            ps.minSize = 0.1;
            ps.maxSize = 0.25;
            if (isWeather) {
                ps.createBoxEmitter(
                    new Vector3(-0.5, -0.3, -0.5),
                    new Vector3(0.5, -0.3, 0.5),
                    new Vector3(-WEATHER_BOX_XZ_HALF, 0, -WEATHER_BOX_XZ_HALF),
                    new Vector3(WEATHER_BOX_XZ_HALF, WEATHER_BOX_Y_RANGE, WEATHER_BOX_XZ_HALF)
                );
            }
            ps.addColorGradient(0, new Color4(1, 1, 1, 0.9), new Color4(1, 1, 1, 1));
            ps.addColorGradient(1, new Color4(1, 1, 1, 0), new Color4(1, 1, 1, 0));
            break;
        }
        case 'fireworks': {
            ps.blendMode = ParticleSystem.BLENDMODE_ADD;
            ps.emitRate = 5; // 低发射率环境光晕；实际爆发由 burst 管理器生成临时系统
            ps.gravity = new Vector3(0, -2, 0);
            ps.minLifeTime = 1.5;
            ps.maxLifeTime = 3;
            ps.minEmitPower = 2;
            ps.maxEmitPower = 5;
            ps.minSize = 0.05;
            ps.maxSize = 0.12;
            ps.createSphereEmitter(2);
            ps.addColorGradient(0, new Color4(1, 0.9, 0.4, 0.3), new Color4(1, 0.8, 0.2, 0.2));
            ps.addColorGradient(1, new Color4(1, 0.5, 0.1, 0), new Color4(0.8, 0.3, 0, 0));
            break;
        }
        case 'fireflies': {
            ps.blendMode = ParticleSystem.BLENDMODE_ADD;
            ps.emitRate = 15;
            ps.gravity = new Vector3(0, 0, 0);
            ps.minLifeTime = 4;
            ps.maxLifeTime = 8;
            ps.minEmitPower = 0.2;
            ps.maxEmitPower = 0.5;
            ps.minSize = 0.1;
            ps.maxSize = 0.2;
            ps.createSphereEmitter(8);
            ps.addColorGradient(0, new Color4(0.6, 1, 0.3, 0), new Color4(0.8, 1, 0.4, 0));
            ps.addColorGradient(0.3, new Color4(0.6, 1, 0.3, 1), new Color4(0.8, 1, 0.4, 1));
            ps.addColorGradient(0.6, new Color4(0.6, 1, 0.3, 0.2), new Color4(0.8, 1, 0.4, 0.2));
            ps.addColorGradient(1, new Color4(0.6, 1, 0.3, 1), new Color4(0.8, 1, 0.4, 1));
            break;
        }
        case 'leaves': {
            ps.blendMode = ParticleSystem.BLENDMODE_STANDARD;
            ps.emitRate = 30;
            ps.gravity = new Vector3(0, -1, 0);
            ps.minLifeTime = 8;
            ps.maxLifeTime = 14;
            ps.minEmitPower = 0.5;
            ps.maxEmitPower = 1.5;
            ps.minAngularSpeed = -2;
            ps.maxAngularSpeed = 2;
            ps.minSize = 0.2;
            ps.maxSize = 0.4;
            if (isWeather) {
                ps.createBoxEmitter(
                    new Vector3(-0.8, -0.3, -0.8),
                    new Vector3(0.8, 0.3, 0.8),
                    new Vector3(-WEATHER_BOX_XZ_HALF, 0, -WEATHER_BOX_XZ_HALF),
                    new Vector3(WEATHER_BOX_XZ_HALF, WEATHER_BOX_Y_RANGE, WEATHER_BOX_XZ_HALF)
                );
            }
            ps.addColorGradient(0, new Color4(0.9, 0.5, 0.2, 1), new Color4(0.8, 0.6, 0.1, 1));
            ps.addColorGradient(1, new Color4(0.9, 0.5, 0.2, 0), new Color4(0.8, 0.6, 0.1, 0));
            break;
        }
    }

    // 保存基础参数值（供运行时滑条更新使用）
    _baseEmitRate = ps.emitRate;
    _baseMinSize = ps.minSize;
    _baseMaxSize = ps.maxSize;
    _baseMinEmitPower = ps.minEmitPower;
    _baseMaxEmitPower = ps.maxEmitPower;

    // 保存初始发射方向，风力始终基于初始值计算，避免叠加
    _initialDir1 = ps.direction1.clone();
    _initialDir2 = ps.direction2.clone();

    // 应用 multiplier
    const er = envState.particleEmitRate;
    if (er !== 1) {
        ps.emitRate = Math.max(0, ps.emitRate * er);
    }

    const sz = envState.particleSize;
    if (sz !== 1) {
        ps.minSize *= sz;
        ps.maxSize *= sz;
    }

    const sp = envState.particleSpeed;
    if (sp !== 1) {
        ps.minEmitPower *= sp;
        ps.maxEmitPower *= sp;
    }

    if (windEnabled) {
        applyWindToParticles(ps);
    }

    // 每帧更新 emitter 位置（基于 groundLevel 和类型定位策略）
    _envSys.particles.followObserver = scene.onBeforeRenderObservable.add(() => {
        const cam = scene.activeCamera;
        if (!cam) {
            return;
        }
        const e = ps.emitter;
        if (!(e instanceof Vector3)) {
            return;
        }

        const groundY = envState.groundLevel ?? 0;

        if (isWeather) {
            // 全景天气：XZ 跟随相机，Y 固定在世界空间地面以上
            e.x = cam.position.x;
            e.z = cam.position.z;
            e.y = groundY + WEATHER_HEIGHT_ABOVE_GROUND;
        } else {
            // 局部效果：XZ 跟随相机，Y 相对于地面偏移
            e.x = cam.position.x;
            e.z = cam.position.z;
            if (type === 'fireflies') {
                e.y = groundY + FIREFLY_HEIGHT_OFFSET;
            } else if (type === 'fireworks') {
                e.y = groundY + FIREWORK_HEIGHT_OFFSET;
            }
        }
    });

    _envSys.particles.system = ps;
    ps.start();

    // 粒子类型变更后同步溅射状态（雨/雪才有溅射）
    syncSplashState();

    // 烟花类型启动 burst 调度
    if (type === 'fireworks') {
        scheduleNextFireworkBurst();
    }
}

export function disposeParticles(): void {
    const scene = getScene();
    if (_envSys.particles.followObserver) {
        scene.onBeforeRenderObservable.remove(_envSys.particles.followObserver);
        _envSys.particles.followObserver = null;
    }
    if (_envSys.particles.system) {
        _envSys.particles.system.dispose();
        _envSys.particles.system = null;
    }
    disposeSplash(); // 粒子销毁时同步销毁溅射
    stopFireworkBursts(); // 烟花 burst 清理
    // 释放粒子纹理缓存（防止 GPU 资源泄漏）
    for (const tex of _particleTextures.values()) {
        tex.dispose();
    }
    _particleTextures.clear();
    _initialDir1 = null;
    _initialDir2 = null;
    _baseEmitRate = 0;
    _baseMinSize = 0;
    _baseMaxSize = 0;
    _baseMinEmitPower = 0;
    _baseMaxEmitPower = 0;
    _prevCustomTexKey = null;
    // 不重置 _currentParticleType，以便 particleEnabled 自动恢复时知道上次类型
}

/** 获取当前粒子类型（用于 particleEnabled 自动启停） */
export function getCurrentParticleType(): EnvState['particleType'] {
    return _currentParticleType;
}

// ======== Splash System (Phase B: 雨雪落地溅射) ========

/** 判断当前粒子类型是否支持溅射 */
function isWeatherType(type: EnvState['particleType']): boolean {
    return type === 'rain' || type === 'snow';
}

/** 创建溅射粒子系统（地面随机位置脉冲触发，视觉欺骗方案） */
export function createSplashEmitter(): void {
    if (_splashSystem) {
        return;
    }
    const scene = getScene();
    const ps = new GPUParticleSystem('splashParticles', { capacity: 500 }, scene);
    ps.particleTexture = makeParticleTexture('splash');
    ps.emitRate = 8; // 低频持续发射，位置随机化产生溅射感
    ps.emitter = new Vector3(0, 0, 0);
    ps.minLifeTime = 0.3;
    ps.maxLifeTime = 0.6;
    ps.minSize = 0.03;
    ps.maxSize = 0.08;
    ps.minEmitPower = 2;
    ps.maxEmitPower = 5;
    ps.gravity = new Vector3(0, -15, 0);
    ps.blendMode = ParticleSystem.BLENDMODE_STANDARD;

    // 向上溅射 + 水平随机偏移
    ps.direction1 = new Vector3(-1, 2, -1);
    ps.direction2 = new Vector3(1, 4, 1);

    ps.addColorGradient(0, new Color4(0.8, 0.9, 1, 0.8), new Color4(0.9, 0.95, 1, 0.9));
    ps.addColorGradient(1, new Color4(0.8, 0.9, 1, 0), new Color4(0.9, 0.95, 1, 0));

    _splashSystem = ps;
    ps.start();

    // 每帧在地面随机位置移动发射器，产生散落溅射效果
    _envSys.splash.observer = scene.onBeforeRenderObservable.add(() => {
        if (!envState.particleSplash || !isWeatherType(_currentParticleType)) {
            return;
        }
        const cam = scene.activeCamera;
        if (!cam) return;
        const groundY = envState.groundLevel ?? 0;
        // 在相机附近 80x80 范围内随机跳动
        const rx = cam.position.x + (Math.random() - 0.5) * 80;
        const rz = cam.position.z + (Math.random() - 0.5) * 80;
        ps.emitter = new Vector3(rx, groundY + 0.1, rz);

        // 雨滴落水涟漪：水面开启时，溅射位置在水面范围内则概率触发
        if (envState.waterEnabled) {
            const halfSize = envState.waterSize / 2;
            if (Math.abs(rx) <= halfSize && Math.abs(rz) <= halfSize && Math.random() < 0.25) {
                addRipple(new Vector3(rx, envState.waterLevel, rz), 1.5, 0.25, 1, 2);
            }
        }
    });
}

/** 销毁溅射粒子系统 */
export function disposeSplash(): void {
    if (_splashSystem) {
        _splashSystem.dispose();
        _splashSystem = null;
    }
    if (_envSys.splash.observer) {
        const scene = getScene();
        scene.onBeforeRenderObservable.remove(_envSys.splash.observer);
        _envSys.splash.observer = null;
    }
}

/** 溅射开关切换（由 env-impl 检测 particleSplash 变化时调用） */
export function syncSplashState(): void {
    const shouldShow = envState.particleSplash && isWeatherType(_currentParticleType) && envState.particleEnabled;
    if (shouldShow && !_splashSystem) {
        createSplashEmitter();
    } else if (!shouldShow && _splashSystem) {
        disposeSplash();
    }
}

// ======== Firework Multi-Burst System ========
interface FireworkBurstInstance {
    system: GPUParticleSystem;
    cleanupTimer: ReturnType<typeof setTimeout>;
}
let _fireworkBursts: FireworkBurstInstance[] = [];
let _fireworkScheduler: ReturnType<typeof setTimeout> | null = null;

function spawnFireworkBurst(): void {
    const scene = getScene();
    const cam = scene.activeCamera;
    if (!cam) return;

    const groundY = envState.groundLevel ?? 0;
    // 在相机附近随机位置爆散
    const pos = new Vector3(
        cam.position.x + (Math.random() - 0.5) * 30,
        groundY + FIREWORK_HEIGHT_OFFSET + (Math.random() - 0.5) * 4,
        cam.position.z + (Math.random() - 0.5) * 30,
    );

    const burst = new GPUParticleSystem(
        `firework_${_fireworkBursts.length}_${Date.now()}`,
        { capacity: 200 },
        scene,
    );
    burst.particleTexture = makeParticleTexture('fireworks');
    burst.emitter = pos;
    // 瞬时高密度爆发：emitRate=2000，50ms 内出约 100 粒子，之后停发
    burst.emitRate = 2000;
    setTimeout(() => { burst.emitRate = 0; }, 50);

    burst.minLifeTime = 0.4;
    burst.maxLifeTime = 1.0;
    burst.minEmitPower = 4;
    burst.maxEmitPower = 10;
    burst.gravity = new Vector3(0, -2, 0);
    burst.blendMode = ParticleSystem.BLENDMODE_ADD;
    burst.createSphereEmitter(0.2);

    // 每发随机色相
    const hue = Math.random();
    const r = 0.5 + Math.cos(hue * Math.PI * 2) * 0.5;
    const g = 0.5 + Math.cos((hue + 1 / 3) * Math.PI * 2) * 0.5;
    const b = 0.5 + Math.cos((hue + 2 / 3) * Math.PI * 2) * 0.5;

    burst.addColorGradient(0, new Color4(r, g, b, 1), new Color4(r, g, b, 1));
    burst.addColorGradient(0.4, new Color4(r, g, b, 0.8), new Color4(r * 0.8, g * 0.8, b * 0.8, 0.6));
    burst.addColorGradient(1, new Color4(r * 0.3, g * 0.3, b * 0.3, 0), new Color4(r * 0.2, g * 0.2, b * 0.2, 0));

    // 尺寸：爆炸膨胀后缩小
    burst.minSize = 0.05;
    burst.maxSize = 0.1;
    burst.addSizeGradient(0, 0.02, 0.04);
    burst.addSizeGradient(0.3, 0.2, 0.35);
    burst.addSizeGradient(1, 0.04, 0.08);

    burst.start();

    const cleanupTimer = setTimeout(() => {
        burst.dispose();
        _fireworkBursts = _fireworkBursts.filter((b) => b.system !== burst);
    }, 3000);

    _fireworkBursts.push({ system: burst, cleanupTimer });
}

function scheduleNextFireworkBurst(): void {
    const delay = 1200 + Math.random() * 1800; // 1.2~3s 间隔
    _fireworkScheduler = setTimeout(() => {
        if (_currentParticleType !== 'fireworks') return;
        if (!envState.particleEnabled) return;
        spawnFireworkBurst();
        scheduleNextFireworkBurst();
    }, delay);
}

function stopFireworkBursts(): void {
    if (_fireworkScheduler !== null) {
        clearTimeout(_fireworkScheduler);
        _fireworkScheduler = null;
    }
    for (const b of _fireworkBursts) {
        clearTimeout(b.cleanupTimer);
        b.system.dispose();
    }
    _fireworkBursts = [];
}

// ======== Wind System ========
// 基于初始方向计算风力，可安全多次调用（每帧调用也不会叠加）
export function applyWindToParticles(ps: GPUParticleSystem): void {
    if (!_initialDir1 || !_initialDir2) {
        return;
    }
    // 粒子风响应系数 0.1（比布料小，粒子更轻但受发射方向约束）
    const wind = getWindVector().scale(0.1);
    ps.direction1 = _initialDir1.clone().add(wind);
    ps.direction2 = _initialDir2.clone().add(wind);
}

// 运行时动态更新风力（由 ensureEnvUpdateObserver 每帧调用）
export function updateParticleWind(): void {
    if (_envSys.particles.system) {
        applyWindToParticles(_envSys.particles.system);
    }
}

/** 运行时更新粒子参数（密度/大小/速度），响应滑条变化 */
export function updateParticleParams(): void {
    const ps = _envSys.particles.system;
    if (!ps) {
        return;
    }
    ps.emitRate = Math.max(0, _baseEmitRate * envState.particleEmitRate);
    ps.minSize = _baseMinSize * envState.particleSize;
    ps.maxSize = _baseMaxSize * envState.particleSize;
    ps.minEmitPower = _baseMinEmitPower * envState.particleSpeed;
    ps.maxEmitPower = _baseMaxEmitPower * envState.particleSpeed;
}

/** 运行时更新粒子纹理（响应自定义纹理变化） */
let _prevCustomTexKey: string | null = null;
export function updateParticleTexture(): void {
    const ps = _envSys.particles.system;
    if (!ps || !_currentParticleType || _currentParticleType === 'none') {
        return;
    }
    const url = envState.particleCustomTexture || undefined;
    const newKey = url ? `_custom_${url}` : null;
    // 切换前 dispose 上一个自定义纹理（释放 GPU 资源）
    if (_prevCustomTexKey && _prevCustomTexKey !== newKey) {
        const old = _particleTextures.get(_prevCustomTexKey);
        if (old) {
            old.dispose();
            _particleTextures.delete(_prevCustomTexKey);
        }
    }
    ps.particleTexture = makeParticleTexture(_currentParticleType, url);
    _prevCustomTexKey = newKey;
}

import {
    Scene,
    Color3,
    Vector3,
    Texture,
    Constants,
    Mesh,
    MeshBuilder,
    ShaderMaterial,
    Observer,
    DirectionalLight,
    DefaultRenderingPipeline,
    Effect,
    PostProcess,
} from '@babylonjs/core';
import { EnvState, envState } from '../../core/config';
import { getWindVector, isWindActive } from '../../core/physics/wind-utils';
import { _envSys, getScene, ensureEnvUpdateObserver } from './env-impl';

// ======== 常量定义 ========
const WATER_BASE_SIZE = 60; // 水面基准尺寸（世界单位），通过缩放调整最终大小
const LOD_HIGH_DISTANCE = 30; // LOD 切换距离（近）
const LOD_LOW_DISTANCE = 80; // LOD 切换距离（远）
const UNDERWATER_TRANSITION_SPEED = 0.5; // 水下过渡速度（秒）

// ======== 水下状态（供 Env Update Observer 和 disposeWater 使用）========
export let _underwaterActive = false;
export let _underwaterSavedFog: { mode: number; color: Color3; density: number } | null = null;
export let _underwaterTransitionProgress = 0;
export let _underwaterTarget = false;

// ======== 波方向计算（风向联动）========
/**
 * 根据风向计算 4 层 Gerstner 波的 vec2 方向数组。
 * 主方向与风向对齐，其余 3 层以微小偏移分散，保持波浪自然丰富度。
 * 风向为零或无效时回退到默认的均匀分布方向。
 */
function computeWaveDirs(windDir: [number, number, number]): number[] {
    // Float32Array → number[] 因为 Babylon setArray2 需要 number[]
    const arr: number[] = new Array(8).fill(0); // 4 × vec2
    if (!windDir || (windDir[0] === 0 && windDir[2] === 0)) {
        // 无有效风向 → 回退到原硬编码的均匀分布
        const fallback: [number, number][] = [
            [0.8, 0.6], [-0.3, 0.9], [-0.7, -0.5], [0.5, -0.8],
        ];
        for (let i = 0; i < 4; i++) {
            const len = Math.sqrt(fallback[i][0] ** 2 + fallback[i][1] ** 2);
            arr[i * 2] = fallback[i][0] / len;
            arr[i * 2 + 1] = fallback[i][1] / len;
        }
        return arr;
    }
    // 从 windDirection 计算风向角（XZ 平面）
    const angle = Math.atan2(windDir[0], windDir[2]);
    // 4 个波方向：主方向对齐风向，其余偏移以保持波面复杂度
    const offsets = [0, 0.3, -0.2, 0.1];
    for (let i = 0; i < 4; i++) {
        const a = angle + offsets[i];
        arr[i * 2] = Math.sin(a);
        arr[i * 2 + 1] = Math.cos(a);
    }
    return arr;
}

// === LOD 水面：记录所有 LOD 子网格，用于同步缩放和位置 ===
let _waterLODs: Mesh[] = [];

// === 每帧更新水面的 observer ===
let _waterUpdateObserver: Observer<Scene> | null = null;

// ======== 涟漪系统（Interaction Ripples）========
const MAX_RIPPLES = 8;
interface RippleSource {
    position: Vector3;
    radius: number;
    strength: number;
    speed: number;
    life: number;
    maxLife: number;
}
let _ripples: RippleSource[] = [];
let _rippleDirty = true;

// ======== 水下 Tint 后处理（自定义 PostProcess，替代不存在的 tintColor/tintAmount）========
Effect.ShadersStore['underwaterTintFragmentShader'] = [
    'precision highp float;',
    'varying vec2 vUV;',
    'uniform sampler2D textureSampler;',
    'uniform vec3 tintColor;',
    'uniform float tintAmount;',
    'void main() {',
    '    vec4 color = texture2D(textureSampler, vUV);',
    '    vec3 mixed = mix(color.rgb, tintColor, tintAmount);',
    '    gl_FragColor = vec4(mixed, color.a);',
    '}',
].join('\n');

let _tintPostProcess: PostProcess | null = null;

function ensureTintPostProcess(camera: any): void {
    if (_tintPostProcess) return;
    _tintPostProcess = new PostProcess(
        'underwaterTint',
        'underwaterTint',
        ['tintColor', 'tintAmount'],
        null,
        1.0,
        camera,
        Constants.TEXTURE_BILINEAR_SAMPLINGMODE
    );
    (_tintPostProcess as any).disable();
}

function disposeTintPostProcess(): void {
    if (_tintPostProcess) {
        _tintPostProcess.dispose();
        _tintPostProcess = null;
    }
}

export function addRipple(pos: Vector3, radius = 5, strength = 0.5, speed = 2, maxLife = 3): void {
    let idx = -1;
    let oldestLife = Infinity;
    for (let i = 0; i < _ripples.length; i++) {
        if (_ripples[i].life <= 0) {
            idx = i;
            break;
        }
        if (_ripples[i].life < oldestLife) {
            oldestLife = _ripples[i].life;
            idx = i;
        }
    }
    if (idx === -1 && _ripples.length < MAX_RIPPLES) {
        idx = _ripples.length;
        _ripples.push({
            position: new Vector3(0, 0, 0),
            radius: 0,
            strength: 0,
            speed: 0,
            life: 0,
            maxLife: 0,
        });
    }
    if (idx === -1) {
        return;
    }
    const r = _ripples[idx];
    r.position.copyFrom(pos);
    r.radius = Math.max(0.1, radius);
    r.strength = Math.max(0, Math.min(1, strength));
    r.speed = Math.max(0.1, speed);
    r.life = maxLife > 0 ? maxLife : 9999;
    r.maxLife = maxLife;
    _rippleDirty = true;
}

export function clearRipples(): void {
    _ripples = [];
    _rippleDirty = true;
}

// ======== 焦散系统（静态纹理 + UV 滚动）========
let _causticTexture: Texture | null = null;
const CAUSTIC_TEX_SIZE = 128;

function ensureCausticTexture(scene: Scene): Texture {
    if (_causticTexture) {
        return _causticTexture;
    }
    const S = CAUSTIC_TEX_SIZE;
    const canvas = document.createElement('canvas');
    canvas.width = S;
    canvas.height = S;
    const ctx = canvas.getContext('2d')!;
    const imgData = ctx.createImageData(S, S);
    const data = imgData.data;
    for (let y = 0; y < S; y++) {
        for (let x = 0; x < S; x++) {
            const u = x / S,
                v = y / S;
            let n = 0,
                total = 0,
                amp = 1,
                freq = 4;
            for (let o = 0; o < 3; o++) {
                n += amp * (Math.sin(u * freq * Math.PI) * Math.cos(v * freq * Math.PI));
                total += amp;
                amp *= 0.5;
                freq *= 2;
            }
            n = (n / total) * 0.5 + 0.5;
            const i = (y * S + x) * 4;
            const val = Math.floor(128 + (n - 0.5) * 128);
            data[i] = val;
            data[i + 1] = val;
            data[i + 2] = val;
            data[i + 3] = 255;
        }
    }
    ctx.putImageData(imgData, 0, 0);
    const tex = new Texture(canvas.toDataURL(), scene, false, false);
    tex.wrapU = Constants.TEXTURE_WRAP_ADDRESSMODE;
    tex.wrapV = Constants.TEXTURE_WRAP_ADDRESSMODE;
    _causticTexture = tex;
    return tex;
}

// ======== Custom Water Shader — Gerstner Waves + Foam ========
const WATER_VERT_SRC = `
precision highp float;
attribute vec3 position;
attribute vec2 uv;
attribute vec3 normal;
uniform mat4 world;
uniform mat4 viewProjection;
uniform float time;
uniform float waveHeight;
uniform float waveSpeed;

// Gerstner 波参数
// WAVE_DIR 由外部 uniform uWindDir[4] 驱动（风向联动），在 createWater 时计算并传入
const int WAVE_COUNT = 4;
uniform vec2 uWindDir[4];
const float WAVE_FREQ[4] = float[4](0.15, 0.2, 0.25, 0.3);
const float WAVE_AMP[4] = float[4](0.3, 0.25, 0.2, 0.15);
const float WAVE_SPEED[4] = float[4](0.7, 0.9, 0.5, 1.2);

varying vec2 vUV;
varying vec3 vWorldPos;
varying vec3 vNormal;
varying float vHeight;

void main() {
    vUV = uv;
    vec3 worldPos = (world * vec4(position, 1.0)).xyz;
    vec3 p = worldPos;
    vec3 n = vec3(0.0, 1.0, 0.0);

    for (int i = 0; i < WAVE_COUNT; i++) {
        vec2 dir = uWindDir[i];
        float f = WAVE_FREQ[i];
        float a = WAVE_AMP[i] * waveHeight;
        float th = f * dot(dir, p.xz) + WAVE_SPEED[i] * time * waveSpeed;
        float c = cos(th), s = sin(th);
        p.x += a * dir.x * c; p.z += a * dir.y * c; p.y += a * s;
        n.x -= dir.x * f * a * c; n.z -= dir.y * f * a * c;
    }

    vWorldPos = p;
    vNormal = normalize(n);
    vHeight = p.y;
    gl_Position = viewProjection * vec4(p, 1.0);
}`;

const WATER_FRAG_SRC = `
precision highp float;
varying vec2 vUV;
varying vec3 vWorldPos;
varying vec3 vNormal;
varying float vHeight;

uniform vec3 cameraPosition;
uniform vec3 waterColor;
uniform float waterTransparency;
uniform float waterLevel;
uniform float time;
uniform float envIntensity;
uniform vec3 foamColor;
uniform float foamThreshold;
uniform float foamIntensity;
uniform vec3 fogColor;
uniform float fogDensity;
uniform vec3 lightDir;
uniform vec3 lightColor;
uniform float ambientIntensity;

// ======== 可调节的视觉参数（从硬编码提取）========
uniform float fresnelBias;      // Fresnel 偏移（默认 0.02）
uniform float fresnelPower;      // Fresnel 幂次（默认 3.0）
uniform float diffuseStrength;    // 漫反射强度（默认 0.15）
uniform float ambientStrength;    // 环境光强度系数（默认 0.15）
uniform float foamTransitionRange; // 泡沫过渡范围（默认 0.15）
uniform float rippleNormalStrength; // 涟漪法线影响强度（默认 0.15）
uniform float rippleGlintStrength; // 涟漪光泽强度（默认 0.25）
uniform vec3 causticColor1;     // 焦散颜色1（亮部，默认 vec3(1.0, 0.9, 0.6)）
uniform vec3 causticColor2;     // 焦散颜色2（暗部，默认 vec3(1.0, 1.0, 0.8)）
uniform float causticScrollX;   // 焦散UV滚动速度X（默认 0.10）
uniform float causticScrollY;   // 焦散UV滚动速度Y（默认 0.15）
uniform float fresnelAlphaInfluence; // Fresnel对alpha的影响（默认 0.5）
uniform float foamAlphaInfluence;    // 泡沫对alpha的影响（默认 0.2）

uniform sampler2D uCausticTex;
uniform float uCausticIntensity;
uniform float uCausticSpeed;
uniform float uCausticScale;

uniform vec4 uRipplePosRad[8];
uniform vec4 uRippleStrSpdLife[8];
uniform int uRippleCount;

float calcRipple(vec3 worldPos, vec3 center, float radius, float strength, float speed, float life) {
    vec2 delta = worldPos.xz - center.xz;
    float dist = length(delta);
    if (dist > radius || life <= 0.0) return 0.0;
    float phase = life * speed;
    float ripple = sin(dist * 3.0 - phase) * exp(-dist / (radius * 0.5));
    ripple *= strength * (1.0 - dist / radius);
    float lifeFactor = min(1.0, life / 1.0);
    ripple *= lifeFactor;
    return max(0.0, ripple);
}

#ifdef ENV_TEXTURE
uniform samplerCube envTexture;
#endif

void main() {
    vec3 viewDir = normalize(cameraPosition - vWorldPos);
    vec3 normal = normalize(vNormal);
    vec3 reflectDir = reflect(-viewDir, normal);

    vec3 reflection = vec3(0.0);
    #ifdef ENV_TEXTURE
    reflection = textureCube(envTexture, reflectDir).rgb * envIntensity;
    #endif

    float fresnel = fresnelBias + (1.0 - fresnelBias) * pow(1.0 - max(dot(viewDir, normal), 0.0), fresnelPower);

    vec3 base = waterColor;
    vec3 color = mix(base, reflection, fresnel);

    float diff = max(dot(normal, normalize(lightDir)), 0.0);
    color += diff * lightColor * diffuseStrength;
    color += ambientIntensity * waterColor * ambientStrength;

    float foamH = vHeight - waterLevel;
    float foam = smoothstep(foamThreshold, foamThreshold + foamTransitionRange, foamH);
    foam = clamp(foam, 0.0, 1.0);
    color = mix(color, foamColor, foam * foamIntensity);

    float rippleSum = 0.0;
    for (int i = 0; i < 8; i++) {
        if (i >= uRippleCount) break;
        vec4 pr = uRipplePosRad[i];
        vec4 ssl = uRippleStrSpdLife[i];
        if (pr.w <= 0.0 || ssl.z <= 0.0) continue;
        float r = calcRipple(vWorldPos, pr.xyz, pr.w, ssl.x, ssl.y, ssl.z);
        rippleSum += r;
    }
    vec3 rippleN = vec3(rippleSum * rippleNormalStrength, 0.0, rippleSum * rippleNormalStrength);
    normal = normalize(normal + rippleN);
    float rippleGlint = max(0.0, rippleSum * rippleGlintStrength);
    color += vec3(rippleGlint);

    vec2 causticUV = vWorldPos.xz * uCausticScale + vec2(time * uCausticSpeed * causticScrollX, time * uCausticSpeed * causticScrollY);
    float caustic = texture2D(uCausticTex, causticUV).r;
    vec3 causticCol = mix(causticColor1, causticColor2, caustic);
    color += causticCol * caustic * uCausticIntensity;

    float depth = length(vWorldPos - cameraPosition);
    float fog = 1.0 - exp(-fogDensity * depth);
    color = mix(color, fogColor, fog);

    float alpha = mix(waterTransparency, 1.0, fresnel * fresnelAlphaInfluence + foam * foamAlphaInfluence);
    alpha = clamp(alpha, 0.0, 1.0);

    gl_FragColor = vec4(color, alpha);
}`;

// ======== Water System ========

/**
 * 同步水面材质的全部 uniform 参数（非破坏性，不销毁/重建材质）。
 * 由 createWater 在惰性路径和首次创建后调用。
 */
function _syncWaterUniforms(state: EnvState, scene: Scene): void {
    const mat = _envSys.water.material as ShaderMaterial | null;
    const mesh = _envSys.water.mesh;
    if (!mat || !mesh) {
        return;
    }

    // ——— 基础参数 ———
    mat.setFloat('waveHeight', state.waterWaveHeight);
    mat.setFloat('waveSpeed', (state.waterAnimSpeed ?? 1) * 1.0);
    mat.setColor3('waterColor', new Color3(state.waterColor[0], state.waterColor[1], state.waterColor[2]));
    mat.setFloat('waterTransparency', state.waterTransparency);
    mat.setFloat('waterLevel', state.waterLevel);

    const hasEnv = !!scene.environmentTexture;
    mat.setFloat('envIntensity', hasEnv ? (scene.environmentIntensity ?? 0.8) : 0);
    if (hasEnv && scene.environmentTexture) {
        mat.setTexture('envTexture', scene.environmentTexture);
    }

    // ——— 泡沫 ———
    mat.setColor3('foamColor', new Color3(1, 1, 1));
    mat.setFloat('foamThreshold', state.foamThreshold);
    mat.setFloat('foamIntensity', state.foamIntensity);

    // ——— 灯光 ———
    const dirLight = scene.getLightByName('dir') as DirectionalLight | null;
    if (dirLight) {
        mat.setVector3('lightDir', dirLight.direction);
        mat.setColor3('lightColor', dirLight.diffuse);
    } else {
        mat.setVector3('lightDir', new Vector3(-0.5, -1, -0.5));
        mat.setColor3('lightColor', new Color3(1, 1, 1));
    }
    mat.setFloat('ambientIntensity', 0.3);

    // ——— 焦散 ———
    const causticTex = ensureCausticTexture(scene);
    mat.setTexture('uCausticTex', causticTex);
    mat.setFloat('uCausticIntensity', 0.15);
    mat.setFloat('uCausticSpeed', 0.5);
    mat.setFloat('uCausticScale', 0.04);

    // ——— 高级参数（从 EnvState 读取，持久化）———
    mat.setFloat('fresnelBias', state.fresnelBias);
    mat.setFloat('fresnelPower', state.fresnelPower);
    mat.setFloat('diffuseStrength', state.diffuseStrength);
    mat.setFloat('ambientStrength', state.ambientStrength);
    mat.setFloat('foamTransitionRange', state.foamTransitionRange);
    mat.setFloat('rippleNormalStrength', state.rippleNormalStrength);
    mat.setFloat('rippleGlintStrength', state.rippleGlintStrength);
    mat.setVector3('causticColor1', new Vector3(state.causticColor1[0], state.causticColor1[1], state.causticColor1[2]));
    mat.setVector3('causticColor2', new Vector3(state.causticColor2[0], state.causticColor2[1], state.causticColor2[2]));
    mat.setFloat('causticScrollX', state.causticScrollX);
    mat.setFloat('causticScrollY', state.causticScrollY);
    mat.setFloat('fresnelAlphaInfluence', state.fresnelAlphaInfluence);
    mat.setFloat('foamAlphaInfluence', state.foamAlphaInfluence);

    // ——— 雾 ———
    mat.setColor3('fogColor', scene.fogColor);
    mat.setFloat('fogDensity', scene.fogDensity);

    // ——— 波方向（风向联动）———
    const windDirs = computeWaveDirs(envState.windDirection);
    mat.setArray2('uWindDir', windDirs);

    // ——— 涟漪数组（初始化为空）———
    mat.setArray4('uRipplePosRad', new Array(MAX_RIPPLES * 4).fill(0));
    mat.setArray4('uRippleStrSpdLife', new Array(MAX_RIPPLES * 4).fill(0));
    mat.setInt('uRippleCount', 0);
}

/**
 * 更新水面网格的位置和缩放（非破坏性）。
 */
function _updateWaterMesh(state: EnvState): void {
    const mesh = _envSys.water.mesh;
    if (!mesh) {
        return;
    }
    mesh.position.y = state.waterLevel;
    const scale = Math.max(1, state.waterSize / WATER_BASE_SIZE);
    mesh.scaling = new Vector3(scale, 1, scale);
}

export function createWater(state: EnvState): void {
    ensureEnvUpdateObserver();

    // **惰性路径**：水面已初始化且启用 → 只同步参数，不销毁重建
    if (state.waterEnabled && _envSys.water.material && _envSys.water.mesh) {
        const scene = getScene();
        _syncWaterUniforms(state, scene);
        _updateWaterMesh(state);
        return;
    }

    // **关闭路径**：水面未启用 → 清理资源
    if (!state.waterEnabled) {
        disposeWater();
        return;
    }

    // **首次创建路径**：水面不存在且启用 → 全量构建
    const scene = getScene();

    _waterLODs = [];
    // 使用基准尺寸创建网格，通过缩放调整最终大小（避免尺寸叠加错误）
    const meshHigh = MeshBuilder.CreateGround(
        'envWater',
        { width: WATER_BASE_SIZE, height: WATER_BASE_SIZE, subdivisions: 48 },
        scene
    );
    meshHigh.isPickable = false;
    meshHigh.position.y = state.waterLevel;
    const scale = Math.max(1, state.waterSize / WATER_BASE_SIZE);
    meshHigh.scaling = new Vector3(scale, 1, scale);

    const meshMid = MeshBuilder.CreateGround(
        'envWater_LOD1',
        { width: WATER_BASE_SIZE, height: WATER_BASE_SIZE, subdivisions: 16 },
        scene
    );
    meshMid.isPickable = false;
    meshMid.position = new Vector3(0, 0, 0); // 相对于父网格的偏移
    meshMid.parent = meshHigh; // 建立父子关系，自动继承变换

    const meshLow = MeshBuilder.CreateGround(
        'envWater_LOD2',
        { width: WATER_BASE_SIZE, height: WATER_BASE_SIZE, subdivisions: 6 },
        scene
    );
    meshLow.isPickable = false;
    meshLow.position = new Vector3(0, 0, 0); // 相对于父网格的偏移
    meshLow.parent = meshHigh; // 建立父子关系，自动继承变换

    meshHigh.addLODLevel(LOD_HIGH_DISTANCE, meshMid);
    meshHigh.addLODLevel(LOD_LOW_DISTANCE, meshLow);
    _waterLODs = [meshMid, meshLow];

    const hasEnv = !!scene.environmentTexture;
    const mat = new ShaderMaterial(
        'customWaterMat',
        scene,
        {
            vertexSource: WATER_VERT_SRC,
            fragmentSource: WATER_FRAG_SRC,
        },
        {
            attributes: ['position', 'uv', 'normal'],
            uniforms: [
                'world',
                'viewProjection',
                'time',
                'waveHeight',
                'waveSpeed',
                'cameraPosition',
                'waterColor',
                'waterTransparency',
                'waterLevel',
                'envIntensity',
                'foamColor',
                'foamThreshold',
                'foamIntensity',
                'fogColor',
                'fogDensity',
                'lightDir',
                'lightColor',
                'ambientIntensity',
                'uRipplePosRad',
                'uRippleStrSpdLife',
                'uRippleCount',
                'uCausticIntensity',
                'uCausticSpeed',
                'uCausticScale',
                'fresnelBias',
                'fresnelPower',
                'diffuseStrength',
                'ambientStrength',
                'foamTransitionRange',
                'rippleNormalStrength',
                'rippleGlintStrength',
                'causticColor1',
                'causticColor2',
                'causticScrollX',
                'causticScrollY',
                'fresnelAlphaInfluence',
                'foamAlphaInfluence',
                'uWindDir',
            ],
            uniformBuffers: [],
            samplers: ['uCausticTex'].concat(hasEnv ? ['envTexture'] : []),
            defines: hasEnv ? ['ENV_TEXTURE'] : [],
            needAlphaBlending: true,
        }
    );

    meshHigh.material = mat;
    meshMid.material = mat;
    meshLow.material = mat;

    _envSys.water.mesh = meshHigh;
    _envSys.water.material = mat;

    // 同步所有 uniform（复用 _syncWaterUniforms 逻辑）
    _syncWaterUniforms(state, scene);

    // —— 每帧更新 observer（涟漪衰减 + 动态数据）——
    if (!_waterUpdateObserver) {
        _waterUpdateObserver = scene.onBeforeRenderObservable.add(() => {
            if (!_envSys.water.material) {
                return;
            }
            const m = _envSys.water.material as ShaderMaterial;
            const now = performance.now() / 1000;
            m.setFloat('time', now);
            const cam = scene.activeCamera;
            if (cam) {
                m.setVector3('cameraPosition', cam.position);
            }
            m.setColor3('fogColor', scene.fogColor);
            m.setFloat('fogDensity', scene.fogDensity);
            const dl = scene.getLightByName('dir') as DirectionalLight | null;
            if (dl) {
                m.setVector3('lightDir', dl.direction);
                m.setColor3('lightColor', dl.diffuse);
            }

            const dt = scene.deltaTime / 1000;
            if (dt > 0) {
                let anyAlive = false;
                for (const r of _ripples) {
                    if (r.life > 0) {
                        r.life -= dt;
                        if (r.life < 0) {
                            r.life = 0;
                        }
                        if (r.life > 0) {
                            anyAlive = true;
                        }
                    }
                }
                if (!anyAlive && _ripples.length > 0) {
                    _ripples = [];
                    _rippleDirty = true;
                }
            }
            if (_rippleDirty) {
                _rippleDirty = false;
                const posRad: number[] = new Array(MAX_RIPPLES * 4).fill(0);
                const strSpdLife: number[] = new Array(MAX_RIPPLES * 4).fill(0);
                const count = Math.min(_ripples.length, MAX_RIPPLES);
                for (let i = 0; i < count; i++) {
                    const r = _ripples[i];
                    if (r.life <= 0) {
                        continue;
                    }
                    posRad[i * 4 + 0] = r.position.x;
                    posRad[i * 4 + 1] = r.position.y;
                    posRad[i * 4 + 2] = r.position.z;
                    posRad[i * 4 + 3] = r.radius;
                    strSpdLife[i * 4 + 0] = r.strength;
                    strSpdLife[i * 4 + 1] = r.speed;
                    strSpdLife[i * 4 + 2] = r.life;
                    strSpdLife[i * 4 + 3] = 0;
                }
                m.setArray4('uRipplePosRad', posRad);
                m.setArray4('uRippleStrSpdLife', strSpdLife);
                m.setInt('uRippleCount', count);
            }
        });
    }
}

export function disposeWater(): void {
    if (_envSys.water.mesh) {
        _envSys.water.mesh.dispose(true); // true = recursive, disposes LOD children too
        _envSys.water.mesh = null;
    }
    // mesh.dispose(true) 已递归销毁所有子 LOD 网格，仅需清空引用
    _waterLODs = [];
    clearRipples(); // 清理残留涟漪，避免 dispose 后再次 createWater 时显示旧数据
    if (_envSys.water.material) {
        _envSys.water.material.dispose();
        _envSys.water.material = null;
    }
    // 释放焦散纹理，防止内存泄漏
    if (_causticTexture) {
        _causticTexture.dispose();
        _causticTexture = null;
    }
    if (_waterUpdateObserver) {
        getScene().onBeforeRenderObservable.remove(_waterUpdateObserver);
        _waterUpdateObserver = null;
    }
    _underwaterActive = false;
    _underwaterSavedFog = null;
    _underwaterTransitionProgress = 0;
    _underwaterTarget = false;
    disposeTintPostProcess();
}

