    if (customMap) {
        for (const [pattern, category] of Object.entries(customMap)) {
            try {
                if (new RegExp(pattern, 'i').test(name)) {
                    return category as MaterialCategory;
                }
            } catch {
                // 无效正则，跳过
            }
        }
    }

    // 按优先级匹配，命中即返回（包含匹配，不区分大小写）
    const lowerName = name.toLowerCase();
    for (const [keywords, cat] of CATEGORY_RULES) {
        if (keywords.some((k) => lowerName.includes(k))) {
            return cat;
        }
    }
    return '服装';
}

/** @internal exported for testing + pre-capture in scene-loader */
export function _capture(mat: Material): void {
    if (_origValues.has(mat) || !(mat instanceof StandardMaterial)) {
        return;
    }
    _origValues.set(mat, {
        diffuse: mat.diffuseColor.clone(),
        specular: mat.specularColor.clone(),
        specularPower: mat.specularPower,
        ambient: mat.ambientColor.clone(),
    });
}

/** @internal exported for testing */
export function _applyAll(id: string): void {
    const meshes = _getMeshesById(id);
    if (!meshes) {
        return;
    }
    const state = _catState.get(id);
    if (!state) {
        return;
    }
    const perMat = _matState.get(id) ?? new Map();
    for (let mi = 0; mi < meshes.length; mi++) {
        const mesh = meshes[mi];
        const m = mesh.material;
        if (!m || !(m instanceof StandardMaterial)) {
            continue;
        }
        _capture(m);
        const o = _origValues.get(m)!;
        const p = state.get(_catOf(m.name));
        if (!p) {
            continue;
        }
        m.diffuseColor.set(
            o.diffuse.r * p.diffuseMul,
            o.diffuse.g * p.diffuseMul,
            o.diffuse.b * p.diffuseMul
        );
        m.specularColor.set(
            o.specular.r * p.specularMul,
            o.specular.g * p.specularMul,
            o.specular.b * p.specularMul
        );
        m.specularPower = p.shininess;
        m.ambientColor.set(
            o.ambient.r * p.ambientMul,
            o.ambient.g * p.ambientMul,
            o.ambient.b * p.ambientMul
        );
        const mp = perMat.get(mi);
        if (mp) {
            m.diffuseColor.set(
                o.diffuse.r * mp.diffuseMul,
                o.diffuse.g * mp.diffuseMul,
                o.diffuse.b * mp.diffuseMul
            );
            m.specularColor.set(
                o.specular.r * mp.specularMul,
                o.specular.g * mp.specularMul,
                o.specular.b * mp.specularMul
            );
            m.specularPower = mp.shininess;
            m.ambientColor.set(
                o.ambient.r * mp.ambientMul,
                o.ambient.g * mp.ambientMul,
                o.ambient.b * mp.ambientMul
            );
        }
    }
}

function _ensureState(id: string): Map<string, MaterialCategoryParams> {
    let m = _catState.get(id);
    if (m) {
        return m;
    }
    m = new Map();
    for (const c of CATEGORIES) {
        m.set(c, { diffuseMul: 1, specularMul: 1, shininess: 50, ambientMul: 1 });
    }
    _catState.set(id, m);
    return m;
}

export function isMatEnabled(id: string, matIndex: number): boolean {
    return _matEnabled.get(id)?.get(matIndex) ?? true;
}

export function setMatEnabled(id: string, matIndex: number, enabled: boolean): void {
    const meshes = _getMeshesById(id);
    if (!meshes || matIndex < 0 || matIndex >= meshes.length) {
        return;
    }
    const current = isMatEnabled(id, matIndex);
    if (current === enabled) {
        return;
    }
    meshes[matIndex].setEnabled(enabled);
    if (enabled) {
        _matEnabled.get(id)?.delete(matIndex);
    } else {
        let m = _matEnabled.get(id);
        if (!m) {
            m = new Map();
            _matEnabled.set(id, m);
        }
        m.set(matIndex, false);
    }
    triggerAutoSave();
}

export function getMatCatGroups(id: string): Map<string, { name: string; mat: Material }[]> {
    const groups = new Map<string, { name: string; mat: Material }[]>();
    const meshes = _getMeshesById(id);
    if (!meshes) {
        return groups;
    }
    for (const mesh of meshes) {
        const m = mesh.material;
        if (!m || !(m instanceof StandardMaterial)) {
            continue;
        }
        const cat = _catOf(m.name);
        if (!groups.has(cat)) {
            groups.set(cat, []);
        }
        groups.get(cat)!.push({ name: m.name, mat: m });
    }
    return groups;
}

export function getMatCatParams(id: string, cat: string): MaterialCategoryParams {
    if (!CATEGORY_SET.has(cat)) {
        console.warn(`[material] getMatCatParams: unknown category "${cat}"`);
        return { diffuseMul: 1, specularMul: 1, shininess: 50, ambientMul: 1 };
    }
    return { ..._ensureState(id).get(cat)! };
}

export function setMatCatParams(
    id: string,
    cat: string,
    params: Partial<MaterialCategoryParams>
): void {
    if (!CATEGORY_SET.has(cat)) {
        console.warn(`[material] setMatCatParams: unknown category "${cat}"`);
        return;
    }
    const target = _ensureState(id).get(cat)!;
    if (params.diffuseMul !== undefined) {
        target.diffuseMul = Math.max(0, Math.min(2, params.diffuseMul));
    }
    if (params.specularMul !== undefined) {
        target.specularMul = Math.max(0, Math.min(2, params.specularMul));
    }
    if (params.shininess !== undefined) {
        target.shininess = Math.max(0, Math.min(200, Math.round(params.shininess)));
    }
    if (params.ambientMul !== undefined) {
        target.ambientMul = Math.max(0, Math.min(2, params.ambientMul));
    }
    _applyAll(id);
    triggerAutoSave();
}

export function resetMatCatParams(id: string): void {
    _catState.delete(id);
    _matState.delete(id); // 同时清理逐材质覆盖，避免残留状态在下次 _applyAll 中复现
    const meshes = _getMeshesById(id);
    if (!meshes) {
        return;
    }
    for (const mesh of meshes) {
        const m = mesh.material;
        if (!m || !(m instanceof StandardMaterial)) {
            continue;
        }
        const o = _origValues.get(m);
        if (o) {
            m.diffuseColor.copyFrom(o.diffuse);
            m.specularColor.copyFrom(o.specular);
            m.specularPower = o.specularPower;
            m.ambientColor.copyFrom(o.ambient);
        }
    }
    triggerAutoSave();
}

function _ensureMatState(id: string): Map<number, MaterialCategoryParams> {
    let m = _matState.get(id);
    if (m) {
        return m;
    }
    m = new Map();
    _matState.set(id, m);
    return m;
}

export function getMatDetailList(
    id: string
): { name: string; index: number; params: MaterialCategoryParams; modified: boolean }[] {
    const result: {
        name: string;
        index: number;
        params: MaterialCategoryParams;
        modified: boolean;
    }[] = [];
    const meshes = _getMeshesById(id);
    if (!meshes) {
        return result;
    }
    const perMat = _matState.get(id) ?? new Map();
    for (let mi = 0; mi < meshes.length; mi++) {
        const m = meshes[mi].material;
        if (!m || !(m instanceof StandardMaterial)) {
            continue;
        }
        const mp = perMat.get(mi);
        const params: MaterialCategoryParams = mp
            ? { ...mp }
            : { diffuseMul: 1, specularMul: 1, shininess: 50, ambientMul: 1 };
        result.push({ name: m.name, index: mi, params, modified: !!mp });
    }
    return result;
}

export function getMatParams(id: string, matIndex: number): MaterialCategoryParams | null {
    const modelState = _matState.get(id);
    if (!modelState) {
        return null;
    }
    const entry = modelState.get(matIndex);
    return entry ? { ...entry } : null;
}

export function setMatParams(
    id: string,
    matIndex: number,
    params: Partial<MaterialCategoryParams>
): void {
    const meshes = _getMeshesById(id);
    if (!meshes || matIndex < 0 || matIndex >= meshes.length) {
        console.warn(
            `setMatParams: invalid matIndex ${matIndex} for target "${id}" (${meshes ? meshes.length : 0} meshes)`
        );
        return;
    }
    const state = _ensureMatState(id);
    let entry = state.get(matIndex);
    if (!entry) {
        entry = { diffuseMul: 1, specularMul: 1, shininess: 50, ambientMul: 1 };
        state.set(matIndex, entry);
    }
    if (params.diffuseMul !== undefined) {
        entry.diffuseMul = Math.max(0, Math.min(2, params.diffuseMul));
    }
    if (params.specularMul !== undefined) {
        entry.specularMul = Math.max(0, Math.min(2, params.specularMul));
    }
    if (params.shininess !== undefined) {
        entry.shininess = Math.max(0, Math.min(200, Math.round(params.shininess)));
    }
    if (params.ambientMul !== undefined) {
        entry.ambientMul = Math.max(0, Math.min(2, params.ambientMul));
    }
    _applyAll(id);
    triggerAutoSave();
}

export function resetSingleMatParams(id: string, matIndex: number): void {
    const meshes = _getMeshesById(id);
    if (!meshes || matIndex < 0 || matIndex >= meshes.length) {
        console.warn(`resetSingleMatParams: invalid matIndex ${matIndex} for target "${id}"`);
        return;
    }
    const modelState = _matState.get(id);
    if (modelState) {
        modelState.delete(matIndex);
    }
    _applyAll(id);
    triggerAutoSave();
}

/** 清理指定模型的全部材质状态（分类 + 逐材质 + 启用标记）。
 *  供模型移除时统一调用，替代外部直接操作内部 Map。 */
export function disposeModelMaterialState(id: string): void {
    _catState.delete(id);
    _matState.delete(id);
    _matEnabled.delete(id);
}

/**
 * 检查指定分类的全部材质是否都已启用。
 * 用于 batch level 的 headerToggle bind，返回 true 表示全开。
 */
export function isMatCategoryAllEnabled(id: string, cat: string): boolean {
    const meshes = _getMeshesById(id);
    if (!meshes) return true;
    const state = _ensureState(id);
    if (!state.has(cat)) return true;
    for (let mi = 0; mi < meshes.length; mi++) {
        const m = meshes[mi].material;
        if (!m || !(m instanceof StandardMaterial)) continue;
        if (_catOf(m.name) !== cat) continue;
        if (!isMatEnabled(id, mi)) return false;
    }
    return true;
}

/**
 * 按分类批量切换材质可见性。
 * 将指定分类下所有材质统一设为 enabled/disabled。
 */
export function setMatCategoryEnabled(id: string, cat: string, enabled: boolean): void {
    const meshes = _getMeshesById(id);
    if (!meshes) return;
    const state = _ensureState(id);
    if (!state.has(cat)) return;
    for (let mi = 0; mi < meshes.length; mi++) {
        const m = meshes[mi].material;
        if (!m || !(m instanceof StandardMaterial)) continue;
        if (_catOf(m.name) !== cat) continue;
        const current = isMatEnabled(id, mi);
        if (current === enabled) continue;
        meshes[mi].setEnabled(enabled);
        if (enabled) {
            _matEnabled.get(id)?.delete(mi);
        } else {
            let me = _matEnabled.get(id);
            if (!me) {
                me = new Map();
                _matEnabled.set(id, me);
            }
            me.set(mi, false);
        }
    }
    triggerAutoSave();
}

/** 重置所有逐材质覆盖（per-material），保留分类调整（皮肤/头发等）。
 *  如需完整恢复材质到原始状态请先调用 resetMatCatParams。 */
export function resetPerMaterialParams(id: string): void {
    _matState.delete(id);
    _applyAll(id);
    triggerAutoSave();
}

/** @deprecated 使用 resetPerMaterialParams */
export const resetAllMatParams = resetPerMaterialParams;

export function getMatState(id: string): {
    categories: Record<string, MaterialCategoryParams>;
    overrides: Record<number, MaterialCategoryParams>;
    enabled: Record<number, boolean>;
} | null {
    const catState = _catState.get(id);
    const matState = _matState.get(id);
    const enabledState = _matEnabled.get(id);
    if (!catState && !matState && !enabledState) {
        return null;
    }
    const categories: Record<string, MaterialCategoryParams> = {};
    if (catState) {
        for (const [cat, params] of catState) {
            categories[cat] = { ...params };
        }
    }
    const overrides: Record<number, MaterialCategoryParams> = {};
    if (matState) {
        for (const [idx, params] of matState) {
            overrides[idx] = { ...params };
        }
    }
    const enabled: Record<number, boolean> = {};
    if (enabledState) {
        for (const [idx, val] of enabledState) {
            enabled[idx] = val;
        }
    }
    return { categories, overrides, enabled };
}

export function applyMatState(
    id: string,
    state: {
        categories?: Record<string, MaterialCategoryParams>;
        overrides?: Record<number, MaterialCategoryParams>;
        enabled?: Record<number, boolean>;
    }
): void {
    if (state.categories) {
        for (const [cat, params] of Object.entries(state.categories)) {
            setMatCatParams(id, cat as MaterialCategory, params);
        }
    }
    if (state.overrides) {
        for (const [idxStr, params] of Object.entries(state.overrides)) {
            const idx = parseInt(idxStr, 10);
            setMatParams(id, idx, params);
        }
    }
    if (state.enabled) {
        for (const [idxStr, val] of Object.entries(state.enabled)) {
            const idx = parseInt(idxStr, 10);
            setMatEnabled(id, idx, val);
        }
    }
}

// [doc:architecture] Scene Loader — PMX 模型加载、缩略图捕获
// 职责: 模型文件解析、实例创建、缩略图生成、outfit 预加载
// 注意: 从 scene.ts 静态导入但仅在函数体内访问，ES module live binding 保证安全。

import { Mesh } from '@babylonjs/core/Meshes/mesh';
import { ImportMeshAsync } from '@babylonjs/core/Loading/sceneLoader';
import { MmdStandardMaterialProxy } from 'babylon-mmd/esm/Runtime/mmdStandardMaterialProxy';
import { SaveThumbnail } from '../../core/wails-bindings';
import {
    dom,
    setStatus,
    setFocusedModelId,
    pendingVmd,
    setPendingVmd,
    ModelInstance,
    PropInstance,
    propRegistry,
    overridePaths,
    libraryRoot,
    triggerAutoSave,
    formatError,
    uiState,
    type RuntimeModel,
} from '../../core/config';
import { resolveFileUrl, normPath } from '../../core/fileservice';
import type { IMmdRuntime } from 'babylon-mmd/esm/Runtime/IMmdRuntime';
import type { IMmdModel } from 'babylon-mmd/esm/Runtime/IMmdModel';
import { MmdWasmModel } from 'babylon-mmd/esm/Runtime/Optimized/mmdWasmModel';
import { loadVMDMotion } from '../motion/vmd-loader';
import { _capture } from './material';
import { rebuildShadowCasters } from '../render/lighting';

// ======== Loader Dependencies ========

let _scene: import('@babylonjs/core/scene').Scene | null = null;
let _mmdRuntime: IMmdRuntime | null = null;
let _modelManager: import('./model-manager').ModelManager | null = null;
let _refreshWaterRenderList: (() => void) | null = null;
let _tryAutoApplyPreset: ((id: string) => Promise<void>) | null = null;
let _loadOutfits: ((id: string) => Promise<void>) | null = null;
let _rebuildOutlineState: (() => void) | null = null;

export function initLoader(
    scene: import('@babylonjs/core/scene').Scene,
    mmdRuntime: IMmdRuntime,
    modelManager: import('./model-manager').ModelManager,
    refreshWaterRenderList: () => void,
    tryAutoApplyPreset: (id: string) => Promise<void>,
    loadOutfits: (id: string) => Promise<void>,
    rebuildOutlineState?: () => void
): void {
    _scene = scene;
    _mmdRuntime = mmdRuntime;
    _modelManager = modelManager;
    _refreshWaterRenderList = refreshWaterRenderList;
    _tryAutoApplyPreset = tryAutoApplyPreset;
    _loadOutfits = loadOutfits;
    _rebuildOutlineState = rebuildOutlineState ?? null;
}

// ======== Thumbnail Capture ========

const THUMBNAIL_TIMEOUT_MS = 5000;

function withTimeout<T>(promise: Promise<T>, timeoutMs: number, fallback: T): Promise<T> {
    return new Promise((resolve) => {
        const timer = setTimeout(() => resolve(fallback), timeoutMs);
        promise.then(
            (result) => {
                clearTimeout(timer);
                resolve(result);
            },
            () => {
                clearTimeout(timer);
                resolve(fallback);
            }
        );
    });
}

/** Captures a screenshot after model load for thumbnail cache. */
export async function captureThumbnail(filePath: string): Promise<void> {
    try {
        if (!_scene) {
            return;
        }

        let ready = false;
        await withTimeout(
            _scene.whenReadyAsync().then(() => {
                ready = true;
            }),
            THUMBNAIL_TIMEOUT_MS,
            undefined
        );

        if (!ready) {
            await new Promise((r) => requestAnimationFrame(r));
        }

        const base64 = dom.canvas.toDataURL('image/png', 0.8);
        const raw = base64.replace(/^data:image\/png;base64,/, '');
        await SaveThumbnail(filePath, raw);
    } catch (err) {
        console.warn('captureThumbnail:', err);
    }
}

// ======== PMX Loading ========

export async function loadPMXFile(
    filePath: string,
    asStage?: boolean,
    skipAutoApply?: boolean
): Promise<string | null> {
    if (!_scene || !_mmdRuntime) {
        return null;
    }
    let loadedMeshes: Mesh[] = [];
    let wasmModel: IMmdModel | null = null;
    let registeredId: string | null = null;
    try {
        // Check if already loaded — switch focus via ModelManager
        const existing = _modelManager?.findByFilePath(filePath);
        if (existing) {
            setFocusedModelId(existing.id);
            _modelManager?.focus(existing.id);
            setStatus(`✓ 已切换至: ${existing.name}`, true);
            return existing.id;
        }

        const { url, port, dir: modelDir } = await resolveFileUrl(filePath);
        const fileName = normPath(filePath).split('/').pop() || '';

        setStatus('加载中...', false);
        dom.loadingEl.style.display = 'block';
        dom.loadingText.textContent = '加载中 0%';

        // Keep a reference so we can clean up meshes on failure
        const result = await ImportMeshAsync(url, _scene, {
            onProgress: (evt) => {
                if (evt.lengthComputable) {
                    const pct = Math.round((evt.loaded / evt.total) * 100);
                    dom.loadingText.textContent = `加载中 ${pct}%`;
                }
            },
        });
        loadedMeshes = result.meshes.filter((m) => m instanceof Mesh) as Mesh[];

        dom.loadingEl.style.display = 'none';

        const meshes = loadedMeshes;
        if (meshes.length === 0) {
            setStatus('✗ 未加载到网格', false);
            return null;
        }

        const id = `model_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
        const displayName = fileName.replace(/\.pmx$/i, '');

        if (asStage) {
            // Stage: pure static mesh, no MMD runtime, no physics
            const inst: ModelInstance = {
                id,
                name: displayName,
                filePath,
                port,
                modelDir,
                meshes,
                rootMesh: meshes[0],
                vmdData: null,
                vmdName: '',
                vmdPath: null,
                animationDuration: 0,
                vmdLayers: [],
                kind: 'stage',
                visible: true,
                opacity: 1.0,
                wireframe: false,
                showBoneLines: false,
                showBoneJoints: false,
                physicsEnabled: false,
                scaling: 1.0,
                rotationY: 0,
            };
            // Register via ModelManager only — it owns the registry
            _modelManager.register(inst);
            registeredId = id;
            // Pre-capture material original values for reset functionality
            for (const mesh of meshes) {
                if (mesh.material) {
                    _capture(mesh.material);
                }
            }
            // 绑定 Reflection Probe 到新材料（如果探针已启用）
            try {
                const { bindReflectionProbeToModel } = await import('../render/renderer');
                bindReflectionProbeToModel(meshes);
            } catch {
                // Intentionally empty — renderer 未初始化时忽略
            }
            setStatus(`✓ ${displayName} (场景)`, true);
            _modelManager.arrange();
            _refreshWaterRenderList();
            rebuildShadowCasters();
            _rebuildOutlineState?.();
            triggerAutoSave();
            try {
                document.dispatchEvent(new CustomEvent('mmku:modelLoaded'));
            } catch {
                // Intentionally empty — 自定义事件派发失败不影响模型加载主流程
            }
            return id;
        }

        // Actor: create MMD model from the loaded mesh via the runtime
        const rootMesh = meshes[0];
        wasmModel = _mmdRuntime.createMmdModel(rootMesh, {
            materialProxyConstructor: MmdStandardMaterialProxy,
        });

        const inst: ModelInstance = {
            id,
            name: displayName,
            filePath,
            port,
            modelDir,
            meshes,
            rootMesh,
            mmdModel: wasmModel as RuntimeModel,
            vmdData: null,
            vmdName: '',
            vmdPath: null,
            animationDuration: 0,
            vmdLayers: [],
            kind: 'actor',
            visible: true,
            opacity: 1.0,
            wireframe: false,
            showBoneLines: false,
            showBoneJoints: false,
            physicsEnabled: uiState.defaultPhysicsEnabled !== false,
            scaling: 1.0,
            rotationY: 0,
        };
        // 默认模型自动缩放：按统一目标高度归一化（仅 actor）
        if (uiState.autoScaleModel) {
            const bb = rootMesh.getHierarchyBoundingVectors(true);
            const h = bb.max.y - bb.min.y;
            if (h > 1e-3) inst.scaling = 18 / h;
        }
        // Register via ModelManager only — it owns the registry
        // Must register BEFORE VMD load because loadVMDMotion queries modelRegistry
        _modelManager.register(inst);
        registeredId = id;
        // Pre-capture material original values for reset functionality
        for (const mesh of meshes) {
            if (mesh.material) {
                _capture(mesh.material);
            }
        }
        // 绑定 Reflection Probe 到新材料（如果探针已启用）
        try {
            const { bindReflectionProbeToModel } = await import('../render/renderer');
            bindReflectionProbeToModel(meshes);
        } catch {
            // Intentionally empty — renderer 未初始化时忽略
        }
        if (wasmModel instanceof MmdWasmModel) {
            const states = wasmModel.rigidBodyStates;
            if (states) {
                _modelManager.storeRigidBodyState(id, states);
            }
        }
        setFocusedModelId(id);

        // 道具路径下的模型同时注册到 propRegistry（兼容灯光/阴影/序列化）
        const propDir = (overridePaths.prop || (libraryRoot ? libraryRoot + '/prop' : '')).toLowerCase();
        if (propDir && filePath.toLowerCase().startsWith(propDir)) {
            const rootMesh = inst.meshes[0];
            propRegistry.set(id, {
                id,
                name: displayName,
                filePath,
                port,
                modelDir,
                meshes: inst.meshes,
                rootMesh,
                position: [0, 0, 0],
                rotationY: 0,
                scaling: 1.0,
                visible: true,
            });
        }

        // Apply pending VMD if any — failure is isolated, won't roll back model
        let appliedVmd = '';
        if (pendingVmd && _mmdRuntime) {
            const vmdData = pendingVmd.data;
            appliedVmd = pendingVmd.name;
            setPendingVmd(null);
            try {
                await loadVMDMotion(vmdData, appliedVmd, id);
            } catch (vmdErr) {
                console.warn('VMD 加载失败，模型已保留:', vmdErr);
                appliedVmd = '';
                setStatus(`⚠ VMD 加载失败，模型已加载: ${displayName}`, false);
            }
        }

        _modelManager.focus(id);
        setStatus(appliedVmd ? `✓ ${displayName} + ${appliedVmd}` : `✓ ${displayName}`, true);
        _modelManager.arrange();
        _refreshWaterRenderList();
        rebuildShadowCasters();

        // Auto-capture thumbnail for future popup display
        captureThumbnail(filePath).catch(() => {});
        if (!skipAutoApply) {
            _tryAutoApplyPreset(id).catch((err: unknown) => console.warn('auto-apply preset:', err));
        }
        // Pre-load outfit file for UI entry availability
        _loadOutfits(id).catch(() => {});

        // Re-apply outline state so new model gets edge rendering if enabled
        _rebuildOutlineState?.();

        // Notify auto-save that scene state has changed
        triggerAutoSave();

        // Dispatch event so UI layers (e.g. model popup) can refresh
        try {
            document.dispatchEvent(new CustomEvent('mmku:modelLoaded'));
        } catch {
            // Intentionally empty — 自定义事件派发失败不影响模型加载主流程
        }

        return registeredId;
    } catch (err) {
        // 🔴 2: If model was registered, use remove() for clean disposal (handles meshes + cloth)
        // 🟡 3: Destroy leaked MMD runtime model before mesh disposal
        if (wasmModel && _mmdRuntime) {
            try {
                _mmdRuntime.destroyMmdModel(wasmModel);
            } catch (destroyErr) {
                console.warn('destroyMmdModel in cleanup:', destroyErr);
            }
        }
        if (registeredId && _modelManager) {
            try {
                _modelManager.remove(registeredId);
            } catch (removeErr) {
                console.warn('Cleanup after load failure:', removeErr);
            }
        } else {
            // Not yet registered — dispose meshes directly
            loadedMeshes.forEach((m) => {
                try {
                    m.dispose();
                } catch {
                    // Intentionally empty — 清理阶段单个 mesh dispose 失败不影响整体回滚
                }
            });
        }
        dom.loadingEl.style.display = 'none';
        console.error('loadPMXFile:', err);
        setStatus('✗ 模型加载失败: ' + formatError(err), false);
        return null;
    } finally {
        dom.loadingEl.style.display = 'none';
    }
}

// [doc:architecture] Model Manager — 模型注册表 + 生命周期 + 属性管理
// 职责: 封装 modelRegistry、focusedModelId、per-model 状态 map
//       提供模型 CRUD、属性设置、骨骼覆盖、物理类别、Morph 操作
// 消费者: scene.ts (编排器)、model-detail.ts (UI)、serialization
//
// 设计原则:
// - 不直接 import triggerAutoSave → 通过构造函数注入的 triggerAutoSave 回调触发（避免循环依赖）
// - 不引用 scene.ts 中的任何符号 → 无循环依赖
// - 模型状态完全封装，外部只能通过方法访问

import { Scene } from '@babylonjs/core/scene';
import { Mesh } from '@babylonjs/core/Meshes/mesh';
import { MeshBuilder } from '@babylonjs/core/Meshes/meshBuilder';
import { Observer } from '@babylonjs/core/Misc/observable';
import { Vector3 } from '@babylonjs/core/Maths/math.vector';
import { Color3 } from '@babylonjs/core/Maths/math.color';
import { StandardMaterial } from '@babylonjs/core/Materials/standardMaterial';

import {
    ModelInstance,
    setFocusedModelId,
    focusedModelId as configFocusedId,
    type PhysicsCategory,
    type RuntimeModel,
} from '../../core/config';
import { orbitToCartesian, cartesianToOrbit, normalizeOrbit } from '../../core/orbit';
import type { ClothInstance } from '../../physics/xpbd-cloth';
import { disposeCloth } from '../../physics/xpbd-cloth';
import { disposeOverlay, restoreMaterials } from '../../outfit/outfit-overlay';

// ======== Per-model state maps ========
// (owned by ModelManager, not exported directly)

const PHYSICS_CAT_PATTERNS: [PhysicsCategory, RegExp][] = [
    ['skirt', /スカート|skirt|フリル|frill|裾|hem/],
    ['chest', /胸|chest|bust|バスト/],
    ['hair', /髪|hair|ahoge|bangs|ponytail|前髪|後ろ髪/],
    ['accessory', /リボン|ribbon|アクセサリ|accessory|飾り|collar|ネクタイ|tie|紐|string|襟/],
];

function _classifyBonePhysics(name: string): PhysicsCategory | null {
    const l = name.toLowerCase();
    for (const [cat, re] of PHYSICS_CAT_PATTERNS) {
        if (re.test(l)) {
            return cat;
        }
    }
    return null;
}

function _buildRigidBodyCatMap(mmdModel: RuntimeModel): Map<number, PhysicsCategory> {
    const bones = mmdModel.runtimeBones;
    const map = new Map<number, PhysicsCategory>();
    for (let i = 0; i < bones.length; i++) {
        const bone = bones[i];
        if (bone.rigidBodyIndices.length === 0) {
            continue;
        }
        const cat = _classifyBonePhysics(bone.name);
        if (!cat) {
            continue;
        }
        for (const rbi of bone.rigidBodyIndices) {
            map.set(rbi, cat);
        }
    }
    return map;
}

/** Apply the current visibility, opacity, and wireframe state to meshes. */
function syncModelVisibility(inst: ModelInstance): void {
    for (const m of inst.meshes) {
        m.setEnabled(inst.visible);
        if (m.material) {
            m.material.alpha = inst.opacity;
            if (m.material instanceof StandardMaterial) {
                m.material.wireframe = inst.wireframe;
            }
        }
    }
}

/** Apply the current scaling and rotation state to the root mesh. */
function syncModelTransform(inst: ModelInstance): void {
    if (inst.meshes.length > 0) {
        const root = inst.meshes[0];
        root.scaling.setAll(inst.scaling);
        root.rotation.y = inst.rotationY;
    }
}

// ======== Formation Types ========

export type FormationType = 'line' | 'v-shape' | 'circle' | 'grid' | 'diagonal' | 'arc';

const FORMATION_LABELS: Record<FormationType, string> = {
    'line': '一字排列',
    'v-shape': 'V 字阵型',
    'circle': '圆形阵型',
    'grid': '网格阵型',
    'diagonal': '对角排列',
    'arc': '弧形排列',
};

export function getFormationLabels(): Record<FormationType, string> {
    return { ...FORMATION_LABELS };
}

function _computeFormationPos(
    type: FormationType,
    index: number,
    total: number,
    spacing: number
): [number, number, number] {
    const cx = 0, cz = 0;
    switch (type) {
        case 'line': {
            const x = (index - (total - 1) / 2) * spacing;
            return [cx + x, 0, cz];
        }
        case 'v-shape': {
            const half = Math.floor(total / 2);
            const row = Math.abs(index - half);
            const x = (index - half) * spacing * 0.6;
            const z = row * spacing * 0.8;
            return [cx + x, 0, cz + z];
        }
        case 'circle': {
            const radius = Math.max(spacing, (total * spacing) / (2 * Math.PI));
            const angle = (index / total) * Math.PI * 2 - Math.PI / 2;
            const x = cx + Math.cos(angle) * radius;
            const z = cz + Math.sin(angle) * radius;
            return [x, 0, z];
        }
        case 'grid': {
            const cols = Math.ceil(Math.sqrt(total));
            const row = Math.floor(index / cols);
            const col = index % cols;
            const x = (col - (cols - 1) / 2) * spacing;
            const z = row * spacing;
            return [cx + x, 0, cz + z];
        }
        case 'diagonal': {
            const x = (index - (total - 1) / 2) * spacing * 0.7;
            const z = index * spacing * 0.5;
            return [cx + x, 0, cz + z];
        }
        case 'arc': {
            const radius = Math.max(spacing * 2, total * spacing * 0.8);
            const spread = Math.min(Math.PI * 0.8, (total - 1) * 0.4);
            const angle = -spread / 2 + (index / Math.max(1, total - 1)) * spread;
            const x = cx + Math.sin(angle) * radius;
            const z = cz + (1 - Math.cos(angle)) * radius * 0.3;
            return [x, 0, z];
        }
    }
}

// ======== ModelManager Class ========

export class ModelManager {
    // --- State ---
    readonly modelRegistry = new Map<string, ModelInstance>();
    /** Delegates to config's focusedModelId for cross-module consistency. */
    get focusedModelId(): string | null {
        return configFocusedId;
    }
    private set _focusedModelId(v: string | null) {
        setFocusedModelId(v);
    }

    private _initialRigidBodyStates = new Map<string, Uint8Array>();
    private _physicsCatState = new Map<string, Map<string, boolean>>();
    private _boneOverlayMap = new Map<
        string,
        { lineSystem: Mesh; overlay: Mesh; joints: Mesh[]; update: () => void }
    >();
    private _boneUpdateObserver: Observer<Scene> | null = null;

    /** Cleanup callback invoked by removeModel for external per-model state. */
    onRemoveModel: ((id: string) => void) | null = null;

    constructor(
        private scene: Scene,
        private triggerAutoSave: () => void,
        private autoFrame: (center: Vector3, extent: number) => void
    ) {}

    // ======== XPBD Cloth Management ========

    /** XPBD 布料实例（key = model ID） */
    readonly clothInstances = new Map<string, ClothInstance>();
    private _clothUpdateObserver: Observer<Scene> | null = null;

    /**
     * 获取当前聚焦模型的指定骨骼世界矩阵（列主序 Float32Array[16]）。
     * 用于 XPBD 布料锚点跟随。
     */
    getBoneWorldMatrix(boneName: string): Float32Array | null {
        const mmd = this.focusedMmdModel();
        if (!mmd) {
            return null;
        }
        const bone = mmd.runtimeBones.find((b) => b.name === boneName);
        if (!bone) {
            return null;
        }
        return bone.worldMatrix; // already Float32Array[16], column-major
    }

    /** 为指定模型添加布料实例并关联每帧回调。 */
    addCloth(modelId: string, cloth: ClothInstance, updateFn: (dt: number) => void): void {
        cloth.updateFn = updateFn;
        this.clothInstances.set(modelId, cloth);
        this.ensureClothUpdateObserver();
    }

    /** 移除并销毁指定模型的布料实例。 */
    removeCloth(modelId: string): void {
        const cloth = this.clothInstances.get(modelId);
        if (cloth) {
            try {
                disposeCloth(cloth);
            } catch (e) {
                console.warn('removeCloth: disposeCloth failed', e);
            }
            this.clothInstances.delete(modelId);
        }
        if (this.clothInstances.size === 0) {
            this._disposeClothObserver();
        }
    }

    private ensureClothUpdateObserver(): void {
        if (this._clothUpdateObserver) {
            return;
        }
        this._clothUpdateObserver = this.scene.onBeforeRenderObservable.add(() => {
            const dt = this.scene.deltaTime / 1000; // ms → s
            for (const [id, cloth] of this.clothInstances) {
                if (!cloth.enabled || !cloth.updateFn) {
                    continue;
                }
                // 如果模型已被移除，跳过
                if (!this.modelRegistry.has(id)) {
                    continue;
                }
                try {
                    cloth.updateFn(dt);
                } catch (e) {
                    console.warn('cloth updateFn error:', e);
                }
            }
        });
    }

    private _disposeClothObserver(): void {
        if (this._clothUpdateObserver) {
            this.scene.onBeforeRenderObservable.remove(this._clothUpdateObserver);
            this._clothUpdateObserver = null;
        }
    }

    // ======== Registry ========

    /** Get a model by ID. Returns undefined if not found. */
    get(id: string): ModelInstance | undefined {
        return this.modelRegistry.get(id);
    }

    /** Get all registered models as an array. */
    getAll(): ModelInstance[] {
        return Array.from(this.modelRegistry.values());
    }

    /** Get the number of registered models. */
    get size(): number {
        return this.modelRegistry.size;
    }

    /** Register a new model instance. */
    register(inst: ModelInstance): void {
        this.modelRegistry.set(inst.id, inst);
    }

    /** Store initial rigid body state for physics toggle restoration. */
    storeRigidBodyState(id: string, states: Uint8Array): void {
        this._initialRigidBodyStates.set(id, new Uint8Array(states));
    }

    // ======== Convenience getters ========

    /** Get the currently focused ModelInstance, or undefined. */
    focused(): ModelInstance | undefined {
        return configFocusedId ? this.modelRegistry.get(configFocusedId) : undefined;
    }

    /** Get the currently focused runtime model (RuntimeModel), or null. */
    focusedMmdModel(): RuntimeModel | null {
        return configFocusedId ? (this.modelRegistry.get(configFocusedId).mmdModel ?? null) : null;
    }

    /** Find a model by file path. Returns the first match or undefined. */
    findByFilePath(filePath: string): ModelInstance | undefined {
        for (const inst of this.modelRegistry.values()) {
            if (inst.filePath === filePath) {
                return inst;
            }
        }
        return undefined;
    }

    // ======== Model Lifecycle ========

    /** Remove a model and clean up all associated state. */
    remove(id: string): void {
        const inst = this.modelRegistry.get(id);
        if (!inst) {
            return;
        }

        // Clean up cloth before disposing meshes
        disposeOverlay(inst);
        restoreMaterials(inst);
        this.removeCloth(id);

        // ⚠️ onRemoveModel（mmdRuntime.destroyMmdModel）必须在网格释放之前调用！
        // destroyMmdModel 需要 skeleton 尚存才能从运行时中解除 observable 链接，
        // 否则下一帧渲染循环中 mmdWasmModel.skeleton 为 null 会抛 TypeError。
        // onRemoveModel 也必须在 modelRegistry.delete 之前调用，
        // 因为外部回调需要通过 modelRegistry.get(id) 获取模型实例。
        this.onRemoveModel?.(id);

        for (const m of inst.meshes) {
            if (m instanceof Mesh) {
                m.dispose();
            }
        }
        inst._origTextures = undefined;
        inst.outfitFile = undefined;

        this.modelRegistry.delete(id);
        this._initialRigidBodyStates.delete(id);
        this._physicsCatState.delete(id);
        this._boneOverlayMap.delete(id);
        this.destroyBoneOverlay(id);

        // Update focus
        if (configFocusedId === id) {
            setFocusedModelId(
                this.modelRegistry.size > 0 ? this.modelRegistry.keys().next().value : null
            );
        }
        if (configFocusedId) {
            this.focus(configFocusedId);
        }
    }

    /** Remove the currently focused model. */
    removeFocused(): void {
        if (!configFocusedId) {
            return;
        }
        this.remove(configFocusedId);
    }

    /** Focus a model by ID: set focus + auto-frame camera. */
    focus(id: string): void {
        const inst = this.modelRegistry.get(id);
        if (!inst) {
            setFocusedModelId(null);
            return;
        }
        setFocusedModelId(id);

        // Auto-frame camera: compute bounding box from all meshes
        const min = new Vector3(Infinity, Infinity, Infinity);
        const max = new Vector3(-Infinity, -Infinity, -Infinity);
        for (const m of inst.meshes) {
            m.computeWorldMatrix(true);
            const bb = m.getBoundingInfo().boundingBox;
            min.minimizeInPlace(bb.minimumWorld);
            max.maximizeInPlace(bb.maximumWorld);
        }
        const center = min.add(max).scale(0.5);
        const size = max.subtract(min);
        const extent = Math.max(size.x, size.y, size.z);

        this.autoFrame(center, extent);

        this.triggerAutoSave();
    }

    /** Arrange all models in a horizontal row. */
    arrange(): void {
        const models = Array.from(this.modelRegistry.values());
        const spacing = 3;
        models.forEach((inst, i) => {
            const offsetX = (i - (models.length - 1) / 2) * spacing;
            if (inst.meshes.length > 0) {
                inst.meshes[0].position.x = offsetX;
            }
        });
        this.triggerAutoSave();
    }

    /** Apply a formation preset to all models. */
    setFormation(type: FormationType): void {
        const models = Array.from(this.modelRegistry.values());
        const n = models.length;
        if (n === 0) return;
        const spacing = 3;
        for (let i = 0; i < n; i++) {
            const inst = models[i];
            if (inst.meshes.length === 0) continue;
            const pos = _computeFormationPos(type, i, n, spacing);
            inst.meshes[0].position.set(pos[0], pos[1], pos[2]);
        }
        this.triggerAutoSave();
    }

    // ======== Property Setters ========

    setVisibility(id: string, visible: boolean): void {
        const inst = this.modelRegistry.get(id);
        if (!inst) {
            return;
        }
        inst.visible = visible;
        syncModelVisibility(inst);
        this.triggerAutoSave();
    }

    setOpacity(id: string, opacity: number): void {
        const inst = this.modelRegistry.get(id);
        if (!inst) {
            return;
        }
        inst.opacity = Math.max(0, Math.min(1, opacity));
        syncModelVisibility(inst);
        this.triggerAutoSave();
    }

    setWireframe(id: string, wireframe: boolean): void {
        const inst = this.modelRegistry.get(id);
        if (!inst) {
            return;
        }
        inst.wireframe = wireframe;
        syncModelVisibility(inst);
        this.triggerAutoSave();
    }

    setBoneLinesVis(id: string, show: boolean): void {
        const inst = this.modelRegistry.get(id);
        if (!inst) {
            return;
        }
        inst.showBoneLines = show;
        const hasAny = show || inst.showBoneJoints;
        const hadOverlay = this._boneOverlayMap.has(id);
        if (hasAny && !hadOverlay) {
            this.createBoneOverlay(id);
        } else if (!hasAny && hadOverlay) {
            this.destroyBoneOverlay(id);
        } else if (hadOverlay) {
            const entry = this._boneOverlayMap.get(id)!;
            entry.lineSystem.setEnabled(show);
        }
        this.triggerAutoSave();
    }

    setBoneJointsVis(id: string, show: boolean): void {
        const inst = this.modelRegistry.get(id);
        if (!inst) {
            return;
        }
        inst.showBoneJoints = show;
        const hasAny = show || inst.showBoneLines;
        const hadOverlay = this._boneOverlayMap.has(id);
        if (hasAny && !hadOverlay) {
            this.createBoneOverlay(id);
        } else if (!hasAny && hadOverlay) {
            this.destroyBoneOverlay(id);
        } else if (hadOverlay) {
            const entry = this._boneOverlayMap.get(id)!;
            entry.overlay.setEnabled(show);
        }
        this.triggerAutoSave();
    }

    setPhysics(id: string, enabled: boolean): void {
        const inst = this.modelRegistry.get(id);
        if (!inst) {
            return;
        }
        inst.physicsEnabled = enabled;
        const mmdModel = inst.mmdModel;
        if (mmdModel) {
            const states = mmdModel.rigidBodyStates;
            if (states) {
                if (enabled) {
                    const init = this._initialRigidBodyStates.get(id) || new Uint8Array(0);
                    if (init.length === states.length) {
                        states.set(init);
                    } else {
                        states.fill(1);
                    }
                } else {
                    states.fill(0);
                }
            }
        }
        this._physicsCatState.delete(id);
        this.triggerAutoSave();
    }

    setScaling(id: string, scaling: number): void {
        const inst = this.modelRegistry.get(id);
        if (!inst) {
            return;
        }
        if (!Number.isFinite(scaling)) {
            console.warn('[model-manager] setScaling: 无效值', scaling);
            return;
        }
        inst.scaling = Math.max(0.01, scaling);
        syncModelTransform(inst);
        this.triggerAutoSave();
    }

    setRotationY(id: string, rotationY: number): void {
        const inst = this.modelRegistry.get(id);
        if (!inst) {
            return;
        }
        inst.rotationY = rotationY;
        syncModelTransform(inst);
        this.triggerAutoSave();
    }

    setPosition(id: string, x: number, y: number, z: number): void {
        const inst = this.modelRegistry.get(id);
        if (!inst) {
            return;
        }
        if (!Number.isFinite(x) || !Number.isFinite(y) || !Number.isFinite(z)) {
            console.warn('[model-manager] setPosition: 无效坐标', { x, y, z });
            return;
        }
        if (inst.meshes.length > 0) {
            inst.meshes[0].position.set(x, y, z);
        }
        this.triggerAutoSave();
    }

    getPosition(id: string): [number, number, number] {
        const inst = this.modelRegistry.get(id);
        if (!inst || inst.meshes.length === 0) {
            return [0, 0, 0];
        }
        const p = inst.meshes[0].position;
        return [p.x, p.y, p.z];
    }

    /** [doc:adr-049] 以球面坐标（方位角/仰角/距离）定位模型，等价于围绕原点旋转。 */
    setOrbit(id: string, azimuth: number, elevation: number, distance: number): void {
        const inst = this.modelRegistry.get(id);
        if (!inst) {
            return;
        }
        // 边界保护：钳制到合法值域（绝不产生 NaN / 退化），损坏场景文件反序列化也能安全定位。
        const invalid =
            !Number.isFinite(azimuth) ||
            !Number.isFinite(elevation) ||
            !Number.isFinite(distance) ||
            distance <= 0 ||
            elevation < -90 ||
            elevation > 90;
        const o = normalizeOrbit(azimuth, elevation, distance);
        if (invalid) {
            console.warn('[model-manager] setOrbit: 输入越界已钳制', { azimuth, elevation, distance, result: o });
        }
        inst.positionMode = 'orbit';
        inst.orbitAzimuth = o.azimuth;
        inst.orbitElevation = o.elevation;
        inst.orbitDistance = o.distance;
        const [x, y, z] = orbitToCartesian(o.azimuth, o.elevation, o.distance);
        if (inst.meshes.length > 0) {
            inst.meshes[0].position.set(x, y, z);
        }
        this.triggerAutoSave();
    }

    /** [doc:adr-049] 读取模型当前球面坐标。orbit 模式下返回存储值，否则从当前笛卡尔位置反推。 */
    getOrbit(id: string): { azimuth: number; elevation: number; distance: number } | null {
        const inst = this.modelRegistry.get(id);
        if (!inst) {
            return null;
        }
        if (inst.positionMode === 'orbit' && inst.orbitAzimuth !== undefined && inst.orbitElevation !== undefined && inst.orbitDistance !== undefined) {
            return { azimuth: inst.orbitAzimuth, elevation: inst.orbitElevation, distance: inst.orbitDistance };
        }
        const [x, y, z] = this.getPosition(id);
        return cartesianToOrbit(x, y, z);
    }

    /** [doc:adr-049] 切换坐标模式。切到 orbit 时从当前笛卡尔位置反推球面参数（无跳变）；切回 cartesian 保留当前位置。 */
    setPositionMode(id: string, mode: 'cartesian' | 'orbit'): void {
        const inst = this.modelRegistry.get(id);
        if (!inst) {
            return;
        }
        if (mode === 'orbit') {
            const [x, y, z] = this.getPosition(id);
            const o = cartesianToOrbit(x, y, z);
            inst.orbitAzimuth = o.azimuth;
            inst.orbitElevation = o.elevation;
            inst.orbitDistance = o.distance;
        } else {
            // cartesian 模式：确保 mesh 位置与实例当前位置一致（orbit 模式已写入）
            const [x, y, z] = this.getPosition(id);
            if (inst.meshes.length > 0) {
                inst.meshes[0].position.set(x, y, z);
            }
        }
        inst.positionMode = mode;
        this.triggerAutoSave();
    }

    /** [doc:adr-049] 读取模型当前坐标模式（默认 'cartesian'）。 */
    getPositionMode(id: string): 'cartesian' | 'orbit' {
        const inst = this.modelRegistry.get(id);
        return inst?.positionMode ?? 'cartesian';
    }

    resetTransform(id: string): void {
        const inst = this.modelRegistry.get(id);
        if (!inst) {
            return;
        }
        inst.visible = true;
        inst.opacity = 1.0;
        inst.wireframe = false;
        inst.scaling = 1.0;
        inst.rotationY = 0;
        if (inst.meshes.length > 0) {
            inst.meshes[0].position.set(0, 0, 0);
        }
        syncModelVisibility(inst);
        syncModelTransform(inst);
        this.triggerAutoSave();
    }

    /** Stop VMD animation on a model and clean up associated state. */
    /** 清空模型的 VMD 数据（vmdData/vmdName/vmdPath/animationDuration）。
     *  注意：此方法不暂停动画或修改播放状态——暂停由上层 `stopVMD` 编排。 */
    clearVmdData(id: string): void {
        const inst = this.modelRegistry.get(id);
        if (!inst) {
            return;
        }
        inst.vmdData = null;
        inst.vmdName = '';
        inst.vmdPath = null;
        inst.animationDuration = 0;
        inst.vmdLayers = [];
        this.triggerAutoSave();
    }

    // ======== Physics Categories ========

    getPhysicsCategories(id: string): PhysicsCategory[] {
        const inst = this.modelRegistry.get(id);
        if (!inst.mmdModel) {
            return [];
        }
        const map = _buildRigidBodyCatMap(inst.mmdModel);
        const set = new Set(map.values());
        return [...set];
    }

    getPhysicsCatState(id: string): Record<string, boolean> | null {
        const state = this._physicsCatState.get(id);
        if (!state || state.size === 0) {
            return null;
        }
        const result: Record<string, boolean> = {};
        for (const [cat, enabled] of state) {
            result[cat] = enabled;
        }
        return result;
    }

    isPhysicsCategoryEnabled(id: string, cat: string): boolean {
        return this._physicsCatState.get(id)?.get(cat) ?? true;
    }

    setPhysicsCategory(id: string, cat: string, enabled: boolean): void {
        const inst = this.modelRegistry.get(id);
        if (!inst || !inst.mmdModel) {
            return;
        }
        // 若启用子类别但总开关未开，自动开启总开关防止 UI 状态不一致
        if (enabled && !inst.physicsEnabled) {
            this.setPhysics(id, true);
        }
        const states = inst.mmdModel.rigidBodyStates;
        if (!states) {
            return;
        }
        const catMap = _buildRigidBodyCatMap(inst.mmdModel);
        const init = this._initialRigidBodyStates.get(id);
        for (const [rbi, c] of catMap) {
            if (c !== cat || rbi >= states.length) {
                continue;
            }
            states[rbi] = enabled ? (init ? init[rbi] : 1) : 0;
        }
        let physMap = this._physicsCatState.get(id);
        if (!physMap) {
            physMap = new Map();
            this._physicsCatState.set(id, physMap);
        }
        physMap.set(cat, enabled);
        this.triggerAutoSave();
    }

    // ======== Morphs ========

    getMorphs(id: string): Array<{ name: string; type: number }> {
        const inst = this.modelRegistry.get(id);
        if (!inst.mmdModel.morph.morphs) {
            return [];
        }
        return inst.mmdModel.morph.morphs.map((m) => ({ name: m.name, type: m.type }));
    }

    setMorphWeight(id: string, morphName: string, weight: number): void {
        const inst = this.modelRegistry.get(id);
        if (!inst.mmdModel.morph) {
            return;
        }
        inst.mmdModel.morph.setMorphWeight(morphName, weight);
    }

    getMorphWeight(id: string, morphName: string): number {
        const inst = this.modelRegistry.get(id);
        if (!inst.mmdModel.morph) {
            return 0;
        }
        return inst.mmdModel.morph.getMorphWeight(morphName);
    }

    resetMorphs(id: string): void {
        const inst = this.modelRegistry.get(id);
        if (!inst.mmdModel.morph) {
            return;
        }
        inst.mmdModel.morph.resetMorphWeights();
        this.triggerAutoSave();
    }

    // ======== Skeletal Bone Overlay ========

    private createBoneOverlay(id: string): void {
        const inst = this.modelRegistry.get(id);
        if (!inst.mmdModel) {
            return;
        }
        if (this._boneOverlayMap.has(id)) {
            return;
        }

        const bones = inst.mmdModel.runtimeBones;
        if (!bones || bones.length === 0) {
            return;
        }

        const physicsBoneSet = new Set<number>();
        for (let i = 0; i < bones.length; i++) {
            if (bones[i].rigidBodyIndices.length > 0) {
                physicsBoneSet.add(i);
            }
        }

        const lines: Vector3[][] = [];
        const tmp = new Vector3();
        const joints: Mesh[] = [];
        const jointData: { mesh: Mesh; boneIndex: number }[] = [];
        const lineData: { childIndex: number; parentIndex: number }[] = [];

        for (let i = 0; i < bones.length; i++) {
            const bone = bones[i];
            const parent = bone.parentBone;
            if (!parent) {
                continue;
            }

            // 找到父骨骼的索引
            const parentIndex = bones.indexOf(parent);
            if (parentIndex === -1) {
                continue;
            }

            // Joint sphere at bone position
            bone.getWorldTranslationToRef(tmp);
            const pos = tmp.clone();
            const sphere = MeshBuilder.CreateSphere(
                'bone_joint',
                { diameter: 1.5, segments: 8 },
                this.scene
            );
            sphere.position.copyFrom(pos);
            sphere.isVisible = false;
            joints.push(sphere);
            jointData.push({ mesh: sphere, boneIndex: i });

            // Bone line from parent to child
            const parentPos = new Vector3();
            parent.getWorldTranslationToRef(parentPos);
            lines.push([parentPos.clone(), pos.clone()]);
            lineData.push({ childIndex: i, parentIndex });
        }

        // Create overlay: line system + sphere meshes
        const lineSystem = MeshBuilder.CreateLineSystem(
            'bone_overlay_lines',
            { lines },
            this.scene
        );
        lineSystem.color = new Color3(1, 1, 1);
        lineSystem.isPickable = false;
        lineSystem.setEnabled(inst.showBoneLines);

        // Update function: reposition joints and lines each frame
        const updateFn = () => {
            // 更新骨骼线
            if (inst.showBoneLines && lineSystem.isEnabled()) {
                const positions = lineSystem.getVerticesData('position');
                if (positions) {
                    for (let i = 0; i < lineData.length; i++) {
                        const ld = lineData[i];
                        const childBone = bones[ld.childIndex];
                        const parentBone = bones[ld.parentIndex];

                        if (childBone && parentBone) {
                            // 父骨骼位置 (line 开头)
                            parentBone.getWorldTranslationToRef(tmp);
                            positions[i * 6] = tmp.x;
                            positions[i * 6 + 1] = tmp.y;
                            positions[i * 6 + 2] = tmp.z;

                            // 子骨骼位置 (line 结尾)
                            childBone.getWorldTranslationToRef(tmp);
                            positions[i * 6 + 3] = tmp.x;
                            positions[i * 6 + 4] = tmp.y;
                            positions[i * 6 + 5] = tmp.z;
                        }
                    }
                    lineSystem.updateVerticesData('position', positions);
                }
            }

            // 更新关节球
            if (!inst.showBoneJoints) {
                return;
            }
            for (const jd of jointData) {
                const bone = bones[jd.boneIndex];
                if (!bone) {
                    jd.mesh.setEnabled(false);
                    continue;
                }
                bone.getWorldTranslationToRef(tmp);
                jd.mesh.position.copyFrom(tmp);
                jd.mesh.setEnabled(true);
            }
        };

        const overlay = Mesh.MergeMeshes(joints, true, true, undefined, false, true) as Mesh;
        if (overlay) {
            overlay.position.set(0, 0, 0);
            overlay.isPickable = false;
            overlay.setEnabled(inst.showBoneJoints);
        } else {
            // fallback: keep individual spheres visible
            for (const j of joints) {
                j.isVisible = inst.showBoneJoints;
            }
        }

        this._boneOverlayMap.set(id, {
            lineSystem,
            overlay: overlay || joints[0],
            joints,
            update: updateFn,
        });
        this.ensureBoneUpdateObserver();
    }

    private destroyBoneOverlay(id: string): void {
        const entry = this._boneOverlayMap.get(id);
        if (entry) {
            entry.lineSystem.dispose();
            entry.overlay.dispose();
            for (const j of entry.joints) {
                j.dispose();
            }
            this._boneOverlayMap.delete(id);
        }
    }

    private ensureBoneUpdateObserver(): void {
        if (this._boneUpdateObserver) {
            return;
        }
        this._boneUpdateObserver = this.scene.onBeforeRenderObservable.add(() => {
            const toDelete: string[] = [];
            for (const [id, entry] of this._boneOverlayMap) {
                const inst = this.modelRegistry.get(id);
                if (!inst || (!inst.showBoneLines && !inst.showBoneJoints) || !inst.mmdModel) {
                    entry.lineSystem.dispose();
                    entry.overlay.dispose();
                    for (const j of entry.joints) {
                        j.dispose();
                    }
                    toDelete.push(id);
                    continue;
                }
                entry.update();
            }
            for (const id of toDelete) {
                this._boneOverlayMap.delete(id);
            }
        });
    }

    /** Clean up all observers. Called on shutdown. */
    dispose(): void {
        if (this._boneUpdateObserver) {
            this.scene.onBeforeRenderObservable.remove(this._boneUpdateObserver);
            this._boneUpdateObserver = null;
        }
        this._disposeClothObserver();
        // Dispose all remaining overlays and cloth instances
        for (const [, inst] of this.modelRegistry) {
            disposeOverlay(inst);
            restoreMaterials(inst);
        }
        for (const id of Array.from(this.clothInstances.keys())) {
            this.removeCloth(id);
        }
    }

    // ======== Thumbnail ========

    /** Captures a screenshot after model load for thumbnail cache. */
    async captureThumbnail(
        filePath: string,
        canvas: HTMLCanvasElement,
        saveFn: (path: string, data: string) => Promise<void>
    ): Promise<void> {
        try {
            await new Promise((r) => requestAnimationFrame(r));
            await new Promise((r) => requestAnimationFrame(r));
            const base64 = canvas.toDataURL('image/png', 0.8);
            const raw = base64.replace(/^data:image\/png;base64,/, '');
            await saveFn(filePath, raw);
        } catch (err) {
            console.warn('captureThumbnail:', err);
        }
    }
}

import {
    modelRegistry,
    focusedModelId,
    isPlaying,
    setIsPlaying,
    setAutoLoop,
    setSeekDragging,
    dom,
    setPendingVmd,
    mmdRuntime,
} from '../../core/config';
import { _catState, _matState, _matEnabled, disposeModelMaterialState } from './material';
import { refreshWaterRenderList } from '../env/env';
import { getCameraMode, switchCameraMode } from '../camera/camera';
import { updatePlaybackUI } from '../motion/playback';
import { disposeAudio } from '../../outfit/audio';
import { modelManager } from '../scene';
import type { FormationType } from './model-manager';
import { getFormationLabels } from './model-manager';

export type PhysicsCategory = 'skirt' | 'chest' | 'hair' | 'accessory';

// ======== Model Lifecycle ========

export function removeModel(id: string): void {
    disposeModelMaterialState(id);
    modelManager?.remove(id);
    refreshWaterRenderList();

    if (focusedModelId === null && getCameraMode() === 'concert') {
        switchCameraMode('orbit');
    }
    if (modelRegistry.size === 0) {
        setIsPlaying(false);
        setAutoLoop(true);
        setSeekDragging(false);
        dom.playbackBar.style.display = 'none';
        disposeAudio();
    }
}

export function removeFocusedModel(): void {
    if (!focusedModelId) {
        return;
    }
    removeModel(focusedModelId);
    setPendingVmd(null);
}

export function focusModel(id: string): void {
    modelManager?.focus(id);
    updatePlaybackUI();
}

export function arrangeModels(): void {
    modelManager?.arrange();
}

export function setModelFormation(type: FormationType): void {
    modelManager?.setFormation(type);
}

export { getFormationLabels };
export type { FormationType };

// ======== Visibility / Material / Debug ========

export function setModelVisibility(id: string, visible: boolean): void {
    modelManager?.setVisibility(id, visible);
}

export function setModelOpacity(id: string, opacity: number): void {
    modelManager?.setOpacity(id, opacity);
}

export function setModelWireframe(id: string, wireframe: boolean): void {
    modelManager?.setWireframe(id, wireframe);
}

export function setModelBoneLinesVis(id: string, show: boolean): void {
    modelManager?.setBoneLinesVis(id, show);
}

export function setModelBoneJointsVis(id: string, show: boolean): void {
    modelManager?.setBoneJointsVis(id, show);
}

// ======== Physics ========

export function setModelPhysics(id: string, enabled: boolean): void {
    modelManager?.setPhysics(id, enabled);
}

export function getPhysicsCategories(id: string): PhysicsCategory[] {
    return modelManager?.getPhysicsCategories(id) ?? [];
}

export function getPhysicsCatState(id: string): Record<string, boolean> | null {
    return modelManager?.getPhysicsCatState(id) ?? null;
}

export function isPhysicsCategoryEnabled(id: string, cat: string): boolean {
    return modelManager?.isPhysicsCategoryEnabled(id, cat) ?? false;
}

export function setPhysicsCategory(id: string, cat: string, enabled: boolean): void {
    modelManager?.setPhysicsCategory(id, cat, enabled);
}

// ======== Transform ========

export function setModelScaling(id: string, scaling: number): void {
    modelManager?.setScaling(id, scaling);
}

export function setModelRotationY(id: string, rotationY: number): void {
    modelManager?.setRotationY(id, rotationY);
}

export function setModelPosition(id: string, x: number, y: number, z: number): void {
    modelManager?.setPosition(id, x, y, z);
}

export function getModelPosition(id: string): [number, number, number] {
    return modelManager?.getPosition(id) ?? [0, 0, 0];
}

// ======== [doc:adr-049] 球面坐标轨道控制 ========

export function setModelOrbit(id: string, azimuth: number, elevation: number, distance: number): void {
    modelManager?.setOrbit(id, azimuth, elevation, distance);
}

export function getModelOrbit(id: string): { azimuth: number; elevation: number; distance: number } | null {
    return modelManager?.getOrbit(id) ?? null;
}

export function setModelPositionMode(id: string, mode: 'cartesian' | 'orbit'): void {
    modelManager?.setPositionMode(id, mode);
}

export function getModelPositionMode(id: string): 'cartesian' | 'orbit' {
    return modelManager?.getPositionMode(id) ?? 'cartesian';
}

export function resetModelTransform(id: string): void {
    modelManager?.resetTransform(id);
}

// ======== VMD ========

export function stopVMD(id: string): void {
    const inst = modelRegistry.get(id);
    if (!inst) {
        return;
    }
    if (inst.mmdModel && mmdRuntime) {
        inst.mmdModel.setRuntimeAnimation(null);
    }
    modelManager?.clearVmdData(id);
    if (isPlaying) {
        mmdRuntime.pauseAnimation();
        setIsPlaying(false);
    }
    updatePlaybackUI();
}

// ======== Morph / Expression ========

export function getModelMorphs(id: string): Array<{ name: string; type: number }> {
    return modelManager?.getMorphs(id) ?? [];
}

export function setModelMorphWeight(id: string, morphName: string, weight: number): void {
    modelManager?.setMorphWeight(id, morphName, weight);
}

export function getModelMorphWeight(id: string, morphName: string): number {
    return modelManager?.getMorphWeight(id, morphName) ?? 0;
}

export function resetModelMorphs(id: string): void {
    modelManager?.resetMorphs(id);
}

// ======== VPD Pose ========

import type { VPDBoneData, VPDMorphData } from '../../motion-algos/vpd-parser';
import { Quaternion } from '@babylonjs/core/Maths/math.vector';
import { Vector3 } from '@babylonjs/core/Maths/math.vector';

/**
 * 应用 VPD 姿势到模型（静态姿势，停掉 VMD 播放）。
 * 停掉动画后直接写 linkedBone.position / rotationQuaternion，
 * WASM runtime 无动画输入时不覆盖。
 *
 * @param id       模型 ID
 * @param bones    VPD 解析出的骨骼数据（position + rotation quaternion）
 * @param morphs   VPD 解析出的表情数据（name + weight）
 */
export function applyVPDPose(
    id: string,
    bones: VPDBoneData[],
    morphs: VPDMorphData[],
): void {
    const inst = modelRegistry.get(id);
    if (!inst || !inst.mmdModel) {
        console.warn('[applyVPDPose] 模型未找到:', id);
        return;
    }

    // 1. 停掉 VMD 播放（程序化动作 + 用户 VMD）
    stopVMD(id);

    // 2. 构建骨骼名 → runtimeBone 索引映射
    const runtimeBones = inst.mmdModel.runtimeBones;
    const boneNameToIdx = new Map<string, number>();
    for (let i = 0; i < runtimeBones.length; i++) {
        boneNameToIdx.set(runtimeBones[i].name, i);
    }

    // 3. 应用骨骼变换（写 linkedBone.position / rotationQuaternion）
    for (const b of bones) {
        const idx = boneNameToIdx.get(b.name);
        if (idx === undefined) continue;
        const linked = runtimeBones[idx].linkedBone;
        // position: VPD 是局部坐标（米），直接写入
        linked.position = new Vector3(b.position[0], b.position[1], b.position[2]);
        // rotation: VPD 是四元数 [x, y, z, w]
        linked.rotationQuaternion = new Quaternion(
            b.rotation[0], b.rotation[1], b.rotation[2], b.rotation[3],
        );
    }

    // 4. 应用表情权重
    for (const m of morphs) {
        setModelMorphWeight(id, m.name, m.weight);
    }

    console.log(`[applyVPDPose] 已应用 ${bones.length} 骨骼 + ${morphs.length} 表情到模型 ${id}`);
}

