// [doc:architecture] LipSync — 口型同步
// 规范文档: docs/architecture.md §LipSync
// 职责: 人声频段能量检测 → morph 权重映射
// 依赖: initLipSync(mm) 注入 ModelManager，由 scene.ts 在 initScene 中调用

import {
    LipSyncState as LipSyncStateType,
    DEFAULT_LIPSYNC_STATE,
    findLipMorph,
    findAllLipMorphs,
    amplitudeToWeight,
} from '../../motion-algos/lipsync';
import { focusedModelId, triggerAutoSave } from '../../core/config';
import { isAudioPlaying, getAudioPath } from '../../outfit/audio';
import { setModelMorphWeight } from '../scene';
import { getProcBeatDetector } from './proc-motion-bridge';

let _modelManager: import('../manager/model-manager').ModelManager | null = null;

export function initLipSync(mm: import('../manager/model-manager').ModelManager): void {
    _modelManager = mm;
}

let lipSyncState: LipSyncStateType = { ...DEFAULT_LIPSYNC_STATE };
let lipSyncMorphName: string | null = null;
let lipSyncMorphSet: { open: string | null; close: string | null; pucker: string | null; smile: string | null } | null = null;
let lastFocusedId: string | null = null;

// morphName 缓存：避免每帧 O(M) 扫描 morphs 数组 + 数组分配
let _lastCachedModelId: string | null = null;
let _lastMorphNames: string[] = [];
let _lastMorphNameSet = new Set<string>();

// 平滑滤波器状态（低通滤波，减少 morph 权重抖动）
let _smoothLow = 0;
let _smoothHigh = 0;

// #10: Track last audio path to detect audio source changes
let _lastAudioPath = '';

const VOICE_BIN_START = 10;
const VOICE_BIN_END = 50;
// 高频频段（用于 smile morph 驱动）
const HIGH_BIN_START = 25;
const HIGH_BIN_END = 50;

export function setLipSyncEnabled(on: boolean): void {
    lipSyncState.enabled = on;
    if (!on) {
        resetLipMorph();
        lipSyncMorphName = null; // 立即失效，防止后续误用
    }
    triggerAutoSave();
}

export function setLipSyncSensitivity(v: number): void {
    lipSyncState.sensitivity = Math.max(0, Math.min(1, v));
    triggerAutoSave();
}

export function setLipSyncIntensity(v: number): void {
    lipSyncState.intensity = Math.max(0, Math.min(1, v));
    triggerAutoSave();
}

export function setLipSyncMultiMorphEnabled(v: boolean): void {
    lipSyncState.multiMorphEnabled = v;
    triggerAutoSave();
}

export function getLipSyncState(): LipSyncStateType {
    return { ...lipSyncState };
}

export function setLipSyncState(s: LipSyncStateType): void {
    lipSyncState = { ...s };
}

export function resetLipSyncOnFocusChange(): void {
    lipSyncMorphName = null;
    lipSyncMorphSet = null;
}

function resetLipMorph(): void {
    if (lipSyncMorphName && focusedModelId) {
        setModelMorphWeight(focusedModelId, lipSyncMorphName, 0);
    }
    // 重置 smile morph
    if (lipSyncMorphSet?.smile && focusedModelId) {
        setModelMorphWeight(focusedModelId, lipSyncMorphSet.smile, 0);
    }
}

export function updateLipSync(): void {
    if (!lipSyncState.enabled) {
        return;
    }

    // #10: Audio source change → reset lip sync state immediately
    if (getAudioPath() !== _lastAudioPath) {
        lipSyncMorphName = null;
        lipSyncMorphSet = null;
        _smoothLow = 0;
        _smoothHigh = 0;
        resetLipMorph();
        _lastAudioPath = getAudioPath();
    }

    if (!isAudioPlaying()) {
        // #12: Exponential decay when audio stops (fade over ~20 frames)
        _smoothLow *= 0.85;
        _smoothHigh *= 0.85;
        if (_smoothLow < 0.005 && _smoothHigh < 0.005) {
            _smoothLow = 0;
            _smoothHigh = 0;
            resetLipMorph();
            return;
        }
        // Still decaying — continue to apply morph weights with decaying values
    }
    const modelId = focusedModelId;
    // 聚焦变化时自动重置 morph 名，消除对外部 resetLipSyncOnFocusChange 的依赖
    if (modelId !== lastFocusedId) {
        lipSyncMorphName = null;
        lipSyncMorphSet = null;
        lastFocusedId = modelId;
    }
    if (!modelId) {
        lipSyncMorphName = null;
        lipSyncMorphSet = null;
        return;
    }
    const inst = _modelManager?.modelRegistry.get(modelId);
    if (!inst) {
        lipSyncMorphName = null;
        lipSyncMorphSet = null;
        return;
    }
    if (!inst.mmdModel.morph) {
        lipSyncMorphName = null;
        lipSyncMorphSet = null;
        return;
    }

    const morphs = inst.mmdModel.morph.morphs;
    // morphName 缓存：仅 modelId 变化时重建，消除每帧 O(M) 扫描 + 数组分配
    if (modelId !== _lastCachedModelId) {
        _lastCachedModelId = modelId;
        _lastMorphNames = morphs.map((m) => m.name);
        _lastMorphNameSet = new Set(_lastMorphNames);
    }
    if (!lipSyncMorphName || !_lastMorphNameSet.has(lipSyncMorphName)) {
        lipSyncMorphName = findLipMorph(_lastMorphNames);
        lipSyncMorphSet = findAllLipMorphs(_lastMorphNames);
    }
    if (!lipSyncMorphName) {
        return;
    }

    const beatDetector = getProcBeatDetector();
    const lowLevel = beatDetector ? beatDetector.getLevel(VOICE_BIN_START, VOICE_BIN_END) : 0;
    const highLevel = beatDetector ? beatDetector.getLevel(HIGH_BIN_START, HIGH_BIN_END) : 0;

    // 低通滤波（平滑抖动，系数 0.7 旧值 + 0.3 新值）
    // Skip smoothing when audio stopped (decay mode) to preserve the 0.85 exponential fade
    if (isAudioPlaying()) {
        _smoothLow = _smoothLow * 0.7 + lowLevel * 0.3;
        _smoothHigh = _smoothHigh * 0.7 + highLevel * 0.3;
    }

    const openWeight = amplitudeToWeight(_smoothLow, lipSyncState.sensitivity, lipSyncState.intensity);
    setModelMorphWeight(modelId, lipSyncMorphName, openWeight);

    // 多 Morph LipSync：驱动多个口型 morph
    if (lipSyncState.multiMorphEnabled && lipSyncMorphSet) {
        // close：与 open 反比（嘴开时 close=0，嘴闭时 close=1）
        if (lipSyncMorphSet.close) {
            const closeWeight = amplitudeToWeight(1 - _smoothLow, lipSyncState.sensitivity, lipSyncState.intensity);
            setModelMorphWeight(modelId, lipSyncMorphSet.close, closeWeight);
        }
        // pucker：由高频能量驱动（模拟「う」口型）
        if (lipSyncMorphSet.pucker) {
            const puckerWeight = amplitudeToWeight(_smoothHigh * 0.8, lipSyncState.sensitivity, lipSyncState.intensity);
            setModelMorphWeight(modelId, lipSyncMorphSet.pucker, puckerWeight);
        }
    }

    // 高频能量大时轻微微笑（模拟说话表情）
    if (lipSyncMorphSet?.smile) {
        const smileWeight = Math.max(0, openWeight * 0.3 - 0.1);
        setModelMorphWeight(modelId, lipSyncMorphSet.smile, smileWeight);
    }
}

// [doc:architecture] ScenePlayback — 播放控制 UI 子模块
// 职责: 从 scene.ts 拆出的播放进度 UI / seek 逻辑 + MMD runtime observable 回调聚合
//
// 循环依赖处理：modelManager 以参数形式注入 initPlaybackObservables，
// 而非静态导入 `./scene`，避免 ES module 循环引用隐患。

import {
    dom,
    isPlaying,
    setIsPlaying,
    autoLoop,
    seekDragging,
    formatTime,
    mmdRuntime,
} from '../../core/config';
import { syncAudioPlayback, isAudioPlaying } from '../../outfit/audio';
import { animateCameraVmd } from '../camera/camera';
import type { IMmdRuntime } from 'babylon-mmd/esm/Runtime/IMmdRuntime';
import type { ModelManager } from '../manager/model-manager';
import type { BeatDetector } from '../../motion-algos/beat-detector';

// ======== 辅助函数 ========

/** 获取当前聚焦模型的动画时长，优先使用模型自身时长，降级到 runtime 默认值。 */
function _getDuration(runtime: IMmdRuntime, manager: ModelManager): number {
    const foc = manager.focused();
    return foc?.animationDuration ?? runtime.animationDuration;
}

/** 当前是否有 auto-loop 在进行中（用于避免 UI 闪烁）。 */
let _loopPending = false;

/** Module-level ModelManager 引用，供 updatePlaybackUI 统一获取动画时长。 */
let _manager: ModelManager | null = null;

/** Dispose guard: prevents double-cleanup if dispose() called more than once. */
let _disposed = false;

/** 安全清理 observable 回调，静默吞异常。 */
function _safeRemoveCallback<T>(obs: { removeCallback: (cb: T) => void } | undefined, cb: T): void {
    try {
        obs?.removeCallback(cb);
    } catch {
        // Intentionally empty
    }
}

// ======== Playback Callbacks Initialization ========

export interface PlaybackObservablesDispose {
    (): void;
}

export function initPlaybackObservables(
    runtime: IMmdRuntime,
    manager: ModelManager,
    updatePlaybackUI: () => void,
    updateProcMotion: () => Promise<void>,
    updateLipSync: () => void,
    getProcBeatDetector: () => BeatDetector | null
): PlaybackObservablesDispose {
    _manager = manager;
    _disposed = false; // 重置 dispose guard，支持多轮 init/dispose
    const tickHandler = () => {
        // 每帧统一刷新节拍检测器（供 LipSync + Auto Dance 共享）
        const beatDetector = getProcBeatDetector();
        if (isAudioPlaying() && beatDetector) {
            beatDetector.update();
        }
        updatePlaybackUI();
        const dur = _getDuration(runtime, manager);
        syncAudioPlayback(runtime.currentTime, isPlaying, dur);
        animateCameraVmd(runtime.currentTime * 30);
        // updateProcMotion 是 async 函数，在同步回调中 fire-and-forget
        // 添加 .catch 防止未处理的 Promise 拒绝导致静默崩溃
        updateProcMotion().catch((err: unknown) =>
            console.error('[playback] updateProcMotion:', err)
        );
        updateLipSync();
    };
    runtime.onAnimationTickObservable.add(tickHandler);

    const playHandler = () => {
        setIsPlaying(true);
        updatePlaybackUI();
        const dur = _getDuration(runtime, manager);
        syncAudioPlayback(runtime.currentTime, true, dur);
    };
    runtime.onPlayAnimationObservable.add(playHandler);

    const pauseHandler = () => {
        // NOTE: babylon-mmd fires onPause when animation reaches the end (no
        // separate onFinish event), so the auto-loop logic lives here.

        if (!_loopPending) {
            setIsPlaying(false);
        }
        if (seekDragging) {
            updatePlaybackUI();
            return;
        }
        // Auto-loop: use the focused model's animation duration
        const focModel = manager.focused();
        if (
            autoLoop &&
            focModel &&
            runtime &&
            focModel.animationDuration > 0 &&
            runtime.currentTime >= focModel.animationDuration - 0.1
        ) {
            // 设置 loopPending 标志，阻止 setIsPlaying(false) 导致的 UI 闪烁
            _loopPending = true;
            const loop = autoLoop; // 快照：防止 async 间隙 autoLoop 变化导致状态漂移
            runtime.seekAnimation(0, true).then(() => {
                if (!loop) {
                    _loopPending = false;
                    return;
                }
                // 检查 runtime 和 manager 在 async 间隙是否仍有效
                if (!loop || !runtime || !_manager) {
                    _loopPending = false;
                    return;
                }
                runtime
                    .playAnimation()
                    .then(() => {
                        _loopPending = false;
                        setIsPlaying(true);
                        updatePlaybackUI();
                    })
                    .catch((err: unknown) => {
                        _loopPending = false;
                        console.error('[playback] auto-loop playAnimation failed:', err);
                    });
            }).catch((err: unknown) => {
                _loopPending = false;
                console.error('[playback] auto-loop seekAnimation failed:', err);
            });
            return;
        }
        updatePlaybackUI();
        const dur = _getDuration(runtime, manager);
        syncAudioPlayback(runtime.currentTime, false, dur);
    };
    runtime.onPauseAnimationObservable.add(pauseHandler);

    // 返回 dispose 函数，供场景销毁时清理观察者，防止内存泄漏
    return () => {
        if (_disposed) return;
        _disposed = true;
        _safeRemoveCallback(runtime.onAnimationTickObservable, tickHandler);
        _safeRemoveCallback(runtime.onPlayAnimationObservable, playHandler);
        _safeRemoveCallback(runtime.onPauseAnimationObservable, pauseHandler);
    };
}

export function updatePlaybackUI(): void {
    if (!mmdRuntime || !dom.seekBar) {
        if (dom.playbackBar) {
            dom.playbackBar.style.display = 'none';
        }
        return;
    }
    // 到达此处的 guard 保证了 mmdRuntime 和 dom.seekBar 均可用
    // 它被 observable 回调调用，此时 mmdRuntime 一定可用（已被 initScene 初始化）。
    // 但此函数也可能被外部直接调用（如 seekFromEvent），此时 mmdRuntime 可能为 null，
    // 因此保持顶部的 guard 不变。
    dom.playbackBar.style.display = 'flex';
    dom.btnPlayPause.textContent = isPlaying ? '⏸' : '▶';
    dom.btnLoopToggle.style.opacity = autoLoop ? '1' : '0.35';
    const duration = _manager ? _getDuration(mmdRuntime, _manager) : mmdRuntime.animationDuration;
    dom.timeDisplay.textContent = `${formatTime(mmdRuntime.currentTime)} / ${formatTime(duration)}`;
    if (duration > 0) {
        const pct = (mmdRuntime.currentTime / duration) * 100;
        dom.seekProgress.style.width = `${Math.min(pct, 100)}%`;
    }
}

export function seekFromEvent(e: MouseEvent | PointerEvent): void {
    if (!mmdRuntime || !dom.seekBar) {
        return;
    }
    const duration = mmdRuntime.animationDuration;
    if (duration <= 0) {
        return;
    }
    const rect = dom.seekBar.getBoundingClientRect();
    const ratio = Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width));
    const targetTime = ratio * duration;
    mmdRuntime.seekAnimation(targetTime, true);
    updatePlaybackUI();
    syncAudioPlayback(targetTime, isPlaying, duration);
}

// [doc:architecture] Procedural Motion — 程序化动作系统
// 规范文档: docs/architecture.md §程序化动作
// 职责: Idle / Auto Dance 状态管理、VMD 生成调度、节拍联动、视线追踪实时叠加

import {
    ProcMotionState,
    ProcMotionMode,
    ProcMotionBoneCategory,
    PROC_MOTION_BONE_CATEGORIES,
    DEFAULT_PROC_STATE,
    generateIdleVmd,
    generateAutoDanceVmd,
    generateLifelikeVmd,
    shouldAutoDance,
    shouldIdle,
    PROC_VMD_NAME_IDLE,
    PROC_VMD_NAME_AUTODANCE,
    PROC_VMD_NAME_LIFELIKE,
} from '../../motion-algos/procedural-motion';
import { BeatDetector } from '../../motion-algos/beat-detector';
import { mmdRuntime, triggerAutoSave, focusedModelId } from '../../core/config';
import { isAudioPlaying } from '../../outfit/audio';
import { modelManager, focusedMmdModel, focusedModel, loadVMDMotion, scene } from '../scene';
import { addVmdLayer, removeVmdLayer, getVmdLayers, clearVmdLayers } from './vmd-layers';
import { Quaternion, Vector3 } from '@babylonjs/core/Maths/math.vector';
import { Matrix } from '@babylonjs/core/Maths/math';
import type { IMmdRuntimeBone } from 'babylon-mmd/esm/Runtime/IMmdRuntimeBone';

let procState: ProcMotionState = { ...DEFAULT_PROC_STATE };
let procBeatDetector: BeatDetector | null = null;
let _procVmdActive = false;
let lastBeatBpm = 120;
let procStarting = false;
let _regeneratePending = false;
let procActiveKind: ProcMotionMode = 'idle';
let procModelId: string | null = null;

// ── 对象池（避免每帧 new Vector3/Matrix/Quaternion，消除 GC 压力） ──
const _v3Pool = [new Vector3(), new Vector3(), new Vector3(), new Vector3(), new Vector3(), new Vector3()];
const _mPool = [new Matrix(), new Matrix(), new Matrix(), new Matrix(), new Matrix(), new Matrix(), new Matrix(), new Matrix()];
const _qPool = [new Quaternion(), new Quaternion(), new Quaternion(), new Quaternion(), new Quaternion(), new Quaternion()];
let _v3Idx = 0, _mIdx = 0, _qIdx = 0;
function _v3(): Vector3 { return _v3Pool[_v3Idx++ % _v3Pool.length]; }
function _m(): Matrix { return _mPool[_mIdx++ % _mPool.length]; }
function _q(): Quaternion { return _qPool[_qIdx++ % _qPool.length]; }

// ── 运行时类型检测 ──
// WASM 版 MmdWasmRuntimeBone 没有 updateWorldMatrix 方法，worldMatrix 是 frontBuffer 切片视图
// JS 版 MmdRuntimeBone 有 updateWorldMatrix 方法
// 用此检测决定 gaze observer 走哪条路径
function _isWasmRuntime(bone: IMmdRuntimeBone): boolean {
    return (bone as any).updateWorldMatrix === undefined;
}

// ── WASM 模式辅助：把 Matrix 写回 Float32Array(16) ──
function _writeMatToBuffer(buf: Float32Array, m: Matrix): void {
    const a = m.asArray();
    for (let i = 0; i < 16; ++i) buf[i] = a[i];
}

// ── WASM 模式辅助：递归传播子骨骼 worldMatrix ──
// Babylon.js 矩阵乘法语义：A.multiplyToRef(B, R) ⇒ R = A × B
// 行向量约定 v' = v × M，所以 "先 parent 再 child" 的合成 = childLocal × parentWorld
//
// 数学推导：
//   childWorld = childLocal × parentWorld
//   childLocal = childWorld × parentWorld⁻¹ = childOldMat × parentOldInv
//   childNewWorld = childLocal × parentNewMat = localMat × parentNewMat
function _propagateChildrenWasm(
    parent: IMmdRuntimeBone,
    parentOldMat: Matrix,
    parentNewMat: Matrix
): void {
    const parentOldInv = new Matrix().copyFrom(parentOldMat);
    parentOldInv.invert();
    for (const child of parent.childBones) {
        const childBuf = (child as any).worldMatrix as Float32Array;
        if (!childBuf) continue;
        const childOldMat = Matrix.FromArray(childBuf);
        // localMat = childOldMat × parentOldInv （子→父空间）
        const localMat = new Matrix();
        childOldMat.multiplyToRef(parentOldInv, localMat);
        // childNewMat = localMat × parentNewMat （父空间→新世界）
        const childNewMat = new Matrix();
        localMat.multiplyToRef(parentNewMat, childNewMat);
        _writeMatToBuffer(childBuf, childNewMat);
        _propagateChildrenWasm(child, childOldMat, childNewMat);
    }
}

// ── 眼球追踪平滑状态（按眼骨名独立存储，避免左右眼互相污染） ──
const _prevEyeState: Record<string, { yaw: number; pitch: number }> = {};
const EYE_SMOOTH = 0.35; // 指数平滑系数（0=完全平滑，1=无平滑）

// ── 眼部跟随（眼球追踪，每帧执行） ──
let _headTrackingObserver: any = null;

/** 注销视线追踪 observer。 */
function _teardownGazeTracking(): void {
    if (_headTrackingObserver) {
        scene.onBeforeRenderObservable.remove(_headTrackingObserver);
        _headTrackingObserver = null;
    }
    for (const k in _prevEyeState) delete _prevEyeState[k];
}

/** 注册眼部跟随 + 头部跟随（独立 observer，实时骨骼叠加）。 */
function _setupGazeTracking(): void {
    _teardownGazeTracking();
    const inst = procModelId ? modelManager.get(procModelId) : null;
    const mmdModel = inst?.mmdModel;
    if (!mmdModel) return;

    // 查找头骨和眼球骨骼（runtimeBone）
    const headRuntime = mmdModel.runtimeBones.find(
        b => b.name === '頭' || b.name === 'head' || b.name === 'Head'
    );
    const eyeRuntimes: IMmdRuntimeBone[] = mmdModel.runtimeBones.filter(
        b => ['右目','左目','Eye_R','Eye_L','eye_r','eye_l','RightEye','LeftEye'].includes(b.name)
    );
    console.log(`[gaze:collect] eyeRuntimes=${eyeRuntimes.length} names=[${eyeRuntimes.map(b => b.name).join(',')}]`);

    const needHead = procState.headTrackingEnabled && headRuntime;
    const needEye = procState.eyeTrackingEnabled && eyeRuntimes.length > 0;
    if (!needHead && !needEye) return;

    // ── gaze observer：分 WASM / JS 两路 ──
    // WASM 版：worldMatrix 是 frontBuffer 切片视图，直接覆写 + 递归传播子骨骼
    // JS 版：改 linkedBone.rotationQuaternion + 手动 updateWorldMatrix 重算骨骼链
    // observer 注册在 onBeforeRenderObservable，且在 mmdRuntime.afterPhysics 之后跑，
    // 因此读到的是本帧 WASM 已计算完成的 frontBuffer
    const isWasm = _isWasmRuntime(headRuntime ?? eyeRuntimes[0]);
    _headTrackingObserver = scene.onBeforeRenderObservable.add(() => {
        if (!_procVmdActive) return;
        // 防御：模型已被移除时 mmdModel.mesh/metadata 可能为 null
        if (!mmdModel?.mesh?.metadata) return;
        const cam = scene.activeCamera;
        if (!cam) return;

        if (isWasm) {
            // ═══ WASM 模式：直接覆写 frontBuffer worldMatrix ═══
            // 注意：所有读取必须先 copyFrom 快照，避免读到半写状态

            // 步骤1：头部跟随
            if (needHead && headRuntime) {
                const headBuf = (headRuntime as any).worldMatrix as Float32Array;
                const oldHeadMat = _m().copyFrom(Matrix.FromArray(headBuf));
                const headPos = oldHeadMat.getTranslation();
                const oldHeadRotQ = _q().copyFrom(Quaternion.FromRotationMatrix(oldHeadMat.getRotationMatrix()));

                // lookDir = 头部→相机方向（模型面朝方向，与最初稳定版本一致）
                // FromLookDirectionRH 的 forward 语义是"相机朝向" = cam→head = -lookDir
                // 但之前用 lookDir = headPos - cam.pos 配合 FromLookDirectionRH 工作正常，
                // 说明 RH 内部处理了方向，保持与稳定版本一致即可
                const lookDir = headPos.subtractToRef(cam.position, _v3());
                const lookLen = Math.sqrt(lookDir.x * lookDir.x + lookDir.y * lookDir.y + lookDir.z * lookDir.z);
                if (lookLen > 0.0001) {
                    lookDir.scaleInPlace(1 / lookLen);
                    // 用 FromLookDirectionRH 算目标朝向（yaw/pitch 自动解耦的稳定实现）
                    const targetWorldQ = _q().copyFrom(Quaternion.FromLookDirectionRH(lookDir, Vector3.UpReadOnly));

                    const blended = _q().copyFrom(Quaternion.Slerp(oldHeadRotQ, targetWorldQ, 0.5));

                    // 新 worldMatrix = Compose(scale=One, rotation=blended, translation=headPos)
                    const newHeadMat = _m().copyFrom(Matrix.Compose(Vector3.One(), blended, headPos));
                    _writeMatToBuffer(headBuf, newHeadMat);

                    // 递归传播子骨骼（眼骨/眉毛等跟随头部）
                    _propagateChildrenWasm(headRuntime, oldHeadMat, newHeadMat);
                }
            }

            // [对比诊断] 仅头部跟随时的眼骨状态（每 60 帧打印一次）
            if (needHead && !needEye && eyeRuntimes.length > 0) {
                if ((globalThis as any).__gazeCmpFrame === undefined) (globalThis as any).__gazeCmpFrame = 0;
                const cf = (globalThis as any).__gazeCmpFrame = ((globalThis as any).__gazeCmpFrame + 1) % 60;
                if (cf === 0) {
                    const headBuf = (headRuntime as any).worldMatrix as Float32Array;
                    const headYaw = Math.atan2(-headBuf[8], headBuf[0]) * 180 / Math.PI;
                    console.log(`[gaze:cmp-head-only] headYaw=${headYaw.toFixed(1)}°`);
                    for (const eyeRb of eyeRuntimes) {
                        const eb = (eyeRb as any).worldMatrix as Float32Array;
                        const eyeYaw = Math.atan2(-eb[8], eb[0]) * 180 / Math.PI;
                        const eyePitch = Math.asin(Math.max(-1, Math.min(1, eb[9]))) * 180 / Math.PI;
                        console.log(`[gaze:cmp-head-only] ${eyeRb.name} eyeYaw=${eyeYaw.toFixed(1)}° eyePitch=${eyePitch.toFixed(1)}° eyeT=[${eb[12].toFixed(2)},${eb[13].toFixed(2)},${eb[14].toFixed(2)}]`);
                    }
                }
            }

            // 步骤2：眼球跟随（Slerp 朝向目标：左右眼共用同一 targetWorldQ）
            // 用双眼中心点算 lookDir，左右眼共用同一目标朝向，各自从当前朝向 Slerp 过去。
            // 保证平行注视 + 视觉对称，避免会聚角过大。
            if (needEye) {
                // 双眼中心点（左/右目世界位置的中点）
                const eyeCenter = _v3();
                for (const eyeRb of eyeRuntimes) {
                    const eb = (eyeRb as any).worldMatrix as Float32Array;
                    eyeCenter.x += eb[12];
                    eyeCenter.y += eb[13];
                    eyeCenter.z += eb[14];
                }
                eyeCenter.scaleInPlace(1 / eyeRuntimes.length);

                // 统一目标朝向（从双眼中心朝向相机）
                const lookDir = eyeCenter.subtractToRef(cam.position, _v3());
                if (lookDir.lengthSquared() >= 0.0001) {
                    lookDir.normalize();
                    const targetWorldQ = _q().copyFrom(Quaternion.FromLookDirectionRH(lookDir, Vector3.UpReadOnly));

                    for (const eyeRb of eyeRuntimes) {
                        const eyeBuf = (eyeRb as any).worldMatrix as Float32Array;
                        const eyeMat = _m().copyFrom(Matrix.FromArray(eyeBuf));
                        const eyePos = eyeMat.getTranslation();
                        const curEyeQ = _q().copyFrom(Quaternion.FromRotationMatrix(eyeMat.getRotationMatrix()));

                        // Slerp 朝向目标（与头部跟随同款逻辑，平滑系数一致）
                        const newEyeQ = _q().copyFrom(Quaternion.Slerp(curEyeQ, targetWorldQ, EYE_SMOOTH));

                        const newEyeMat = _m().copyFrom(Matrix.Compose(Vector3.One(), newEyeQ, eyePos));
                        _writeMatToBuffer(eyeBuf, newEyeMat);

                        // 眼骨一般无子骨骼，但保持一致
                        _propagateChildrenWasm(eyeRb, eyeMat, newEyeMat);
                    }

                    // [诊断] 每 60 帧打印一次
                    if ((globalThis as any).__gazeEyeFrame === undefined) (globalThis as any).__gazeEyeFrame = 0;
                    const ef = (globalThis as any).__gazeEyeFrame = ((globalThis as any).__gazeEyeFrame + 1) % 60;
                    if (ef === 0) {
                        const tYaw = Math.atan2(-lookDir.x, -lookDir.z) * 180 / Math.PI;
                        for (const eyeRb of eyeRuntimes) {
                            const eb = (eyeRb as any).worldMatrix as Float32Array;
                            const fbYaw = Math.atan2(-eb[8], eb[0]) * 180 / Math.PI;
                            const fbPitch = Math.asin(Math.max(-1, Math.min(1, eb[9]))) * 180 / Math.PI;
                            console.log(`[gaze:cmp-eye-only] ${eyeRb.name} targetYaw=${tYaw.toFixed(1)}° fbYaw=${fbYaw.toFixed(1)}° fbPitch=${fbPitch.toFixed(1)}° eyeT=[${eb[12].toFixed(2)},${eb[13].toFixed(2)},${eb[14].toFixed(2)}]`);
                        }
                    }
                }
            }
        } else {
            // ═══ JS 模式：改 linkedBone.rotationQuaternion + updateWorldMatrix ═══
            //（原逻辑，调试用，WASM 双缓冲下无效）

            // 步骤1：头部跟随
            if (needHead && headRuntime) {
                const headPos = _v3();
                headRuntime.getWorldTranslationToRef(headPos);
                const oldHeadMat = _m().copyFrom(Matrix.FromArray(headRuntime.worldMatrix));
                const oldHeadRotQ = _q().copyFrom(Quaternion.FromRotationMatrix(oldHeadMat.getRotationMatrix()));
                // lookDir = 头部→相机（与 WASM 模式一致）
                const lookDir = headPos.subtractToRef(cam.position, _v3()).normalize();
                const targetWorldQ = _q().copyFrom(Quaternion.FromLookDirectionRH(lookDir, Vector3.UpReadOnly));
                const blended = _q().copyFrom(Quaternion.Slerp(oldHeadRotQ, targetWorldQ, 0.5));

                const parentBone = headRuntime.parentBone;
                let parentWorldInv = _m();
                if (parentBone) {
                    const parentMat = _m().copyFrom(Matrix.FromArray(parentBone.worldMatrix));
                    parentMat.invertToRef(parentWorldInv);
                } else {
                    Matrix.IdentityToRef(parentWorldInv);
                }
                const parentInvQ = Quaternion.FromRotationMatrix(parentWorldInv);
                const localQ = _q();
                parentInvQ.multiplyToRef(blended, localQ);
                headRuntime.linkedBone.rotationQuaternion = localQ;

                const updateBoneChain = (rb: IMmdRuntimeBone) => {
                    (rb as any).updateWorldMatrix?.(false, false);
                    for (const child of rb.childBones) {
                        updateBoneChain(child);
                    }
                };
                updateBoneChain(headRuntime);
            }

            // 步骤2：眼球跟随（Slerp 朝向目标：与 WASM 模式一致，双眼中心点算 lookDir）
            if (needEye) {
                const eyeCenter = _v3();
                for (const eyeRb of eyeRuntimes) {
                    const eb = (eyeRb as any).worldMatrix as Float32Array;
                    eyeCenter.x += eb[12];
                    eyeCenter.y += eb[13];
                    eyeCenter.z += eb[14];
                }
                eyeCenter.scaleInPlace(1 / eyeRuntimes.length);

                const lookDir = eyeCenter.subtractToRef(cam.position, _v3());
                if (lookDir.lengthSquared() >= 0.0001) {
                    lookDir.normalize();
                    const targetWorldQ = _q().copyFrom(Quaternion.FromLookDirectionRH(lookDir, Vector3.UpReadOnly));

                    for (const eyeRb of eyeRuntimes) {
                        const eyeMat = _m().copyFrom(Matrix.FromArray(eyeRb.worldMatrix));
                        const curWorldQ = _q().copyFrom(Quaternion.FromRotationMatrix(eyeMat.getRotationMatrix()));
                        const newWorldQ = _q().copyFrom(Quaternion.Slerp(curWorldQ, targetWorldQ, EYE_SMOOTH));

                        const parentBone = eyeRb.parentBone;
                        let parentWorldInv = _m();
                        if (parentBone) {
                            const parentMat = _m().copyFrom(Matrix.FromArray(parentBone.worldMatrix));
                            parentMat.invertToRef(parentWorldInv);
                        } else {
                            Matrix.IdentityToRef(parentWorldInv);
                        }
                        const parentInvQ = Quaternion.FromRotationMatrix(parentWorldInv);
                        const localQ = _q();
                        parentInvQ.multiplyToRef(newWorldQ, localQ);
                        eyeRb.linkedBone.rotationQuaternion = localQ;

                        (eyeRb as any).updateWorldMatrix?.(false, false);
                    }
                }
            }
        }

        // 触发 skeleton 重算，把新 worldMatrix 刷到渲染矩阵
        const skeleton = (mmdModel.mesh.metadata as any).skeleton;
        skeleton?._markAsDirty?.();
    }, undefined, false);

    console.log(`[proc-motion] 视线追踪: 眼=${procState.eyeTrackingEnabled} 头=${procState.headTrackingEnabled}`);
}

/** 只读访问器，外部不可直接修改程序化动作激活状态。 */
export function isProcVmdActive(): boolean {
    return _procVmdActive;
}

export function getProcBeatDetector(): BeatDetector | null {
    return procBeatDetector;
}

export function createProcBeatDetector(): BeatDetector {
    procBeatDetector = new BeatDetector();
    return procBeatDetector;
}

/** 清除模型上的 vmdData/vmdName（两分支复用）。 */
function _clearVmdData(inst: import('../../core/config').ModelInstance | null | undefined): void {
    if (inst) {
        inst.vmdData = null;
        inst.vmdName = '';
    }
}

async function startProcMotion(targetMode: ProcMotionMode, bpm?: number): Promise<void> {
    if (procStarting) {
        return;
    }
    procStarting = true;

    // 保存加载前的模型 ID，防止 await 后焦点切换导致操作错配（Issue #3）
    const modelAtStart = focusedMmdModel();
    const modelIdAtStart = focusedModelId ?? null;
    if (!modelAtStart) {
        procStarting = false;
        return;
    }
    const morphNames = modelAtStart.morph.morphs.map((m) => m.name) ?? [];
    const boneNames = modelAtStart.runtimeBones.map((b) => b.name);
    console.log(`[proc-motion] bones: [${boneNames.slice(0, 10).join(', ')}${boneNames.length > 10 ? '...' : ''}]`);
    console.log(`[proc-motion] morphs: [${morphNames.slice(0, 5).join(', ')}${morphNames.length > 5 ? '...' : ''}]`);
    let buf: ArrayBuffer;

    // Issue #2: bpm 无效时降级为 idle，保持状态一致
    const bpmValid = bpm !== null && bpm !== undefined && bpm > 0 && Number.isFinite(bpm);
    if (targetMode === 'autodance' && bpmValid) {
        buf = generateAutoDanceVmd(procState, bpm!, morphNames, boneNames);
        lastBeatBpm = bpm!;
        procActiveKind = 'autodance';
    } else {
        buf = generateIdleVmd(procState, morphNames, boneNames);
        procActiveKind = targetMode === 'autodance' ? 'idle' : targetMode;
    }

    // 【已移除 debug 下载代码】

    _procVmdActive = true;
    procModelId = modelIdAtStart;
    try {
        await loadVMDMotion(
            buf,
            targetMode === 'autodance' && bpmValid ? PROC_VMD_NAME_AUTODANCE : PROC_VMD_NAME_IDLE
        );

        // Issue #3: 验证焦点模型是否在异步期间被切换
        const currentId = focusedModelId ?? null;
        // Issue #4: 验证异步期间用户是否加载了真实 VMD（竞态时序保护）
        // 对比 vmdData 与当前生成的 buf：若不同且非空，说明用户加载了其他 VMD
        const curInst = modelManager.get(modelIdAtStart);
        const vmdDataAfter = curInst?.vmdData;
        const userVmdDuringAsync = vmdDataAfter !== buf && vmdDataAfter !== null && vmdDataAfter !== undefined;
        if (currentId !== modelIdAtStart) {
            console.warn('[proc-motion] 异步期间模型焦点已切换，丢弃本次程序化动作结果');
            // 卸载刚加载的程序化动画
            const inst = modelManager.get(currentId);
            if (inst && inst.mmdModel && mmdRuntime) {
                inst.mmdModel.setRuntimeAnimation(null);
            }
            _procVmdActive = false;
            procModelId = null;
            procActiveKind = 'idle';
        } else if (userVmdDuringAsync) {
            // 异步期间用户加载了真实 VMD，不覆盖 vmdData
            console.log('[proc-motion] 异步期间用户加载了 VMD，跳过本次程序化动作');
            _procVmdActive = false;
            procModelId = null;
            procActiveKind = 'idle';
        } else {
            _clearVmdData(focusedModel());
            // 启动视线追踪（实时骨骼叠加，不依赖 VMD 帧）
            _setupGazeTracking();
        }
    } catch {
        _procVmdActive = false;
        _clearVmdData(focusedModel());
    } finally {
        procStarting = false;
        if (_regeneratePending) {
            _regeneratePending = false;
            // Re-trigger with current state
            const mode = procState.mode === 'autodance' ? 'autodance' : 'idle';
            const bpm = procBeatDetector?.getBPM() ?? 120;
            // Only regenerate if still relevant (mode is 'idle'|'autodance' here, never 'off')
            startProcMotion(mode, mode === 'autodance' ? bpm : undefined);
        }
    }
}

export function stopProcMotion(): void {
    _procVmdActive = false;
    _teardownGazeTracking();
    if (procModelId) {
        const inst = modelManager.get(procModelId);
        if (inst && inst.mmdModel && mmdRuntime) {
            inst.mmdModel.setRuntimeAnimation(null);
        }
        procModelId = null;
    }
}

export function onModelRemoved(id: string): void {
    if (procModelId === id) {
        _procVmdActive = false;
        _teardownGazeTracking();
        procModelId = null;
    }
}

export async function updateProcMotion(): Promise<void> {
    if (procState.mode === 'off' && !procState.autoSwitch) {
        if (_procVmdActive) {
            stopProcMotion();
        }
        return;
    }

    // Issue #1: focusedModel() 可能为 null/undefined
    const model = focusedModel();
    const audioOn = isAudioPlaying();
    const hasUserVmd = model?.vmdData !== null && model?.vmdData !== undefined;
    const mode = procState.mode;
    const autoOk = mode !== 'off' || procState.autoSwitch;
    const wantAutoDance = shouldAutoDance(audioOn, mode) && autoOk;
    const wantIdle = shouldIdle(audioOn, hasUserVmd, mode) && autoOk;

    if (hasUserVmd && _procVmdActive) {
        stopProcMotion();
        return;
    }

    if (wantAutoDance && !hasUserVmd && procBeatDetector) {
        const bpm = procBeatDetector.getBPM();
        if (!_procVmdActive || procActiveKind !== 'autodance' || Math.abs(bpm - lastBeatBpm) > 10) {
            await startProcMotion('autodance', bpm);
        }
        return;
    }

    if (wantIdle && !hasUserVmd) {
        if (!_procVmdActive || procActiveKind !== 'idle') {
            await startProcMotion('idle');
        }
        return;
    }
}

export function setProcMotionMode(mode: ProcMotionMode): void {
    procState = { ...procState, mode };
    if (mode === 'off') {
        stopProcMotion();
    }
    triggerAutoSave();
}

export function setProcMotionIntensity(v: number): void {
    procState = { ...procState, intensity: Math.max(0, Math.min(1, v)) };
    triggerAutoSave();
}

export function setProcMotionSpeed(v: number): void {
    procState = { ...procState, speed: Math.max(0.5, Math.min(2, v)) };
    triggerAutoSave();
}

export function setProcMotionAutoSwitch(on: boolean): void {
    procState = { ...procState, autoSwitch: on };
    triggerAutoSave();
}

export function getProcMotionState(): ProcMotionState {
    return { ...procState };
}

/** 设置程序化动作状态（从存储恢复时使用，不触发自动保存以免干扰反序列化）。
 *  外部直接调用此函数时，请确保调用者在合适时机手动触发保存。 */
export function setProcMotionState(s: ProcMotionState): void {
    procState = { ...s };
}

// ======== 新增开关 Getter/Setter（P0/P1） ========

/** 设置单个微动效果的开关 */
export function setProcMotionBoneToggle(cat: ProcMotionBoneCategory, v: boolean): void {
    if (!PROC_MOTION_BONE_CATEGORIES.includes(cat)) {
        console.warn(`[proc-motion] invalid bone category: ${cat}`);
        return;
    }
    if (typeof v !== 'boolean') {
        console.warn(`[proc-motion] setProcMotionBoneToggle: invalid value type, expected boolean`);
        return;
    }
    const bt = { ...procState.boneToggles };
    bt[cat] = v;
    procState = { ...procState, boneToggles: bt };
    triggerAutoSave();
}

/** 批量设置微动效果开关 */
export function setProcMotionBoneToggles(bt: Partial<Record<ProcMotionBoneCategory, boolean>>): void {
    for (const [k, v] of Object.entries(bt)) {
        if (typeof v !== 'boolean') {
            console.warn(`[proc-motion] setProcMotionBoneToggles: invalid value type for key "${k}", expected boolean`);
            return;
        }
    }
    procState = { ...procState, boneToggles: { ...procState.boneToggles, ...bt } };
    triggerAutoSave();
}

export function setProcMotionVpdApplyEnabled(v: boolean): void {
    if (typeof v !== 'boolean') {
        console.warn(`[proc-motion] setProcMotionVpdApplyEnabled: invalid value type, expected boolean`);
        return;
    }
    procState = { ...procState, vpdApplyEnabled: v };
    triggerAutoSave();
}

export function setProcMotionInterpOverride(v: ProcMotionState['interpOverride']): void {
    const valid = ['auto', 'sharp', 'ease-in-out', 'ease-out'] as const;
    if (!valid.includes(v as typeof valid[number])) {
        console.warn(`[proc-motion] setProcMotionInterpOverride: invalid value "${v}"`);
        return;
    }
    procState = { ...procState, interpOverride: v };
    triggerAutoSave();
}

/** 设置 BPM 量化开关（通过 BeatDetector 实例） */
export function setBpmQuantizeEnabled(v: boolean): void {
    if (typeof v !== 'boolean') {
        console.warn(`[proc-motion] setBpmQuantizeEnabled: invalid value type, expected boolean`);
        return;
    }
    if (procBeatDetector) {
        procBeatDetector.setBpmQuantizeEnabled(v);
    }
}

export function getBpmQuantizeEnabled(): boolean {
    return procBeatDetector?.getBpmQuantizeEnabled() ?? true;
}

/** 通用视线/头部追踪设定（重建追踪以应用新值）。 */
function _setGazeTrackingSetting(field: 'eyeTrackingEnabled' | 'headTrackingEnabled', value: boolean): void {
    procState = { ...procState, [field]: value };
    triggerAutoSave();
    if (_procVmdActive) {
        _teardownGazeTracking();
        _setupGazeTracking();
    }
}

/** 设置眼部跟随开关（实时效果，不重新生成 VMD）。 */
export function setProcMotionEyeTrackingEnabled(v: boolean): void {
    _setGazeTrackingSetting('eyeTrackingEnabled', v);
}

/** 设置头部跟随开关（实时效果，不重新生成 VMD）。 */
export function setProcMotionHeadTrackingEnabled(v: boolean): void {
    _setGazeTrackingSetting('headTrackingEnabled', v);
}

let _gazeLayerActive = false;

/** 图层驱动的视线/头部控制。
 *  由 vmd-layers 在调整 gaze 图层时调用。
 *  - intensity > 0 且 active → 启用眼部追踪
 *  - intensity >= 0.5 且 active → 同时启用头部追踪
 *  - 否则禁用两者。
 *  不干涉 _setGazeTrackingSetting 内部重建逻辑。 */
export function setGazeLayerActive(active: boolean, intensity: number): void {
    _gazeLayerActive = active;
    const shouldEnable = active && intensity > 0;
    setProcMotionEyeTrackingEnabled(shouldEnable);
    setProcMotionHeadTrackingEnabled(shouldEnable && intensity >= 0.5);
}

// ======== Lifelike Motion Layer（微动叠加层） ========

let _lifelikeLayerId: string | null = null;

/** 生成 lifelike VMD 并作为图层添加到当前模型。 */
async function _applyLifelikeLayer(): Promise<void> {
    const modelId = focusedModelId;
    if (!modelId) return;
    const inst = modelManager.get(modelId);
    if (!inst?.mmdModel) return;

    // 先移除旧的 lifelike 图层
    if (_lifelikeLayerId) {
        await removeVmdLayer(_lifelikeLayerId, modelId);
        _lifelikeLayerId = null;
    }

    const morphNames = inst.mmdModel.morph.morphs.map(m => m.name) ?? [];
    const boneNames = inst.mmdModel.runtimeBones.map(b => b.name);
    const buf = generateLifelikeVmd(procState, morphNames, boneNames);

    const layer = await addVmdLayer(buf, 'Lifelike', modelId, procState.lifelikeIntensity);
    if (layer) {
        _lifelikeLayerId = layer.id;
    }
}

/** 移除 lifelike 图层。 */
async function _removeLifelikeLayer(): Promise<void> {
    if (_lifelikeLayerId) {
        const modelId = focusedModelId;
        if (modelId) {
            await removeVmdLayer(_lifelikeLayerId, modelId);
        }
        _lifelikeLayerId = null;
    }
}

/** 设置 lifelike 开关。 */
export async function setLifelikeEnabled(v: boolean): Promise<void> {
    procState = { ...procState, lifelikeEnabled: v };
    triggerAutoSave();
    if (v) {
        await _applyLifelikeLayer();
    } else {
        await _removeLifelikeLayer();
    }
}

/** 设置 lifelike 强度并重新应用。 */
export async function setLifelikeIntensity(v: number): Promise<void> {
    procState = { ...procState, lifelikeIntensity: Math.max(0, Math.min(1, v)) };
    triggerAutoSave();
    if (procState.lifelikeEnabled) {
        await _applyLifelikeLayer();
    }
}

export function regenerateProcMotion(): void {
    if (!_procVmdActive && procState.mode === 'off') {
        return;
    }
    // 无焦点模型时静默返回，添加警告辅助调试
    if (!focusedMmdModel()) {
        console.warn('[proc-motion] regenerateProcMotion: 无焦点 MMD 模型，跳过');
        return;
    }
    // Issue #4: 如果 regenerate 调用时正在生成，标记 deferred 重跑
    if (procStarting) {
        _regeneratePending = true;
        return;
    }
    const mode = procState.mode === 'autodance' ? ('autodance' as const) : ('idle' as const);
    // Issue #5: procBeatDetector 可能为 null
    const bpm = procBeatDetector?.getBPM() ?? 120;
    startProcMotion(mode, mode === 'autodance' ? bpm : undefined);
}

