// [doc:architecture] Motion Layers — 多 VMD 叠加系统
// 职责: 管理模型的多层 VMD 动画，通过 MmdCompositeAnimation 混合
// 依赖: config.ts + scene.ts (懒加载避免循环依赖)

import { VmdLoader } from 'babylon-mmd/esm/Loader/vmdLoader';
import { MmdWasmAnimation } from 'babylon-mmd/esm/Runtime/Optimized/Animation/mmdWasmAnimation';
import { MmdWasmRuntime } from 'babylon-mmd/esm/Runtime/Optimized/mmdWasmRuntime';
import { MmdCompositeAnimation, MmdAnimationSpan } from 'babylon-mmd/esm/Runtime/Animation/mmdCompositeAnimation';
import type { VmdLayer } from '../../core/types';
import {
    mmdRuntime,
    modelRegistry,
    focusedModelId,
    setStatus,
    triggerAutoSave,
} from '../../core/config';
import { resolveFileUrl, normPath } from '../../core/fileservice';
import Encoding from 'encoding-japanese';

function getScene() {
    return import('../scene') as Promise<typeof import('../scene')>;
}

/** 生成唯一图层 ID */
function _nextLayerId(): string {
    return `layer_${crypto.randomUUID().slice(0, 8)}`;
}

/** 解码 Shift-JIS 字节到 Unicode 字符串（VMD 骨骼名用，最大 len 字节） */
function _decodeSjis(bytes: Uint8Array): string {
    let end = 0;
    while (end < bytes.length && bytes[end] !== 0) end++;
    if (end === 0) return '';
    return Encoding.convert(bytes.slice(0, end), {
        to: 'UNICODE',
        from: 'SJIS',
        type: 'string',
    }) as string;
}

const VMD_BONE_FRAME_SIZE = 111; // 标准 VMD 骨骼帧大小（15 骨骼名 + 4 帧号 + 12 位置 + 16 旋转 + 64 插值）

/**
 * 过滤 VMD 二进制数据，只保留指定骨骼的关键帧。
 * 在 VMD 二进制层面操作，完整保留插值曲线、morph 帧、相机帧等所有其他数据。
 * @returns 新的 VMD ArrayBuffer，或 boneFilter 为空时返回原始引用
 */
function _filterVmdBones(data: ArrayBuffer, boneFilter: string[]): ArrayBuffer {
    if (boneFilter.length === 0) return data;
    const src = new Uint8Array(data);
    const view = new DataView(data);
    // VMD 头部: 30(signature) + 20(modelName) = 50, 之后 4 字节骨骼帧数
    const boneCount = view.getUint32(50, true);
    if (boneCount === 0) return data;
    const boneStartOffset = 54;
    const filterSet = new Set(boneFilter);
    const keptIndices: number[] = [];
    for (let i = 0; i < boneCount; i++) {
        const off = boneStartOffset + i * VMD_BONE_FRAME_SIZE;
        const boneName = _decodeSjis(src.slice(off, off + 15));
        if (filterSet.has(boneName)) keptIndices.push(i);
    }
    if (keptIndices.length === boneCount) return data; // 全保留 = 不变
    // 重建 VMD
    const newBoneCount = keptIndices.length;
    const newBoneSize = newBoneCount * VMD_BONE_FRAME_SIZE;
    const morphOffset = boneStartOffset + boneCount * VMD_BONE_FRAME_SIZE;
    const tailSize = data.byteLength - morphOffset;
    const out = new Uint8Array(54 + newBoneSize + tailSize);
    // 复制头部 (signature + modelName)
    out.set(src.slice(0, 50), 0);
    // 写入新的骨骼帧数
    const outView = new DataView(out.buffer, out.byteOffset, out.byteLength);
    outView.setUint32(50, newBoneCount, true);
    // 复制保留的骨骼帧
    let writeOff = 54;
    for (const idx of keptIndices) {
        const srcOff = boneStartOffset + idx * VMD_BONE_FRAME_SIZE;
        out.set(src.slice(srcOff, srcOff + VMD_BONE_FRAME_SIZE), writeOff);
        writeOff += VMD_BONE_FRAME_SIZE;
    }
    // 复制尾部（morph 帧数 + morph 帧 + camera/light/shadow/ik 计数）
    out.set(src.slice(morphOffset), writeOff);
    return out.buffer;
}

/**
 * 添加一个 VMD 图层到模型。
 * @param data VMD 二进制数据
 * @param name 图层显示名称
 * @param targetModelId 目标模型 ID
 * @param weight 混合权重 (0-1)
 * @param boneFilter 骨骼过滤（空=全部）
 */
export async function addVmdLayer(
    data: ArrayBuffer,
    name: string,
    targetModelId?: string,
    weight = 1.0,
    boneFilter: string[] = []
): Promise<VmdLayer | null> {
    const targetId = targetModelId || focusedModelId;
    if (!targetId) {
        setStatus('✗ 没有目标模型', false);
        return null;
    }
    const inst = modelRegistry.get(targetId);
    if (!inst?.mmdModel) {
        setStatus('✗ 目标模型不支持图层', false);
        return null;
    }

    const layer: VmdLayer = {
        id: _nextLayerId(),
        name,
        kind: 'vmd',
        data,
        path: null,
        weight,
        enabled: true,
        boneFilter,
    };

    inst.vmdLayers.push(layer);
    await _rebuildCompositeAnimation(inst.id);
    setStatus(`✓ 图层已添加: ${name}`, true);
    triggerAutoSave();
    return layer;
}

/** 从路径加载并添加 VMD 图层 */
export async function addVmdLayerFromPath(
    path: string,
    targetModelId?: string,
    weight = 1.0,
    boneFilter: string[] = []
): Promise<VmdLayer | null> {
    const targetId = targetModelId || focusedModelId;
    if (!targetId) {
        setStatus('✗ 没有目标模型', false);
        return null;
    }
    const inst = modelRegistry.get(targetId);
    if (inst?.vmdLayers?.some(l => l.path === path)) {
        setStatus(`⚠ 图层已存在: ${normPath(path).split('/').pop()}`, false);
        return null;
    }
    try {
        const { url } = await resolveFileUrl(path);
        const vmdName = normPath(path).split('/').pop() || '';
        const resp = await fetch(url);
        if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
        const data = await resp.arrayBuffer();
        const layer = await addVmdLayer(
            data,
            vmdName.replace(/\.vmd$/i, ''),
            targetId,
            weight,
            boneFilter
        );
        if (layer) {
            layer.path = path;
        }
        return layer;
    } catch (err) {
        console.error('addVmdLayerFromPath:', err);
        setStatus('✗ 图层加载失败', false);
        return null;
    }
}

/**
 * 批量添加 VMD 图层（场景恢复用）。
 * 所有图层只触发一次 composite rebuild，避免 N 次重复解析。
 */
export async function addVmdLayersFromPaths(
    layers: Array<{ path: string; weight: number; boneFilter: string[] }>,
    targetModelId?: string
): Promise<number> {
    const targetId = targetModelId || focusedModelId;
    if (!targetId) return 0;
    const inst = modelRegistry.get(targetId);
    if (!inst?.mmdModel) return 0;

    let addedCount = 0;
    const newLayers: Array<{ data: ArrayBuffer; name: string; weight: number; path: string; boneFilter: string[] }> = [];

    for (const layer of layers) {
        if (inst.vmdLayers.some(l => l.path === layer.path)) continue; // 跳过重复
        try {
            const { url } = await resolveFileUrl(layer.path);
            const vmdName = normPath(layer.path).split('/').pop() || '';
            const resp = await fetch(url);
            if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
            const data = await resp.arrayBuffer();
            newLayers.push({
                data,
                name: vmdName.replace(/\.vmd$/i, ''),
                weight: layer.weight,
                path: layer.path,
                boneFilter: layer.boneFilter,
            });
            addedCount++;
        } catch (err) {
            console.warn(`addVmdLayersFromPaths: skip ${layer.path}`, err);
        }
    }

    if (newLayers.length === 0) return 0;

    for (const nl of newLayers) {
        const vmLayer: VmdLayer = {
            id: _nextLayerId(),
            name: nl.name,
            kind: 'vmd',
            data: nl.data,
            path: nl.path,
            weight: nl.weight,
            enabled: true,
            boneFilter: nl.boneFilter,
        };
        inst.vmdLayers.push(vmLayer);
    }

    await _rebuildCompositeAnimation(targetId);
    setStatus(`✓ 已恢复 ${addedCount} 个图层`, true);
    return addedCount;
}

/**
 * 添加一个视线追踪（gaze）图层。
 * gaze 图层不会参与 VMD composite 混合，而是通过 setGazeLayerActive 控制视线追踪状态。
 * 每个模型只允许一个 gaze 层，重复调用返回 null。
 */
export async function addGazeLayer(
    modelId: string,
    name?: string,
    weight = 1.0,
    enabled = true
): Promise<VmdLayer | null> {
    const inst = modelRegistry.get(modelId);
    if (!inst) {
        setStatus('✗ 模型未找到', false);
        return null;
    }

    if (inst.vmdLayers.some(l => l.kind === 'gaze')) {
        setStatus('⚠ 视线追踪图层已存在', false);
        return null;
    }

    const layer: VmdLayer = {
        id: _nextLayerId(),
        name: name ?? '视线追踪',
        kind: 'gaze',
        data: new ArrayBuffer(0),
        path: null,
        weight,
        enabled,
        boneFilter: [],
    };

    inst.vmdLayers.push(layer);
    if (enabled) {
        await _applyGazeLayers(modelId);
    }
    triggerAutoSave();
    return layer;
}

/** 移除一个 VMD 图层 */
export async function removeVmdLayer(
    layerId: string,
    targetModelId?: string
): Promise<void> {
    const targetId = targetModelId || focusedModelId;
    if (!targetId) return;
    const inst = modelRegistry.get(targetId);
    if (!inst) return;

    const idx = inst.vmdLayers.findIndex(l => l.id === layerId);
    if (idx === -1) return;

    const removed = inst.vmdLayers.splice(idx, 1)[0];
    if (removed.kind === 'gaze') {
        await _applyGazeLayers(inst.id);
    } else {
        await _rebuildCompositeAnimation(inst.id);
    }
    setStatus(`✓ 图层已移除: ${removed.name}`, true);
    triggerAutoSave();
}

/** 切换图层启用/禁用 */
export async function toggleVmdLayer(
    layerId: string,
    targetModelId?: string
): Promise<void> {
    const targetId = targetModelId || focusedModelId;
    if (!targetId) return;
    const inst = modelRegistry.get(targetId);
    if (!inst) return;

    const layer = inst.vmdLayers.find(l => l.id === layerId);
    if (!layer) return;

    layer.enabled = !layer.enabled;
    if (layer.kind === 'gaze') {
        await _applyGazeLayers(inst.id);
    } else {
        await _rebuildCompositeAnimation(inst.id);
    }
    triggerAutoSave();
}

/** 设置图层权重 */
export async function setVmdLayerWeight(
    layerId: string,
    weight: number,
    targetModelId?: string
): Promise<void> {
    const targetId = targetModelId || focusedModelId;
    if (!targetId) return;
    const inst = modelRegistry.get(targetId);
    if (!inst) return;

    const layer = inst.vmdLayers.find(l => l.id === layerId);
    if (!layer) return;

    layer.weight = Math.max(0, Math.min(1, weight));
    if (layer.kind === 'gaze') {
        await _applyGazeLayers(inst.id);
    } else {
        await _rebuildCompositeAnimation(inst.id);
    }
    triggerAutoSave();
}

/** 清除所有图层 */
export async function clearVmdLayers(targetModelId?: string): Promise<void> {
    const targetId = targetModelId || focusedModelId;
    if (!targetId) return;
    const inst = modelRegistry.get(targetId);
    if (!inst) return;

    inst.vmdLayers = [];
    await _rebuildCompositeAnimation(inst.id);
    triggerAutoSave();
}

/** 上一次 gaze 激活状态，用于避免重复调用 setGazeLayerActive */
let _prevGazeActive = false;

/**
 * 快速应用 gaze 层状态（不触发 VMD 重载）。
 * toggle/weight/remove 等仅涉及 gaze 层的操作走此路径。
 */
async function _applyGazeLayers(modelId: string): Promise<void> {
    const inst = modelRegistry.get(modelId);
    if (!inst) return;

    const enabledGaze = inst.vmdLayers.filter(l => l.kind === 'gaze' && l.enabled);
    const hasActiveGaze = enabledGaze.length > 0;
    // 无论状态是否变化，只要 gaze 启用就调用（权重可能变了）；
    // 关闭时才只需在状态切换时调用
    if (hasActiveGaze || hasActiveGaze !== _prevGazeActive) {
        _prevGazeActive = hasActiveGaze;
        try {
            const { setGazeLayerActive } = await import('./proc-motion-bridge');
            if (typeof setGazeLayerActive === 'function') {
                setGazeLayerActive(hasActiveGaze, hasActiveGaze ? enabledGaze[0].weight : 0);
            }
        } catch {
            // proc-motion-bridge not available
        }
    }
}

/**
 * 根据当前图层列表重建 MmdCompositeAnimation 并应用到模型。
 * 核心逻辑：每个启用的 VMD 图层 = 一个 MmdAnimationSpan，权重由 layer.weight 控制。
 * gaze 图层不参与 composite 混合，而是通过 setGazeLayerActive 单独控制。
 */
async function _rebuildCompositeAnimation(modelId: string): Promise<void> {
    const { scene } = await getScene();
    const inst = modelRegistry.get(modelId);
    if (!inst?.mmdModel) return;

    const enabledLayers = inst.vmdLayers.filter(l => l.enabled);
    const vmdEnabledLayers = enabledLayers.filter(l => l.kind === 'vmd');

    // ── Gaze 层处理（快速路径，不参与 VMD composite） ──
    await _applyGazeLayers(modelId);

    const hasBaseVmd = !!inst.vmdData;

    // 没有 VMD 图层 → 回退到单 VMD 模式（如果有 vmdData）
    if (vmdEnabledLayers.length === 0) {
        if (hasBaseVmd) {
            const { loadVMDMotion } = await import('./vmd-loader');
            await loadVMDMotion(inst.vmdData, inst.vmdName, modelId);
        }
        return;
    }

    // 单一 VMD 图层且无基础 VMD → 直接加载，不需要 composite
    if (vmdEnabledLayers.length === 1 && !hasBaseVmd) {
        const layer = vmdEnabledLayers[0];
        const { loadVMDMotion } = await import('./vmd-loader');
        const loadData = layer.boneFilter?.length ? _filterVmdBones(layer.data, layer.boneFilter) : layer.data;
        await loadVMDMotion(loadData, layer.name, modelId);
        return;
    }

    // 多个动画（基础 VMD + VMD 图层）→ 创建 MmdCompositeAnimation 混合叠加
    try {
        const vmdLoader = new VmdLoader(scene);
        const composite = new MmdCompositeAnimation('motionLayers');

        // 收集所有待混合的动画条目：基础 VMD（weight=1.0）+ 各启用的 VMD 图层
        const sources: { data: ArrayBuffer; name: string; weight: number; boneFilter?: string[] }[] = [];
        if (hasBaseVmd) {
            sources.push({ data: inst.vmdData, name: inst.vmdName || 'base', weight: 1.0 });
        }
        for (const layer of vmdEnabledLayers) {
            sources.push({ data: layer.data, name: layer.name, weight: layer.weight, boneFilter: layer.boneFilter });
        }

        let maxEndFrame = 0;

        // weight 归一化：确保总权重 = 1.0，避免多层叠加时骨骼旋转溢出
        const totalWeight = sources.reduce((sum, s) => sum + s.weight, 0);

        for (const src of sources) {
            const loadData = src.boneFilter?.length ? _filterVmdBones(src.data, src.boneFilter) : src.data;
            const mmdAnimation = await vmdLoader.loadFromBufferAsync(src.name, loadData);
            const endFrame = mmdAnimation.endFrame;
            if (endFrame > maxEndFrame) maxEndFrame = endFrame;

            const normalizedWeight = totalWeight > 0 ? src.weight / totalWeight : 0;
            const span = new MmdAnimationSpan(
                mmdAnimation,
                0,          // startFrame
                endFrame,   // endFrame
                0,          // offset (所有动画从头开始)
                normalizedWeight
            );
            composite.addSpan(span);
        }

        (vmdLoader as unknown as { dispose?: () => void }).dispose?.();

        // WASM 运行时不支持 MmdCompositeAnimation（缺 createRuntimeModelAnimation），
        // 回退到主图层
        if (mmdRuntime instanceof MmdWasmRuntime) {
            const totalSources = sources.length;
            if (totalSources > 1) {
                console.warn(`[MotionLayers] WASM runtime: ${totalSources} sources requested, only primary layer supported`);
            }
            const primarySrc = sources[0];
            const { loadVMDMotion } = await import('./vmd-loader');
            await loadVMDMotion(primarySrc.data, primarySrc.name, modelId);
            setStatus(`⚠ WASM 仅支持单图层，已加载: ${primarySrc.name}`, false);
            return;
        }

        // JS 运行时：MmdCompositeAnimation 可直接绑定
        const runtimeAnimation = composite as unknown as import('babylon-mmd/esm/Runtime/Animation/IMmdBindableAnimation').IMmdBindableModelAnimation;

        // 绑定到模型
        inst.mmdModel.setRuntimeAnimation(null);
        const handle = inst.mmdModel.createRuntimeAnimation(runtimeAnimation);
        inst.mmdModel.setRuntimeAnimation(handle);

        // 更新模型状态
        inst.animationDuration = maxEndFrame / 30;
        inst.vmdName = sources.map(s => s.name).join(' + ');

        setStatus(`✓ 图层混合: ${inst.vmdName}`, true);
        triggerAutoSave();
    } catch (err) {
        console.error('Motion Layers rebuild failed:', err);
        setStatus('✗ 图层混合失败', false);
    }
}

/** 获取模型的图层列表 */
export function getVmdLayers(modelId: string): VmdLayer[] {
    const inst = modelRegistry.get(modelId);
    return inst?.vmdLayers ?? [];
}

// [doc:architecture] SceneVMD — VMD/动作加载子模块
// 职责: 从 scene.ts 拆出的 VMD 加载/播放入口
// 依赖: config.ts + scene.ts (懒加载避免循环依赖)

import { VmdLoader } from 'babylon-mmd/esm/Loader/vmdLoader';
import { MmdWasmAnimation } from 'babylon-mmd/esm/Runtime/Optimized/Animation/mmdWasmAnimation';
import { MmdWasmRuntime } from 'babylon-mmd/esm/Runtime/Optimized/mmdWasmRuntime';
import {
    mmdRuntime,
    modelRegistry,
    focusedModelId,
    isPlaying,
    autoLoop,
    setPendingVmd,
    setIsPlaying,
    setStatus,
    triggerAutoSave,
    addRecentMotion,
    dom,
} from '../../core/config';
import { resolveFileUrl, normPath } from '../../core/fileservice';
import { loadCameraVmd } from '../camera/camera';
import { loadAudioFile } from '../../outfit/audio';
import { PROC_VMD_NAME_IDLE, PROC_VMD_NAME_AUTODANCE } from '../../motion-algos/procedural-motion';
import { isAutoLoadCompanionAudioEnabled } from '../../menus/settings';

// Dynamic re-import of scene.ts to access its module-level state
// (scene, focusedMmdModel, focusedModel, isProcVmdActive, stopProcMotion)
// without creating a static circular dependency.
function getScene() {
    return import('../scene') as Promise<typeof import('../scene')>;
}

// 缓存已加载的同名伴音，避免重复加载
const _companionAudioCache = new Set<string>();

// ======== VMD Loading ========
export async function loadVMDMotion(
    data: ArrayBuffer,
    name: string,
    targetModelId?: string
): Promise<void> {
    const { scene, focusedMmdModel: _focusedMmdModel, isProcVmdActive, stopProcMotion, focusedModel: _focusedModel } =
        await getScene();
    // If user loads a real VMD, stop procedural motion
    if (isProcVmdActive() && name !== PROC_VMD_NAME_IDLE && name !== PROC_VMD_NAME_AUTODANCE) {
        stopProcMotion();
    }
    if (!mmdRuntime) {
        setPendingVmd({ data, name });
        setStatus('VMD 已缓存，等待模型加载', false);
        return;
    }
    const targetId = targetModelId || focusedModelId;
    if (!targetId) {
        setStatus('✗ 没有目标模型', false);
        return;
    }
    const inst = modelRegistry.get(targetId);
    if (!inst) {
        setStatus('✗ 目标模型不存在', false);
        return;
    }
    try {
        // Load VMD from buffer using VmdLoader
        const vmdLoader = new VmdLoader(scene);
        const mmdAnimation = await vmdLoader.loadFromBufferAsync(name, data);
        (vmdLoader as unknown as { dispose?: () => void }).dispose?.(); // 释放解析器内部资源（API 可选）

        // Create runtime animation from the loaded data
        // WASM 版需 MmdWasmAnimation 包装；JS 版直接用 mmdAnimation（实现 IMmdBindableModelAnimation）
        let runtimeAnimation: import('babylon-mmd/esm/Runtime/Animation/IMmdBindableAnimation').IMmdBindableModelAnimation;
        if (mmdRuntime instanceof MmdWasmRuntime) {
            runtimeAnimation = new MmdWasmAnimation(mmdAnimation, mmdRuntime.wasmInstance, scene);
        } else {
            runtimeAnimation = mmdAnimation;
        }

        // Extract camera track from VMD and apply to MmdCamera
        try {
            loadCameraVmd(mmdAnimation, '', name);
        } catch {
            // 程序化动作的 VMD 不含相机轨道，此处跳过是正常行为
        }

        // Bind to model
        if (!inst.mmdModel) {
            // 动画已创建但模型是 Stage，无法绑定 — 清理避免泄漏（仅 WASM 版有资源需释放）
            if (runtimeAnimation instanceof MmdWasmAnimation) {
                try {
                    runtimeAnimation.dispose?.();
                } catch {
                    // Intentionally empty — 舞台模型动画句柄清理失败不影响后续流程
                }
            }
            setStatus('✗ 舞台模型不支持 VMD', false);
            return;
        }
        // 释放旧动画句柄，防止切换 VMD 时 WASM 内存泄漏
        inst.mmdModel.setRuntimeAnimation(null);
        const handle = inst.mmdModel.createRuntimeAnimation(runtimeAnimation);
        inst.mmdModel.setRuntimeAnimation(handle);

        inst.vmdData = data;
        _companionAudioCache.clear();
        inst.vmdName = name;
        // Convert from 30fps frames to seconds
        inst.animationDuration = mmdAnimation.endFrame / 30;

        if (!isPlaying && autoLoop) {
            await mmdRuntime.playAnimation();
            setIsPlaying(true);
        }
        setStatus(`✓ VMD: ${name}`, true);
        triggerAutoSave();
    } catch (err) {
        console.error('VMD load failed:', err);
        setStatus('✗ VMD 加载失败', false);
    }
}

export async function loadVMDFromPath(path: string, targetModelId?: string): Promise<void> {
    const { focusedMmdModel, focusedModel } = await getScene();
    dom.loadingEl.style.display = 'block';
    dom.loadingText.textContent = 'VMD 加载中...';
    try {
        const { url } = await resolveFileUrl(path);
        const vmdName = normPath(path).split('/').pop() || '';
        const resp = await fetch(url);
        if (!resp.ok) {
            throw new Error(`HTTP ${resp.status}`);
        }
        const vmdData = await resp.arrayBuffer();
        const vmdDisplayName = vmdName.replace(/\.vmd$/i, '');

        if (mmdRuntime && (targetModelId || focusedMmdModel())) {
            await loadVMDMotion(vmdData, vmdName.replace(/\.vmd$/i, ''), targetModelId);
            const foc = targetModelId ? modelRegistry.get(targetModelId) : focusedModel();
            if (foc) {
                foc.vmdPath = path;
            }
        } else {
            setPendingVmd({ data: vmdData, name: vmdName.replace(/\.vmd$/i, '') });
            setStatus('VMD 已缓存，加载模型后自动应用', false);
        }

        // 记录最近使用动作
        addRecentMotion(path, vmdDisplayName);

        // 尝试加载同目录下的同名音频文件
        await _tryLoadCompanionAudio(path, url);
    } catch (err) {
        console.error('loadVMDFromPath:', err);
        setStatus('✗ VMD 加载失败', false);
    } finally {
        dom.loadingEl.style.display = 'none';
    }
}

/** 尝试加载 VMD 同目录下的同名音频文件（.mp3/.wav/.ogg/.flac）。 */
async function _tryLoadCompanionAudio(vmdPath: string, vmdUrl: string): Promise<void> {
    if (!isAutoLoadCompanionAudioEnabled()) return;
    const baseUrl = vmdUrl.substring(0, vmdUrl.lastIndexOf('/') + 1);
    const basePath = vmdPath.replace(/\.vmd$/i, '');
    if (_companionAudioCache.has(basePath)) return;
    const exts = ['.mp3', '.wav', '.ogg', '.flac', '.wma'];

    // 并行 HEAD 探针，取首个成功的扩展名（Promise.any 只取最快的成功结果）
    const probes = exts.map(async (ext) => {
        const audioPath = basePath + ext;
        const audioName = audioPath.split('/').pop() || '';
        const resp = await fetch(baseUrl + encodeURIComponent(audioName), { method: 'HEAD' });
        if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
        return { audioPath, audioName };
    });

    try {
        const { audioPath, audioName } = await Promise.any(probes);
        await loadAudioFile(audioPath);
        _companionAudioCache.add(basePath);
        setStatus(`✓ VMD + 音频: ${audioName}`, true);
        // 确保播放栏可见
        const { updatePlaybackUI } = await import('./playback');
        updatePlaybackUI();
    } catch {
        // 所有扩展名都未找到，静默跳过
    }
}

export async function loadCameraVmdFromPath(path: string): Promise<void> {
    const { scene } = await getScene();
    dom.loadingEl.style.display = 'block';
    dom.loadingText.textContent = '相机 VMD 加载中...';
    try {
        const { url } = await resolveFileUrl(path);
        const vmdName = normPath(path).split('/').pop() || '';
        const resp = await fetch(url);
        if (!resp.ok) {
            throw new Error(`HTTP ${resp.status}`);
        }
        const vmdData = await resp.arrayBuffer();

        const vmdLoader = new VmdLoader(scene);
        const mmdAnimation = await vmdLoader.loadFromBufferAsync(vmdName, vmdData);
        (vmdLoader as unknown as { dispose?: () => void }).dispose?.();
        loadCameraVmd(mmdAnimation, path, vmdName.replace(/\.vmd$/i, ''));
        setStatus(`✓ 相机 VMD: ${vmdName}`, true);
        triggerAutoSave();
    } catch (err) {
        console.error('loadCameraVmdFromPath:', err);
        setStatus('✗ 相机 VMD 加载失败', false);
    } finally {
        dom.loadingEl.style.display = 'none';
    }
}

export async function loadVPDPose(path: string, targetModelId?: string): Promise<void> {
    const { focusedModel, stopProcMotion, isProcVmdActive } = await getScene();
    dom.loadingEl.style.display = 'block';
    dom.loadingText.textContent = 'VPD 姿势加载中...';
    try {
        const { url } = await resolveFileUrl(path);
        const poseName = normPath(path).split('/').pop() || '';
        const resp = await fetch(url);
        if (!resp.ok) {
            throw new Error(`HTTP ${resp.status}`);
        }
        const rawData = await resp.arrayBuffer();

        // 停掉程序化动作（VPD 姿势不被动画干扰）
        if (isProcVmdActive()) {
            stopProcMotion();
        }

        // 解析 VPD 并作为静态姿势应用（不生成 VMD 动画）
        const { decodeVPDData, parseVPDText } = await import('../../motion-algos/vpd-parser');
        const { applyVPDPose } = await import('../manager/model-ops');
        const text = decodeVPDData(rawData);
        const pose = parseVPDText(text);
        const id = targetModelId || focusedModelId;
        if (!id) {
            setStatus('请先加载模型', true);
            return;
        }
        applyVPDPose(id, pose.bones, pose.morphs);

        const foc = targetModelId ? modelRegistry.get(targetModelId) : focusedModel();
        if (foc) {
            foc.vmdPath = path; // 记录姿势文件路径
        }
        setStatus(`✓ 姿势: ${poseName}`, true);
    } catch (err) {
        console.error('loadVPDPose:', err);
        setStatus('✗ 姿势加载失败', false);
    } finally {
        dom.loadingEl.style.display = 'none';
    }
}

