// [doc:architecture] Scene Lighting — 光照、阴影、太阳盘
// 职责: 方向光/半球光管理、阴影生成器、太阳圆盘可视化
// 注意: 从 scene.ts 静态导入但仅在函数体内访问，ES module live binding 保证安全。

import { HemisphericLight } from '@babylonjs/core/Lights/hemisphericLight';
import { DirectionalLight } from '@babylonjs/core/Lights/directionalLight';
import { SpotLight } from '@babylonjs/core/Lights/spotLight';
import { PointLight } from '@babylonjs/core/Lights/pointLight';
import { Vector3 } from '@babylonjs/core/Maths/math.vector';
import { Color3 } from '@babylonjs/core/Maths/math.color';
import { Mesh } from '@babylonjs/core/Meshes/mesh';
import { MeshBuilder } from '@babylonjs/core/Meshes/meshBuilder';
import type { LinesMesh } from '@babylonjs/core/Meshes/linesMesh';
import { StandardMaterial } from '@babylonjs/core/Materials/standardMaterial';
import { ShadowGenerator } from '@babylonjs/core/Lights/Shadows/shadowGenerator';
import { CascadedShadowGenerator } from '@babylonjs/core/Lights/Shadows/cascadedShadowGenerator';
import { PositionGizmo } from '@babylonjs/core/Gizmos/positionGizmo';
import { RotationGizmo } from '@babylonjs/core/Gizmos/rotationGizmo';
import { UtilityLayerRenderer } from '@babylonjs/core/Rendering/utilityLayerRenderer';
import type { ModelInstance, PropInstance } from '../../core/config';
import { scheduleRefresh } from '../../core/reactivity';
import { resetPerformanceSnapshot } from './performance';

function setKey<T extends object, K extends keyof T>(obj: T, key: K, value: T[K]): void {
    obj[key] = value;
}

// ======== Light State ========

export interface LightState {
    hemiIntensity: number;
    dirIntensity: number;
    dirX: number;
    dirY: number;
    dirZ: number;
    dirColor: [number, number, number];
    hemiColor: [number, number, number];
    groundColor: [number, number, number];
    shadowEnabled: boolean;
    shadowType: 'hard' | 'soft' | 'pcf';
    shadowCascades: number;
    shadowResolution: number; // 新增
    shadowBias: number; // 新增
}

export type StageLightType = 'spot' | 'point' | 'directional';

export interface StageLightState {
    id: string;            // 唯一标识
    name: string;          // 显示名
    enabled: boolean;
    type: StageLightType;   // 灯光类型
    intensity: number;
    color: [number, number, number];
    // SpotLight 专属
    angle: number;          // 锥角（弧度）
    exponent: number;       // 衰减指数
    // PointLight 专属
    range: number;          // 衰减距离
    // 阴影投射
    shadowEnabled: boolean;
    shadowType: 'hard' | 'soft' | 'pcf';
    shadowResolution: number;
    shadowBias: number;
    // 位置
    posX: number;
    posY: number;
    posZ: number;
    // 目标点（spot 用；directional 用其反推方向）
    targetX: number;
    targetY: number;
    targetZ: number;
    // 轨道控制参数（从 posX/Y/Z 实时推导，写回时反算）
    orbitAzimuth: number;   // -180~180 度，水平绕 Y 轴
    orbitElevation: number; // -90~90 度，垂直仰角
    orbitDistance: number;  // 距原点距离
}

function _defaultStageLightState(id: string, name: string): StageLightState {
    return {
        id,
        name,
        enabled: false,
        type: 'spot',
        intensity: 0.8,
        color: [1, 1, 1],
        angle: 0.8,
        exponent: 2,
        range: 50,
        shadowEnabled: false,
        shadowType: 'soft',
        shadowResolution: 1024,
        shadowBias: 0.0001,
        posX: 0,
        posY: 15,
        posZ: -10,
        targetX: 0,
        targetY: 0,
        targetZ: 0,
        orbitAzimuth: 180,
        orbitElevation: 56,
        orbitDistance: 18,
    };
}

// ======== Lights (module-level state) ========

let _scene: import('@babylonjs/core/scene').Scene | null = null;
let _modelRegistry: Map<string, ModelInstance> | null = null;
let _propRegistry: Map<string, PropInstance> | null = null;
let _envSysShadow: { generator: ShadowGenerator | null } | null = null;
let triggerAutoSave: (() => void) | null = null;

export let hemiLight: HemisphericLight;
export let dirLight: DirectionalLight;

interface StageLightEntry {
    state: StageLightState;
    light: SpotLight | PointLight | DirectionalLight;
    indicator: Mesh | null;
    dirLine: Mesh | null;
}
const _stageLights = new Map<string, StageLightEntry>();
let _activeStageLightId: string | null = null;
let _stageLightCounter = 0;

// ======== Gizmo State ========
let _gizmoLayer: UtilityLayerRenderer | null = null;
let _posGizmo: PositionGizmo | null = null;
let _rotGizmo: RotationGizmo | null = null;
let _gizmoTarget: string | null = null; // 当前 gizmo 绑定的灯光 ID

let _shadowEnabled = false;
let _shadowType: LightState['shadowType'] = 'soft';
let _shadowCascades = 2;
let _shadowResolution = 1024;
let _shadowBias = 0.0001;
let _sunDisc: Mesh | null = null;

/** 预设动画期间临时抑制 setLightState 内的自动保存，由 applyEnvPreset 控制 */
let _skipLightAutoSave = false;
export function setSkipLightAutoSave(skip: boolean): void {
    _skipLightAutoSave = skip;
}

const SUN_DISC_DISTANCE = 1000;

/** 太阳圆盘可见的最小方向光强度。低于此值时隐藏。 */
const SUN_DISC_MIN_INTENSITY = 0.01;

export function initLighting(
    scene: import('@babylonjs/core/scene').Scene,
    modelRegistry: Map<string, ModelInstance>,
    propRegistry: Map<string, PropInstance>,
    envSysShadow: { generator: ShadowGenerator | null },
    saveCb: () => void
): void {
    _scene = scene;
    _modelRegistry = modelRegistry;
    _propRegistry = propRegistry;
    _envSysShadow = envSysShadow;
    triggerAutoSave = saveCb;

    hemiLight = new HemisphericLight('hemi', new Vector3(0.5, 1, 0.5), scene);
    hemiLight.intensity = 0.8;
    hemiLight.diffuse = new Color3(1, 1, 1);
    hemiLight.groundColor = new Color3(0.3, 0.3, 0.4);

    dirLight = new DirectionalLight('dir', new Vector3(0, -1, 0), scene);
    dirLight.intensity = 0.4;
    dirLight.position = new Vector3(0, 40, 0);

    const def = _defaultStageLightState('light-1', '主光');
    const light = _createStageLight(def.type, def);
    _stageLights.set(def.id, { state: def, light, indicator: null, dirLine: null });
    _activeStageLightId = def.id;
    _stageLightCounter = 1;
    _updateIndicator(_stageLights.get(def.id)!);
}

function _createStageLight(type: StageLightType, state: StageLightState): SpotLight | PointLight | DirectionalLight {
    const pos = new Vector3(state.posX, state.posY, state.posZ);
    const target = new Vector3(state.targetX, state.targetY, state.targetZ);
    const diffuse = new Color3(state.color[0], state.color[1], state.color[2]);
    const intensity = state.enabled ? state.intensity : 0;

    if (type === 'spot') {
        const light = new SpotLight(state.id, pos, new Vector3(0, -1, 0), state.angle, state.exponent, _scene!);
        light.intensity = intensity;
        light.diffuse = diffuse;
        light.specular = new Color3(0.3, 0.3, 0.3);
        light.setDirectionToTarget(target);
        return light;
    }
    if (type === 'point') {
        const light = new PointLight(state.id, pos, _scene!);
        light.intensity = intensity;
        light.diffuse = diffuse;
        light.specular = new Color3(0.3, 0.3, 0.3);
        light.range = state.range;
        return light;
    }
    // directional
    const dir = target.subtract(pos).normalize();
    const light = new DirectionalLight(state.id, dir, _scene!);
    light.intensity = intensity;
    light.diffuse = diffuse;
    light.specular = new Color3(0.3, 0.3, 0.3);
    light.position = pos.clone();
    return light;
}

// ======== Stage Light Indicator ========

function _createIndicator(): Mesh {
    const mesh = MeshBuilder.CreateSphere('lightIndicator', { diameter: 0.5, segments: 8 }, _scene!);
    const mat = new StandardMaterial('lightIndicatorMat', _scene!);
    mat.emissiveColor = new Color3(1, 1, 1);
    mat.disableLighting = true;
    mesh.material = mat;
    mesh.isPickable = false;
    return mesh;
}

function _createDirLine(): Mesh {
    const mesh = MeshBuilder.CreateLines('lightDirLine', {
        points: [Vector3.Zero(), new Vector3(0, -2, 0)],
    }, _scene!);
    mesh.color = new Color3(1, 1, 0.5);
    mesh.isPickable = false;
    return mesh;
}

function _updateIndicator(entry: StageLightEntry): void {
    if (!_scene) return;
    const { state, light } = entry;

    // 更新球体指示器
    if (state.enabled) {
        if (!entry.indicator) {
            entry.indicator = _createIndicator();
        }
        entry.indicator.position.copyFrom(light.position);
        const scale = state.enabled ? 1 : 0;
        entry.indicator.scaling.setAll(scale);
        entry.indicator.setEnabled(true);

        // 聚光灯：显示方向线
        if (state.type === 'spot' && light instanceof SpotLight) {
            if (!entry.dirLine) {
                entry.dirLine = _createDirLine();
            }
            const target = new Vector3(state.targetX, state.targetY, state.targetZ);
            const dir = target.subtract(light.position).normalize().scale(3);
            entry.dirLine.position.copyFrom(light.position);
            // 更新线段点
            entry.dirLine.dispose();
            entry.dirLine = MeshBuilder.CreateLines('lightDirLine', {
                points: [Vector3.Zero(), dir],
            }, _scene!);
            (entry.dirLine as LinesMesh).color = new Color3(1, 1, 0.5);
            entry.dirLine.isPickable = false;
            entry.dirLine.position.copyFrom(light.position);
            entry.dirLine.setEnabled(true);
        } else {
            if (entry.dirLine) {
                entry.dirLine.dispose();
                entry.dirLine = null;
            }
        }
    } else {
        if (entry.indicator) {
            entry.indicator.setEnabled(false);
        }
        if (entry.dirLine) {
            entry.dirLine.setEnabled(false);
        }
    }
}

function _disposeIndicator(entry: StageLightEntry): void {
    if (entry.indicator) {
        entry.indicator.dispose();
        entry.indicator = null;
    }
    if (entry.dirLine) {
        entry.dirLine.dispose();
        entry.dirLine = null;
    }
}

function _defaultLightState(): LightState {
    return {
        hemiIntensity: 0.8,
        dirIntensity: 0.4,
        dirX: 0,
        dirY: 1,
        dirZ: 0,
        dirColor: [1, 1, 1],
        hemiColor: [1, 1, 1],
        groundColor: [0.3, 0.3, 0.4],
        shadowEnabled: false,
        shadowType: 'soft',
        shadowCascades: 2,
        shadowResolution: 1024, // 新增
        shadowBias: 0.0001, // 新增
    };
}

export function getLightState(): LightState {
    if (!hemiLight || !dirLight || !_envSysShadow) {
        const base = _defaultLightState();
        return {
            ...base,
            shadowEnabled: _shadowEnabled,
            shadowType: _shadowType,
            shadowCascades: _shadowCascades,
            shadowResolution: _shadowResolution,
            shadowBias: _shadowBias,
        };
    }
    return {
        hemiIntensity: hemiLight.intensity,
        dirIntensity: dirLight.intensity,
        dirX: -dirLight.direction.x,
        dirY: -dirLight.direction.y,
        dirZ: -dirLight.direction.z,
        dirColor: [dirLight.diffuse.r, dirLight.diffuse.g, dirLight.diffuse.b],
        hemiColor: [hemiLight.diffuse.r, hemiLight.diffuse.g, hemiLight.diffuse.b],
        groundColor: [hemiLight.groundColor.r, hemiLight.groundColor.g, hemiLight.groundColor.b],
        shadowEnabled: _envSysShadow.generator !== null,
        shadowType: _shadowType,
        shadowCascades: _shadowCascades,
        shadowResolution: _shadowResolution, // 新增
        shadowBias: _shadowBias, // 新增
    };
}

export function setLightState(s: Partial<LightState>): void {
    if (!hemiLight || !dirLight || !triggerAutoSave) {
        return;
    }

    if (s.hemiIntensity !== undefined) {
        hemiLight.intensity = s.hemiIntensity;
    }
    if (s.dirIntensity !== undefined) {
        dirLight.intensity = s.dirIntensity;
    }
    if (s.dirX !== undefined || s.dirY !== undefined || s.dirZ !== undefined) {
        const dir = new Vector3(
            -(s.dirX ?? -dirLight.direction.x),
            -(s.dirY ?? -dirLight.direction.y),
            -(s.dirZ ?? -dirLight.direction.z)
        );
        dir.normalize();
        dirLight.direction = dir;
    }
    if (s.dirColor !== undefined) {
        dirLight.diffuse = new Color3(s.dirColor[0], s.dirColor[1], s.dirColor[2]);
    }
    if (s.hemiColor !== undefined) {
        hemiLight.diffuse = new Color3(s.hemiColor[0], s.hemiColor[1], s.hemiColor[2]);
    }
    if (s.groundColor !== undefined) {
        hemiLight.groundColor = new Color3(s.groundColor[0], s.groundColor[1], s.groundColor[2]);
    }
    if (s.shadowEnabled !== undefined) {
        _shadowEnabled = s.shadowEnabled;
    }
    if (s.shadowType !== undefined) {
        _shadowType = s.shadowType;
    }
    let needRebuildShadow = false;
    if (s.shadowCascades !== undefined) {
        _shadowCascades = s.shadowCascades;
        needRebuildShadow = true;
    }
    if (s.shadowResolution !== undefined && s.shadowResolution !== _shadowResolution) {
        _shadowResolution = s.shadowResolution;
        needRebuildShadow = true;
    }
    if (s.shadowBias !== undefined) {
        _shadowBias = s.shadowBias;
        // 如果阴影生成器已存在，直接更新 bias（避免重建）
        if (_envSysShadow?.generator) {
            _envSysShadow.generator.bias = _shadowBias;
        } else {
            needRebuildShadow = true; // 还未创建，重建时会应用
        }
    }
    if (s.shadowEnabled !== undefined || s.shadowType !== undefined || needRebuildShadow) {
        _ensureShadow();
    }
    _updateSunDisc();
    if (!_skipLightAutoSave) {
        triggerAutoSave();
    }
    scheduleRefresh();
    resetPerformanceSnapshot(); // 用户手动修改灯光/阴影设置：清除自动降级快照，避免 auto 模式后续降级覆盖用户意图
}

/** 平滑过渡当前灯光到目标灯光参数，默认 2 秒 */
export function transitionLighting(
    target: Partial<LightState>,
    duration: number = 2000,
    onComplete?: () => void
): void {
    if (!hemiLight || !dirLight || !triggerAutoSave) {
        return;
    }
    const source = getLightState(); // 当前完整状态
    const startTime = performance.now();

    const animLoop = () => {
        const elapsed = performance.now() - startTime;
        const t = Math.min(elapsed / duration, 1.0);
        const lerp = (a: number, b: number) => a + (b - a) * t;

        const interpState: Partial<LightState> = {};
        // 需要重建阴影生成器的参数 — 动画进行中跳过，仅结束时一次性应用
        const rebuildShadowKeys = new Set<string>([
            'shadowResolution',
            'shadowType',
            'shadowEnabled',
        ]);
        // 仅对 target 中存在的字段插值
        for (const key of Object.keys(target) as (keyof LightState)[]) {
            // 跳过会触发每帧重建阴影生成器的参数，在动画结束时统一处理
            if (rebuildShadowKeys.has(key) && t < 1) {
                continue;
            }
            const a = source[key];
            const b = target[key];
            if (typeof a === 'number' && typeof b === 'number') {
                setKey(interpState, key, lerp(a, b) as LightState[typeof key]);
            } else if (Array.isArray(a) && Array.isArray(b)) {
                setKey(interpState, key, a.map((v, i) => lerp(v, b[i])) as LightState[typeof key]);
            } else {
                // 布尔等类型，在动画结束时才切换
                setKey(interpState, key, (t >= 1 ? b : a) as LightState[typeof key]);
            }
        }
        // 动画结束时一次性应用被跳过的阴影重建参数
        if (t >= 1) {
            for (const key of Object.keys(target) as (keyof LightState)[]) {
                if (rebuildShadowKeys.has(key)) {
                    setKey(interpState, key, target[key] as LightState[typeof key]);
                }
            }
        }
        setLightState(interpState);
        if (t >= 1) {
            if (onComplete) {
                onComplete();
            }
        } else {

        }
    };

}

// ======== Sun Disc ========

function _ensureSunDisc(): Mesh {
    if (!_scene || _sunDisc) {
        return _sunDisc!;
    }
    _sunDisc = MeshBuilder.CreateSphere('sunDisc', { diameter: 30, segments: 16 }, _scene);
    const mat = new StandardMaterial('sunDiscMat', _scene);
    mat.emissiveColor = new Color3(1, 0.9, 0.7);
    mat.disableLighting = true;
    _sunDisc.material = mat;
    _sunDisc.isPickable = false;
    return _sunDisc;
}

/** 更新方向光参考圆盘位置和颜色。圆盘始终在光线来源方向（视线反方向）。
 *  仅作为调光参照，不参与光照计算。 */
export function _updateSunDisc(): void {
    if (!dirLight) return;
    const disc = _ensureSunDisc();
    const d = dirLight.direction;
    const aboveHorizon = d.y < 0;
    const hasIntensity = dirLight.intensity > SUN_DISC_MIN_INTENSITY;
    disc.setEnabled(aboveHorizon && hasIntensity);
    if (aboveHorizon && hasIntensity) {
        disc.position.set(
            -d.x * SUN_DISC_DISTANCE,
            -d.y * SUN_DISC_DISTANCE,
            -d.z * SUN_DISC_DISTANCE
        );
        const b = Math.max(0.05, dirLight.intensity);
        const mat = disc.material as StandardMaterial;
        mat.emissiveColor.set(b, b * 0.9, b * 0.7);
    }
}

export function _disposeSunDisc(): void {
    if (_sunDisc) {
        _sunDisc.dispose();
        _sunDisc = null;
    }
}

// ======== Shadow Generator ========

function _ensureShadow(): void {
    if (!_scene || !_modelRegistry || !_propRegistry || !_envSysShadow) {
        return;
    }

    if (_envSysShadow.generator) {
        _envSysShadow.generator.dispose();
        _envSysShadow.generator = null;
    }
    if (!_shadowEnabled) {
        return;
    }

    const gen = new CascadedShadowGenerator(_shadowResolution, dirLight);
    gen.numCascades = _shadowCascades;
    // CSM 仅支持 FILTER_NONE / FILTER_PCF / FILTER_PCSS
    if (_shadowType === 'pcf') {
        gen.usePercentageCloserFiltering = true;
    } else if (_shadowType === 'soft') {
        gen.useContactHardeningShadow = true;
    }
    gen.bias = _shadowBias;

    for (const [, inst] of _modelRegistry) {
        for (const m of inst.meshes) {
            if (m instanceof Mesh) {
                gen.addShadowCaster(m);
                m.receiveShadows = true;
            }
        }
    }
    for (const [, inst] of _propRegistry) {
        for (const m of inst.meshes) {
            if (m instanceof Mesh) {
                gen.addShadowCaster(m);
                m.receiveShadows = true;
            }
        }
    }

    _envSysShadow.generator = gen;
}

/** 当模型/道具注册表更新时，重新生成阴影投射者列表。 */
export function rebuildShadowCasters(): void {
    _ensureShadow();
    rebuildStageLightShadows();
}

// ======== Stage Lights ========

const _stageShadows = new Map<string, ShadowGenerator>();

export function getStageLights(): StageLightState[] {
    const result: StageLightState[] = [];
    for (const [, entry] of _stageLights) {
        result.push(_readStageLightState(entry));
    }
    return result;
}

export function getActiveStageLightId(): string | null {
    return _activeStageLightId;
}

export function setActiveStageLightId(id: string): void {
    if (_stageLights.has(id)) {
        _activeStageLightId = id;
    }
}

export function getStageLightState(id?: string): StageLightState {
    const entry = _getEntry(id);
    if (!entry) return _defaultStageLightState('light-1', '主光');
    return _readStageLightState(entry);
}

export function setStageLightState(s: Partial<StageLightState>, id?: string): void {
    const targetId = id ?? s.id ?? _activeStageLightId;
    if (!targetId) return;
    const entry = _stageLights.get(targetId);
    if (!entry || !triggerAutoSave) return;

    // 类型切换：dispose 旧灯 + 旧阴影 + 创建新灯
    if (s.type !== undefined && s.type !== entry.state.type) {
        Object.assign(entry.state, s);
        entry.light.dispose();
        _disposeStageShadow(targetId);
        entry.light = _createStageLight(s.type, entry.state);
        _ensureStageShadow(targetId);
        _updateIndicator(entry);
        triggerAutoSave();
        return;
    }

    Object.assign(entry.state, s);
    _applyStageLightParams(entry, s);

    // 阴影重建条件
    const shadowKeys = new Set(['enabled', 'shadowEnabled', 'shadowType', 'shadowResolution', 'shadowBias']);
    let needShadowRebuild = false;
    for (const key of shadowKeys) {
        if ((s as Record<string, unknown>)[key] !== undefined) {
            needShadowRebuild = true;
            break;
        }
    }
    if (needShadowRebuild) {
        _ensureStageShadow(targetId);
    }

    // 更新指示器
    _updateIndicator(entry);

    triggerAutoSave();
}

export function addStageLight(type: StageLightType = 'spot', preset?: Partial<StageLightState>): string {
    _stageLightCounter++;
    const id = `light-${_stageLightCounter}`;
    const defaultNames: Record<StageLightType, string> = {
        spot: '聚光灯',
        point: '点光源',
        directional: '平行光',
    };
    const name = `${defaultNames[type]} ${_stageLightCounter}`;
    const state = { ..._defaultStageLightState(id, name), type, ...preset, id, name };
    state.posX = _stageLightCounter * 2 - 2;
    state.orbitAzimuth = 180 + (_stageLightCounter - 1) * 30;
    const light = _createStageLight(type, state);
    const entry: StageLightEntry = { state, light, indicator: null, dirLine: null };
    _stageLights.set(id, entry);
    _activeStageLightId = id;
    _ensureStageShadow(id);
    _updateIndicator(entry);
    if (triggerAutoSave) triggerAutoSave();
    return id;
}

export function removeStageLight(id: string): boolean {
    const entry = _stageLights.get(id);
    if (!entry) return false;
    if (_stageLights.size <= 1) return false;
    _disposeIndicator(entry);
    entry.light.dispose();
    _disposeStageShadow(id);
    _stageLights.delete(id);
    if (_activeStageLightId === id) {
        _activeStageLightId = _stageLights.keys().next().value ?? null;
    }
    if (triggerAutoSave) triggerAutoSave();
    return true;
}

/** 批量加载舞台灯（反序列化用），会清空现有灯 */
export function loadStageLights(states: StageLightState[]): void {
    // 清空旧灯
    for (const [lid, entry] of _stageLights) {
        _disposeIndicator(entry);
        entry.light.dispose();
    }
    _stageLights.clear();
    for (const [sid] of _stageShadows) {
        _disposeStageShadow(sid);
    }
    _stageShadows.clear();

    if (states.length === 0) {
        const def = _defaultStageLightState('light-1', '主光');
        const light = _createStageLight(def.type, def);
        const entry: StageLightEntry = { state: def, light, indicator: null, dirLine: null };
        _stageLights.set(def.id, entry);
        _activeStageLightId = def.id;
        _stageLightCounter = 1;
        _ensureStageShadow(def.id);
        _updateIndicator(entry);
        return;
    }

    let maxNum = 0;
    for (const s of states) {
        const light = _createStageLight(s.type, s);
        const entry: StageLightEntry = { state: { ...s }, light, indicator: null, dirLine: null };
        _stageLights.set(s.id, entry);
        _ensureStageShadow(s.id);
        _updateIndicator(entry);
        const m = s.id.match(/light-(\d+)/);
        if (m) maxNum = Math.max(maxNum, parseInt(m[1]));
    }
    _stageLightCounter = maxNum;
    _activeStageLightId = states[0].id;
}

/** 重建所有舞台灯的阴影投射者列表（模型/道具变化时调用） */
export function rebuildStageLightShadows(): void {
    for (const [id] of _stageLights) {
        _ensureStageShadow(id);
    }
}

// —— 内部辅助 ——

function _getEntry(id?: string): StageLightEntry | null {
    const targetId = id ?? _activeStageLightId;
    if (!targetId) return null;
    return _stageLights.get(targetId) ?? null;
}

function _readStageLightState(entry: StageLightEntry): StageLightState {
    const { state, light } = entry;
    const base: StageLightState = {
        ...state,
        intensity: light.intensity,
        color: [light.diffuse.r, light.diffuse.g, light.diffuse.b],
        posX: light.position.x,
        posY: light.position.y,
        posZ: light.position.z,
        orbitAzimuth: Math.atan2(light.position.x, light.position.z) * 180 / Math.PI,
        orbitElevation: Math.asin(light.position.y / Math.max(0.1, light.position.length())) * 180 / Math.PI,
        orbitDistance: light.position.length(),
    };
    if (state.type === 'spot' && light instanceof SpotLight) {
        base.angle = light.angle;
        base.exponent = light.exponent;
    }
    if (state.type === 'point' && light instanceof PointLight) {
        base.range = light.range;
    }
    return base;
}

function _applyStageLightParams(entry: StageLightEntry, s: Partial<StageLightState>): void {
    const { state, light } = entry;
    const type = state.type;

    if (s.enabled !== undefined) {
        light.intensity = s.enabled ? state.intensity : 0;
    }
    if (s.intensity !== undefined && state.enabled) {
        light.intensity = s.intensity;
    }
    if (s.color !== undefined) {
        light.diffuse = new Color3(s.color[0], s.color[1], s.color[2]);
    }

    if (type === 'spot' && light instanceof SpotLight) {
        if (s.angle !== undefined) light.angle = s.angle;
        if (s.exponent !== undefined) light.exponent = s.exponent;
    }
    if (type === 'point' && light instanceof PointLight) {
        if (s.range !== undefined) light.range = s.range;
    }

    if (s.orbitAzimuth !== undefined || s.orbitElevation !== undefined || s.orbitDistance !== undefined) {
        const az = (s.orbitAzimuth ?? state.orbitAzimuth) * Math.PI / 180;
        const el = (s.orbitElevation ?? state.orbitElevation) * Math.PI / 180;
        const dist = s.orbitDistance ?? state.orbitDistance;
        light.position = new Vector3(
            dist * Math.cos(el) * Math.sin(az),
            dist * Math.sin(el),
            dist * Math.cos(el) * Math.cos(az)
        );
        if (type === 'spot' && light instanceof SpotLight) {
            light.setDirectionToTarget(new Vector3(state.targetX, state.targetY, state.targetZ));
        }
        if (type === 'directional' && light instanceof DirectionalLight) {
            const dir = new Vector3(
                state.targetX - light.position.x,
                state.targetY - light.position.y,
                state.targetZ - light.position.z
            ).normalize();
            light.direction = dir;
        }
    }
    if (s.posX !== undefined || s.posY !== undefined || s.posZ !== undefined) {
        light.position = new Vector3(
            s.posX ?? light.position.x,
            s.posY ?? light.position.y,
            s.posZ ?? light.position.z
        );
    }
    if (s.targetX !== undefined || s.targetY !== undefined || s.targetZ !== undefined) {
        if (type === 'spot' && light instanceof SpotLight) {
            light.setDirectionToTarget(new Vector3(
                s.targetX ?? state.targetX,
                s.targetY ?? state.targetY,
                s.targetZ ?? state.targetZ
            ));
        }
        if (type === 'directional' && light instanceof DirectionalLight) {
            const dir = new Vector3(
                (s.targetX ?? state.targetX) - light.position.x,
                (s.targetY ?? state.targetY) - light.position.y,
                (s.targetZ ?? state.targetZ) - light.position.z
            ).normalize();
            light.direction = dir;
        }
    }
}

function _ensureStageShadow(id: string): void {
    if (!_scene || !_modelRegistry || !_propRegistry) return;
    const entry = _stageLights.get(id);
    if (!entry) return;
    const { state, light } = entry;

    // dispose 旧的
    const old = _stageShadows.get(id);
    if (old) {
        old.dispose();
        _stageShadows.delete(id);
    }

    if (!state.enabled || !state.shadowEnabled) return;
    if (state.type === 'point') return; // PointLight 不支持 ShadowGenerator
    if (!(light instanceof SpotLight) && !(light instanceof DirectionalLight)) return;

    const gen = new ShadowGenerator(state.shadowResolution, light);
    gen.useBlurExponentialShadowMap = state.shadowType !== 'hard';
    gen.useKernelBlur = state.shadowType === 'pcf';
    gen.bias = state.shadowBias;

    for (const [, inst] of _modelRegistry) {
        for (const m of inst.meshes) {
            if (m instanceof Mesh) {
                gen.addShadowCaster(m);
                m.receiveShadows = true;
            }
        }
    }
    for (const [, inst] of _propRegistry) {
        for (const m of inst.meshes) {
            if (m instanceof Mesh) {
                gen.addShadowCaster(m);
                m.receiveShadows = true;
            }
        }
    }
    _stageShadows.set(id, gen);
}

function _disposeStageShadow(id: string): void {
    const gen = _stageShadows.get(id);
    if (gen) {
        gen.dispose();
        _stageShadows.delete(id);
    }
}

// ======== 3D Gizmo (Position + Rotation) ========

/** 获取或创建 gizmo 渲染层（独立于主场景渲染）。 */
function _getGizmoLayer(): UtilityLayerRenderer {
    if (!_gizmoLayer && _scene) {
        _gizmoLayer = new UtilityLayerRenderer(_scene);
        _gizmoLayer.shouldRender = false; // 默认不渲染
    }
    return _gizmoLayer!;
}

/**
 * 为指定灯光激活 3D 拖拽 Gizmo。
 * - PositionGizmo：拖拽坐标轴移动灯光位置
 * - RotationGizmo：拖拽圆环调整聚光灯方向（仅 spot/directional）
 */
export function attachLightGizmo(id: string): boolean {
    if (!_scene) return false;
    const entry = _stageLights.get(id);
    if (!entry) return false;

    // 先detach之前的
    detachLightGizmo();

    const layer = _getGizmoLayer();
    layer.shouldRender = true;

    // Position gizmo
    _posGizmo = new PositionGizmo(layer);
    _posGizmo.attachedNode = entry.light;
    // 拖拽中实时更新指示器
    _posGizmo.onDragObservable.add(() => {
        if (entry.indicator) {
            entry.indicator.position.copyFrom(entry.light.position);
        }
        if (entry.dirLine) {
            entry.dirLine.position.copyFrom(entry.light.position);
        }
    });
    _posGizmo.onDragEndObservable.add(() => {
        const pos = entry.light.position;
        setStageLightState({
            posX: pos.x,
            posY: pos.y,
            posZ: pos.z,
        }, id);
    });

    // Rotation gizmo（仅 spot/directional，point 无方向）
    if (entry.state.type !== 'point') {
        _rotGizmo = new RotationGizmo(layer);
        _rotGizmo.attachedNode = entry.light;
        _rotGizmo.onDragEndObservable.add(() => {
            // 从灯光当前 position + target 推导新目标
            // （direction 属性不可直接旋转，通过 position 位移同步）
            const pos = entry.light.position;
            if (entry.state.type === 'spot' && entry.light instanceof SpotLight) {
                const curDir = entry.light.direction;
                const target = pos.add(curDir.scale(10));
                setStageLightState({
                    targetX: target.x,
                    targetY: target.y,
                    targetZ: target.z,
                }, id);
            }
            if (entry.state.type === 'directional' && entry.light instanceof DirectionalLight) {
                const dir = entry.light.direction;
                const target = pos.add(dir.scale(10));
                setStageLightState({
                    targetX: target.x,
                    targetY: target.y,
                    targetZ: target.z,
                }, id);
            }
        });
    }

    _gizmoTarget = id;
    return true;
}

/** 移除当前灯光的 3D Gizmo。 */
export function detachLightGizmo(): void {
    if (_posGizmo) {
        _posGizmo.dispose();
        _posGizmo = null;
    }
    if (_rotGizmo) {
        _rotGizmo.dispose();
        _rotGizmo = null;
    }
    if (_gizmoLayer) {
        _gizmoLayer.shouldRender = false;
    }
    _gizmoTarget = null;
}

/** 当前是否有 gizmo 激活。 */
export function isGizmoActive(): boolean {
    return _gizmoTarget !== null;
}

/** 获取当前 gizmo 绑定的灯光 ID。 */
export function getGizmoTargetId(): string | null {
    return _gizmoTarget;
}

// ======== Lighting TWEEN (with cancel support) ========

interface LightingTween {
    id: number;
    cancel: () => void;
}
let _tweenIdCounter = 0;
const _activeTweens = new Map<number, LightingTween>();

function _cancelAllLightingTweens(): void {
    for (const [, tw] of _activeTweens) {
        tw.cancel();
    }
    _activeTweens.clear();
}

function _tweenValue(
    from: number,
    to: number,
    durationMs: number,
    onUpdate: (v: number) => void
): LightingTween {
    const id = ++_tweenIdCounter;
    let cancelled = false;
    const start = performance.now();

  const tick = () => {
    if (cancelled) return;
    const t = Math.min(1, (performance.now() - start) / durationMs);
    const eased = t * (2 - t); // ease-out quad
    onUpdate(from + (to - from) * eased);
    if (t >= 1) {
      _activeTweens.delete(id);
    }
  };

  const tw: LightingTween = { id, cancel: () => { cancelled = true; _activeTweens.delete(id); } };
  _activeTweens.set(id, tw);
  _scene.onBeforeRenderObservable.addOnce(tick);
  return tw;
}

function _tweenColor3(
    from: Color3,
    to: Color3,
    durationMs: number,
    onUpdate: (c: Color3) => void
): void {
    let curR = from.r, curG = from.g, curB = from.b;
    _tweenValue(0, 1, durationMs, (t) => {
        curR = from.r + (to.r - from.r) * t;
        curG = from.g + (to.g - from.g) * t;
        curB = from.b + (to.b - from.b) * t;
        onUpdate(new Color3(curR, curG, curB));
    });
}

// ======== Lighting Preset Application ========

import { LIGHTING_PRESETS, type LightingPresetLight } from './lighting-presets';

/**
 * 应用灯光预设——复用现有灯光，平滑过渡参数。
 * 由 EnvBridge 在 lightingPresetName 变化时调用。
 */
export function applyLightingPresetFromEnv(presetName: string | null): void {
    if (!presetName) return;
    const preset = LIGHTING_PRESETS[presetName];
    if (!preset) return;

    _cancelAllLightingTweens();

    const currentIds = Array.from(_stageLights.keys());
    const targetCount = preset.lights.length;

    // 1. 补齐灯光数量
    while (Array.from(_stageLights.keys()).length < targetCount) {
        const idx = Array.from(_stageLights.keys()).length;
        const pl = preset.lights[idx];
        addStageLight(pl.type, pl.state as Partial<import('./lighting').StageLightState>);
    }

    // 2. 删除多余灯光
    while (Array.from(_stageLights.keys()).length > targetCount) {
        const ids = Array.from(_stageLights.keys());
        removeStageLight(ids[ids.length - 1]);
    }

    // 3. 平滑过渡每盏灯的参数
    const ids = Array.from(_stageLights.keys());
    for (let i = 0; i < ids.length; i++) {
        const entry = _stageLights.get(ids[i]);
        if (!entry) continue;
        const pl = preset.lights[i];

        // 切换类型（需要重建，跳过 tween）
        if (pl.type !== entry.state.type) {
            setStageLightState({ type: pl.type, ...pl.state } as Partial<import('./lighting').StageLightState>, ids[i]);
            continue;
        }

        // 位置过渡（orbit 参数）
        if (pl.state.orbitAzimuth !== undefined || pl.state.orbitElevation !== undefined || pl.state.orbitDistance !== undefined) {
            const fromAz = entry.state.orbitAzimuth;
            const fromEl = entry.state.orbitElevation;
            const fromDist = entry.state.orbitDistance;
            const toAz = (pl.state.orbitAzimuth as number) ?? fromAz;
            const toEl = (pl.state.orbitElevation as number) ?? fromEl;
            const toDist = (pl.state.orbitDistance as number) ?? fromDist;
            _tweenValue(0, 1, 500, (t) => {
                setStageLightState({
                    orbitAzimuth: fromAz + (toAz - fromAz) * t,
                    orbitElevation: fromEl + (toEl - fromEl) * t,
                    orbitDistance: fromDist + (toDist - fromDist) * t,
                }, ids[i]);
            });
        }

        // 强度过渡
        if (pl.state.intensity !== undefined) {
            const from = entry.state.intensity;
            const to = pl.state.intensity as number;
            _tweenValue(from, to, 300, (v) => {
                setStageLightState({ intensity: v }, ids[i]);
            });
        }

        // 颜色过渡
        if (pl.state.color !== undefined) {
            const from = new Color3(entry.state.color[0], entry.state.color[1], entry.state.color[2]);
            const tc = pl.state.color as [number, number, number];
            const to = new Color3(tc[0], tc[1], tc[2]);
            _tweenColor3(from, to, 300, (c) => {
                setStageLightState({ color: [c.r, c.g, c.b] }, ids[i]);
            });
        }

        // 直接设置的参数（无 tween）
        const directKeys = ['angle', 'exponent', 'range', 'shadowEnabled', 'shadowType', 'shadowResolution', 'shadowBias', 'enabled'] as const;
        const directUpdates: Record<string, unknown> = {};
        let hasDirect = false;
        for (const key of directKeys) {
            if (pl.state[key] !== undefined) {
                directUpdates[key] = pl.state[key];
                hasDirect = true;
            }
        }
        if (hasDirect) {
            setStageLightState(directUpdates as Partial<import('./lighting').StageLightState>, ids[i]);
        }
    }
}

// [doc:architecture] Scene Renderer — 渲染管线、后处理、渲染状态
// 职责: DefaultRenderingPipeline 管理、后处理开关、场景背景色、边缘高亮
// 注意: 从 scene.ts 静态导入但仅在函数体内访问，ES module live binding 保证安全。

import { DefaultRenderingPipeline } from '@babylonjs/core/PostProcesses/RenderPipeline/Pipelines/defaultRenderingPipeline';
import { SSRRenderingPipeline } from '@babylonjs/core/PostProcesses/RenderPipeline/Pipelines/ssrRenderingPipeline';
import { SSAO2RenderingPipeline } from '@babylonjs/core/PostProcesses/RenderPipeline/Pipelines/ssao2RenderingPipeline';
import { Color4 } from '@babylonjs/core/Maths/math.color';
import type { Camera } from '@babylonjs/core/Cameras/camera';
import { GlowLayer } from '@babylonjs/core/Layers/glowLayer';
import { ReflectionProbe } from '@babylonjs/core/Probes/reflectionProbe';
import type { Observer } from '@babylonjs/core/Misc/observable';
import { scheduleRefresh } from '../../core/reactivity';
import { resetPerformanceSnapshot } from './performance';

// ======== Tone Mapping Modes ========

export const ToneMappingMode = {
    OFF: 0,
    ACES: 1,
    REINHARD: 2,
    CINEON: 3,
    NEUTRAL: 4,
} as const;

// ======== Render State ========

export interface RenderState {
    // Post-processing
    bloomEnabled: boolean;
    bloomWeight: number; // 0-1, default 0
    bloomThreshold: number; // 0-1, default 0.5
    bloomKernel: number; // 16-256, default 64
    outlineEnabled: boolean;
    outlineColor: [number, number, number]; // RGB 0-1
    fxaaEnabled: boolean;
    msaaSamples: number; // MSAA 采样数（1=关闭，2/4/8=开启）
    // Stage / imageProcessing
    toneMapping: number; // 0=OFF 1=ACES 2=Reinhard 3=Cineon 4=Neutral
    exposure: number; // 0-4, default 1
    contrast: number; // 0-4, default 1
    // Phase 8 — DOF + Vignette
    dofEnabled: boolean;
    dofAperture: number; // 0-1, default 0（内部映射到 fStop 0.5~10）
    vignetteEnabled: boolean;
    vignetteDarkness: number; // 0-1, default 0
    // Phase 9 — 色差 + 颗粒
    chromaticAberrationEnabled: boolean;
    chromaticAberrationAmount: number; // 0-1, default 0（内部映射到 0~8）
    grainEnabled: boolean;
    grainIntensity: number; // 0-1, default 0（内部映射到 0~50）
    // Phase 10 — 锐化 + 辉光
    sharpenAmount: number; // 0-1, default 0（内部映射到 sharpen.edgeAmount）
    glowEnabled: boolean;
    glowIntensity: number; // 0-1, default 0（GlowLayer.intensity）
    // Phase 11 — SSR + Reflection Probe
    ssrEnabled: boolean;
    ssrStrength: number; // 0-1, default 0（SSRRenderingPipeline.strength）
    ssrFalloff: number; // 0-1, default 0（映射到 reflectionSpecularFalloffExponent 1~8）
    ssrStep: number; // 1-32, default 1（SSRRenderingPipeline.step）
    ssrThickness: number; // 0-2, default 0.5（SSRRenderingPipeline.thickness）
    reflectionProbeEnabled: boolean;
    reflectionIntensity: number; // 0-1, default 0
    // Phase 11 — SSAO
    ssaoEnabled: boolean;
    ssaoStrength: number; // 0-1, default 0（SSAO2RenderingPipeline.totalStrength 0~2）
    ssaoRadius: number; // 0-1, default 0（SSAO2RenderingPipeline.radius 0~4）
    ssaoSamples: number; // 4-32, default 8（SSAO2RenderingPipeline.samples）
}

// ======== Renderer State (module-level) ========

let _scene: import('@babylonjs/core/scene').Scene | null = null;
export let pipeline: DefaultRenderingPipeline | undefined;
let _outlineEnabled = false;
let _outlineColor: [number, number, number] = [0, 0, 0];
let _pipelineCamera: Camera | null = null;
let _modelRegistry: Map<string, import('../../core/config').ModelInstance> | null = null;
let _triggerAutoSave: (() => void) | null = null;
let _glowLayer: GlowLayer | null = null;
let _ssrPipeline: SSRRenderingPipeline | null = null;
let _ssaoPipeline: SSAO2RenderingPipeline | null = null;
let _reflectionProbe: ReflectionProbe | null = null;
let _probeRefreshObserver: Observer<import('@babylonjs/core/scene').Scene> | null = null;
let _lastProbeRefresh = 0;

// ======== 数值钳制工具 ========

function clamp(value: number, min: number, max: number): number {
    return Math.max(min, Math.min(max, value));
}

function clampColorChannel(v: number): number {
    return clamp(v, 0, 1);
}

function setKey<T extends object, K extends keyof T>(obj: T, key: K, value: T[K]): void {
    obj[key] = value;
}

// ======== 初始化与释放 ========

export function initRenderer(
    scene: import('@babylonjs/core/scene').Scene,
    modelRegistry: Map<string, import('../../core/config').ModelInstance>,
    triggerAutoSave: () => void
): void {
    _scene = scene;
    _modelRegistry = modelRegistry;
    _triggerAutoSave = triggerAutoSave;

    pipeline = new DefaultRenderingPipeline('default', true, scene, [scene.activeCamera!]);
    pipeline.samples = 1; // MSAA off (performance)
    pipeline.fxaaEnabled = false;
    pipeline.bloomEnabled = false;
    pipeline.imageProcessingEnabled = true;

    // Reflection Probe 自动刷新 — 每 10 秒检查一次环境变化
    _probeRefreshObserver = scene.onBeforeRenderObservable.add(() => {
        if (!_reflectionProbe || !scene) return;
        const now = performance.now();
        if (now - _lastProbeRefresh < 10000) return;
        _lastProbeRefresh = now;
        try {
            _reflectionProbe!.renderList = scene.meshes.filter((m) =>
                m.name.includes('sky') || m.name.includes('env') || m.name.includes('ground') || m.name.includes('water')
            );
            // 强制刷新：临时设置 refreshRate 为 1 触发重新渲染
            _reflectionProbe!.refreshRate = 1;
            _reflectionProbe!.refreshRate = 0;
        } catch {
            // Intentionally empty — refresh 失败不影响渲染
        }
    });
}

/** 检查渲染器是否已初始化。外部代码在调用 setRenderState 前可先检查。 */
export function isRendererReady(): boolean {
    return pipeline !== undefined && _scene !== null && _modelRegistry !== null;
}

/** 释放渲染管线及相关资源。在场景销毁时调用。 */
export function disposeRenderer(): void {
    if (_probeRefreshObserver && _scene) {
        _scene.onBeforeRenderObservable.remove(_probeRefreshObserver);
        _probeRefreshObserver = null;
    }
    if (_glowLayer) {
        _glowLayer.dispose();
        _glowLayer = null;
    }
    if (_ssrPipeline) {
        _ssrPipeline.dispose();
        _ssrPipeline = null;
    }
    if (_ssaoPipeline) {
        _ssaoPipeline.dispose();
        _ssaoPipeline = null;
    }
    if (_reflectionProbe) {
        _reflectionProbe.dispose();
        _reflectionProbe = null;
    }
    if (pipeline) {
        pipeline.dispose();
        pipeline = undefined;
    }
    _scene = null;
    _modelRegistry = null;
    _triggerAutoSave = null;
    _pipelineCamera = null;
    _outlineEnabled = false;
    _outlineColor = [0, 0, 0];
}

// ======== 状态读取 ========

export function getRenderState(): RenderState {
    if (!_scene || !pipeline) {
        return defaultRenderState();
    }
    return {
        bloomEnabled: pipeline.bloomEnabled,
        bloomWeight: pipeline.bloomWeight ?? 0,
        bloomThreshold: pipeline.bloomThreshold ?? 0.5,
        bloomKernel: pipeline.bloomKernel ?? 64,
        outlineEnabled: _outlineEnabled,
        outlineColor: _outlineColor,
        fxaaEnabled: pipeline.fxaaEnabled,
        msaaSamples: pipeline.samples ?? 1,
        toneMapping: pipeline.imageProcessing.toneMappingType ?? 0,
        exposure: pipeline.imageProcessing.exposure ?? 1,
        contrast: pipeline.imageProcessing.contrast ?? 1,
        dofEnabled: pipeline.depthOfFieldEnabled,
        // fStop 0.5~10 → 归一化 0~1（0=无虚化 fStop=10, 1=最大虚化 fStop=0.5）
        dofAperture: pipeline.depthOfField ? clamp((10 - pipeline.depthOfField.fStop) / 9.5, 0, 1) : 0,
        vignetteEnabled: pipeline.imageProcessing.vignetteEnabled ?? false,
        vignetteDarkness: pipeline.imageProcessing.vignetteWeight ?? 0,
        chromaticAberrationEnabled: pipeline.chromaticAberrationEnabled ?? false,
        chromaticAberrationAmount: pipeline.chromaticAberration ? clamp(pipeline.chromaticAberration.aberrationAmount / 8, 0, 1) : 0,
        grainEnabled: pipeline.grainEnabled ?? false,
        grainIntensity: pipeline.grain ? clamp(pipeline.grain.intensity / 50, 0, 1) : 0,
        sharpenAmount: pipeline.sharpen ? clamp(pipeline.sharpen.edgeAmount, 0, 1) : 0,
        glowEnabled: _glowLayer !== null && _glowLayer.intensity > 0,
        glowIntensity: _glowLayer ? clamp(_glowLayer.intensity, 0, 1) : 0,
        ssrEnabled: _ssrPipeline !== null && _ssrPipeline.isEnabled,
        ssrStrength: _ssrPipeline ? clamp(_ssrPipeline.strength, 0, 1) : 0,
        ssrFalloff: _ssrPipeline ? clamp((_ssrPipeline.reflectionSpecularFalloffExponent - 1) / 7, 0, 1) : 0,
        ssrStep: _ssrPipeline ? clamp(_ssrPipeline.step, 1, 32) : 1,
        ssrThickness: _ssrPipeline ? clamp(_ssrPipeline.thickness, 0, 2) : 0.5,
        reflectionProbeEnabled: _reflectionProbe !== null,
        reflectionIntensity: _reflectionProbe ? 1 : 0,
        ssaoEnabled: _ssaoPipeline !== null,
        ssaoStrength: _ssaoPipeline ? clamp(_ssaoPipeline.totalStrength / 2, 0, 1) : 0,
        ssaoRadius: _ssaoPipeline ? clamp(_ssaoPipeline.radius / 4, 0, 1) : 0,
        ssaoSamples: _ssaoPipeline ? clamp(_ssaoPipeline.samples, 4, 32) : 8,
    };
}

export function defaultRenderState(): RenderState {
    return {
        bloomEnabled: false,
        bloomWeight: 0,
        bloomThreshold: 0.5,
        bloomKernel: 64,
        outlineEnabled: false,
        outlineColor: [0, 0, 0],
        fxaaEnabled: false,
        msaaSamples: 1,
        toneMapping: 0,
        exposure: 1,
        contrast: 1,
        dofEnabled: false,
        dofAperture: 0,
        vignetteEnabled: false,
        vignetteDarkness: 0,
        chromaticAberrationEnabled: false,
        chromaticAberrationAmount: 0,
        grainEnabled: false,
        grainIntensity: 0,
        sharpenAmount: 0,
        glowEnabled: false,
        glowIntensity: 0,
        ssrEnabled: false,
        ssrStrength: 0,
        ssrFalloff: 0,
        ssrStep: 1,
        ssrThickness: 0.5,
        reflectionProbeEnabled: false,
        reflectionIntensity: 0,
        ssaoEnabled: false,
        ssaoStrength: 0,
        ssaoRadius: 0,
        ssaoSamples: 8,
    };
}

// ======== 内部状态应用（无自动保存） ========

/**
 * 内部版 setRenderState，不触发自动保存。
 * 供 transitionRenderState 在中间帧调用，避免每帧触发保存 I/O。
 */
function _applyRenderState(s: Partial<RenderState>): void {
    if (!pipeline || !_scene || !_modelRegistry) {
        console.warn('[renderer] _applyRenderState: pipeline/scene 未初始化，状态更新被忽略');
        return;
    }

    // 数值钳制（全部 0-1 归一化范围）
    const w = s.bloomWeight !== undefined ? clamp(s.bloomWeight, 0, 1) : undefined;
    const th = s.bloomThreshold !== undefined ? clamp(s.bloomThreshold, 0, 1) : undefined;
    const k = s.bloomKernel !== undefined ? clamp(s.bloomKernel, 16, 256) : undefined;
    const e = s.exposure !== undefined ? clamp(s.exposure, 0, 4) : undefined;
    const c = s.contrast !== undefined ? clamp(s.contrast, 0, 4) : undefined;
    const da = s.dofAperture !== undefined ? clamp(s.dofAperture, 0, 1) : undefined;
    const vd = s.vignetteDarkness !== undefined ? clamp(s.vignetteDarkness, 0, 1) : undefined;
    const ca = s.chromaticAberrationAmount !== undefined ? clamp(s.chromaticAberrationAmount, 0, 1) : undefined;
    const gi = s.grainIntensity !== undefined ? clamp(s.grainIntensity, 0, 1) : undefined;
    const sa = s.sharpenAmount !== undefined ? clamp(s.sharpenAmount, 0, 1) : undefined;
    const gl = s.glowIntensity !== undefined ? clamp(s.glowIntensity, 0, 1) : undefined;
    const ssrStr = s.ssrStrength !== undefined ? clamp(s.ssrStrength, 0, 1) : undefined;
    const ssrFal = s.ssrFalloff !== undefined ? clamp(s.ssrFalloff, 0, 1) : undefined;
    const ssrStp = s.ssrStep !== undefined ? clamp(s.ssrStep, 1, 32) : undefined;
    const ssrThk = s.ssrThickness !== undefined ? clamp(s.ssrThickness, 0, 2) : undefined;

    // Post-processing
    if (s.bloomEnabled !== undefined) {
        pipeline.bloomEnabled = s.bloomEnabled;
    }
    if (w !== undefined) {
        pipeline.bloomWeight = w;
    }
    if (th !== undefined) {
        pipeline.bloomThreshold = th;
    }
    if (k !== undefined) {
        pipeline.bloomKernel = k;
    }
    if (s.fxaaEnabled !== undefined) {
        pipeline.fxaaEnabled = s.fxaaEnabled;
    }
    if (s.msaaSamples !== undefined) {
        pipeline.samples = clamp(s.msaaSamples, 1, 8);
    }

    // Outline — 仅在状态/颜色实际变化时遍历模型
    const outlineChanged = s.outlineEnabled !== undefined;
    const outlineColorChanged = s.outlineColor !== undefined;

    if (outlineChanged) {
        _outlineEnabled = s.outlineEnabled!;
    }
    if (outlineColorChanged) {
        _outlineColor = s.outlineColor;
    }
    if (outlineChanged || outlineColorChanged) {
        for (const inst of _modelRegistry.values()) {
            for (const m of inst.meshes) {
                if (outlineChanged) {
                    if (_outlineEnabled) {
                        m.enableEdgesRendering();
                    } else {
                        m.disableEdgesRendering();
                    }
                }
                if (m.edgesRenderer && outlineColorChanged) {
                    m.edgesColor = new Color4(
                        clampColorChannel(_outlineColor[0]),
                        clampColorChannel(_outlineColor[1]),
                        clampColorChannel(_outlineColor[2]),
                        1
                    );
                }
            }
        }
    }

    // DOF — 可选链保护（0-1 → fStop 0.5~10）
    if (s.dofEnabled !== undefined) {
        pipeline.depthOfFieldEnabled = s.dofEnabled;
    }
    if (da !== undefined && pipeline.depthOfField) {
        pipeline.depthOfField.fStop = 10 - da * 9.5;  // 0→清晰(f10), 1→虚化(f0.5)
    }

    // Vignette
    if (s.vignetteEnabled !== undefined && pipeline.imageProcessing) {
        pipeline.imageProcessing.vignetteEnabled = s.vignetteEnabled;
    }
    if (vd !== undefined && pipeline.imageProcessing) {
        pipeline.imageProcessing.vignetteWeight = vd;
    }

    // Chromatic Aberration（0-1 → 0~8）
    if (s.chromaticAberrationEnabled !== undefined) {
        pipeline.chromaticAberrationEnabled = s.chromaticAberrationEnabled;
    }
    if (ca !== undefined && pipeline.chromaticAberration) {
        pipeline.chromaticAberration.aberrationAmount = ca * 8;
    }

    // Grain（0-1 → 0~50）
    if (s.grainEnabled !== undefined) {
        pipeline.grainEnabled = s.grainEnabled;
    }
    if (gi !== undefined && pipeline.grain) {
        pipeline.grain.intensity = gi * 50;
    }

    // Sharpen
    if (sa !== undefined && pipeline.sharpen) {
        pipeline.sharpenEnabled = sa > 0;
        pipeline.sharpen.edgeAmount = sa;
    }

    // GlowLayer + Bloom 互斥：Bloom weight > 0.5 时自动降低 Glow 强度防止白出
    if (s.glowEnabled !== undefined || gl !== undefined) {
        const targetGlow = gl ?? (_glowLayer ? _glowLayer.intensity : 0);
        const bloomW = pipeline.bloomWeight ?? 0;
        const adjustedGlow = bloomW > 0.5 ? targetGlow * (1 - (bloomW - 0.5)) : targetGlow;
        if (s.glowEnabled !== undefined) {
            if (s.glowEnabled && !_glowLayer && _scene) {
                _glowLayer = new GlowLayer('glow', _scene, { blurKernelSize: 32 });
                _glowLayer.intensity = adjustedGlow;
            } else if (!s.glowEnabled && _glowLayer) {
                _glowLayer.dispose();
                _glowLayer = null;
            }
        }
        if (_glowLayer && gl !== undefined) {
            _glowLayer.intensity = adjustedGlow;
        }
    }

    // SSR (Screen-Space Reflections) — 独立 pipeline，不走 DefaultRenderingPipeline
    if (s.ssrEnabled !== undefined || ssrStr !== undefined || ssrFal !== undefined || ssrStp !== undefined || ssrThk !== undefined) {
        if (s.ssrEnabled !== undefined) {
            const ssrCamera = _pipelineCamera ?? _scene.activeCamera;
            if (s.ssrEnabled && !_ssrPipeline && _scene && ssrCamera) {
                try {
                    _ssrPipeline = new SSRRenderingPipeline('ssr', _scene, [ssrCamera]);
                    _ssrPipeline.maxDistance = 50;
                    _ssrPipeline.step = 1;
                    _ssrPipeline.thickness = 0.5;
                    _ssrPipeline.strength = 1;
                    _ssrPipeline.reflectionSpecularFalloffExponent = 1;
                    _ssrPipeline.samples = 1;
                    _ssrPipeline.isEnabled = true;
                } catch (err) {
                    console.warn('[renderer] SSR pipeline 创建失败:', err);
                    _ssrPipeline = null;
                }
            } else if (!s.ssrEnabled && _ssrPipeline) {
                _ssrPipeline.dispose();
                _ssrPipeline = null;
            }
        }
        if (_ssrPipeline) {
            if (ssrStr !== undefined) _ssrPipeline.strength = ssrStr;
            if (ssrFal !== undefined) _ssrPipeline.reflectionSpecularFalloffExponent = 1 + ssrFal * 7; // 0→1, 1→8
            if (ssrStp !== undefined) _ssrPipeline.step = Math.round(ssrStp);
            if (ssrThk !== undefined) _ssrPipeline.thickness = ssrThk;
            // SSR + Bloom 互斥：Bloom weight > 0.5 时自动降低 SSR 强度防止白出
            // 基于当前 pipeline 强度（已更新）而非传入值，避免覆盖用户设置
            const bloomW = pipeline.bloomWeight ?? 0;
            if (bloomW > 0.5) {
                _ssrPipeline.strength *= (1 - (bloomW - 0.5));
            }
        }
    }

    // Reflection Probe — 环境反射
    if (s.reflectionProbeEnabled !== undefined || s.reflectionIntensity !== undefined) {
        if (s.reflectionProbeEnabled !== undefined) {
            if (s.reflectionProbeEnabled && !_reflectionProbe && _scene) {
                try {
                    _reflectionProbe = new ReflectionProbe('envProbe', 256, _scene);
                    _reflectionProbe.renderList = _scene.meshes.filter((m) =>
                        m.name.includes('sky') || m.name.includes('env') || m.name.includes('ground') || m.name.includes('water')
                    );
                    _reflectionProbe.refreshRate = 0; // 静态环境，仅渲染一次
                } catch (err) {
                    console.warn('[renderer] ReflectionProbe 创建失败:', err);
                    _reflectionProbe = null;
                }
            } else if (!s.reflectionProbeEnabled && _reflectionProbe) {
                // 清除所有模型材质的 reflectionTexture
                if (_modelRegistry) {
                    for (const inst of _modelRegistry.values()) {
                        for (const mesh of inst.meshes) {
                            const m = mesh.material;
                            if (m && 'reflectionTexture' in m) {
                                (m as { reflectionTexture: unknown }).reflectionTexture = null;
                            }
                        }
                    }
                }
                _reflectionProbe.dispose();
                _reflectionProbe = null;
            }
        }
        // 绑定反射探针到模型材质
        if (_reflectionProbe && s.reflectionProbeEnabled) {
            const rt = _reflectionProbe.cubeTexture;
            if (rt && _modelRegistry) {
                for (const inst of _modelRegistry.values()) {
                    for (const mesh of inst.meshes) {
                        const m = mesh.material;
                        if (m && 'reflectionTexture' in m) {
                            (m as { reflectionTexture: import('@babylonjs/core/Materials/Textures/texture').Texture }).reflectionTexture = rt;
                            // 设置反射强度
                            if (s.reflectionIntensity !== undefined && 'reflectionColor' in m) {
                                const intensity = s.reflectionIntensity;
                                (m as { reflectionColor: import('@babylonjs/core/Maths/math.color').Color3 }).reflectionColor.set(intensity, intensity, intensity);
                            }
                        }
                    }
                }
            }
        }
    }

    // SSAO (Screen-Space Ambient Occlusion) — 独立 pipeline
    if (s.ssaoEnabled !== undefined || s.ssaoStrength !== undefined || s.ssaoRadius !== undefined || s.ssaoSamples !== undefined) {
        if (s.ssaoEnabled !== undefined) {
            const ssaoCamera = _pipelineCamera ?? _scene.activeCamera;
            if (s.ssaoEnabled && !_ssaoPipeline && _scene && ssaoCamera) {
                try {
                    _ssaoPipeline = new SSAO2RenderingPipeline('ssao', _scene, 0.5, [ssaoCamera]);
                    _ssaoPipeline.totalStrength = 1.0;
                    _ssaoPipeline.radius = 2.0;
                    _ssaoPipeline.samples = 8;
                    _ssaoPipeline.epsilon = 0.02;
                    _ssaoPipeline.expensiveBlur = true;
                    _ssaoPipeline.bilateralSamples = 16;
                    _ssaoPipeline.bilateralSoften = 0.5;
                } catch (err) {
                    console.warn('[renderer] SSAO pipeline 创建失败:', err);
                    _ssaoPipeline = null;
                }
            } else if (!s.ssaoEnabled && _ssaoPipeline) {
                _ssaoPipeline.dispose();
                _ssaoPipeline = null;
            }
        }
        if (_ssaoPipeline) {
            if (s.ssaoStrength !== undefined) _ssaoPipeline.totalStrength = clamp(s.ssaoStrength * 2, 0, 2);
            if (s.ssaoRadius !== undefined) _ssaoPipeline.radius = clamp(s.ssaoRadius * 4, 0, 4);
            if (s.ssaoSamples !== undefined) _ssaoPipeline.samples = Math.round(clamp(s.ssaoSamples, 4, 32));
        }
    }

    // Stage / imageProcessing
    if (pipeline.imageProcessing) {
        if (s.toneMapping !== undefined) {
            pipeline.imageProcessing.toneMappingType = s.toneMapping;
        }
        if (e !== undefined) {
            pipeline.imageProcessing.exposure = e;
        }
        if (c !== undefined) {
            pipeline.imageProcessing.contrast = c;
        }
    }
}

// ======== 对外状态设置（含自动保存） ========

export function setRenderState(s: Partial<RenderState>): void {
    if (!pipeline || !_scene || !_modelRegistry || !_triggerAutoSave) {
        console.warn('[renderer] setRenderState: pipeline/scene 未初始化，状态更新被忽略');
        return;
    }

    _applyRenderState(s);

    _triggerAutoSave();
    scheduleRefresh();
    resetPerformanceSnapshot(); // 用户手动修改渲染设置：清除自动降级快照，避免 auto 模式后续降级覆盖用户意图
}

// ======== 平滑过渡 ========

/**
 * 平滑过渡渲染状态到目标值，默认 2 秒。
 * 数值/颜色字段做 lerp 插值；布尔字段按阈值提前启用；枚举字段在动画结束时切换。
 * 中间帧不触发自动保存，仅最终帧保存一次。
 */
export function transitionRenderState(
    target: Partial<RenderState>,
    duration: number = 2000,
    onComplete?: () => void
): void {
    if (!pipeline || !_scene || !_triggerAutoSave) {
        return;
    }

    const source = getRenderState();
    const startTime = performance.now();

    // 数值字段列表（需要 lerp）
    const numericKeys: (keyof RenderState)[] = [
        'bloomWeight',
        'bloomThreshold',
        'bloomKernel',
        'exposure',
        'contrast',
        'dofAperture',
        'vignetteDarkness',
        'chromaticAberrationAmount',
        'grainIntensity',
        'sharpenAmount',
        'glowIntensity',
        'ssrStrength',
        'ssrFalloff',
        'ssrStep',
        'ssrThickness',
        'reflectionIntensity',
        'ssaoStrength',
        'ssaoRadius',
        'ssaoSamples',
    ];
    // 颜色字段列表（逐通道 lerp）
    const colorKeys: (keyof RenderState)[] = ['outlineColor'];
    // 布尔字段列表（按阈值提前启用/禁用以减少视觉跳跃）
    const boolKeys: (keyof RenderState)[] = [
        'bloomEnabled',
        'outlineEnabled',
        'fxaaEnabled',
        'dofEnabled',
        'vignetteEnabled',
        'chromaticAberrationEnabled',
        'grainEnabled',
        'glowEnabled',
        'ssrEnabled',
        'reflectionProbeEnabled',
        'ssaoEnabled',
    ];
    // 枚举字段（动画结束时切换）
    const enumKeys: (keyof RenderState)[] = ['toneMapping'];

    const lerp = (a: number, b: number, t: number) => a + (b - a) * t;

    /**
     * 判断布尔字段是否应在当前插值进度 t 时切换。
     * 对于启用（false→true）：当关联数值字段超过阈值时提前启用，减少跳跃感。
     * 对于禁用（true→false）：在动画结束时切换。
     */
    function shouldActivateBool(key: keyof RenderState, t: number): boolean {
        const targetVal = target[key] as boolean | undefined;
        if (targetVal === undefined) {
            return source[key] as boolean;
        }

        if (targetVal) {
            // 从 false → true：当关联数值超过半程时提前启用
            if (key === 'bloomEnabled') {
                const b =
                    target.bloomWeight !== undefined ? target.bloomWeight : source.bloomWeight;
                return t >= 0.3 || (b > 0 && source.bloomWeight > 0);
            }
            if (key === 'dofEnabled') {
                return t >= 0.3;
            }
            if (key === 'vignetteEnabled') {
                return t >= 0.3;
            }
            if (key === 'chromaticAberrationEnabled' || key === 'grainEnabled') {
                return t >= 0.3;
            }
            if (key === 'glowEnabled') {
                return t >= 0.3;
            }
            if (key === 'ssrEnabled' || key === 'reflectionProbeEnabled' || key === 'ssaoEnabled') {
                return t >= 0.3;
            }
            // outline / fxaa 无关联数值，延迟到 80%
            if (key === 'outlineEnabled' || key === 'fxaaEnabled') {
                return t >= 0.8;
            }
            return t >= 1;
        } else {
            // 从 true → false：动画结束时再禁用
            return t >= 1 ? false : (source[key] as boolean);
        }
    }

    const animLoop = () => {
        const elapsed = performance.now() - startTime;
        const t = Math.min(elapsed / duration, 1.0);
        const interp: Partial<RenderState> = {};

        // 数值字段插值
        for (const key of numericKeys) {
            if (target[key] !== undefined) {
                const a = source[key] as number;
                const b = target[key] as number;
                setKey(interp, key, lerp(a, b, t) as RenderState[typeof key]);
            }
        }
        // 颜色字段插值（逐通道）
        for (const key of colorKeys) {
            if (target[key] !== undefined) {
                const a = source[key] as number[];
                const b = target[key] as number[];
                setKey(interp, key, a.map((v, i) => lerp(v, b[i], t)) as RenderState[typeof key]);
            }
        }
        // 布尔字段：按阈值提前切换
        for (const key of boolKeys) {
            if (target[key] !== undefined) {
                setKey(interp, key, shouldActivateBool(key, t) as RenderState[typeof key]);
            }
        }
        // 枚举字段：t >= 1 时切换到目标值，否则保持当前值
        for (const key of enumKeys) {
            if (target[key] !== undefined) {
                setKey(interp, key, (t >= 1 ? target[key] : source[key]) as RenderState[typeof key]);
            }
        }

        // 中间帧调用 _applyRenderState（不触发自动保存），最终帧用 setRenderState（触发一次保存）
        if (t >= 1) {
            setRenderState(interp);
            if (onComplete) {
                onComplete();
            }
        } else {
            _applyRenderState(interp);

}
};

    _scene.onBeforeRenderObservable.addOnce(animLoop);
}

// ======== 相机重挂接 ========

/** Re-attach the rendering pipeline to the current active camera (call after camera switch). */
export function reattachPipeline(): void {
    if (!_scene || !pipeline) {
        return;
    }
    if (_scene.activeCamera) {
        // 先清除 pipeline 中所有已注册的相机，再添加当前相机
        const existingCameras = pipeline.cameras;
        if (existingCameras) {
            for (const cam of existingCameras) {
                try {
                    pipeline.removeCamera(cam);
                } catch {
                    // Intentionally empty — 移除已有相机失败，继续添加新相机即可
                }
            }
        }
        pipeline.addCamera(_scene.activeCamera);
        _pipelineCamera = _scene.activeCamera;
        // SSR pipeline 也需要重新挂接相机
        if (_ssrPipeline) {
            try {
                _ssrPipeline.dispose();
                _ssrPipeline = null;
                // 下次 _applyRenderState 时会重建
            } catch {
                // Intentionally empty — SSR pipeline dispose 失败不影响主流程
            }
        }
        // SSAO pipeline 也需要重新挂接相机
        if (_ssaoPipeline) {
            try {
                _ssaoPipeline.dispose();
                _ssaoPipeline = null;
                // 下次 _applyRenderState 时会重建
            } catch {
                // Intentionally empty — SSAO pipeline dispose 失败不影响主流程
            }
        }
    }
}

// ======== 边缘高亮重建 ========

/** 当环境变化时（天空/地面/水面切换），刷新 Reflection Probe 的 renderList。 */
export function refreshReflectionProbe(): void {
    if (!_reflectionProbe || !_scene) return;
    _reflectionProbe.renderList = _scene.meshes.filter((m) =>
        m.name.includes('sky') || m.name.includes('env') || m.name.includes('ground') || m.name.includes('water')
    );
    // 强制刷新：临时设置 refreshRate 为 1 触发重新渲染
    _reflectionProbe.refreshRate = 1;
    _reflectionProbe.refreshRate = 0;
}

/** 将 Reflection Probe 绑定到指定模型的所有材质（模型加载后调用）。 */
export function bindReflectionProbeToModel(meshes: import('@babylonjs/core/Meshes/mesh').Mesh[]): void {
    if (!_reflectionProbe) return;
    const rt = _reflectionProbe.cubeTexture;
    if (!rt) return;
    for (const mesh of meshes) {
        const m = mesh.material;
        if (m && 'reflectionTexture' in m) {
            (m as { reflectionTexture: import('@babylonjs/core/Materials/Textures/texture').Texture }).reflectionTexture = rt;
        }
    }
}

/** 当模型注册表更新时，重新应用边缘高亮状态。 */
export function rebuildOutlineState(): void {
    if (!_modelRegistry) {
        return;
    }
    for (const inst of _modelRegistry.values()) {
        for (const m of inst.meshes) {
            if (_outlineEnabled) {
                m.enableEdgesRendering();
                if (m.edgesRenderer) {
                    m.edgesColor = new Color4(
                        clampColorChannel(_outlineColor[0]),
                        clampColorChannel(_outlineColor[1]),
                        clampColorChannel(_outlineColor[2]),
                        1
                    );
                }
            } else {
                m.disableEdgesRendering();
            }
        }
    }
}

// [doc:architecture] Scene Bundle — 场景打包/解包
// 职责: 收集场景引用资源、重写 libraryRef、调用 Go 后端打包/解包
// 依赖: scene-serialize.ts + config.ts + wails bindings

import {
    libraryRoot,
    externalPaths,
    setStatus,
    setLibraryRoot,
} from '../core/config';
import { computeLibraryRef, resolveLibraryRef } from '../core/utils';
import {
    serializeScene,
    deserializeScene,
    resolvePathFromRef,
    type SceneFile,
} from './scene-serialize';
import {
    BundleScene,
    SelectBundleSaveFile,
    ExtractZip,
    SelectSceneOpenFile,
    LoadSceneFile,
} from '../core/wails-bindings';

/** 简易 dirname。 */
function _dirname(p: string): string {
    const n = p.replace(/\\/g, '/');
    const idx = n.lastIndexOf('/');
    return idx >= 0 ? n.slice(0, idx) : '.';
}

/** 简易 join。 */
function _join(...parts: string[]): string {
    return parts.join('/').replace(/\/+/g, '/');
}

// ======== Asset Collection ========

/** 收集场景所有引用资源的绝对路径（去重）。 */
function collectSceneAssets(scene: SceneFile): string[] {
    const paths = new Set<string>();

    function add(filePath: string | undefined | null, libraryRef?: string) {
        if (!filePath && !libraryRef) return;
        const resolved = resolvePathFromRef(filePath ?? '', libraryRef);
        if (resolved) paths.add(resolved);
    }

    // Models (PMX)
    for (const m of scene.models) {
        add(m.filePath, m.libraryRef);
        // VMD per model
        add(m.vmdPath, m.vmdLibraryRef);
        // VMD layers
        if (m.vmdLayers) {
            for (const layer of m.vmdLayers) {
                add(layer.path);
            }
        }
    }

    // Camera VMD
    if (scene.cameraVmd) {
        add(scene.cameraVmd.path, scene.cameraVmd.libraryRef);
    }

    // Audio
    if (scene.audio) {
        add(scene.audio.path, scene.audio.libraryRef);
    }

    // Props
    if (scene.props) {
        for (const p of scene.props) {
            add(p.filePath, p.libraryRef);
        }
    }

    return Array.from(paths);
}

/** 收集 PMX 模型同目录下的纹理/换装文件。 */
async function collectModelTextures(pmxPath: string): Promise<string[]> {
    const extras: string[] = [];
    try {
        const dir = _dirname(pmxPath);
        // 使用 Go 绑定列出目录内容（如果可用）
        // 注意：ListSubDirs 只列子目录，我们需要列文件
        // 这里用简化的策略：纹理文件通常与 PMX 同目录
        // 通过 ReadFile 无法列目录，暂时只收集 PMX 本身
        // 纹理由 PMX loader 自动处理（相对路径引用）
    } catch {
        // 静默失败 — 纹理收集是尽力而为
    }
    return extras;
}

// ======== libraryRef Rewriting ========

/** 将 SceneFile 中的 libraryRef 重写为 bundle 内部路径。 */
function rewriteRefsForBundle(scene: SceneFile, libraryRoot: string): SceneFile {
    const rewritten = JSON.parse(JSON.stringify(scene)) as SceneFile;

    function rewritePath(filePath: string | undefined | null, libraryRef: string | undefined): string | undefined {
        if (!filePath && !libraryRef) return undefined;

        // 尝试解析绝对路径
        const abs = resolvePathFromRef(filePath ?? '', libraryRef);
        if (!abs) return undefined;

        // 计算在 bundle assets/ 内的相对路径
        return _bundleInternalPath(abs, libraryRoot);
    }

    // Models
    for (const m of rewritten.models) {
        const newRef = rewritePath(m.filePath, m.libraryRef);
        if (newRef) {
            m.libraryRef = newRef;
            m.filePath = '';  // 清除绝对路径，只保留 libraryRef
        }
        // VMD
        const vmdRef = rewritePath(m.vmdPath, m.vmdLibraryRef);
        if (vmdRef) {
            m.vmdLibraryRef = vmdRef;
            m.vmdPath = '';
        }
        // VMD layers — 没有 libraryRef，需要添加
        if (m.vmdLayers) {
            for (const layer of m.vmdLayers) {
                if (layer.path) {
                    const layerRef = rewritePath(layer.path, undefined);
                    if (layerRef) {
                        (layer as Record<string, unknown>).libraryRef = layerRef;
                        layer.path = '';
                    }
                }
            }
        }
    }

    // Camera VMD
    if (rewritten.cameraVmd) {
        const cvRef = rewritePath(rewritten.cameraVmd.path, rewritten.cameraVmd.libraryRef);
        if (cvRef) {
            rewritten.cameraVmd.libraryRef = cvRef;
            rewritten.cameraVmd.path = '';
        }
    }

    // Audio
    if (rewritten.audio) {
        const aRef = rewritePath(rewritten.audio.path, rewritten.audio.libraryRef);
        if (aRef) {
            rewritten.audio.libraryRef = aRef;
            rewritten.audio.path = '';
        }
    }

    // Props
    if (rewritten.props) {
        for (const p of rewritten.props) {
            const pRef = rewritePath(p.filePath, p.libraryRef);
            if (pRef) {
                p.libraryRef = pRef;
                p.filePath = '';
            }
        }
    }

    return rewritten;
}

/** 计算资源在 bundle 内部的 libraryRef 路径。 */
function _bundleInternalPath(absPath: string, libRoot: string): string {
    const normalised = absPath.replace(/\\/g, '/');
    const rootNorm = libRoot.replace(/\\/g, '/');

    // 在主库内
    if (normalised.startsWith(rootNorm + '/')) {
        return normalised.slice(rootNorm.length + 1); // "actors/miku.pmx"
    }

    // 在外部库内
    for (const ext of externalPaths) {
        const extNorm = ext.path.replace(/\\/g, '/');
        if (normalised.startsWith(extNorm + '/')) {
            return `${ext.name}:${normalised.slice(extNorm.length + 1)}`; // "mylib:actors/miku.pmx"
        }
    }

    // 不在任何库内 — 用文件名
    return normalised.split('/').pop() ?? normalised;
}

// ======== Export (Pack) ========

/** 导出场景为 bundle zip 文件。 */
export async function exportSceneBundle(): Promise<void> {
    setStatus('正在收集场景资源…', true);

    const scene = serializeScene();
    const assetPaths = collectSceneAssets(scene);

    // 重写 libraryRef
    const rewritten = rewriteRefsForBundle(scene, libraryRoot);

    // 选择保存路径
    const targetPath = await SelectBundleSaveFile();
    if (!targetPath) {
        setStatus('', false);
        return;
    }

    setStatus('正在打包…', true);
    try {
        await BundleScene(targetPath, JSON.stringify(rewritten), assetPaths);
        setStatus(`✓ 场景包已导出: ${targetPath.split('/').pop()}`, true);
    } catch (err) {
        console.error('exportSceneBundle:', err);
        setStatus('✗ 导出失败', false);
    }
}

// ======== Import (Unpack) ========

/** 导入场景 bundle zip 文件。 */
export async function importSceneBundle(): Promise<void> {
    const zipPath = await SelectSceneOpenFile();
    if (!zipPath) return;

    setStatus('正在解包场景…', true);
    try {
        // 解压到缓存目录
        const result = await ExtractZip(zipPath, '');
        if (!result || !result.dir) {
            setStatus('✗ 解压失败', false);
            return;
        }

        const extractDir = result.dir;

        // 读取 scene.json
        const sceneJsonPath = _join(extractDir, 'scene.json');
        const sceneJson = await LoadSceneFile(sceneJsonPath);
        if (!sceneJson) {
            setStatus('✗ 场景包内无 scene.json', false);
            return;
        }

        // 解析场景文件
        const sceneData = JSON.parse(sceneJson) as SceneFile;

        // 临时将 libraryRoot 指向解压目录
        // resolveLibraryRef 会自动在解压目录下查找资源
        const origRoot = libraryRoot;
        setLibraryRoot(extractDir);

        try {
            await deserializeScene(sceneData);
            setStatus(`✓ 场景包已导入`, true);
        } finally {
            // 恢复 libraryRoot
            setLibraryRoot(origRoot);
        }
    } catch (err) {
        console.error('importSceneBundle:', err);
        setStatus('✗ 导入失败', false);
    }
}

